def env_flag_enabled(name, default=False):
    """Return True when an environment flag is explicitly enabled."""
    raw_value = os.environ.get(name)
    if raw_value is None:
        return bool(default)
    return str(raw_value).strip().lower() in {'1', 'true', 'yes', 'on'}


