def should_log_performance_path(path):
    """Return True for pages/APIs useful for diagnosing loading slowness."""
    if not PERFORMANCE_LOG_ENABLED or not path:
        return False

    if path in PERFORMANCE_LOG_PATHS:
        return True

    monitored_prefixes = (
        '/preview_tsr_archive',
        '/download_tsr_archive',
        '/search_clients',
        '/search_products',
        '/export_'
    )
    return path.startswith(monitored_prefixes)


@app.before_request
def restore_pwa_session_before_route():
    ensure_user_approval_columns()
    restore_user_from_pwa_login_cookie()


@app.before_request
def keep_authenticated_pwa_session_permanent():
    """Refresh persistent sessions for installed PWA/mobile users.

    Flask-Login remember cookies restore the user, while Flask's permanent
    session keeps the active app session from becoming browser-session-only.
    """
    try:
        if current_user and getattr(current_user, 'is_authenticated', False):
            session.permanent = True
            session.modified = True
    except Exception:
        pass


@app.before_request
def start_performance_timer():
    if should_log_performance_path(request.path):
        g._perf_start = time.perf_counter()


@app.before_request
def block_new_workflows_when_disabled():
    if new_workflows_enabled():
        return
    if not is_new_workflow_path(request.path):
        return

    if request.accept_mimetypes.accept_json or request.path.startswith(('/get_', '/save_', '/submit_', '/approve_', '/reject_', '/delete_', '/upload_', '/download_', '/preview_', '/open_', '/inline_', '/mark_', '/create_', '/complete_', '/resend_', '/settings/')):
        return jsonify({
            'success': False,
            'status': 'disabled',
            'message': 'This workflow is scheduled to open on July 6.'
        }), 403

    return redirect(url_for('dashboard_page'))


@app.context_processor
def inject_feature_flags():
    return {
        'new_workflows_enabled': new_workflows_enabled()
    }


@app.after_request
def log_performance_timer(response):
    start_time = getattr(g, '_perf_start', None)
    if start_time is None:
        return response

    duration_ms = (time.perf_counter() - start_time) * 1000
    if duration_ms >= PERFORMANCE_LOG_MIN_MS:
        query_string = request.query_string.decode('utf-8', errors='ignore')
        path_label = request.path + (f"?{query_string}" if query_string else "")
        print(
            f"[PERF] {request.method} {path_label} -> {response.status_code} in {duration_ms:.1f} ms",
            flush=True
        )

    response.headers['X-Response-Time-ms'] = f"{duration_ms:.1f}"
    return response


@app.after_request
def prevent_login_redirect_cache(response):
    """Avoid PWA/browser caching login redirects as protected pages."""
    try:
        if request.path == '/login' or response.status_code in {301, 302, 303, 307, 308}:
            response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
            response.headers['Pragma'] = 'no-cache'
            response.headers['Expires'] = '0'
    except Exception:
        pass
    return response


_shift_file_original_filename_ready = False


def derive_original_filename_from_stored_filename(filename):
    """Return clean client-facing filename from randomized stored filename."""
    safe_name = os.path.basename(clean_str(filename))
    if not safe_name:
        return ''

    match = re.match(r'^shift_\d+_[0-9a-fA-F]{16}_(.+)$', safe_name)
    if match:
        return match.group(1)

    return safe_name


def get_shift_file_display_name(file_rec_or_filename):
    """Return original upload filename for email/UI while keeping disk filename safe."""
    if hasattr(file_rec_or_filename, 'filename'):
        original = clean_str(getattr(file_rec_or_filename, 'original_filename', ''))
        if original:
            return os.path.basename(original)
        return derive_original_filename_from_stored_filename(getattr(file_rec_or_filename, 'filename', ''))

    return derive_original_filename_from_stored_filename(file_rec_or_filename)


def get_shift_file_disk_name(file_rec_or_filename):
    """Return randomized disk filename used for storage/delete lookup."""
    if hasattr(file_rec_or_filename, 'filename'):
        return os.path.basename(clean_str(getattr(file_rec_or_filename, 'filename', '')))
    return os.path.basename(clean_str(file_rec_or_filename))

def get_unique_upload_filename(preferred_filename):
    """Return a clean unique upload filename without random prefixes.

    Used for generated Online TSR PDFs so browser/static downloads keep the
    same clean filename as the Offline TSR Download PDF button.
    """
    safe_name = secure_filename(os.path.basename(clean_str(preferred_filename) or ''))
    if not safe_name:
        safe_name = 'Online_TSR.pdf'

    stem, ext = os.path.splitext(safe_name)
    ext = ext or '.pdf'
    candidate = f"{stem}{ext}"
    counter = 2

    while os.path.exists(os.path.join(app.config['UPLOAD_FOLDER'], candidate)):
        candidate = f"{stem}_{counter}{ext}"
        counter += 1

    return candidate


