# --- v5.4.4 TIMEZONE HELPER (PH TIME UTC+8) ---

def get_manila_time():
    """ Returns current time in Philippines (UTC+8) """
    return datetime.now(timezone.utc) + timedelta(hours=8)

def get_manila_today():
    """Return current Manila calendar date."""
    return get_manila_time().date()


def should_notify_schedule(shift):
    """Only notify engineers for today/future schedules.

    Backfilling historical schedules should stay silent because those jobs are
    already in the past and do not require engineer email alerts.
    """
    if not shift or not getattr(shift, 'start_time', None):
        return False
    return shift.start_time.date() >= get_manila_today()


def should_notify_snapshot(snapshot):
    """Only notify delete events for today/future schedule snapshots."""
    if not snapshot:
        return False

    raw_date = snapshot.get('date_iso') or snapshot.get('date')
    if raw_date:
        parsed = parse_date(raw_date)
        if parsed:
            return parsed >= get_manila_today()

    return True


# --- DATABASE MODELS ---

class User(UserMixin, db.Model):
    must_change_password = db.Column(db.Boolean, default=False)
    """
    Identity and Access Management (IAM) Model.
    Permission Hierarchy:
    - superadmin: Full authority over personnel accounts and system resets.
    - regional_admin: Oversight of Cebu and Davao branches only.
    - admin: Standard management (Legacy/General).
    - engineer: Technical staff (Self-access only).
    """
    id = db.Column(db.Integer, primary_key=True)
    
    username = db.Column(db.String(100), unique=True, nullable=False)
    
    password = db.Column(db.String(200), nullable=False)
    
    # Permission Scope Definition (Mapped to UI visibility)
    role = db.Column(db.String(20), default='engineer') 

    # S1 Approval Routing Foundation:
    # These fields do not replace the existing User.role hierarchy. They mark
    # accounts that may be selected as business approvers in Settings later.
    can_approve_requests = db.Column(db.Boolean, default=False, nullable=False)
    approval_scope = db.Column(db.String(50), default='', nullable=True)
    approval_title = db.Column(db.String(100), default='', nullable=True)
    is_active = db.Column(db.Boolean, default=True, nullable=False)

    # v5.4.0: Direct Relationship to Engineer profile
    engineer_rel = db.relationship('Engineer', backref='user_account', uselist=False)

    @property
    def engineer_profile(self):
        """Personalization v5.4: Links user account to the correct engineer profile.

        Important:
        - Admin Kevin must resolve by employee ID, not by first-name matching.
        - This prevents another engineer named Kevin from being treated as the regional admin profile.
        """
        if self.engineer_rel:
            return self.engineer_rel

        username = (self.username or '').strip().lower()
        if username == REGIONAL_ADMIN_USERNAME:
            return Engineer.query.filter_by(employee_id=REGIONAL_ADMIN_EMPLOYEE_ID).first()

        # Fallback for older engineer accounts without user_id linkage.
        return Engineer.query.filter(Engineer.name.ilike(f"{self.username}%")).first()


class ApprovalRouting(db.Model):
    """S1 Settings foundation: requester-to-approver business routing.

    This is intentionally generic so Field Operations modules can reuse the same
    routing engine later:
    - Reimbursement
    - Travel Request
    - Cash Advance
    - Request For Payment

    request_scope may be:
    - all
    - reimbursement
    - travel_request
    - cash_advance
    - request_for_payment
    """
    id = db.Column(db.Integer, primary_key=True)
    requester_user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False, index=True)
    approver_user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False, index=True)
    request_scope = db.Column(db.String(50), default='all', nullable=False, index=True)
    active = db.Column(db.Boolean, default=True, nullable=False, index=True)
    created_at = db.Column(db.DateTime, default=get_manila_time)
    updated_at = db.Column(db.DateTime, default=get_manila_time, onupdate=get_manila_time)

    requester = db.relationship('User', foreign_keys=[requester_user_id], backref='approval_routes_as_requester')
    approver = db.relationship('User', foreign_keys=[approver_user_id], backref='approval_routes_as_approver')

    __table_args__ = (
        # S11D.3 Multi-Approver Routing:
        # A requester may have multiple approvers for the same request type.
        # Only the exact requester + approver + scope combination must be unique.
        db.UniqueConstraint('requester_user_id', 'approver_user_id', 'request_scope', name='uq_approval_routing_requester_approver_scope'),
    )


class UniversalApprovalAuditTrail(db.Model):
    """S9 Universal Approval Audit Trail.

    Generic, append-only workflow history shared by:
    - reimbursement
    - travel_request
    - cash_advance
    - request_for_payment

    This is separate from ActivityLog because ActivityLog is system-wide/noisy,
    while this table is request-lifecycle specific and can be shown inside each
    request later.
    """
    id = db.Column(db.Integer, primary_key=True)
    module = db.Column(db.String(50), nullable=False, index=True)
    record_id = db.Column(db.Integer, nullable=False, index=True)
    action = db.Column(db.String(80), nullable=False, index=True)
    actor_user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=True, index=True)
    actor_username = db.Column(db.String(100), nullable=True)
    actor_display_name = db.Column(db.String(150), nullable=True)
    status_from = db.Column(db.String(50), nullable=True)
    status_to = db.Column(db.String(50), nullable=True)
    remarks = db.Column(db.Text, nullable=True)
    metadata_json = db.Column(db.Text, nullable=True)
    created_at = db.Column(db.DateTime, default=get_manila_time, nullable=False, index=True)

    actor = db.relationship('User', foreign_keys=[actor_user_id])


