    travel_request_id = db.Column(db.Integer, db.ForeignKey('travel_request.id'), nullable=False, unique=True, index=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False, index=True)
    engineer_id = db.Column(db.Integer, db.ForeignKey('engineer.id'), nullable=True, index=True)

    status = db.Column(db.String(40), nullable=False, default='Draft', index=True)
    cash_advance_amount = db.Column(db.Float, default=0)
    total_actual_expenses = db.Column(db.Float, default=0)
    due_to_shimadzu = db.Column(db.Float, default=0)
    due_to_employee = db.Column(db.Float, default=0)
    currency_code = db.Column(db.String(3), nullable=False, default='PHP')
    usd_to_php_rate = db.Column(db.Float, default=0)

    submitted_at = db.Column(db.DateTime, nullable=True)
    approved_at = db.Column(db.DateTime, nullable=True)
    approved_by_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=True, index=True)
    rejected_at = db.Column(db.DateTime, nullable=True)
    rejected_by_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=True, index=True)
    approval_remarks = db.Column(db.Text, nullable=True)

    approval_action = db.Column(db.String(20), nullable=True)
    approval_name_snapshot = db.Column(db.String(150), nullable=True)
    approval_title_snapshot = db.Column(db.String(150), nullable=True)
    approval_signature_snapshot = db.Column(db.Text, nullable=True)
    approval_signature_layout = db.Column(db.String(50), nullable=True)
    approval_signed_at = db.Column(db.DateTime, nullable=True)

    accounting_status = db.Column(db.String(40), nullable=True, index=True)
    accounting_remarks = db.Column(db.Text, nullable=True)
    completed_at = db.Column(db.DateTime, nullable=True)
    completed_by_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=True, index=True)
    completion_remarks = db.Column(db.Text, nullable=True)

    created_at = db.Column(db.DateTime, default=get_manila_time)
    updated_at = db.Column(db.DateTime, default=get_manila_time, onupdate=get_manila_time)

    travel_request = db.relationship('TravelRequest', foreign_keys=[travel_request_id], backref=db.backref('liquidation_header', uselist=False))
    requester = db.relationship('User', foreign_keys=[user_id])
    engineer = db.relationship('Engineer', foreign_keys=[engineer_id])
    approver = db.relationship('User', foreign_keys=[approved_by_id])
    completed_by = db.relationship('User', foreign_keys=[completed_by_id])

    rows = db.relationship(
        'TravelLiquidationRow',
        backref='liquidation',
        lazy=True,
        cascade='all, delete-orphan'
    )


