def normalize_email_recipient_group(group_key):
    group_key = (clean_str(group_key) or '').strip().lower()
    return group_key if group_key in EMAIL_RECIPIENT_GROUPS else ''


def normalize_single_email_address(email_value):
    email_value = (clean_str(email_value) or '').strip()
    if not email_value:
        return ''
    if not re.match(r'^[^@\s]+@[^@\s]+\.[^@\s]+$', email_value):
        return ''
    return email_value.lower()


