def get_active_email_recipients_by_group(group_key):
    """Return active recipient emails for one Settings-managed group."""
    ensure_email_recipient_setting_table()

    group_key = normalize_email_recipient_group(group_key)
    if not group_key:
        return []

    recipients = (
        EmailRecipientSetting.query
        .filter_by(group_key=group_key, is_active=True)
        .order_by(EmailRecipientSetting.sort_order.asc(), EmailRecipientSetting.email.asc())
        .all()
    )
    return normalize_email_list([recipient.email for recipient in recipients])


