def email_template_setting_to_dict(template):
    cfg = EMAIL_TEMPLATE_DEFAULTS.get(template.template_key or '', {})
    return {
        'id': template.id,
        'template_key': template.template_key or '',
        'template_type': template.template_type or cfg.get('template_type') or 'subject',
        'label': template.label or cfg.get('label') or template.template_key or '',
        'description': template.description or cfg.get('description') or '',
        'template_value': template.template_value or cfg.get('default_template') or '',
        'default_template': cfg.get('default_template') or '',
        'is_active': bool(template.is_active),
        'allowed_placeholders': EMAIL_TEMPLATE_ALLOWED_PLACEHOLDERS.get(template.template_key or '', []),
        'created_at': template.created_at.isoformat() if getattr(template, 'created_at', None) else None,
        'updated_at': template.updated_at.isoformat() if getattr(template, 'updated_at', None) else None
    }


def get_email_template_value(template_key):
    """Return active Settings-managed template value or default fallback."""
    ensure_email_template_setting_table()

    template_key = normalize_email_template_key(template_key)
    if not template_key:
        return ''

    cfg = EMAIL_TEMPLATE_DEFAULTS.get(template_key, {})
    template = EmailTemplateSetting.query.filter_by(template_key=template_key).first()

    if template and template.is_active and clean_str(template.template_value):
        return clean_str(template.template_value) or ''

    return cfg.get('default_template') or ''


def render_email_template(template_value, context=None):
    """Render {placeholder} values safely for email subject/body snippets."""
    context = context or {}
    template_value = clean_str(template_value) or ''

    def replace_match(match):
        key = (match.group(1) or '').strip()
        value = context.get(key, '')
        if value is None:
            value = ''
        return str(value)

    rendered = re.sub(r'\{([a-zA-Z0-9_]+)\}', replace_match, template_value)
    rendered = re.sub(r'[\r\n\t]+', ' ', rendered)
    rendered = re.sub(r'\s{2,}', ' ', rendered).strip()
    return rendered


def render_email_subject_template(template_key, context=None):
    """Render one subject template using Settings-managed value."""
    template_key = normalize_email_template_key(template_key)
    if not template_key:
        return ''

    template_value = get_email_template_value(template_key)
    rendered = render_email_template(template_value, context or {})
    fallback = EMAIL_TEMPLATE_DEFAULTS.get(template_key, {}).get('default_template') or ''
    if not rendered and fallback:
        rendered = render_email_template(fallback, context or {})

    return (rendered or 'Notification')[:180]


