def create_system_notifications_for_users(users, title, message='', module='general', record_id=None, target_url='', metadata=None, exclude_user_ids=None):
    """Create notifications for multiple users, deduped by user ID."""
    exclude_ids = {clean_int(item) for item in (exclude_user_ids or []) if clean_int(item)}
    created = []
    seen = set()

    for user in users or []:
        user_id = clean_int(getattr(user, 'id', user))
        if not user_id or user_id in seen or user_id in exclude_ids:
            continue
        notification = create_system_notification(
            user_id=user_id,
            title=title,
            message=message,
            module=module,
            record_id=record_id,
            target_url=target_url,
            metadata=metadata
        )
        if notification:
            created.append(notification)
            seen.add(user_id)

    return created


def resolve_pending_approval_notifications(module='general', record_id=None, event='submitted', exclude_user_ids=None):
    """Remove stale pending approval notifications for a processed record.

    S11F:
    - Removes current pending approval notifications tagged with metadata.event.
    - Also removes older pending approval notifications that were created before
      metadata.event was consistently saved, as long as their title/message still
      clearly indicate "awaiting approval".
    - Does not remove requester status notifications such as approved/rejected.
    """
    ensure_system_notification_table()

    module_key = normalize_approval_scope(module)
    target_id = clean_int(record_id)
    if not target_id:
        return 0

    event_key = (clean_str(event) or '').strip().lower()
    exclude_ids = {clean_int(item) for item in (exclude_user_ids or []) if clean_int(item)}
    stale_notifications = (
        SystemNotification.query
        .filter(SystemNotification.module == module_key)
        .filter(SystemNotification.record_id == target_id)
        .order_by(SystemNotification.id.asc())
        .all()
    )

    removed_count = 0
    for notification in stale_notifications:
        if clean_int(getattr(notification, 'user_id', None)) in exclude_ids:
            continue

        metadata = {}
        if clean_str(getattr(notification, 'metadata_json', None)):
            try:
                metadata = json.loads(notification.metadata_json)
            except Exception:
                metadata = {}

        notification_event = (clean_str(metadata.get('event')) or '').strip().lower()
        title_text = (clean_str(getattr(notification, 'title', None)) or '').strip().lower()
        message_text = (clean_str(getattr(notification, 'message', None)) or '').strip().lower()
        combined_text = f"{title_text} {message_text}"

        is_exact_event_match = bool(event_key and notification_event == event_key)
        is_legacy_pending_approval = (
            event_key == 'submitted'
            and not notification_event
            and (
                'awaiting approval' in combined_text
                or 'pending approval' in combined_text
                or 'approval required' in combined_text
                or 'submitted' in combined_text
            )
        )

        if event_key and not (is_exact_event_match or is_legacy_pending_approval):
            continue

        db.session.delete(notification)
        removed_count += 1

    return removed_count


def clear_existing_pending_approval_notifications(module='general', record_id=None):
    """Delete existing pending-approval notifications before creating fresh ones.

    This prevents duplicate unread "awaiting approval" cards if a Draft/Rejected
    request is submitted again or a user double-clicks submit.
    """
    return resolve_pending_approval_notifications(
        module=module,
        record_id=record_id,
        event='submitted'
    )


def get_user_email_for_notification(user):
    """Return best email address for approval notification emails.

    F4A5G1:
    Older notification helpers only checked engineer_profile.email, but Engineer
    records in this app store contact emails as email_address_1/2/3. That made
    newly configured approvers receive in-app notifications but no email. Keep
    the legacy username fallback, but first scan every known email field safely.
    """
    if not user:
        return ''

    candidates = []

    # Future-proof in case a later User model/migration adds a direct email field.
    for attr_name in ('email', 'email_address', 'work_email', 'notification_email'):
        candidates.append(clean_str(getattr(user, attr_name, None)))

    profile = getattr(user, 'engineer_profile', None)
    if profile:
        for attr_name in (
            'email',
            'email_address',
            'email_address_1',
            'email_address_2',
            'email_address_3',
            'work_email',
            'notification_email'
        ):
            candidates.append(clean_str(getattr(profile, attr_name, None)))

    for email_addr in candidates:
        email_addr = clean_str(email_addr)
        if email_addr and '@' in email_addr:
            return email_addr

    email_map = {
        'diary': 'diary@shimadzu.com.ph',
        'hanna': 'hanna@shimadzu.com.ph',
        'kevin': 'kevin@shimadzu.com.ph',
        'jonamar': 'jonamar@shimadzu.com.ph',
        'robert': 'robert@shimadzu.com.ph',
        'rodito': 'rodito@shimadzu.com.ph'
    }
    email_addr = email_map.get((getattr(user, 'username', '') or '').strip().lower(), '')
    return email_addr or ''


def get_users_email_addresses_for_notifications(users):
    """Return unique email addresses for notification recipients."""
    emails = []
    seen = set()
    for user in users or []:
        email_addr = clean_str(get_user_email_for_notification(user))
        if not email_addr:
            continue
        key = email_addr.lower()
        if key in seen:
            continue
        seen.add(key)
        emails.append(email_addr)
    return emails


def get_requester_accounting_copy_emails(record, primary_emails=None):
    """Return requester and Settings-managed CC copies for accounting handoffs."""
    requester_id = clean_int(getattr(record, 'user_id', None))
    requester = db.session.get(User, requester_id) if requester_id else None
    copy_emails = []
    copy_emails.extend(get_users_email_addresses_for_notifications([requester] if requester else []))
    copy_emails.extend(get_active_email_recipients_by_group('accounting_handoff_cc'))
    primary_keys = {
        (clean_str(email_addr) or '').strip().lower()
        for email_addr in normalize_email_list(primary_emails)
        if clean_str(email_addr)
    }
    unique_copy_emails = []
    seen = set(primary_keys)
    for email_addr in normalize_email_list(copy_emails):
        email_key = (clean_str(email_addr) or '').strip().lower()
        if not email_key or email_key in seen:
            continue
        seen.add(email_key)
        unique_copy_emails.append(email_addr)
    return unique_copy_emails


def travel_request_notification_url(request_rec):
    """Frontend target for Travel Request notifications."""
    if not request_rec:
        return '/approvals'
    status = travel_request_normalize_status(getattr(request_rec, 'status', ''))
    if status == 'Submitted':
        return f"/approvals?module=travel_request&id={request_rec.id}"
    return f"/travel_request?travel_request_id={request_rec.id}"


TRAVEL_REQUEST_SYSTEM_LINK = 'https://tinyurl.com/spc-msdsvc-sms'


def format_travel_request_date_range(start_date, end_date):
    """Return readable travel date range for approval emails."""
    if not start_date and not end_date:
        return 'Not specified'

    if start_date and not end_date:
        return start_date.strftime('%B %-d, %Y') if os.name != 'nt' else start_date.strftime('%B %#d, %Y')

    if end_date and not start_date:
        return end_date.strftime('%B %-d, %Y') if os.name != 'nt' else end_date.strftime('%B %#d, %Y')

    def day_no(date_value):
        return date_value.strftime('%-d') if os.name != 'nt' else date_value.strftime('%#d')

    if start_date == end_date:
        return f"{start_date.strftime('%B')} {day_no(start_date)}, {start_date.year}"

    if start_date.year == end_date.year and start_date.month == end_date.month:
        return f"{start_date.strftime('%B')} {day_no(start_date)} - {day_no(end_date)}, {start_date.year}"

    if start_date.year == end_date.year:
        return f"{start_date.strftime('%B')} {day_no(start_date)} - {end_date.strftime('%B')} {day_no(end_date)}, {start_date.year}"

    return f"{start_date.strftime('%B')} {day_no(start_date)}, {start_date.year} - {end_date.strftime('%B')} {day_no(end_date)}, {end_date.year}"


def safe_json_list(raw_value):
    """Return a list from JSON text, accepting legacy comma text safely."""
    raw_value = clean_str(raw_value)
    if not raw_value:
        return []

    try:
        parsed = json.loads(raw_value)
        if isinstance(parsed, list):
            return [clean_str(item) for item in parsed if clean_str(item)]
        if clean_str(parsed):
            return [clean_str(parsed)]
    except Exception:
        pass

    return [clean_str(item) for item in str(raw_value).split(',') if clean_str(item)]


def build_travel_request_schedule_suggestions(request_rec):
    """S11H2B: Client/product suggestions for editable Travel Blocks.

    Travel requests may contain several client visits and multiple pieces of
    equipment per visit. Do not force one auto-fill choice in backend; return
    ordered suggestions so the frontend can auto-fill only when exactly one
    safe option exists, or show chips when there are multiple options.
    """
    if not request_rec:
        return []

    suggestions = []
    seen = set()

    def add_suggestion(client_id=None, client_name='', product_id='', product_name='', route_label='', visit_purpose='', source='travel_request'):
        client_id_clean = clean_int(client_id)
        product_id_clean = clean_str(product_id) or ''
        client_name_clean = clean_str(client_name) or ''
        product_name_clean = clean_str(product_name) or ''

        if not client_id_clean and not client_name_clean:
            return

        # Resolve fresh names from master records when IDs are available.
        client_rec = db.session.get(Client, client_id_clean) if client_id_clean else None
        if client_rec:
            client_name_clean = clean_str(client_rec.name) or client_name_clean

        product_rec = db.session.get(Product, product_id_clean) if product_id_clean else None
        if product_rec:
            product_name_clean = clean_str(product_rec.name) or product_name_clean
            if not client_id_clean and clean_int(getattr(product_rec, 'client_id', None)):
                client_id_clean = clean_int(product_rec.client_id)
                product_client = db.session.get(Client, client_id_clean)
                if product_client:
                    client_name_clean = clean_str(product_client.name) or client_name_clean

        key = (
            client_id_clean or 0,
            (client_name_clean or '').strip().lower(),
            (product_id_clean or '').strip().lower()
        )
        if key in seen:
            return
        seen.add(key)

        product_label = product_name_clean
        if product_id_clean:
            product_label = f"{product_name_clean} ({product_id_clean})" if product_name_clean else product_id_clean

        label_parts = [client_name_clean]
        if product_label:
            label_parts.append(product_label)

        suggestions.append({
            'client_id': client_id_clean,
            'client_name': client_name_clean,
            'product_id': product_id_clean,
            'product_name': product_name_clean,
            'product_label': product_label,
            'route_label': clean_str(route_label) or '',
            'visit_purpose': clean_str(visit_purpose) or '',
            'source': source,
            'label': ' — '.join([part for part in label_parts if part])
        })

    routes = sorted(
        list(getattr(request_rec, 'routes', None) or []),
        key=lambda route: (clean_int(getattr(route, 'sequence_no', None)) or 0, clean_int(getattr(route, 'id', None)) or 0)
    )

    for route in routes:
        from_location = clean_str(getattr(route, 'from_location', None)) or ''
        to_location = clean_str(getattr(route, 'to_location', None)) or ''
        route_label = f"{from_location} → {to_location}" if from_location or to_location else (clean_str(getattr(route, 'route_summary', None)) or '')

        visits = sorted(
            list(getattr(route, 'visits', None) or []),
            key=lambda visit: (clean_int(getattr(visit, 'sequence_no', None)) or 0, clean_int(getattr(visit, 'id', None)) or 0)
        )

        for visit in visits:
            product_ids = safe_json_list(getattr(visit, 'product_ids_json', None))
            product_names = safe_json_list(getattr(visit, 'product_names_json', None))

            if product_ids:
                for idx, product_id in enumerate(product_ids):
                    add_suggestion(
                        client_id=getattr(visit, 'client_id', None),
                        client_name=getattr(visit, 'client_name', None),
                        product_id=product_id,
                        product_name=product_names[idx] if idx < len(product_names) else '',
                        route_label=route_label,
                        visit_purpose=getattr(visit, 'visit_purpose', None),
                        source='travel_route_visit'
                    )
            else:
                add_suggestion(
                    client_id=getattr(visit, 'client_id', None),
                    client_name=getattr(visit, 'client_name', None),
                    product_id=getattr(visit, 'product_id', None),
                    product_name=getattr(visit, 'product_name', None),
                    route_label=route_label,
                    visit_purpose=getattr(visit, 'visit_purpose', None),
                    source='travel_route_visit'
                )

    # Legacy header fallback when old/simple requests only have client_name.
    if not suggestions and clean_str(getattr(request_rec, 'client_name', None)):
        add_suggestion(
            client_name=getattr(request_rec, 'client_name', None),
            route_label=clean_str(getattr(request_rec, 'destination', None)) or '',
            visit_purpose=clean_str(getattr(request_rec, 'purpose', None)) or '',
            source='travel_request_header'
        )

    for idx, suggestion in enumerate(suggestions, start=1):
        suggestion['index'] = idx

    return suggestions


def travel_request_email_context(request_rec):
    """Build common readable Travel Request email fields."""
    requester = getattr(request_rec, 'requester', None)
    requester_engineer = db.session.get(Engineer, clean_int(getattr(request_rec, 'engineer_id', None))) if request_rec and clean_int(getattr(request_rec, 'engineer_id', None)) else None
    requester_name = clean_str(getattr(requester_engineer, 'name', None)) or travel_request_user_display_name(requester) or clean_str(getattr(requester, 'username', None)) or 'Requester'
    request_no = clean_str(getattr(request_rec, 'request_no', None)) or f"TR-{getattr(request_rec, 'id', '')}"
    currency_code = normalize_travel_currency_code(getattr(request_rec, 'currency_code', None) or 'PHP')
    amount = travel_request_money(getattr(request_rec, 'requested_amount', 0))
    amount_label = format_travel_currency_amount(amount, currency_code)
    approved_amount = travel_request_money(getattr(request_rec, 'approved_amount', 0) or getattr(request_rec, 'requested_amount', 0))
    approved_amount_label = format_travel_currency_amount(approved_amount, currency_code)
    destination = clean_str(getattr(request_rec, 'destination', None)) or 'Not specified'
    request_type = clean_str(getattr(request_rec, 'request_type', None)) or 'Client Visit / Service'
    purpose = clean_str(getattr(request_rec, 'purpose', None)) or request_type or 'Travel Request'
    travel_dates = format_travel_request_date_range(
        getattr(request_rec, 'departure_date', None),
        getattr(request_rec, 'return_date', None)
    )

    participant_names = []
    try:
        for participant in get_travel_request_participants(request_rec):
            participant_label = (
                clean_str(getattr(participant, 'display_name', None)) or
                clean_str(getattr(getattr(participant, 'engineer', None), 'name', None)) or
                approval_user_display_name(getattr(participant, 'user', None)) or
                clean_str(getattr(participant, 'username', None)) or
                ''
            )
            if participant_label and participant_label not in participant_names:
                participant_names.append(participant_label)
    except Exception:
        participant_names = []

    if requester_name and requester_name not in participant_names:
        participant_names.insert(0, requester_name)

    request_remarks = ''
    try:
        remarks_list = [
            clean_str(getattr(line, 'remarks', None))
            for line in (getattr(request_rec, 'lines', None) or [])
            if clean_str(getattr(line, 'remarks', None))
        ]
        request_remarks = '\n'.join(dict.fromkeys(remarks_list))
    except Exception:
        request_remarks = ''

    return {
        'request_no': request_no,
        'currency_code': currency_code,
        'requester_name': requester_name,
        'participant_names': participant_names,
        'participants_label': ', '.join(participant_names) if participant_names else 'Not specified',
        'amount_label': amount_label,
        'approved_amount_label': approved_amount_label,
        'destination': destination,
        'request_type': request_type,
        'purpose': purpose,
        'request_remarks': request_remarks,
        'travel_dates': travel_dates,
        'system_link': TRAVEL_REQUEST_SYSTEM_LINK
    }


def format_travel_request_notification_email(action_label, request_rec, actor_user=None, remarks=''):
    """Return subject/text/html for Travel Request notification email."""
    ctx = travel_request_email_context(request_rec)
    actor_name = universal_approval_actor_name(actor_user) if actor_user else ctx['requester_name']

    subject_map = {
        'submitted': f"Travel Request Awaiting Approval - {ctx['request_no']}",
        'approved': f"Travel Request Approved - {ctx['request_no']}",
        'rejected': f"Travel Request Rejected - {ctx['request_no']}"
    }
    title_map = {
        'submitted': 'Travel Request Awaiting Approval',
        'approved': 'Travel Request Approved',
        'rejected': 'Travel Request Rejected'
    }

    subject = subject_map.get(action_label, f"Travel Request Update - {ctx['request_no']}")
    title = title_map.get(action_label, 'Travel Request Update')

    requester_remarks = clean_str(ctx.get('request_remarks')) or ''
    action_remarks = clean_str(remarks) or clean_str(getattr(request_rec, 'approval_remarks', None)) or ''
    actor_label = 'Updated By'
    action_note = 'Please open the Medical Service system for full details.'

    if action_label == 'approved':
        actor_label = 'Approved By'
        action_note = 'This travel request has been approved. You may proceed with the next workflow stage.'
    elif action_label == 'rejected':
        actor_label = 'Rejected By'
        action_note = 'This travel request was returned for correction. Please review the remarks, update the request, and resubmit if needed.'

    text_lines = [
        title,
        '',
        f"Request No.: {ctx['request_no']}",
        f"Request Type: {ctx['request_type']}",
        f"Requested By: {ctx['requester_name']}",
        f"Participants: {ctx['participants_label']}",
        f"Destination: {ctx['destination']}",
        f"Travel Dates: {ctx['travel_dates']}",
        f"Requested Amount: {ctx['amount_label']}",
    ]

    if action_label == 'approved':
        text_lines.append(f"Approved Amount: {ctx['approved_amount_label']}")

    text_lines.extend([
        f"Purpose / Details: {ctx['purpose']}",
        f"Requester Remarks: {requester_remarks or 'None'}",
    ])

    if actor_name:
        text_lines.append(f"{actor_label}: {actor_name}")
    if action_remarks:
        text_lines.append(f"Approval Remarks: {action_remarks}")

    text_lines.extend([
        '',
        action_note,
        '',
        f"System Link: {ctx['system_link']}",
        '',
        'Medical Service SMS',
        'Shimadzu Philippines Corporation'
    ])
    text_body = "\n".join(text_lines)

    rows = [
        ('Request No.', ctx['request_no']),
        ('Request Type', ctx['request_type']),
        ('Requested By', ctx['requester_name']),
        ('Participants', ctx['participants_label']),
        ('Destination', ctx['destination']),
        ('Travel Dates', ctx['travel_dates']),
        ('Requested Amount', ctx['amount_label']),
    ]
    if action_label == 'approved':
        rows.append(('Approved Amount', ctx['approved_amount_label']))

    rows.extend([
        ('Purpose / Details', ctx['purpose']),
        ('Requester Remarks', requester_remarks or 'None'),
        (actor_label, actor_name)
    ])

    if action_remarks:
        rows.append(('Approval Remarks', action_remarks))

    detail_rows = ''.join(
        f"<tr><td style='padding:8px 10px;font-weight:700;border-bottom:1px solid #e5e7eb;color:#334155;vertical-align:top;'>{html.escape(label)}</td>"
        f"<td style='padding:8px 10px;border-bottom:1px solid #e5e7eb;color:#0f172a;vertical-align:top;'>{html.escape(str(value or ''))}</td></tr>"
        for label, value in rows
    )

    html_body = f"""
    <div style="font-family:Arial,sans-serif;color:#111827;line-height:1.5;">
        <h2 style="margin:0 0 12px;color:#0f172a;">{html.escape(title)}</h2>
        <p style="margin:0 0 14px;color:#374151;">{html.escape(action_note)}</p>
        <table style="border-collapse:collapse;border:1px solid #e5e7eb;min-width:420px;">
            {detail_rows}
        </table>
        <p style="margin-top:16px;color:#374151;">Please open the Medical Service system for full details.</p>
        <p style="margin-top:8px;color:#374151;">
            <strong>System Link:</strong><br>
            <a href="{html.escape(ctx['system_link'])}" style="color:#0d6efd;text-decoration:none;font-weight:700;">{html.escape(ctx['system_link'])}</a>
        </p>
        <p style="margin-top:16px;color:#374151;">
            Regards,<br>
            Medical Service SMS<br>
            Shimadzu Philippines Corporation
        </p>
    </div>
    """
    return subject, text_body, html_body


def send_travel_request_notification_email_async(app_obj, recipient_user_ids, travel_request_id, action_label, actor_user_id=None, remarks=''):
    """Send Travel Request notification email in background."""
    recipient_ids = [clean_int(item) for item in (recipient_user_ids or []) if clean_int(item)]
    if not recipient_ids:
        return

    def worker():
        with app_obj.app_context():
            try:
                request_rec = db.session.get(TravelRequest, clean_int(travel_request_id))
                if not request_rec:
                    print(f"[EMAIL] Travel notification skipped: request #{travel_request_id} not found.", flush=True)
                    return

                recipients = [db.session.get(User, user_id) for user_id in recipient_ids]
                recipients = [user for user in recipients if user]
                recipient_emails = get_users_email_addresses_for_notifications(recipients)
                if not recipient_emails:
                    print("[EMAIL] Travel notification skipped: no recipient email addresses.", flush=True)
                    return

                actor_user = db.session.get(User, clean_int(actor_user_id)) if actor_user_id else None
                subject, text_body, html_body = format_travel_request_notification_email(
                    action_label,
                    request_rec,
                    actor_user=actor_user,
                    remarks=remarks
                )
                sent, message = send_email_notification(recipient_emails, subject, text_body, html_body)
                print(f"[EMAIL] Travel notification {action_label}: sent={sent} | {message}", flush=True)
            except Exception as email_error:
                print(f"[EMAIL] Travel notification worker failed: {email_error}", flush=True)

    email_thread = threading.Thread(target=worker, daemon=True)
    email_thread.start()
    print(f"[EMAIL] Travel notification background email queued: {action_label}", flush=True)


