def travel_request_pdf_filename(request_rec):
    """Return a safe filename for the Accounting Travel Request PDF attachment."""
    ctx = travel_request_email_context(request_rec)
    request_no = clean_str(ctx.get('request_no')) or f"TR-{getattr(request_rec, 'id', '')}"
    requester = clean_str(ctx.get('requester_name')) or 'Requester'
    safe_name = secure_filename(f"Travel_Request_{request_no}_{requester}.pdf")
    return safe_name or f"Travel_Request_TR-{getattr(request_rec, 'id', '')}.pdf"


def build_travel_request_accounting_summary_pdf_bytes(request_rec, approved_by_user=None, remarks=''):
    """Fallback generated summary PDF for Accounting email attachment.

    This PDF is generated in-memory during the approval email handoff. It does
    not alter the request lifecycle, stored attachments, or frontend print flow.
    """
    from reportlab.lib import colors
    from reportlab.lib.enums import TA_CENTER, TA_LEFT
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle

    ctx = travel_request_email_context(request_rec)
    approved_by = universal_approval_actor_name(approved_by_user) if approved_by_user else 'Approver'
    approval_remarks = clean_str(remarks) or clean_str(getattr(request_rec, 'approval_remarks', None)) or 'None'

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=A4,
        rightMargin=14 * mm,
        leftMargin=14 * mm,
        topMargin=12 * mm,
        bottomMargin=12 * mm
    )

    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        'TravelRequestPdfTitle',
        parent=styles['Title'],
        fontName='Helvetica-Bold',
        fontSize=15,
        leading=18,
        alignment=TA_CENTER,
        textColor=colors.HexColor('#0f172a'),
        spaceAfter=8
    )
    section_style = ParagraphStyle(
        'TravelRequestPdfSection',
        parent=styles['Heading3'],
        fontName='Helvetica-Bold',
        fontSize=10.5,
        leading=13,
        textColor=colors.HexColor('#1e293b'),
        spaceBefore=8,
        spaceAfter=4
    )
    normal_style = ParagraphStyle(
        'TravelRequestPdfNormal',
        parent=styles['BodyText'],
        fontName='Helvetica',
        fontSize=8.5,
        leading=11,
        alignment=TA_LEFT
    )
    small_style = ParagraphStyle(
        'TravelRequestPdfSmall',
        parent=normal_style,
        fontSize=7.8,
        leading=10
    )

    def ptxt(value, style=normal_style):
        return Paragraph(html.escape(str(value or '')), style)

    def money_label(value):
        return format_travel_currency_amount(value, ctx.get('currency_code') or getattr(request_rec, 'currency_code', None) or 'PHP')

    story = []
    story.append(Paragraph('TRAVEL REQUEST FORM', title_style))
    story.append(Paragraph('Approved Travel Request / Accounting Handoff Copy', normal_style))
    story.append(Spacer(1, 5))

    header_rows = [
        ['Request No.', ctx['request_no'], 'Status', clean_str(getattr(request_rec, 'status', None)) or 'Approved'],
        ['Request Type', ctx['request_type'], 'Requested By', ctx['requester_name']],
        ['Participants', ctx['participants_label'], 'Travel Dates', ctx['travel_dates']],
        ['Destination', ctx['destination'], 'Purpose / Details', ctx['purpose']],
        ['Requested Amount', ctx['amount_label'], 'Approved Amount', ctx['approved_amount_label']],
        ['Approved By', approved_by, 'Approval Remarks', approval_remarks],
    ]
    header_table = Table(
        [[ptxt(a, small_style), ptxt(b, small_style), ptxt(c, small_style), ptxt(d, small_style)] for a, b, c, d in header_rows],
        colWidths=[27 * mm, 60 * mm, 28 * mm, 60 * mm]
    )
    header_table.setStyle(TableStyle([
        ('GRID', (0, 0), (-1, -1), 0.35, colors.HexColor('#cbd5e1')),
        ('BACKGROUND', (0, 0), (0, -1), colors.HexColor('#f1f5f9')),
        ('BACKGROUND', (2, 0), (2, -1), colors.HexColor('#f1f5f9')),
        ('FONTNAME', (0, 0), (0, -1), 'Helvetica-Bold'),
        ('FONTNAME', (2, 0), (2, -1), 'Helvetica-Bold'),
        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
        ('LEFTPADDING', (0, 0), (-1, -1), 5),
        ('RIGHTPADDING', (0, 0), (-1, -1), 5),
        ('TOPPADDING', (0, 0), (-1, -1), 4),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 4),
    ]))
    story.append(header_table)

    # Route plan and client visit details.
    routes = sorted(
        list(getattr(request_rec, 'routes', None) or []),
        key=lambda route: (clean_int(getattr(route, 'sequence_no', None)) or 0, clean_int(getattr(route, 'id', None)) or 0)
    )
    if routes:
        story.append(Paragraph('Route Plan / Visit Details', section_style))
        route_data = [[ptxt('#', small_style), ptxt('Route', small_style), ptxt('Travel Type', small_style), ptxt('Client / Activity Details', small_style)]]
        for route in routes:
            from_location = clean_str(getattr(route, 'from_location', None)) or ''
            to_location = clean_str(getattr(route, 'to_location', None)) or ''
            route_label = f"{from_location} → {to_location}" if from_location or to_location else (clean_str(getattr(route, 'route_summary', None)) or 'Route')
            visits = sorted(
                list(getattr(route, 'visits', None) or []),
                key=lambda visit: (clean_int(getattr(visit, 'sequence_no', None)) or 0, clean_int(getattr(visit, 'id', None)) or 0)
            )
            visit_lines = []
            for visit in visits:
                client_name = clean_str(getattr(visit, 'client_name', None)) or clean_str(getattr(getattr(visit, 'client', None), 'name', None)) or 'Client / Activity'
                product_names = safe_json_list(getattr(visit, 'product_names_json', None))
                product_ids = safe_json_list(getattr(visit, 'product_ids_json', None))
                equipment_parts = []
                if product_names or product_ids:
                    max_len = max(len(product_names), len(product_ids))
                    for idx in range(max_len):
                        product_name = product_names[idx] if idx < len(product_names) else ''
                        product_id = product_ids[idx] if idx < len(product_ids) else ''
                        equipment_parts.append(f"{product_name} ({product_id})" if product_name and product_id else (product_name or product_id))
                else:
                    product_name = clean_str(getattr(visit, 'product_name', None)) or ''
                    product_id = clean_str(getattr(visit, 'product_id', None)) or ''
                    if product_name or product_id:
                        equipment_parts.append(f"{product_name} ({product_id})" if product_name and product_id else (product_name or product_id))
                visit_purpose = clean_str(getattr(visit, 'visit_purpose', None)) or clean_str(getattr(visit, 'purpose_tags', None)) or clean_str(getattr(visit, 'notes', None)) or ''
                detail = client_name
                if equipment_parts:
                    detail += f" | Equipment: {', '.join(equipment_parts)}"
                if visit_purpose:
                    detail += f" | Purpose: {visit_purpose}"
                visit_lines.append(detail)
            if not visit_lines:
                visit_lines.append(clean_str(getattr(route, 'route_summary', None)) or ctx['purpose'])
            route_data.append([
                ptxt(clean_int(getattr(route, 'sequence_no', None)) or '', small_style),
                ptxt(route_label, small_style),
                ptxt(clean_str(getattr(route, 'travel_type', None)) or '', small_style),
                ptxt('\n'.join(visit_lines), small_style)
            ])
        route_table = Table(route_data, colWidths=[12 * mm, 45 * mm, 30 * mm, 88 * mm], repeatRows=1)
        route_table.setStyle(TableStyle([
            ('GRID', (0, 0), (-1, -1), 0.35, colors.HexColor('#cbd5e1')),
            ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#e2e8f0')),
            ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
            ('VALIGN', (0, 0), (-1, -1), 'TOP'),
            ('LEFTPADDING', (0, 0), (-1, -1), 4),
            ('RIGHTPADDING', (0, 0), (-1, -1), 4),
            ('TOPPADDING', (0, 0), (-1, -1), 4),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 4),
        ]))
        story.append(route_table)

    lines = sorted(
        list(getattr(request_rec, 'lines', None) or []),
        key=lambda line: (getattr(line, 'line_date', None) or getattr(request_rec, 'departure_date', None) or datetime.min.date(), clean_int(getattr(line, 'id', None)) or 0)
    )
    if lines:
        story.append(Paragraph('Cash Advance / Expense Lines', section_style))
        line_data = [[ptxt('Date', small_style), ptxt('Type', small_style), ptxt('Description', small_style), ptxt('Origin', small_style), ptxt('Destination', small_style), ptxt('Amount', small_style)]]
        for line in lines:
            line_date = getattr(line, 'line_date', None)
            line_data.append([
                ptxt(line_date.strftime('%m/%d/%Y') if line_date else '', small_style),
                ptxt(clean_str(getattr(line, 'line_type', None)) or '', small_style),
                ptxt(clean_str(getattr(line, 'description', None)) or clean_str(getattr(line, 'remarks', None)) or '', small_style),
                ptxt(clean_str(getattr(line, 'origin', None)) or '', small_style),
                ptxt(clean_str(getattr(line, 'destination', None)) or '', small_style),
                ptxt(money_label(getattr(line, 'amount', 0)), small_style),
            ])
        line_table = Table(line_data, colWidths=[23 * mm, 27 * mm, 52 * mm, 26 * mm, 26 * mm, 21 * mm], repeatRows=1)
        line_table.setStyle(TableStyle([
            ('GRID', (0, 0), (-1, -1), 0.35, colors.HexColor('#cbd5e1')),
            ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#e2e8f0')),
            ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
            ('VALIGN', (0, 0), (-1, -1), 'TOP'),
            ('ALIGN', (-1, 1), (-1, -1), 'RIGHT'),
            ('LEFTPADDING', (0, 0), (-1, -1), 4),
            ('RIGHTPADDING', (0, 0), (-1, -1), 4),
            ('TOPPADDING', (0, 0), (-1, -1), 4),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 4),
        ]))
        story.append(line_table)

    story.append(Spacer(1, 10))
    story.append(Paragraph('Approval Snapshot', section_style))
    approval_rows = [
        ['Approval Action', clean_str(getattr(request_rec, 'approval_action', None)) or 'Approved'],
        ['Approver Name', clean_str(getattr(request_rec, 'approval_name_snapshot', None)) or approved_by],
        ['Approver Title', clean_str(getattr(request_rec, 'approval_title_snapshot', None)) or approval_user_title_label(approved_by_user) or 'Approver'],
        ['Approval Date', getattr(request_rec, 'approval_signed_at', None).strftime('%m/%d/%Y %I:%M %p') if getattr(request_rec, 'approval_signed_at', None) else ''],
    ]
    approval_table = Table([[ptxt(a, small_style), ptxt(b, small_style)] for a, b in approval_rows], colWidths=[40 * mm, 135 * mm])
    approval_table.setStyle(TableStyle([
        ('GRID', (0, 0), (-1, -1), 0.35, colors.HexColor('#cbd5e1')),
        ('BACKGROUND', (0, 0), (0, -1), colors.HexColor('#f1f5f9')),
        ('FONTNAME', (0, 0), (0, -1), 'Helvetica-Bold'),
        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
        ('LEFTPADDING', (0, 0), (-1, -1), 5),
        ('RIGHTPADDING', (0, 0), (-1, -1), 5),
        ('TOPPADDING', (0, 0), (-1, -1), 4),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 4),
    ]))
    story.append(approval_table)

    story.append(Spacer(1, 8))
    story.append(Paragraph('Generated by Medical Service SMS for Accounting processing.', small_style))

    doc.build(story)
    buffer.seek(0)
    return buffer.getvalue()


def get_travel_request_official_form_template_path():
    """Return the official Travel Request / Order Form PDF template path if available.

    Preferred production locations:
    - TRAVEL_REQUEST_FORM_TEMPLATE_PATH environment variable
    - app root: TRAVEL REQUEST FORM.pdf
    - static/forms/TRAVEL REQUEST FORM.pdf
    - static/templates/TRAVEL REQUEST FORM.pdf

    S12B6N: Accounting handoff must use the official form template only.
    Missing template/dependency should fail clearly instead of silently sending
    the older custom summary PDF.
    """
    candidate_paths = []

    configured_path = clean_str(os.environ.get('TRAVEL_REQUEST_FORM_TEMPLATE_PATH'))
    if configured_path:
        candidate_paths.append(configured_path)

    candidate_paths.extend([
        os.path.join(basedir, 'TRAVEL REQUEST FORM.pdf'),
        os.path.join(basedir, 'forms', 'TRAVEL REQUEST FORM.pdf'),
        os.path.join(basedir, 'static', 'forms', 'TRAVEL REQUEST FORM.pdf'),
        os.path.join(basedir, 'static', 'templates', 'TRAVEL REQUEST FORM.pdf'),
        os.path.join('/data', 'TRAVEL REQUEST FORM.pdf'),
        os.path.join('/data', 'forms', 'TRAVEL REQUEST FORM.pdf'),
        os.path.join('/data', 'templates', 'TRAVEL REQUEST FORM.pdf'),
    ])

    for candidate_path in candidate_paths:
        if candidate_path and os.path.exists(candidate_path):
            return candidate_path

    return ''


def build_travel_request_accounting_pdf_bytes(request_rec, approved_by_user=None, remarks=''):
    """Build the official Travel Request / Order Form PDF for Accounting.

    S12B6N:
    Uses the company TRAVEL REQUEST FORM.pdf as the visual template, overlays
    approved request data into the official fields, and returns the finished PDF
    bytes for the Accounting email attachment. This function must not fall back
    to the older custom summary PDF because Accounting needs the exact official
    form layout.
    """
    template_path = get_travel_request_official_form_template_path()
    if not template_path:
        raise FileNotFoundError(
            'Official Travel Request template not found. Put TRAVEL REQUEST FORM.pdf in the project root, '
            'forms/, static/forms/, static/templates/, /data/, /data/forms/, or set TRAVEL_REQUEST_FORM_TEMPLATE_PATH.'
        )

    try:
        try:
            from pypdf import PdfReader, PdfWriter
        except Exception:
            from PyPDF2 import PdfReader, PdfWriter
        from reportlab.pdfgen import canvas
        from reportlab.pdfbase.pdfmetrics import stringWidth
        from reportlab.lib.utils import ImageReader
    except Exception as pdf_import_error:
        raise RuntimeError(
            'Official Travel Request PDF dependencies are unavailable. Install pypdf or PyPDF2 and reportlab.'
        ) from pdf_import_error

    try:
        ctx = travel_request_email_context(request_rec)
        approved_by = universal_approval_actor_name(approved_by_user) if approved_by_user else 'Approver'
        approval_remarks = clean_str(remarks) or clean_str(getattr(request_rec, 'approval_remarks', None)) or ''
        approved_at = getattr(request_rec, 'approval_signed_at', None) or getattr(request_rec, 'approved_at', None)
        generated_date = approved_at.strftime('%m/%d/%Y') if approved_at else get_manila_time().strftime('%m/%d/%Y')

        reader = PdfReader(template_path)
        if not reader.pages:
            raise ValueError('Official Travel Request PDF template has no pages.')

        base_page = reader.pages[0]
        page_width = float(base_page.mediabox.width)
        page_height = float(base_page.mediabox.height)

        overlay_buffer = io.BytesIO()
        c = canvas.Canvas(overlay_buffer, pagesize=(page_width, page_height))
        c.setTitle(ctx.get('request_no') or 'Travel Request')

        def safe_text(value):
            return clean_str(value) or ''

        def pdf_title_case_name(value):
            text_value = safe_text(value)
            if not text_value:
                return ''
            # Preserve separators while title-casing ordinary name words.
            small_words = {'jr', 'sr', 'ii', 'iii', 'iv'}
            def fix_word(word):
                if not word:
                    return word
                stripped = word.strip()
                if stripped.lower().rstrip('.') in small_words:
                    return stripped.upper().replace('JR', 'Jr').replace('SR', 'Sr')
                if stripped.isupper() and len(stripped) <= 4:
                    return stripped
                return stripped[:1].upper() + stripped[1:].lower()
            parts = []
            for chunk in re.split(r'(\s+|,\s*)', text_value):
                if not chunk or chunk.isspace() or chunk.strip() == ',':
                    parts.append(chunk)
                elif chunk.endswith(',') and len(chunk) > 1:
                    parts.append(fix_word(chunk[:-1]) + ',')
                else:
                    parts.append(fix_word(chunk))
            return ''.join(parts).strip().upper()

        def draw_text(x, y, value, size=8, bold=False, max_width=None, align='left'):
            text_value = safe_text(value)
            if not text_value:
                return
            font_name = 'Helvetica-Bold' if bold else 'Helvetica'
            c.setFont(font_name, size)
            c.setFillColorRGB(0, 0, 0)
            text_value = text_value.replace('\r', ' ').replace('\n', ' ')
            if max_width:
                # Single-line trim with ellipsis to prevent crossing printed form boundaries.
                while stringWidth(text_value, font_name, size) > max_width and len(text_value) > 4:
                    text_value = text_value[:-4].rstrip() + '...'
            if align == 'right' and max_width:
                c.drawRightString(x + max_width, y, text_value)
            elif align == 'center' and max_width:
                c.drawCentredString(x + (max_width / 2), y, text_value)
            else:
                c.drawString(x, y, text_value)

        def draw_wrapped_text(x, y, value, max_width, max_lines=2, size=7.5, line_height=9, bold=False):
            text_value = safe_text(value)
            if not text_value:
                return
            font_name = 'Helvetica-Bold' if bold else 'Helvetica'
            words = text_value.replace('\r', ' ').replace('\n', ' ').split()
            lines = []
            current = ''
            for word in words:
                candidate = f'{current} {word}'.strip()
                if stringWidth(candidate, font_name, size) <= max_width or not current:
                    current = candidate
                else:
                    lines.append(current)
                    current = word
                    if len(lines) >= max_lines:
                        break
            if current and len(lines) < max_lines:
                lines.append(current)
            if len(lines) > max_lines:
                lines = lines[:max_lines]
            if words and len(lines) == max_lines:
                # Ensure final line fits after possible ellipsis.
                last = lines[-1]
                while stringWidth(last, font_name, size) > max_width and len(last) > 4:
                    last = last[:-4].rstrip() + '...'
                lines[-1] = last
            c.setFont(font_name, size)
            c.setFillColorRGB(0, 0, 0)
            for idx, line in enumerate(lines):
                c.drawString(x, y - (idx * line_height), line)

        def compact_join_for_pdf(items, max_items=3):
            return ', '.join(compact_list_for_pdf(items, max_items=max_items))

        def compact_list_for_pdf(items, max_items=3):
            clean_items = []
            for item in items or []:
                item_text = safe_text(item)
                if item_text and item_text not in clean_items:
                    clean_items.append(item_text)
            if len(clean_items) > max_items and max_items > 1:
                visible_items = clean_items[:max_items - 1]
                visible_items.append(f"+{len(clean_items) - max_items} more")
            else:
                visible_items = clean_items[:max_items]
            return visible_items

        def draw_check(x, y):
            c.setFont('Helvetica-Bold', 10)
            c.setFillColorRGB(0, 0, 0)
            c.drawString(x, y, 'X')

        def draw_signature_data_url(signature_data, x, y, box_width, box_height, label='', label_size=4.8):
            """Draw a saved signature data URL centered inside a PDF box."""
            png_bytes = reimbursement_signature_data_url_to_png_bytes(signature_data) if signature_data else None
            if not png_bytes:
                return False
            try:
                image_reader = ImageReader(io.BytesIO(png_bytes))
                image_width, image_height = image_reader.getSize()
                if not image_width or not image_height:
                    return False

                fit_scale = min(float(box_width) / float(image_width), float(box_height) / float(image_height))
                draw_width = image_width * fit_scale
                draw_height = image_height * fit_scale
                draw_x = x + ((box_width - draw_width) / 2.0)
                draw_y = y + ((box_height - draw_height) / 2.0)
                c.drawImage(
                    image_reader,
                    draw_x,
                    draw_y,
                    width=draw_width,
                    height=draw_height,
                    preserveAspectRatio=True,
                    mask='auto'
                )
                if label:
                    c.setFillColorRGB(0, 0, 0)
                    c.setFont('Helvetica', label_size)
                    c.drawCentredString(x + (box_width / 2.0), max(y - 5.0, 2.0), str(label)[:30])
                return True
            except Exception as signature_draw_error:
                print(f"[TravelRequestPDF] Signature image skipped: {signature_draw_error}", flush=True)
                return False

        def draw_signature_group(people, x, y, box_width, box_height, max_columns=3):
            """Draw requester/participant signatures in the official form signature area."""
            signature_people = [person for person in (people or []) if clean_str(person.get('signature_data'))]
            if not signature_people:
                return 0

            count = len(signature_people)
            columns = min(max_columns, max(count, 1))
            rows = 1 if count <= columns else 2
            cell_width = box_width / float(columns)
            cell_height = box_height / float(rows)
            drawn = 0

            for idx, person in enumerate(signature_people[:columns * rows]):
                row = idx // columns
                col = idx % columns
                cell_x = x + (col * cell_width)
                cell_y = y + ((rows - 1 - row) * cell_height)
                label = clean_str(person.get('name')) or ''
                if draw_signature_data_url(person.get('signature_data'), cell_x + 2.0, cell_y + 4.0, cell_width - 4.0, cell_height - 9.0, label=label, label_size=3.8):
                    drawn += 1

            if count > columns * rows:
                c.setFillColorRGB(0, 0, 0)
                c.setFont('Helvetica', 4.5)
                c.drawRightString(x + box_width, y - 5.0, f"+{count - (columns * rows)} more signed")

            return drawn

        def money_value_from_line(line):
            try:
                return travel_request_money(getattr(line, 'amount', 0))
            except Exception:
                return 0.0

        def money_text(amount):
            return f'{travel_request_money(amount):,.2f}'

        requester_name = pdf_title_case_name(ctx.get('requester_name') or '')
        participant_names_clean = [
            pdf_title_case_name(name)
            for name in (ctx.get('participant_names') or [])
            if safe_text(name)
        ]
        participant_label = ', '.join(dict.fromkeys(participant_names_clean)) if participant_names_clean else pdf_title_case_name(ctx.get('participants_label') or '')
        traveller_name = requester_name
        if participant_label and participant_label != requester_name:
            traveller_name = participant_label

        signature_people = get_travel_request_signature_people(request_rec)
        for person in signature_people:
            if isinstance(person, dict):
                person['name'] = pdf_title_case_name(person.get('name'))

        request_type = (ctx.get('request_type') or '').strip()
        request_type_lower = request_type.lower()
        purpose_text = ctx.get('purpose') or request_type or 'Travel Request'
        destination_text = ctx.get('destination') or ''
        travel_dates_text = ctx.get('travel_dates') or ''

        # Gather route/client/equipment/activity details.
        customers = []
        equipment = []
        activity_details = []
        route_labels = []
        routes = sorted(
            list(getattr(request_rec, 'routes', None) or []),
            key=lambda route: (clean_int(getattr(route, 'sequence_no', None)) or 0, clean_int(getattr(route, 'id', None)) or 0)
        )
        for route in routes:
            from_location = safe_text(getattr(route, 'from_location', None))
            to_location = safe_text(getattr(route, 'to_location', None))
            route_label = f'{from_location} -> {to_location}' if from_location or to_location else safe_text(getattr(route, 'route_summary', None))
            if route_label and route_label not in route_labels:
                route_labels.append(route_label)
            visits = sorted(
                list(getattr(route, 'visits', None) or []),
                key=lambda visit: (clean_int(getattr(visit, 'sequence_no', None)) or 0, clean_int(getattr(visit, 'id', None)) or 0)
            )
            for visit in visits:
                client_name = safe_text(getattr(visit, 'client_name', None)) or safe_text(getattr(getattr(visit, 'client', None), 'name', None))
                if client_name and client_name not in customers:
                    customers.append(client_name)
                product_names = safe_json_list(getattr(visit, 'product_names_json', None))
                product_ids = safe_json_list(getattr(visit, 'product_ids_json', None))
                if product_names or product_ids:
                    for idx in range(max(len(product_names), len(product_ids))):
                        product_name = product_names[idx] if idx < len(product_names) else ''
                        product_id = product_ids[idx] if idx < len(product_ids) else ''
                        label = f'{product_name} ({product_id})' if product_name and product_id else (product_name or product_id)
                        if label and label not in equipment:
                            equipment.append(label)
                else:
                    product_name = safe_text(getattr(visit, 'product_name', None))
                    product_id = safe_text(getattr(visit, 'product_id', None))
                    label = f'{product_name} ({product_id})' if product_name and product_id else (product_name or product_id)
                    if label and label not in equipment:
                        equipment.append(label)
                visit_purpose = safe_text(getattr(visit, 'visit_purpose', None)) or safe_text(getattr(visit, 'purpose_tags', None)) or safe_text(getattr(visit, 'notes', None))
                if visit_purpose and visit_purpose not in activity_details:
                    activity_details.append(visit_purpose)

        if not customers and safe_text(getattr(request_rec, 'client_name', None)):
            customers.append(safe_text(getattr(request_rec, 'client_name', None)))
        if not activity_details:
            activity_details.append(purpose_text)
        if not route_labels and destination_text:
            route_labels.append(destination_text)

        customer_lines = compact_list_for_pdf(customers, max_items=5) if customers else []
        equipment_lines = compact_list_for_pdf(equipment, max_items=5) if equipment else []
        customer_text = ', '.join(customer_lines) if customer_lines else ('N/A' if 'client' in request_type_lower or 'service' in request_type_lower else purpose_text)
        equipment_text = ', '.join(equipment_lines) if equipment_lines else 'N/A'
        route_text = ' | '.join(route_labels) if route_labels else destination_text

        # Cash advance mapping to official rows.
        airfare = landfare = per_diem = hotel = misc = 0.0
        airfare_note = ''
        allow_airfare_c_o_note = travel_request_allows_airfare_c_o(request_rec)
        for line in sorted(list(getattr(request_rec, 'lines', None) or []), key=lambda item: clean_int(getattr(item, 'id', None)) or 0):
            line_type = travel_request_line_text(line)
            amount = money_value_from_line(line)
            line_remarks = safe_text(getattr(line, 'remarks', None))
            if not allow_airfare_c_o_note:
                line_remarks = remove_travel_airfare_c_o_label(line_remarks)
            if travel_request_line_is_airfare_text(line_type):
                airfare += amount
                if amount == 0 and line_remarks and not airfare_note:
                    airfare_note = line_remarks
            elif travel_request_line_is_landfare_text(line_type):
                landfare += amount
            elif any(key in line_type for key in ['per diem', 'allowance', 'meal']):
                per_diem += amount
            elif any(key in line_type for key in ['hotel', 'accommodation', 'lodging']):
                hotel += amount
            else:
                misc += amount
        total_amount = travel_request_money(getattr(request_rec, 'approved_amount', 0) or getattr(request_rec, 'requested_amount', 0))
        if not any([airfare, landfare, per_diem, hotel, misc]) and total_amount:
            misc = total_amount

        # Official form field overlays. Coordinates are based on the template's
        # native 612 x 1008 point page size.
        draw_text(514, 947, generated_date, size=8, max_width=60)
        draw_check(413, 912)  # Medical department
        draw_check(37, 899)   # Service department
        draw_wrapped_text(12, 866, traveller_name, max_width=410, max_lines=1, size=8.5, bold=True)
        draw_signature_group(signature_people, 426, 842, 160, 54, max_columns=3)

        is_training = 'training' in request_type_lower or 'seminar' in request_type_lower
        is_meeting = 'meeting' in request_type_lower
        is_client_service = not (is_training or is_meeting)

        if is_client_service:
            # Service Dept / CSC section.
            service_row_y_positions = [798, 781, 764, 747, 730]
            for idx, customer_line in enumerate((customer_lines or [customer_text])[:len(service_row_y_positions)]):
                draw_wrapped_text(130, service_row_y_positions[idx], customer_line, max_width=176, max_lines=1, size=6.6)
            for idx, equipment_line in enumerate((equipment_lines or [equipment_text])[:len(service_row_y_positions)]):
                draw_wrapped_text(331, service_row_y_positions[idx], equipment_line, max_width=168, max_lines=1, size=6.6)
            purpose_lower = purpose_text.lower()
            purpose_raw = safe_text(purpose_text)
            is_pm_purpose = bool(re.search(r'\bPM\b|preventive\s+maintenance|preventive', purpose_raw, flags=re.I))
            if 'warranty' in purpose_lower:
                draw_check(37, 798)
            if 'repair' in purpose_lower:
                draw_check(37, 781)
            if is_pm_purpose:
                draw_check(37, 764)
            if 'install' in purpose_lower:
                draw_check(37, 747)
            if not any(key in purpose_lower for key in ['warranty', 'repair', 'preventive', 'install']) and not is_pm_purpose:
                draw_check(37, 730)
                draw_wrapped_text(130, 714, purpose_text, max_width=176, max_lines=2, size=6.6, line_height=7.8)
                draw_wrapped_text(331, 714, equipment_text, max_width=168, max_lines=2, size=6.6, line_height=7.8)
        else:
            # Training, seminar, meeting, and similar Medical Service travel
            # should stay under the Service Dept/CSC purpose area, not Sales/Others.
            # Details start on the first Service Dept row, while Others is checked below.
            draw_check(37, 730)  # Service Dept / Others
            detail_lines = []
            detail_lines.append(f'Type: {request_type}')
            if purpose_text and purpose_text != request_type:
                detail_lines.append(f'Details: {purpose_text}')
            if customer_text and customer_text not in {'N/A', purpose_text}:
                detail_lines.append(f'Customer/Host: {customer_text}')
            if participant_label:
                detail_lines.append(f'Participants: {participant_label}')
            if approval_remarks:
                detail_lines.append(f'Approval Remarks: {approval_remarks}')
            y_positions = [798, 781, 764, 747]
            for idx, detail_line in enumerate(detail_lines[:len(y_positions)]):
                draw_wrapped_text(130, y_positions[idx], detail_line, max_width=370, max_lines=1, size=7.2)

        draw_wrapped_text(204, 508, route_text, max_width=372, max_lines=1, size=8)
        draw_wrapped_text(204, 488, travel_dates_text, max_width=372, max_lines=1, size=8)

        draw_text(331, 457, money_text(airfare), size=8, max_width=90, align='right')
        if airfare == 0 and airfare_note:
            draw_wrapped_text(426, 457, airfare_note, max_width=150, max_lines=1, size=6.8)
        draw_text(331, 445, money_text(landfare), size=8, max_width=90, align='right')
        draw_text(331, 434, money_text(per_diem), size=8, max_width=90, align='right')
        draw_text(331, 422, money_text(hotel), size=8, max_width=90, align='right')
        draw_text(331, 410, money_text(misc), size=8, max_width=90, align='right')
        draw_text(331, 388, money_text(total_amount), size=8, bold=True, max_width=90, align='right')

        # Special instruction and approval fields.
        # F4A5J6: Put the deposit X inside the official checkbox.
        # The previous x=28 placed the mark beside the box instead of inside it.
        draw_check(18, 341)  # Check for deposit
        health_text = 'Fit to travel'
        draw_wrapped_text(434, 277, health_text, max_width=142, max_lines=1, size=8)
        approver_label = pdf_title_case_name(safe_text(getattr(request_rec, 'approval_name_snapshot', None)) or approved_by)
        # F4A5I2: The approver name/signature must be stamped only in the official
        # APPROVED BY block. The NOTED BY / CHECKED BY blocks should stay blank.

        manager_signature_data = safe_text(getattr(request_rec, 'approval_signature_snapshot', None))
        if not manager_signature_data and approved_by_user:
            manager_signature_data = get_user_signature_snapshot(approved_by_user)
        # F4A5J5: Move the approver signature closer to the printed approver
        # name while keeping the name/date in the corrected F4A5J4 position.
        # A shorter/lower signature box prevents the saved signature from
        # floating too high above the official Approved By line.
        draw_signature_data_url(manager_signature_data, 421, 195, 160, 28, label='', label_size=4.8)
        # F4A5J4: Keep the printed name below the official underline and center
        # it inside the Approved By line. The previous Y value made the underline
        # cut through the approver name on the generated PDF.
        draw_text(426, 191, approver_label, size=7.5, bold=True, max_width=150, align='center')
        if approved_at:
            draw_text(426, 181, f"Approved: {approved_at.strftime('%m/%d/%Y %I:%M %p')}", size=6.7, max_width=150, align='center')

        # Small reference footer inside unused lower margin for traceability.
        draw_text(31, 59, f"System Ref: {ctx.get('request_no')} | Approved Amount: {format_travel_currency_amount(total_amount, ctx.get('currency_code') or getattr(request_rec, 'currency_code', None) or 'PHP')}", size=6.5, max_width=360)

        c.save()
        overlay_buffer.seek(0)
        overlay_reader = PdfReader(overlay_buffer)
        base_page.merge_page(overlay_reader.pages[0])

        # Flatten visually by removing interactive annotations from the final copy.
        # The original template file remains untouched.
        if '/Annots' in base_page:
            del base_page['/Annots']

        writer = PdfWriter()
        writer.add_page(base_page)
        output_buffer = io.BytesIO()
        writer.write(output_buffer)
        output_buffer.seek(0)
        return output_buffer.getvalue()

    except Exception as official_pdf_error:
        print(f'[TravelRequestPDF] Official template overlay failed: {official_pdf_error}', flush=True)
        raise

