def send_travel_request_accounting_email_async(app_obj, travel_request_id, accounting_emails, approved_by_user_id=None, remarks=''):
    """Send approved Travel Request handoff email to Settings-managed Accounting recipients."""
    recipient_emails = normalize_email_list(accounting_emails)
    if not recipient_emails:
        return False

    def worker():
        temp_pdf_path = ''
        with app_obj.app_context():
            try:
                request_rec = db.session.get(TravelRequest, clean_int(travel_request_id))
                if not request_rec:
                    print(f"[EMAIL] Travel accounting handoff skipped: request #{travel_request_id} not found.", flush=True)
                    return

                approver = db.session.get(User, clean_int(approved_by_user_id)) if approved_by_user_id else None
                subject, text_body, html_body = format_travel_request_accounting_email(
                    request_rec,
                    approved_by_user=approver,
                    remarks=remarks
                )

                pdf_filename = travel_request_pdf_filename(request_rec)
                pdf_bytes = build_travel_request_accounting_pdf_bytes(
                    request_rec,
                    approved_by_user=approver,
                    remarks=remarks
                )
                with tempfile.NamedTemporaryFile(delete=False, suffix='.pdf') as temp_pdf:
                    temp_pdf.write(pdf_bytes)
                    temp_pdf_path = temp_pdf.name

                requester_copy_emails = get_requester_accounting_copy_emails(request_rec, recipient_emails)
                sent, message = send_email_with_attachments(
                    recipient_emails,
                    subject,
                    text_body,
                    html_body,
                    attachments=[{
                        'display_name': pdf_filename,
                        'filename': pdf_filename,
                        'path': temp_pdf_path
                    }],
                    cc_emails=requester_copy_emails
                )
                print(f"[EMAIL] Travel accounting handoff with PDF attachment: sent={sent} | {message}", flush=True)

                if sent:
                    request_rec.sent_to_accounting_at = get_manila_time()
                    request_rec.accounting_status = 'Sent to Accounting'
                    request_rec.updated_at = get_manila_time()
                    db.session.add(ActivityLog(
                        user=universal_approval_actor_name(approver) if approver else 'System',
                        action=f"Sent approved Travel Request PDF to Accounting: {request_rec.request_no or f'TR-{request_rec.id}'}"
                    ))
                    db.session.commit()
                else:
                    request_rec.accounting_status = 'Accounting Email Failed'
                    request_rec.accounting_remarks = message or 'Unable to send accounting email with Travel Request PDF.'
                    request_rec.updated_at = get_manila_time()
                    db.session.add(ActivityLog(
                        user=universal_approval_actor_name(approver) if approver else 'System',
                        action=f"Failed to send Travel Request PDF to Accounting: {request_rec.request_no or f'TR-{request_rec.id}'}"
                    ))
                    db.session.commit()

            except Exception as email_error:
                db.session.rollback()
                print(f"[EMAIL] Travel accounting handoff worker failed: {email_error}", flush=True)
            finally:
                if temp_pdf_path:
                    try:
                        os.unlink(temp_pdf_path)
                    except Exception:
                        pass

    email_thread = threading.Thread(target=worker, daemon=True)
    email_thread.start()
    print("[EMAIL] Travel accounting handoff background email queued.", flush=True)
    return True




def reimbursement_notification_url(header):
    """Frontend target for Reimbursement notifications."""
    if not header:
        return '/approvals'
    status = reimbursement_normalize_status(getattr(header, 'status', ''))
    if status == 'Submitted':
        return f"/approvals?module=reimbursement&id={header.id}"
    return f"/reimbursement?reimbursement_id={header.id}"


def reimbursement_email_context(header):
    """Build common readable Reimbursement email fields."""
    requester = db.session.get(User, header.user_id) if getattr(header, 'user_id', None) else None
    engineer = db.session.get(Engineer, header.engineer_id) if getattr(header, 'engineer_id', None) else None
    requester_name = (
        clean_str(getattr(engineer, 'name', None)) or
        approval_user_display_name(requester) or
        clean_str(getattr(requester, 'username', None)) or
        'Requester'
    )
    request_label = f"Reimbursement #{getattr(header, 'id', '')}"
    period = 'Not specified'
    if getattr(header, 'start_date', None) and getattr(header, 'end_date', None):
        try:
            period = reimbursement_excel_period_label(header.start_date, header.end_date)
        except Exception:
            period = f"{header.start_date} to {header.end_date}"
    total_amount = round(sum(reimbursement_money_value(row.row_total) for row in (header.rows or [])), 2)
    amount_label = f"PHP {total_amount:,.2f}"
    return {
        'request_label': request_label,
        'requester_name': requester_name,
        'period': period,
        'amount_label': amount_label,
        'total_amount': total_amount
    }


