def send_reimbursement_notification_email_async(app_obj, recipient_user_ids, reimbursement_id, action_label, actor_user_id=None, remarks=''):
    """Send Reimbursement notification email in background."""
    recipient_ids = [clean_int(item) for item in (recipient_user_ids or []) if clean_int(item)]
    if not recipient_ids:
        return

    def worker():
        with app_obj.app_context():
            try:
                header = db.session.get(ReimbursementHeader, clean_int(reimbursement_id))
                if not header:
                    print(f"[EMAIL] Reimbursement notification skipped: header #{reimbursement_id} not found.", flush=True)
                    return

                recipients = [db.session.get(User, user_id) for user_id in recipient_ids]
                recipients = [user for user in recipients if user]
                recipient_emails = get_users_email_addresses_for_notifications(recipients)
                if not recipient_emails:
                    print("[EMAIL] Reimbursement notification skipped: no recipient email addresses.", flush=True)
                    return

                actor_user = db.session.get(User, clean_int(actor_user_id)) if actor_user_id else None
                subject, text_body, html_body = format_reimbursement_notification_email(
                    action_label,
                    header,
                    actor_user=actor_user,
                    remarks=remarks
                )
                sent, message = send_email_notification(recipient_emails, subject, text_body, html_body)
                print(f"[EMAIL] Reimbursement notification {action_label}: sent={sent} | {message}", flush=True)
            except Exception as email_error:
                print(f"[EMAIL] Reimbursement notification worker failed: {email_error}", flush=True)

    email_thread = threading.Thread(target=worker, daemon=True)
    email_thread.start()
    print(f"[EMAIL] Reimbursement notification background email queued: {action_label}", flush=True)

