def build_reimbursement_package_zip_bytes(header):
    """Generate the same reimbursement ZIP package used by Download Package."""
    engineer = db.session.get(Engineer, header.engineer_id) if getattr(header, 'engineer_id', None) else None
    engineer_name = getattr(engineer, 'name', '') if engineer else ''

    reimbursement_wb = build_reimbursement_excel_workbook(header)
    reimbursement_buffer = io.BytesIO()
    reimbursement_wb.save(reimbursement_buffer)
    reimbursement_buffer.seek(0)

    pcv_buffer = build_reimbursement_pcv_template_pdf(header)
    rfp_buffer = build_reimbursement_rfp_template_pdf(header)
    all_receipts_buffer = build_reimbursement_all_receipts_pdf(header)

    zip_buffer = io.BytesIO()
    with zipfile.ZipFile(zip_buffer, 'w', compression=zipfile.ZIP_DEFLATED) as package:
        package.writestr(
            reimbursement_excel_filename(header, engineer_name),
            reimbursement_buffer.getvalue()
        )
        package.writestr(
            reimbursement_pcv_filename(header, engineer_name),
            pcv_buffer.getvalue()
        )
        package.writestr(
            reimbursement_rfp_filename(header, engineer_name),
            rfp_buffer.getvalue()
        )
        if all_receipts_buffer:
            package.writestr(
                reimbursement_all_receipts_filename(header, engineer_name),
                all_receipts_buffer.getvalue()
            )

    zip_buffer.seek(0)
    return reimbursement_package_filename(header, engineer_name), zip_buffer.getvalue()


