@app.route('/mark_scoped_notifications_read', methods=['POST'])
@csrf.exempt
@login_required
def mark_scoped_notifications_read():
    ensure_system_notification_table()
    payload = request.get_json(silent=True) or {}
    scope = clean_str(payload.get('scope') or request.args.get('scope')).lower()
    module_map = {
        'travel_request': 'travel_request',
        'reimbursement': 'reimbursement',
        'cash_advance': 'cash_advance'
    }

    if scope == 'approval' and not is_approval_center_user():
        return jsonify({'success': False, 'error': 'You are not assigned as an approver.'}), 403
    if scope not in {'approval', 'travel_request', 'reimbursement', 'cash_advance'}:
        return jsonify({'success': False, 'error': 'Unknown notification scope.'}), 400

    unread_items = notification_base_query(
        module=module_map.get(scope),
        unread_only=True
    ).limit(500).all()
    now = get_manila_time()
    updated_count = 0
    for notification in unread_items:
        if notification_matches_scope(notification, scope):
            notification.is_read = True
            notification.read_at = now
            updated_count += 1

    db.session.commit()
    return jsonify({
        'success': True,
        'scope': scope,
        'updated_count': updated_count
    })


@app.route('/mark_notification_read', methods=['POST'])
@csrf.exempt
@login_required
def mark_notification_read():
    """Mark one notification as read for the current user."""
    ensure_system_notification_table()
    payload = request.get_json(silent=True) or {}
    notification_id = clean_int(payload.get('notification_id') or payload.get('id'))

    notification = db.session.get(SystemNotification, notification_id) if notification_id else None
    if not notification or notification.user_id != current_user.id:
        return jsonify({'success': False, 'error': 'Notification not found.'}), 404

    notification.is_read = True
    notification.read_at = get_manila_time()
    db.session.commit()

    return jsonify({
        'success': True,
        'notification': system_notification_to_dict(notification)
    })


@app.route('/mark_all_notifications_read', methods=['POST'])
@csrf.exempt
@login_required
def mark_all_notifications_read():
    """Mark all notifications as read for the current user."""
    ensure_system_notification_table()
    now = get_manila_time()

    unread_items = SystemNotification.query.filter_by(user_id=current_user.id, is_read=False).all()
    for notification in unread_items:
        notification.is_read = True
        notification.read_at = now

    db.session.commit()
    return jsonify({
        'success': True,
        'updated_count': len(unread_items)
    })



