def tsr_knowledge_entry_to_dict(entry):
    return {
        'id': entry.id,
        'complaint': entry.complaint or '',
        'actions_taken': entry.actions_taken or '',
        'client_name': entry.client_name or '',
        'product_name': entry.product_name or '',
        'serial_number': entry.serial_number or '',
        'task': entry.task or '',
        'service_category': entry.service_category or '',
        'engineer_name': entry.engineer_name or '',
        'created_at': entry.created_at.strftime('%Y-%m-%d') if entry.created_at else ''
    }


def tsr_knowledge_rank_score(entry, q='', search_type='all', client='', product='', serial='', task=''):
    """Return a relevance score so TSR knowledge results show best matches first.

    Ranking priority:
    1. Exact complaint/action keyword match
    2. Same serial number
    3. Same product/model
    4. Same client/task context
    5. Most recent entry
    """
    def norm(value):
        return (value or '').strip().lower()

    q_norm = norm(q)
    client_norm = norm(client)
    product_norm = norm(product)
    serial_norm = norm(serial)
    task_norm = norm(task)

    complaint_norm = norm(getattr(entry, 'complaint', ''))
    actions_norm = norm(getattr(entry, 'actions_taken', ''))
    entry_client_norm = norm(getattr(entry, 'client_name', ''))
    entry_product_norm = norm(getattr(entry, 'product_name', ''))
    entry_serial_norm = norm(getattr(entry, 'serial_number', ''))
    entry_task_norm = norm(getattr(entry, 'task', ''))

    score = 0

    if search_type == 'complaint':
        searchable_texts = [complaint_norm]
    elif search_type == 'action':
        searchable_texts = [actions_norm]
    else:
        searchable_texts = [complaint_norm, actions_norm, entry_client_norm, entry_product_norm, entry_serial_norm, entry_task_norm]

    if q_norm:
        for text_value in searchable_texts:
            if not text_value:
                continue
            if text_value == q_norm:
                score += 120
            elif text_value.startswith(q_norm):
                score += 90
            elif q_norm in text_value:
                score += 70

        q_words = [word for word in re.split(r'\s+', q_norm) if len(word) >= 3]
        if q_words:
            matched_words = sum(1 for word in q_words if any(word in text_value for text_value in searchable_texts))
            score += matched_words * 8

    if serial_norm and entry_serial_norm:
        if entry_serial_norm == serial_norm:
            score += 60
        elif serial_norm in entry_serial_norm or entry_serial_norm in serial_norm:
            score += 40

    if product_norm and entry_product_norm:
        if entry_product_norm == product_norm:
            score += 35
        elif product_norm in entry_product_norm or entry_product_norm in product_norm:
            score += 25

    if client_norm and entry_client_norm:
        if entry_client_norm == client_norm:
            score += 25
        elif client_norm in entry_client_norm or entry_client_norm in client_norm:
            score += 15

    if task_norm and entry_task_norm:
        if entry_task_norm == task_norm:
            score += 15
        elif task_norm in entry_task_norm or entry_task_norm in task_norm:
            score += 8

    if getattr(entry, 'created_at', None):
        age_days = max((get_manila_time().replace(tzinfo=None) - entry.created_at).days, 0)
        if age_days <= 30:
            score += 10
        elif age_days <= 90:
            score += 6
        elif age_days <= 365:
            score += 3

    return score


@app.route('/search_tsr_knowledge')
@login_required
def search_tsr_knowledge():
    """Search reusable complaint/action history for Offline TSR reference.

    Phase 6C.1B:
    - type=complaint searches the complaint field directly.
    - type=action searches actions taken directly.
    - Context values are fallback helpers, not hard blockers, so keyword search
      still works even when product/serial/client data is incomplete.
    """
    if not (is_admin_authorized() or getattr(current_user, 'role', None) == 'engineer'):
        return denied()

    ensure_tsr_knowledge_entry_table()

    q = clean_str(request.args.get('q')) or ''
    client = clean_str(request.args.get('client')) or ''
    product = clean_str(request.args.get('product')) or ''
    serial = clean_str(request.args.get('serial')) or ''
    task = clean_str(request.args.get('task')) or ''
    search_type = (clean_str(request.args.get('type')) or 'all').lower()
    if search_type not in {'all', 'complaint', 'action'}:
        search_type = 'all'

    query = TsrKnowledgeEntry.query
    filters = []

    if q:
        like = f"%{q}%"
        if search_type == 'complaint':
            filters.append(TsrKnowledgeEntry.complaint.ilike(like))
        elif search_type == 'action':
            filters.append(TsrKnowledgeEntry.actions_taken.ilike(like))
        else:
            filters.append(or_(
                TsrKnowledgeEntry.complaint.ilike(like),
                TsrKnowledgeEntry.actions_taken.ilike(like),
                TsrKnowledgeEntry.client_name.ilike(like),
                TsrKnowledgeEntry.product_name.ilike(like),
                TsrKnowledgeEntry.serial_number.ilike(like),
                TsrKnowledgeEntry.task.ilike(like)
            ))
    else:
        context_filters = []
        if serial:
            context_filters.append(TsrKnowledgeEntry.serial_number.ilike(f"%{serial}%"))
        if product:
            context_filters.append(TsrKnowledgeEntry.product_name.ilike(f"%{product}%"))
        if client:
            context_filters.append(TsrKnowledgeEntry.client_name.ilike(f"%{client}%"))
        if task:
            context_filters.append(TsrKnowledgeEntry.task.ilike(f"%{task}%"))
        if context_filters:
            filters.append(or_(*context_filters))

    if search_type == 'complaint':
        filters.append(TsrKnowledgeEntry.complaint.isnot(None))
        filters.append(TsrKnowledgeEntry.complaint != '')
    elif search_type == 'action':
        filters.append(TsrKnowledgeEntry.actions_taken.isnot(None))
        filters.append(TsrKnowledgeEntry.actions_taken != '')

    if filters:
        query = query.filter(and_(*filters))

    # Fetch a wider recent pool, then sort by relevance in Python so live SQLite
    # keeps compatibility without requiring full-text search or schema changes.
    entries = query.order_by(TsrKnowledgeEntry.created_at.desc()).limit(100).all()
    ranked_entries = sorted(
        entries,
        key=lambda entry: (
            tsr_knowledge_rank_score(entry, q=q, search_type=search_type, client=client, product=product, serial=serial, task=task),
            entry.created_at or datetime.min
        ),
        reverse=True
    )[:25]

    return jsonify({
        'status': 'success',
        'type': search_type,
        'count': len(ranked_entries),
        'entries': [tsr_knowledge_entry_to_dict(entry) for entry in ranked_entries]
    })



@app.route('/get_tsr_knowledge_quick_picks')
@login_required
def get_tsr_knowledge_quick_picks():
    """Return equipment-tied recent/common TSR knowledge quick picks.

    Phase 2 Step 4:
    - Quick picks are intentionally tied to the selected equipment context.
    - Same serial number is preferred; same product/model is allowed as fallback.
    - No global fallback is returned, so engineers do not see unrelated machines.
    """
    if not (is_admin_authorized() or getattr(current_user, 'role', None) == 'engineer'):
        return denied()

    ensure_tsr_knowledge_entry_table()

    product = clean_str(request.args.get('product')) or ''
    serial = clean_str(request.args.get('serial')) or ''
    client = clean_str(request.args.get('client')) or ''
    task = clean_str(request.args.get('task')) or ''

    if not serial and not product:
        return jsonify({
            'status': 'success',
            'equipment_scoped': False,
            'message': 'Select a schedule/equipment first to load equipment-specific quick picks.',
            'recent_complaints': [],
            'common_complaints': [],
            'recent_actions': [],
            'common_actions': []
        })

    context_filters = []
    if serial:
        context_filters.append(TsrKnowledgeEntry.serial_number.ilike(f"%{serial}%"))
    if product:
        context_filters.append(TsrKnowledgeEntry.product_name.ilike(f"%{product}%"))

    entries = (
        TsrKnowledgeEntry.query
        .filter(or_(*context_filters))
        .order_by(TsrKnowledgeEntry.created_at.desc())
        .limit(250)
        .all()
    )

    ranked_entries = sorted(
        entries,
        key=lambda entry: (
            tsr_knowledge_rank_score(entry, q='', search_type='all', client=client, product=product, serial=serial, task=task),
            entry.created_at or datetime.min
        ),
        reverse=True
    )

    def text_key(value):
        return re.sub(r'\s+', ' ', (value or '').strip().lower())

    def build_recent(field_name, limit=6):
        recent = []
        seen = set()
        for entry in ranked_entries:
            value = clean_str(getattr(entry, field_name, None)) or ''
            key = text_key(value)
            if not key or key in seen:
                continue
            seen.add(key)
            recent.append(tsr_knowledge_entry_to_dict(entry))
            if len(recent) >= limit:
                break
        return recent

    def build_common(field_name, limit=6):
        grouped = {}
        for entry in ranked_entries:
            value = clean_str(getattr(entry, field_name, None)) or ''
            key = text_key(value)
            if not key:
                continue
            if key not in grouped:
                grouped[key] = {
                    'count': 0,
                    'entry': entry,
                    'latest': entry.created_at or datetime.min,
                    'score': tsr_knowledge_rank_score(entry, q='', search_type='all', client=client, product=product, serial=serial, task=task)
                }
            grouped[key]['count'] += 1
            if (entry.created_at or datetime.min) > grouped[key]['latest']:
                grouped[key]['latest'] = entry.created_at or datetime.min
                grouped[key]['entry'] = entry
            grouped[key]['score'] = max(grouped[key]['score'], tsr_knowledge_rank_score(entry, q='', search_type='all', client=client, product=product, serial=serial, task=task))

        common = sorted(
            grouped.values(),
            key=lambda item: (item['count'], item['score'], item['latest']),
            reverse=True
        )[:limit]

        results = []
        for item in common:
            entry_dict = tsr_knowledge_entry_to_dict(item['entry'])
            entry_dict['usage_count'] = item['count']
            results.append(entry_dict)
        return results

    return jsonify({
        'status': 'success',
        'equipment_scoped': True,
        'context': {
            'product_name': product,
            'serial_number': serial,
            'client_name': client,
            'task': task
        },
        'recent_complaints': build_recent('complaint'),
        'common_complaints': build_common('complaint'),
        'recent_actions': build_recent('actions_taken'),
        'common_actions': build_common('actions_taken')
    })




def build_online_tsr_pdf_filename(submission, shift, tsr_number='', payload=None):
    """Build the visible Online TSR PDF filename using the Offline TSR download rule.

    Visible/original filename must match the browser Download PDF filename:
    - NCS_TSR_Shimadzu_Client_Product(Serial)_Task_MMDDYYYY.pdf
    - NCS_TSR_B_Shimadzu_Client_Product(Serial)_Task_MMDDYYYY.pdf when billing/PO applies

    The actual stored disk filename is still randomized later by ShiftFile.filename.
    """
    payload = payload if isinstance(payload, dict) else {}
    selected_schedule = payload.get('selectedSchedule') if isinstance(payload.get('selectedSchedule'), dict) else {}

    # If the frontend explicitly supplies its download filename in a future patch,
    # trust it first so both sides remain perfectly aligned.
    frontend_filename = (
        clean_str(payload.get('pdf_filename')) or
        clean_str(payload.get('download_filename')) or
        clean_str(payload.get('tsr_pdf_filename')) or
        clean_str(payload.get('_download_filename'))
    )

    if frontend_filename:
        safe_name = secure_filename(os.path.basename(frontend_filename))
        if safe_name:
            if not safe_name.lower().endswith('.pdf'):
                safe_name = f"{safe_name}.pdf"
            if 'TSR' not in safe_name.upper():
                safe_name = f"TSR_{safe_name}"
            return safe_name

    def first_value(*keys):
        for key in keys:
            value = clean_str(payload.get(key))
            if value:
                return value
            value = clean_str(selected_schedule.get(key))
            if value:
                return value
        return ''

    def clean_filename_part(value, fallback):
        value = clean_str(value) or fallback
        value = re.sub(r'[^A-Za-z0-9()\-]+', '_', value)
        value = re.sub(r'_+', '_', value).strip('_')
        return value or fallback

    def format_tsr_date(value):
        raw_value = clean_str(value) or ''
        parsed = None
        for fmt in ('%Y-%m-%d', '%m/%d/%Y', '%m-%d-%Y', '%b %d, %Y'):
            try:
                parsed = datetime.strptime(raw_value, fmt).date()
                break
            except Exception:
                pass
        if not parsed and getattr(shift, 'start_time', None):
            parsed = shift.start_time.date()
        if not parsed:
            parsed = get_manila_today()
        return parsed.strftime('%m%d%Y')

    client_name = first_value('tsr-customer-name', 'client_name') or clean_str(getattr(submission, 'client_name', '')) or 'Client'
    product_name = first_value('tsr-equipment-model', 'product_name') or clean_str(getattr(submission, 'product_name', '')) or 'Product'
    serial_number = first_value('tsr-serial-no', 'product_id', 'serial_number') or clean_str(getattr(submission, 'serial_number', ''))
    task_name = first_value('task') or clean_str(getattr(shift, 'title', '')) or 'Service'
    service_date = first_value('tsr-service-date', 'date_iso', 'date_label')

    product_label = clean_filename_part(product_name, 'Product')
    serial_clean = clean_filename_part(serial_number, '') if serial_number else ''
    if serial_clean:
        product_label = f"{product_label}({serial_clean})"

    # Match frontend billing filename condition: add B when billing/PO fields are present.
    billing_fields = [
        payload.get('tsr-billing-statement'),
        payload.get('tsr-purchase-order'),
        payload.get('billing_statement'),
        payload.get('purchase_order'),
    ]
    billing_flag = any(clean_str(value) for value in billing_fields)

    prefix = 'NCS_TSR_B_Shimadzu' if billing_flag else 'NCS_TSR_Shimadzu'
    raw_name = "_".join([
        prefix,
        clean_filename_part(client_name, 'Client'),
        product_label,
        clean_filename_part(task_name, 'Service'),
        format_tsr_date(service_date)
    ]) + '.pdf'

    safe_name = secure_filename(raw_name)
    if not safe_name.lower().endswith('.pdf'):
        safe_name = f"{safe_name}.pdf"
    if 'TSR' not in safe_name.upper():
        safe_name = f"TSR_{safe_name}"
    return safe_name

def generate_online_tsr_submission_pdf(submission, shift, payload):
    """Generate a basic official TSR PDF from the online Offline TSR payload.

    Phase 3 Step 2 only creates the server-side PDF file.
    Attaching it to the schedule happens in Phase 3 Step 3.
    """
    from reportlab.lib import colors
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle

    selected_schedule = payload.get('selectedSchedule') if isinstance(payload.get('selectedSchedule'), dict) else {}

    def payload_value(*keys):
        for key in keys:
            value = clean_str(payload.get(key))
            if value:
                return value
        return ''

    def schedule_value(*keys):
        for key in keys:
            value = clean_str(selected_schedule.get(key))
            if value:
                return value
        return ''

    def safe_paragraph(value):
        return Paragraph(html.escape(clean_str(value) or ''), body_style)

    tsr_number = payload_value('tsr-number', 'tsr_number') or clean_str(submission.tsr_number) or f"ONLINE-{submission.id}"
    pdf_filename = build_online_tsr_pdf_filename(submission, shift, tsr_number, payload=payload)
    pdf_path = os.path.join(app.config['UPLOAD_FOLDER'], pdf_filename)
    os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        'TSRTitle',
        parent=styles['Title'],
        fontName='Helvetica-Bold',
        fontSize=16,
        leading=20,
        alignment=1,
        spaceAfter=8
    )
    section_style = ParagraphStyle(
        'TSRSection',
        parent=styles['Heading2'],
        fontName='Helvetica-Bold',
        fontSize=10,
        leading=12,
        textColor=colors.HexColor('#0f172a'),
        spaceBefore=8,
        spaceAfter=4
    )
    body_style = ParagraphStyle(
        'TSRBody',
        parent=styles['BodyText'],
        fontName='Helvetica',
        fontSize=8.5,
        leading=11,
        wordWrap='CJK'
    )

    doc = SimpleDocTemplate(
        pdf_path,
        pagesize=A4,
        rightMargin=12 * mm,
        leftMargin=12 * mm,
        topMargin=12 * mm,
        bottomMargin=12 * mm
    )

    story = [
        Paragraph('TECHNICAL SERVICE REPORT', title_style),
        Paragraph('Generated by MEDICAL SERVICE Online TSR Save', body_style),
        Spacer(1, 6)
    ]

    def detail_table(rows):
        table_rows = [[Paragraph(f'<b>{html.escape(label)}</b>', body_style), safe_paragraph(value)] for label, value in rows]
        table = Table(table_rows, colWidths=[44 * mm, 130 * mm])
        table.setStyle(TableStyle([
            ('GRID', (0, 0), (-1, -1), 0.35, colors.HexColor('#cbd5e1')),
            ('BACKGROUND', (0, 0), (0, -1), colors.HexColor('#f8fafc')),
            ('VALIGN', (0, 0), (-1, -1), 'TOP'),
            ('LEFTPADDING', (0, 0), (-1, -1), 5),
            ('RIGHTPADDING', (0, 0), (-1, -1), 5),
            ('TOPPADDING', (0, 0), (-1, -1), 4),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 4),
        ]))
        return table

    story.append(Paragraph('Customer / Equipment', section_style))
    story.append(detail_table([
        ('TSR No.', tsr_number),
        ('Customer Name', payload_value('tsr-customer-name') or schedule_value('client_name')),
        ('Address', payload_value('tsr-address') or schedule_value('client_address')),
        ('Requested By', payload_value('tsr-requested-by')),
        ('Department', payload_value('tsr-department')),
        ('Equipment / Model', payload_value('tsr-equipment-model') or schedule_value('product_name')),
        ('Serial No.', payload_value('tsr-serial-no') or schedule_value('product_id')),
        ('Service Category', payload_value('tsr-service-category') or payload_value('tsr-service-category-other')),
    ]))

    story.append(Paragraph('Service Details', section_style))
    story.append(detail_table([
        ('Schedule ID', getattr(shift, 'id', '')),
        ('Task', schedule_value('task') or clean_str(getattr(shift, 'title', ''))),
        ('Date of Service', payload_value('tsr-service-date') or schedule_value('date_iso', 'date_label')),
        ('Time Started', payload_value('tsr-time-started') or schedule_value('time_start')),
        ('Time Finished', payload_value('tsr-time-finished') or schedule_value('time_end')),
        ('Serviced By', payload_value('tsr-serviced-by') or clean_str(submission.submitted_by_name)),
        ('Acknowledged By', payload_value('tsr-acknowledged-by')),
        ('Contact No.', payload_value('tsr-contact-no')),
        ('Email Add.', payload_value('tsr-email-add')),
    ]))

    story.append(Paragraph('Complaint', section_style))
    story.append(detail_table([('Complaint', payload_value('tsr-complaint'))]))

    story.append(Paragraph('Actions Taken', section_style))
    story.append(detail_table([('Actions Taken', payload_value('tsr-actions-taken'))]))

    story.append(Paragraph('Remarks / Recommendations', section_style))
    story.append(detail_table([('Remarks', payload_value('tsr-remarks'))]))

    story.append(Paragraph('Documents / Billing', section_style))
    story.append(detail_table([
        ('Submitted Documents', payload_value('tsr-documents')),
        ('Billing Statement', payload_value('tsr-billing-statement')),
        ('Sales Invoice', payload_value('tsr-sales-invoice')),
        ('Purchase Order', payload_value('tsr-purchase-order')),
    ]))

    story.append(Spacer(1, 8))
    story.append(Paragraph(
        f"Online submission #{submission.id} generated on {get_manila_time().strftime('%Y-%m-%d %H:%M')} PH time.",
        body_style
    ))

    doc.build(story)
    return pdf_filename


def get_tsr_completion_linked_shifts(shift):
    """Return schedules that should complete together after online TSR Save.

    Covers multi-day chains via group_id and linked engineer/day time overrides
    via parent_shift_id. For single multi-engineer schedules, updating the one
    shared Shift row is enough because every engineer card reads that same row.
    """
    if not shift:
        return []

    linked_by_id = {shift.id: shift}

    if shift.group_id:
        group_shifts = Shift.query.filter_by(group_id=shift.group_id).all()
        for group_shift in group_shifts:
            linked_by_id[group_shift.id] = group_shift

        group_ids = list(linked_by_id.keys())
        if group_ids:
            overrides = Shift.query.filter(
                Shift.parent_shift_id.in_(group_ids),
                Shift.override_kind == 'time_override'
            ).all()
            for override in overrides:
                linked_by_id[override.id] = override

    if shift.parent_shift_id:
        parent_shift = db.session.get(Shift, shift.parent_shift_id)
        if parent_shift:
            linked_by_id[parent_shift.id] = parent_shift
            if parent_shift.group_id:
                for group_shift in Shift.query.filter_by(group_id=parent_shift.group_id).all():
                    linked_by_id[group_shift.id] = group_shift

    return list(linked_by_id.values())


def complete_linked_schedules_for_online_tsr(shift):
    """Mark the selected schedule and its linked multi-day/override rows completed."""
    return complete_schedules_for_online_tsr(shift, completion_scope='linked_all')


def normalize_online_tsr_completion_scope(value):
    scope = (clean_str(value) or '').strip().lower()
    if scope in {'current_day', 'current', 'selected', 'selected_day', 'single'}:
        return 'current_day'
    return 'linked_all'


def complete_schedules_for_online_tsr(shift, completion_scope='linked_all'):
    """Mark either the selected schedule only or its linked multi-day rows completed."""
    scope = normalize_online_tsr_completion_scope(completion_scope)
    shifts = [shift] if scope == 'current_day' else get_tsr_completion_linked_shifts(shift)
    completed = []
    for linked_shift in shifts:
        if not linked_shift or not linked_shift.client_id:
            continue
        if (linked_shift.status or '') != 'Completed':
            linked_shift.status = 'Completed'
        completed.append(linked_shift.id)
    return sorted(set(completed))


def online_tsr_engineer_initials():
    engineer = getattr(current_user, 'engineer_profile', None) if current_user else None
    initials = clean_str(getattr(engineer, 'initials', None)) if engineer else ''
    if not initials:
        name = clean_str(getattr(engineer, 'name', None)) if engineer else ''
        if not name:
            name = clean_str(getattr(current_user, 'username', None)) if current_user else ''
        parts = [part for part in re.split(r'[\s._-]+', name or '') if part]
        initials = ''.join(part[0] for part in parts[:3]) if parts else 'ENG'
    initials = re.sub(r'[^A-Za-z0-9]+', '', initials or '').upper()
    return (initials or 'ENG')[:5]


def online_tsr_daily_sequence_date():
    return get_manila_time().date()


def parse_online_tsr_sequence_date(value):
    text = clean_str(value)
    if not text:
        return None
    text = text[:10]
    for fmt in ('%Y-%m-%d', '%m/%d/%Y', '%m-%d-%Y'):
        try:
            return datetime.strptime(text, fmt).date()
        except Exception:
            continue
    return None


def online_tsr_next_number_for_date(sequence_date=None, initials=None):
    ensure_online_tsr_submission_table()
    sequence_date = sequence_date or online_tsr_daily_sequence_date()
    initials = (clean_str(initials) or online_tsr_engineer_initials()).upper()
    prefix = sequence_date.strftime('%Y%m%d')
    submissions = (
        OnlineTsrSubmission.query
        .filter(OnlineTsrSubmission.tsr_number.like(f"{prefix}-%-{initials}"))
        .all()
    )
    highest = 0
    pattern = re.compile(rf'^{re.escape(prefix)}-(\d{{1,4}})-{re.escape(initials)}$', re.IGNORECASE)
    for submission in submissions:
        match = pattern.match(clean_str(getattr(submission, 'tsr_number', None)) or '')
        if match:
            highest = max(highest, clean_int(match.group(1)) or 0)
    return f"{prefix}-{highest + 1:02d}-{initials}"


def online_tsr_submitted_number_is_available(tsr_number, sequence_date=None, initials=None):
    ensure_online_tsr_submission_table()
    tsr_number = clean_str(tsr_number).upper()
    if not tsr_number:
        return False
    sequence_date = sequence_date or online_tsr_daily_sequence_date()
    initials = (clean_str(initials) or online_tsr_engineer_initials()).upper()
    prefix = sequence_date.strftime('%Y%m%d')
    pattern = re.compile(rf'^{re.escape(prefix)}-(\d{{1,4}})-{re.escape(initials)}$', re.IGNORECASE)
    if not pattern.match(tsr_number):
        return False
    existing = (
        OnlineTsrSubmission.query
        .filter(db.func.upper(OnlineTsrSubmission.tsr_number) == tsr_number)
        .first()
    )
    return existing is None


@app.route('/get_next_online_tsr_number')
@login_required
def get_next_online_tsr_number():
    if not (is_admin_authorized() or getattr(current_user, 'role', None) == 'engineer'):
        return denied()
    try:
        sequence_date = parse_online_tsr_sequence_date(request.args.get('service_date') or request.args.get('date')) or online_tsr_daily_sequence_date()
        tsr_number = online_tsr_next_number_for_date(sequence_date)
        return jsonify({
            'success': True,
            'tsr_number': tsr_number,
            'sequence_scope': 'engineer_daily',
            'date': sequence_date.isoformat()
        })
    except Exception as exc:
        print(f"[ONLINE-TSR] Next TSR number failed: {exc}", flush=True)
        return jsonify({'success': False, 'message': 'Unable to assign the next TSR number.'}), 500


def attach_online_tsr_pdf_to_shift(shift, pdf_filename):
    """Attach generated online TSR PDF to the selected schedule using ShiftFile.

    Phase 3 Step 3 keeps disk filenames randomized while preserving the
    readable generated TSR filename in original_filename for UI/email/report use.
    Phase 3 Step 4 explicitly stamps uploaded_at so generated TSRs sort and
    display consistently in Reports/Archive just like manual TSR uploads.
    """
    ensure_shift_file_original_filename_column()

    safe_original = secure_filename(os.path.basename(clean_str(pdf_filename) or ''))
    if not safe_original:
        raise ValueError('Generated TSR PDF filename is empty.')

    source_path = os.path.join(app.config['UPLOAD_FOLDER'], safe_original)
    if not os.path.exists(source_path):
        raise FileNotFoundError(f'Generated TSR PDF was not found: {safe_original}')

    disk_filename = get_unique_upload_filename(safe_original)
    disk_path = os.path.join(app.config['UPLOAD_FOLDER'], disk_filename)

    os.replace(source_path, disk_path)

    file_rec = ShiftFile(
        shift_id=shift.id,
        filename=disk_filename,
        original_filename=safe_original,
        uploaded_at=get_manila_time()
    )
    db.session.add(file_rec)
    return file_rec


def attach_uploaded_online_tsr_pdf_to_shift(shift, uploaded_pdf, display_filename=None):
    """Attach the exact browser-generated Offline TSR PDF blob to a schedule.

    This keeps Save Online visually identical to the Download PDF button because
    the frontend uploads the same PDF blob it would download locally.
    Disk storage is still randomized; original_filename remains clean/readable.
    """
    ensure_shift_file_original_filename_column()

    if not uploaded_pdf or not getattr(uploaded_pdf, 'filename', None):
        raise ValueError('No generated TSR PDF was uploaded.')

    requested_name = (
        clean_str(display_filename) or
        clean_str(getattr(uploaded_pdf, 'filename', None)) or
        'Online_TSR.pdf'
    )
    safe_original = secure_filename(os.path.basename(requested_name))
    if not safe_original:
        safe_original = 'Online_TSR.pdf'
    if not safe_original.lower().endswith('.pdf'):
        safe_original = f"{safe_original}.pdf"
    if 'TSR' not in safe_original.upper():
        safe_original = f"TSR_{safe_original}"

    os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)
    disk_filename = get_unique_upload_filename(safe_original)
    disk_path = os.path.join(app.config['UPLOAD_FOLDER'], disk_filename)

    uploaded_pdf.save(disk_path)

    if not os.path.exists(disk_path) or os.path.getsize(disk_path) <= 0:
        raise ValueError('Uploaded TSR PDF was empty or could not be saved.')

    file_rec = ShiftFile(
        shift_id=shift.id,
        filename=disk_filename,
        original_filename=safe_original,
        uploaded_at=get_manila_time()
    )
    db.session.add(file_rec)
    return file_rec


def attach_uploaded_online_tsr_extra_files_to_shift(shift, excluded_file_ids=None):
    """Attach extra offline TSR supporting documents uploaded with a queued TSR.

    IMPORTANT:
    - Engineer/client signatures are embedded inside the generated TSR PDF only.
    - Signature upload fields must NOT be saved as separate schedule attachments.
    - Real supporting attachments/images remain allowed.
    """
    ensure_shift_file_original_filename_column()

    excluded_file_ids = {id(file_obj) for file_obj in (excluded_file_ids or []) if file_obj}
    saved_files = []
    os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

    attachment_field_names = {
        'tsr_attachment',
        'tsr_attachments',
        'tsr_image',
        'tsr_images',
        'attachment',
        'attachments',
        'image',
        'images'
    }

    # These fields are intentionally ignored because signatures belong inside
    # the generated TSR PDF, not as separate schedule attachments.
    signature_field_names = {
        'tsr_signature',
        'tsr_signatures',
        'signature',
        'signatures',
        'engineer_signature',
        'client_signature',
        'engineer-signature',
        'client-signature',
        'tsr_engineer_signature',
        'tsr_client_signature'
    }

    for field_name in request.files:
        normalized_field_name = (field_name or '').strip().lower()

        if normalized_field_name in {'tsr_pdf', 'pdf', 'file'}:
            continue
        if normalized_field_name in signature_field_names or 'signature' in normalized_field_name:
            print(f"[ONLINE-TSR] Skipped signature field as separate attachment: {field_name}", flush=True)
            continue
        if field_name == 'report_file' and request.files.get(field_name) and id(request.files.get(field_name)) in excluded_file_ids:
            continue

        if not (
            normalized_field_name in attachment_field_names or
            normalized_field_name.startswith('tsr_attachment') or
            normalized_field_name.startswith('tsr_image')
        ):
            continue

        for file_obj in request.files.getlist(field_name):
            if not file_obj or not getattr(file_obj, 'filename', None):
                continue
            if id(file_obj) in excluded_file_ids:
                continue
            if not allowed_file(file_obj.filename):
                print(f"[ONLINE-TSR] Skipped unsupported offline TSR attachment: {file_obj.filename}", flush=True)
                continue

            original_name = secure_filename(os.path.basename(file_obj.filename))
            if not original_name:
                continue

            disk_filename = get_unique_upload_filename(original_name)
            disk_path = os.path.join(app.config['UPLOAD_FOLDER'], disk_filename)
            file_obj.save(disk_path)

            if not os.path.exists(disk_path) or os.path.getsize(disk_path) <= 0:
                try:
                    os.remove(disk_path)
                except OSError:
                    pass
                continue

            file_rec = ShiftFile(
                shift_id=shift.id,
                filename=disk_filename,
                original_filename=original_name,
                uploaded_at=get_manila_time()
            )
            db.session.add(file_rec)
            saved_files.append(file_rec)

    return saved_files




def auto_capture_tsr_client_contact_from_payload(shift, payload):
    """Safely add TSR recipient contact details to the linked client record.

    Generated TSRs already carry the recipient fields in payload_json. Capture
    those details so future Send Email to Client suggestions do not need OCR,
    especially for image/scanned TSR PDFs.

    Priority for contact name:
    1. tsr-acknowledged-by (end user / TSR receiver)
    2. tsr-requested-by

    This helper only inserts missing emails for the resolved schedule client. It
    never overwrites existing client/contact data. It also mirrors captured
    contact details into the legacy Client contact slots used by the Clients
    page when a safe matching/empty slot is available.
    """
    if not shift or not isinstance(payload, dict):
        return []

    def resolve_client_for_tsr_contact():
        """Resolve the client even when older/override shifts lack client_id."""
        selected_schedule = payload.get('selectedSchedule') if isinstance(payload.get('selectedSchedule'), dict) else {}
        candidate_ids = [
            getattr(shift, 'client_id', None),
            payload.get('client_id'),
            payload.get('clientId'),
            payload.get('selected_client_id'),
            selected_schedule.get('client_id'),
            selected_schedule.get('clientId'),
            selected_schedule.get('client_id_value'),
        ]
        for candidate_id in candidate_ids:
            clean_id = clean_int(candidate_id)
            if clean_id:
                client_rec = db.session.get(Client, clean_id)
                if client_rec:
                    return client_rec

        # Fallback for older payloads: match by the customer/client name already
        # printed on the TSR. Exact normalized match only to avoid wrong clients.
        name_candidates = [
            payload.get('tsr-customer-name'),
            payload.get('tsr_customer_name'),
            selected_schedule.get('client_name'),
            selected_schedule.get('client'),
            selected_schedule.get('customer_name'),
        ]
        normalized_names = [normalize_text_for_compare(name) for name in name_candidates if clean_str(name)]
        normalized_names = [name for name in normalized_names if name]
        if not normalized_names:
            return None

        for client_rec in Client.query.all():
            client_name_key = normalize_text_for_compare(getattr(client_rec, 'name', '') or '')
            if client_name_key and client_name_key in normalized_names:
                return client_rec
        return None

    def format_tsr_contact_name(value):
        """Normalize auto-captured TSR contact names for client records.

        Engineers may type names in lowercase/uppercase on the TSR form. Keep
        the cleanup scoped to auto-captured contacts only so client/company names
        and manually maintained records are not unexpectedly changed.
        """
        raw_name = clean_str(value)
        if not raw_name:
            return ''

        import re

        particles = {'de', 'del', 'dela', 'da', 'das', 'do', 'dos', 'van', 'von'}
        roman_suffixes = {'ii', 'iii', 'iv', 'vi', 'vii', 'viii', 'ix', 'x'}
        suffixes = {'jr', 'sr'}

        def fix_word(word):
            if not word:
                return word
            bare = word.strip()
            trailing_dot = bare.endswith('.')
            core = bare[:-1] if trailing_dot else bare
            lower = core.lower()

            if lower in roman_suffixes:
                fixed = lower.upper()
            elif lower in suffixes:
                fixed = lower.capitalize()
            elif lower == 'ma':
                fixed = 'Ma'
            elif lower in particles:
                fixed = lower
            else:
                # Handles apostrophes/hyphens like O'Neil or Anne-Marie.
                fixed = re.sub(
                    r"[A-Za-zÀ-ÖØ-öø-ÿ]+",
                    lambda m: m.group(0)[:1].upper() + m.group(0)[1:].lower(),
                    core
                )
            return fixed + ('.' if trailing_dot else '')

        return ' '.join(fix_word(part) for part in raw_name.split())[:100]

    # Email and contact values come from offline_tsr.html .tsr-field IDs.
    raw_email = (
        payload.get('tsr-email-add') or
        payload.get('tsr_email_add') or
        payload.get('email') or
        payload.get('client_email') or
        ''
    )
    raw_contact_name = (
        clean_str(payload.get('tsr-acknowledged-by')) or
        clean_str(payload.get('tsr_acknowledged_by')) or
        clean_str(payload.get('tsr-requested-by')) or
        clean_str(payload.get('tsr_requested_by')) or
        ''
    )
    contact_name = format_tsr_contact_name(raw_contact_name)
    contact_phone = (
        clean_str(payload.get('tsr-contact-no')) or
        clean_str(payload.get('tsr_contact_no')) or
        clean_str(payload.get('contact_no')) or
        ''
    )[:50]

    # Be forgiving: the form has a dedicated Email Add field, but engineers may
    # paste contact details into nearby fields. Capture any valid email found
    # there while still using Acknowledged By as the display name when possible.
    email_candidates = parse_manual_recipient_emails([
        raw_email,
        payload.get('tsr-acknowledged-by'),
        payload.get('tsr_acknowledged_by'),
        payload.get('tsr-requested-by'),
        payload.get('tsr_requested_by')
    ])
    if not email_candidates:
        print(
            f"[ONLINE-TSR] Contact auto-capture skipped: no email in TSR payload for shift_id={getattr(shift, 'id', None)}",
            flush=True
        )
        return []

    client = resolve_client_for_tsr_contact()
    if not client or not getattr(client, 'id', None):
        print(
            f"[ONLINE-TSR] Contact auto-capture skipped: no linked Medical Center resolved for shift_id={getattr(shift, 'id', None)} emails={email_candidates}",
            flush=True
        )
        return []

    client_id = clean_int(client.id)
    legacy_emails = set()
    contact_table_emails = set()

    for field_name in ('email_address_1', 'email_address_2', 'email_address_3'):
        for existing_email in parse_manual_recipient_emails(getattr(client, field_name, None)):
            legacy_emails.add(existing_email.lower())

    try:
        existing_contacts = Contact.query.filter_by(client_id=client_id).order_by(Contact.id.asc()).all()
    except Exception:
        existing_contacts = []

    for contact in existing_contacts:
        for existing_email in parse_manual_recipient_emails(getattr(contact, 'email', None)):
            contact_table_emails.add(existing_email.lower())

    def fill_first_safe_client_contact_slot(email_key):
        """Mirror TSR contact into legacy Client contact slots.

        Preference order:
        1. Existing slot with the same email: fill missing name/phone only.
        2. Existing slot with the same contact name and blank email: fill email.
        3. Completely empty slot.

        This avoids overwriting manually maintained client contacts while still
        making auto-captured TSR contacts visible on older Clients page layouts.
        """
        if not client:
            return False

        normalized_contact_name = normalize_text_for_compare(contact_name)

        # 1) Same email already in a legacy slot: enrich only blank fields.
        for slot_no in (1, 2, 3):
            email_field = f'email_address_{slot_no}'
            name_field = f'contact_person_{slot_no}'
            phone_field = f'contact_number_{slot_no}'
            slot_emails = [e.lower() for e in parse_manual_recipient_emails(getattr(client, email_field, None))]
            if email_key not in slot_emails:
                continue
            changed = False
            if contact_name and not clean_str(getattr(client, name_field, None)):
                setattr(client, name_field, contact_name)
                changed = True
            if contact_phone and not clean_str(getattr(client, phone_field, None)):
                setattr(client, phone_field, contact_phone)
                changed = True
            return changed

        # 2) Same contact name with blank email: fill the email/phone safely.
        if normalized_contact_name:
            for slot_no in (1, 2, 3):
                email_field = f'email_address_{slot_no}'
                name_field = f'contact_person_{slot_no}'
                phone_field = f'contact_number_{slot_no}'
                current_email = clean_str(getattr(client, email_field, None))
                current_name = clean_str(getattr(client, name_field, None))
                current_phone = clean_str(getattr(client, phone_field, None))
                if current_email:
                    continue
                if normalize_text_for_compare(current_name) != normalized_contact_name:
                    continue
                setattr(client, email_field, email_key)
                if contact_phone and not current_phone:
                    setattr(client, phone_field, contact_phone)
                legacy_emails.add(email_key)
                return True

        # 3) Completely empty slot.
        if email_key not in legacy_emails:
            for slot_no in (1, 2, 3):
                email_field = f'email_address_{slot_no}'
                name_field = f'contact_person_{slot_no}'
                phone_field = f'contact_number_{slot_no}'

                current_email = clean_str(getattr(client, email_field, None))
                current_name = clean_str(getattr(client, name_field, None))
                current_phone = clean_str(getattr(client, phone_field, None))

                if current_email or current_name or current_phone:
                    continue

                setattr(client, email_field, email_key)
                if contact_name:
                    setattr(client, name_field, contact_name)
                if contact_phone:
                    setattr(client, phone_field, contact_phone)
                legacy_emails.add(email_key)
                return True

        return False

    def upsert_contact_table_email(email_key):
        """Insert/enrich the Contact-table row used by the Medical Center page."""
        matching_contact = None
        for contact in existing_contacts:
            contact_emails = [e.lower() for e in parse_manual_recipient_emails(getattr(contact, 'email', None))]
            if email_key in contact_emails:
                matching_contact = contact
                break

        if matching_contact:
            contact_changed = False
            if contact_name and not clean_str(getattr(matching_contact, 'name', None)):
                matching_contact.name = contact_name
                contact_changed = True
            if contact_phone and not clean_str(getattr(matching_contact, 'phone', None)):
                matching_contact.phone = contact_phone
                contact_changed = True
            return 'enriched' if contact_changed else 'existing'

        new_contact = Contact(
            client_id=client_id,
            name=contact_name,
            phone=contact_phone,
            email=email_key
        )
        db.session.add(new_contact)
        existing_contacts.append(new_contact)
        contact_table_emails.add(email_key)
        return 'created'

    created_emails = []
    mirrored_emails = []
    enriched_emails = []
    existing_emails = []

    for email_addr in email_candidates:
        email_key = clean_str(email_addr).lower()
        if not email_key:
            continue
        if not CLIENT_EMAIL_REGEX.fullmatch(email_key):
            print(
                f"[ONLINE-TSR] Contact auto-capture skipped invalid email for client_id={client_id}: {email_key}",
                flush=True
            )
            continue

        contact_result = upsert_contact_table_email(email_key)
        if contact_result == 'created':
            created_emails.append(email_key)
        elif contact_result == 'enriched':
            enriched_emails.append(email_key)
        else:
            existing_emails.append(email_key)

        if fill_first_safe_client_contact_slot(email_key):
            mirrored_emails.append(email_key)

    changed_emails = list(dict.fromkeys(created_emails + mirrored_emails + enriched_emails))
    saved_emails = list(dict.fromkeys(changed_emails + existing_emails))

    if changed_emails:
        client_label = clean_str(getattr(client, 'name', None)) if client else f'Client #{client_id}'
        shown_emails = ', '.join(changed_emails[:3])
        more_note = f" (+{len(changed_emails) - 3} more)" if len(changed_emails) > 3 else ''
        db.session.add(ActivityLog(
            user=(getattr(current_user, 'username', '') or 'System').capitalize(),
            action=(
                f"Auto-captured TSR contact for {client_label}: "
                f"{contact_name or 'Unnamed contact'} <{shown_emails}>{more_note}"
            )[:255]
        ))
        print(
            f"[ONLINE-TSR] Auto-captured TSR contact(s) for client_id={client_id}: {changed_emails}",
            flush=True
        )
    else:
        print(
            f"[ONLINE-TSR] Contact auto-capture found only existing contacts for client_id={client_id}: {email_candidates}",
            flush=True
        )

    try:
        db.session.flush()
    except Exception:
        raise

    return saved_emails


def save_tsr_payload_contact_to_medical_center(shift, payload, source_label='online_tsr'):
    """Directly save the TSR Email Add field into the linked Medical Center.

    This is the durable path used by the Medical Center page. Send Email can
    fall back to the TSR payload, but the client contact list only shows rows
    from the Contact table. Keep this helper small and explicit so missed
    auto-captures can be repaired safely.
    """
    if not shift or not isinstance(payload, dict):
        return []

    selected_schedule = payload.get('selectedSchedule') if isinstance(payload.get('selectedSchedule'), dict) else {}
    client_id = (
        clean_int(getattr(shift, 'client_id', None)) or
        clean_int(payload.get('client_id')) or
        clean_int(payload.get('clientId')) or
        clean_int(payload.get('selected_client_id')) or
        clean_int(selected_schedule.get('client_id')) or
        clean_int(selected_schedule.get('clientId'))
    )
    if not client_id:
        return []

    client = db.session.get(Client, client_id)
    if not client:
        return []

    emails = parse_manual_recipient_emails([
        payload.get('tsr-email-add'),
        payload.get('tsr_email_add'),
        payload.get('email'),
        payload.get('client_email')
    ])
    if not emails:
        return []

    contact_name = (
        clean_str(payload.get('tsr-acknowledged-by')) or
        clean_str(payload.get('tsr_acknowledged_by')) or
        clean_str(payload.get('tsr-requested-by')) or
        clean_str(payload.get('tsr_requested_by')) or
        'TSR Contact'
    )[:100]
    contact_phone = (
        clean_str(payload.get('tsr-contact-no')) or
        clean_str(payload.get('tsr_contact_no')) or
        clean_str(payload.get('contact_no')) or
        ''
    )[:50]

    try:
        contacts = Contact.query.filter_by(client_id=client_id).order_by(Contact.id.asc()).all()
    except Exception:
        contacts = []

    saved_emails = []
    changed_emails = []

    def mirror_to_empty_legacy_slot(email_key):
        for slot_no in (1, 2, 3):
            email_field = f'email_address_{slot_no}'
            name_field = f'contact_person_{slot_no}'
            phone_field = f'contact_number_{slot_no}'
            existing_email = clean_str(getattr(client, email_field, None))
            existing_name = clean_str(getattr(client, name_field, None))
            existing_phone = clean_str(getattr(client, phone_field, None))

            if existing_email:
                if email_key in [e.lower() for e in parse_manual_recipient_emails(existing_email)]:
                    if contact_name and not existing_name:
                        setattr(client, name_field, contact_name)
                    if contact_phone and not existing_phone:
                        setattr(client, phone_field, contact_phone)
                    return
                continue

            if existing_name or existing_phone:
                continue

            setattr(client, email_field, email_key)
            setattr(client, name_field, contact_name)
            if contact_phone:
                setattr(client, phone_field, contact_phone)
            return

    for email_addr in emails:
        email_key = clean_str(email_addr).lower() if clean_str(email_addr) else ''
        if not email_key or not CLIENT_EMAIL_REGEX.fullmatch(email_key):
            continue

        matching_contact = None
        for contact in contacts:
            contact_emails = [e.lower() for e in parse_manual_recipient_emails(getattr(contact, 'email', None))]
            if email_key in contact_emails:
                matching_contact = contact
                break

        if matching_contact:
            contact_changed = False
            if contact_name and not clean_str(getattr(matching_contact, 'name', None)):
                matching_contact.name = contact_name
                contact_changed = True
            if contact_phone and not clean_str(getattr(matching_contact, 'phone', None)):
                matching_contact.phone = contact_phone
                contact_changed = True
            if contact_changed:
                changed_emails.append(email_key)
        else:
            matching_contact = Contact(
                client_id=client_id,
                name=contact_name,
                phone=contact_phone,
                email=email_key
            )
            db.session.add(matching_contact)
            contacts.append(matching_contact)
            changed_emails.append(email_key)

        mirror_to_empty_legacy_slot(email_key)
        saved_emails.append(email_key)

    saved_emails = list(dict.fromkeys(saved_emails))
    changed_emails = list(dict.fromkeys(changed_emails))

    if changed_emails:
        db.session.add(ActivityLog(
            user=(getattr(current_user, 'username', '') or 'System').capitalize(),
            action=(
                f"Saved TSR contact to Medical Center from {source_label}: "
                f"{clean_str(getattr(client, 'name', 'Client')) or 'Client'} - {', '.join(changed_emails[:3])}"
            )[:255]
        ))
        print(
            f"[ONLINE-TSR] Saved TSR contact row(s) for client_id={client_id} from {source_label}: {changed_emails}",
            flush=True
        )

    if saved_emails:
        db.session.flush()

    return saved_emails


def repair_recent_online_tsr_contacts_for_medical_centers(limit=150):
    """Repair recent online TSR payloads whose Email Add was not yet a contact."""
    try:
        submissions = (
            OnlineTsrSubmission.query
            .filter(OnlineTsrSubmission.shift_id.isnot(None))
            .order_by(OnlineTsrSubmission.id.desc())
            .limit(limit)
            .all()
        )
    except Exception as repair_query_error:
        print(f"[ONLINE-TSR] Contact repair scan skipped: {repair_query_error}", flush=True)
        return []

    repaired_emails = []
    for submission in submissions:
        payload = parse_online_tsr_payload_json(submission)
        if not payload:
            continue
        if not parse_manual_recipient_emails([payload.get('tsr-email-add'), payload.get('tsr_email_add')]):
            continue

        shift = db.session.get(Shift, clean_int(getattr(submission, 'shift_id', None)))
        if not shift:
            continue

        saved_emails = save_tsr_payload_contact_to_medical_center(
            shift,
            payload,
            source_label=f'tsr_submission_{submission.id}'
        )
        if saved_emails:
            payload['_auto_captured_contact_emails'] = saved_emails
            submission.payload_json = json.dumps(payload, ensure_ascii=False)
            repaired_emails.extend(saved_emails)

    repaired_emails = list(dict.fromkeys(repaired_emails))
    if repaired_emails:
        db.session.commit()
    return repaired_emails


def correct_product_from_tsr_revision(shift, payload):
    """Apply intentional product/serial correction from TSR revision mode.

    The normal TSR form locks database-backed equipment fields. Revision mode may
    explicitly request a correction when the client reports a wrong serial or
    product name. This updates the product master and linked schedules so future
    TSRs, timeline cards, and reports use the corrected equipment details.
    """
    if not shift or not isinstance(payload, dict):
        return None

    if not payload.get('_tsr_equipment_correction_requested'):
        return None

    old_serial = clean_str(getattr(shift, 'product_id', None))
    product_rec = db.session.get(Product, old_serial) if old_serial else None
    if not product_rec:
        return {
            'status': 'skipped',
            'reason': 'product_not_found',
            'old_serial': old_serial
        }

    new_serial = clean_str(payload.get('tsr-serial-no')).upper()
    new_name = clean_str(payload.get('tsr-equipment-model'))

    if not new_serial:
        return {'status': 'skipped', 'reason': 'missing_serial', 'old_serial': old_serial}
    if not new_name:
        return {'status': 'skipped', 'reason': 'missing_product_name', 'old_serial': old_serial}

    old_name = clean_str(getattr(product_rec, 'name', None))
    if new_serial == old_serial and new_name == old_name:
        return {
            'status': 'unchanged',
            'old_serial': old_serial,
            'new_serial': new_serial,
            'old_name': old_name,
            'new_name': new_name
        }

    if new_serial != old_serial:
        existing_product = db.session.get(Product, new_serial)
        if existing_product:
            return {
                'status': 'blocked',
                'reason': 'duplicate_serial',
                'old_serial': old_serial,
                'new_serial': new_serial,
                'existing_name': clean_str(getattr(existing_product, 'name', None))
            }

        replacement = Product(
            serial_number=new_serial,
            name=new_name,
            client_id=getattr(product_rec, 'client_id', None),
            start_warranty_date=getattr(product_rec, 'start_warranty_date', None),
            end_warranty_date=getattr(product_rec, 'end_warranty_date', None)
        )
        db.session.add(replacement)
        db.session.flush()

        linked_schedule_count = Shift.query.filter_by(product_id=old_serial).update(
            {'product_id': new_serial},
            synchronize_session=False
        )
        shift.product_id = new_serial
        db.session.delete(product_rec)
    else:
        product_rec.name = new_name
        linked_schedule_count = Shift.query.filter_by(product_id=old_serial).count()

    db.session.add(ActivityLog(
        user=(getattr(current_user, 'username', '') or 'System').capitalize(),
        action=(
            f"Corrected equipment from TSR revision: "
            f"{old_name or 'Unnamed'} ({old_serial}) -> {new_name} ({new_serial}); "
            f"{linked_schedule_count} linked schedule(s) updated"
        )[:255]
    ))

    return {
        'status': 'updated',
        'old_serial': old_serial,
        'new_serial': new_serial,
        'old_name': old_name,
        'new_name': new_name,
        'linked_schedule_count': linked_schedule_count
    }


def ensure_product_from_tsr_payload(shift, payload):
    """Create/link missing schedule equipment from explicit Create TSR fields.

    Warranty values are intentionally not accepted from the TSR payload. A new
    inventory record starts on the server date it is added and has no end date.
    """
    if not shift or not isinstance(payload, dict):
        return {'status': 'blocked', 'reason': 'invalid_context'}

    current_serial = (clean_str(getattr(shift, 'product_id', None)) or '').upper()
    current_product = db.session.get(Product, current_serial) if current_serial else None
    if current_product:
        return {
            'status': 'existing',
            'serial_number': current_product.serial_number,
            'product_name': current_product.name,
            'client_id': current_product.client_id
        }

    client_id = clean_int(getattr(shift, 'client_id', None))
    product_name = (clean_str(payload.get('tsr-equipment-model')) or '')[:100]
    serial_number = (clean_str(payload.get('tsr-serial-no')) or '').upper()[:100]
    if not client_id:
        return {'status': 'blocked', 'reason': 'missing_client'}
    if not product_name or not serial_number:
        return {
            'status': 'blocked',
            'reason': 'missing_equipment_details',
            'missing_fields': [
                label for label, value in (
                    ('Equipment / Model', product_name),
                    ('Serial No.', serial_number)
                ) if not value
            ]
        }

    existing_product = db.session.get(Product, serial_number)
    created = False
    if existing_product:
        existing_client_id = clean_int(getattr(existing_product, 'client_id', None))
        if existing_client_id and existing_client_id != client_id:
            return {
                'status': 'blocked',
                'reason': 'serial_owned_by_other_client',
                'serial_number': serial_number,
                'existing_name': clean_str(getattr(existing_product, 'name', None)),
                'existing_client_id': existing_client_id
            }
        if not existing_client_id:
            existing_product.client_id = client_id
        if not clean_str(getattr(existing_product, 'name', None)):
            existing_product.name = product_name
        product_rec = existing_product
    else:
        product_rec = Product(
            serial_number=serial_number,
            name=product_name,
            client_id=client_id,
            start_warranty_date=get_manila_today(),
            end_warranty_date=None
        )
        db.session.add(product_rec)
        created = True

    linked_shift_ids = []
    for linked_shift in get_tsr_completion_linked_shifts(shift):
        if not linked_shift or clean_int(getattr(linked_shift, 'client_id', None)) != client_id:
            continue
        if not clean_str(getattr(linked_shift, 'product_id', None)):
            linked_shift.product_id = serial_number
            linked_shift_ids.append(linked_shift.id)
    if not clean_str(getattr(shift, 'product_id', None)):
        shift.product_id = serial_number
        linked_shift_ids.append(shift.id)

    selected_schedule = payload.get('selectedSchedule') if isinstance(payload.get('selectedSchedule'), dict) else {}
    selected_schedule['product_id'] = serial_number
    selected_schedule['product_name'] = product_rec.name or product_name
    payload['selectedSchedule'] = selected_schedule
    payload['tsr-equipment-model'] = product_rec.name or product_name
    payload['tsr-serial-no'] = serial_number

    db.session.add(ActivityLog(
        user=(getattr(current_user, 'username', '') or 'System').capitalize(),
        action=(
            f"{'Added' if created else 'Linked'} equipment from Create TSR: "
            f"{product_rec.name or product_name} ({serial_number}) to client #{client_id}; "
            f"schedule(s): {','.join(map(str, sorted(set(linked_shift_ids)))) or shift.id}"
        )[:255]
    ))

    return {
        'status': 'created' if created else 'linked_existing',
        'serial_number': serial_number,
        'product_name': product_rec.name or product_name,
        'client_id': client_id,
        'start_warranty_date': product_rec.start_warranty_date.isoformat() if product_rec.start_warranty_date else '',
        'end_warranty_date': '',
        'linked_shift_ids': sorted(set(linked_shift_ids))
    }


def get_online_tsr_missing_core_details(shift, payload):
    """Return required Create TSR fields missing from the submitted payload."""
    missing = []
    if not clean_str(payload.get('tsr-service-category')):
        missing.append('Service Category')
    if not clean_str(payload.get('tsr-actions-taken')):
        missing.append('Actions Taken')

    current_serial = clean_str(getattr(shift, 'product_id', None)) if shift else None
    current_product = db.session.get(Product, current_serial) if current_serial else None
    if not current_product:
        if not clean_str(payload.get('tsr-equipment-model')):
            missing.append('Equipment / Model')
        if not clean_str(payload.get('tsr-serial-no')):
            missing.append('Serial No.')
    return missing



def parse_online_tsr_time_value(value):
    """Parse TSR actual service time values from the offline TSR form."""
    raw = clean_str(value)
    if not raw:
        return None
    raw = raw.strip()
    for fmt in ('%H:%M', '%I:%M %p', '%I:%M%p'):
        try:
            return datetime.strptime(raw.upper(), fmt).time()
        except Exception:
            continue
    return None


def update_shift_time_from_online_tsr_payload(shift, payload):
    """Update selected schedule start/end time from editable TSR time fields only.

    Client/equipment schedule fields remain locked in the TSR UI. Engineers may
    correct the actual start/end time before saving the TSR, and the timeline
    should reflect that correction after the TSR save completes.

    IMPORTANT: Shift.start_time and Shift.end_time are DateTime columns. The
    Offline TSR form sends time-only values, so combine the submitted time with
    the existing schedule date before assigning. Assigning datetime.time directly
    causes SQLite to fail during autoflush/commit.
    """
    if not shift or not isinstance(payload, dict):
        return []

    changes = []
    next_start_time = parse_online_tsr_time_value(payload.get('tsr-time-started'))
    next_end_time = parse_online_tsr_time_value(payload.get('tsr-time-finished'))

    existing_start = getattr(shift, 'start_time', None)
    existing_end = getattr(shift, 'end_time', None)

    base_start_date = existing_start.date() if isinstance(existing_start, datetime) else get_manila_today()
    base_end_date = existing_end.date() if isinstance(existing_end, datetime) else base_start_date

    if next_start_time:
        next_start = datetime.combine(base_start_date, next_start_time)
        existing_start_time = existing_start.time() if isinstance(existing_start, datetime) else None
        if existing_start_time != next_start_time:
            old_start = existing_start.strftime('%H:%M') if existing_start else ''
            shift.start_time = next_start
            changes.append(('start_time', old_start, next_start_time.strftime('%H:%M')))

    if next_end_time:
        next_end = datetime.combine(base_end_date, next_end_time)
        existing_end_time = existing_end.time() if isinstance(existing_end, datetime) else None
        if existing_end_time != next_end_time:
            old_end = existing_end.strftime('%H:%M') if existing_end else ''
            shift.end_time = next_end
            changes.append(('end_time', old_end, next_end_time.strftime('%H:%M')))

    if changes:
        db.session.add(shift)
        try:
            details = ', '.join([f"{field}: {old or 'blank'} → {new}" for field, old, new in changes])
            db.session.add(ActivityLog(
                user=(getattr(current_user, 'username', '') or 'System').capitalize(),
                action=f"Updated schedule time from TSR save for schedule #{shift.id}: {details}"
            ))
        except Exception:
            pass

    return changes


def parse_online_tsr_payload_json(submission):
    """Return a safe dict from a saved OnlineTsrSubmission payload_json."""
    if not submission:
        return {}
    try:
        payload = json.loads(submission.payload_json or '{}')
        return payload if isinstance(payload, dict) else {}
    except Exception:
        return {}


def online_tsr_submission_to_dict(submission, include_payload=True):
    """Serialize an online TSR submission for revision/edit flows."""
    if not submission:
        return {}

    payload = parse_online_tsr_payload_json(submission) if include_payload else {}
    return {
        'id': submission.id,
        'submission_id': submission.id,
        'shift_id': submission.shift_id,
        'tsr_number': submission.tsr_number or '',
        'client_name': submission.client_name or '',
        'product_name': submission.product_name or '',
        'serial_number': submission.serial_number or '',
        'submitted_by_user_id': submission.submitted_by_user_id,
        'submitted_by_name': submission.submitted_by_name or '',
        'status': submission.status or '',
        'revision_no': clean_int(getattr(submission, 'revision_no', None)) or 1,
        'parent_submission_id': clean_int(getattr(submission, 'parent_submission_id', None)),
        'revision_reason': clean_str(getattr(submission, 'revision_reason', None)),
        'is_latest': bool(getattr(submission, 'is_latest', True)),
        'created_at': submission.created_at.isoformat() if getattr(submission, 'created_at', None) else '',
        'revised_at': submission.revised_at.isoformat() if getattr(submission, 'revised_at', None) else '',
        'revised_by_user_id': clean_int(getattr(submission, 'revised_by_user_id', None)),
        'attached_file_id': clean_int(payload.get('_attached_file_id')),
        'attached_filename': clean_str(payload.get('_attached_display_filename')) or clean_str(payload.get('_generated_pdf_filename')),
        'was_emailed': bool(payload.get('_last_emailed_at') or payload.get('_sent_recipient_emails')),
        'last_emailed_at': clean_str(payload.get('_last_emailed_at')),
        'recipients': parse_manual_recipient_emails(payload.get('_sent_recipient_emails') or []),
        'payload': payload if include_payload else None
    }


def get_latest_online_tsr_submission_for_shift(shift_id):
    """Return the latest active online TSR submission for one schedule."""
    ensure_online_tsr_submission_table()
    shift_id = clean_int(shift_id)
    if not shift_id:
        return None

    latest = OnlineTsrSubmission.query.filter_by(
        shift_id=shift_id,
        is_latest=True
    ).order_by(
        OnlineTsrSubmission.revision_no.desc(),
        OnlineTsrSubmission.created_at.desc(),
        OnlineTsrSubmission.id.desc()
    ).first()
    if latest:
        return latest

    return OnlineTsrSubmission.query.filter_by(shift_id=shift_id).order_by(
        OnlineTsrSubmission.created_at.desc(),
        OnlineTsrSubmission.id.desc()
    ).first()


def mark_existing_online_tsr_submissions_superseded(shift_id, exclude_submission_id=None):
    """Mark earlier online TSR submissions for a schedule as not latest."""
    ensure_online_tsr_submission_table()
    shift_id = clean_int(shift_id)
    if not shift_id:
        return 0

    query = OnlineTsrSubmission.query.filter_by(shift_id=shift_id)
    exclude_submission_id = clean_int(exclude_submission_id)
    if exclude_submission_id:
        query = query.filter(OnlineTsrSubmission.id != exclude_submission_id)

    count = 0
    for submission in query.all():
        if getattr(submission, 'is_latest', True):
            submission.is_latest = False
            count += 1
    return count


def online_tsr_has_serviced_signature(payload):
    """Return True when a Create TSR payload includes the engineer signature."""
    if not isinstance(payload, dict):
        return False
    signatures = payload.get('signatures')
    if not isinstance(signatures, dict):
        return False
    signature_value = clean_str(signatures.get('serviced')) or ''
    return signature_value.startswith('data:image/') and ',' in signature_value


@app.route('/save_offline_tsr_online', methods=['POST'])
@csrf.exempt
@login_required
def save_offline_tsr_online():
    """Phase 3 Step 3: receive online Offline TSR payload, generate PDF, and attach it to the selected schedule.

    This validates the selected schedule, stores the TSR payload, creates the
    server-side PDF, and saves it through the same ShiftFile attachment system
    used by manually uploaded TSR files.
    """
    if not (is_admin_authorized() or getattr(current_user, 'role', None) == 'engineer'):
        return denied()

    ensure_online_tsr_submission_table()

    if request.is_json:
        payload = request.get_json(silent=True) or {}
    else:
        raw_payload = (
            request.form.get('payload_json') or
            request.form.get('payload') or
            request.form.get('tsr_payload') or
            request.form.get('data') or
            request.form.get('json') or
            ''
        )
        if raw_payload:
            try:
                payload = json.loads(raw_payload)
            except Exception:
                payload = {}
        else:
            payload = dict(request.form.items())

    payload_fields = payload.get('fields')
    if isinstance(payload_fields, dict):
        flattened_payload = dict(payload_fields)
        for key, value in payload.items():
            if key != 'fields':
                flattened_payload[key] = value
        payload = flattened_payload

    for filename_key in ('pdf_filename', 'download_filename', 'tsr_pdf_filename'):
        if request.form.get(filename_key) and not payload.get(filename_key):
            payload[filename_key] = request.form.get(filename_key)

    selected_schedule = payload.get('selectedSchedule') if isinstance(payload.get('selectedSchedule'), dict) else {}
    schedule_id = (
        clean_int(payload.get('schedule_id')) or
        clean_int(payload.get('selectedScheduleId')) or
        clean_int(selected_schedule.get('id'))
    )

    if not schedule_id:
        return jsonify({'status': 'error', 'message': 'Please select a schedule before saving online.'}), 400

    shift = db.session.get(Shift, schedule_id)
    if not shift:
        return jsonify({'status': 'error', 'message': 'Selected schedule was not found.'}), 404

    if not can_work_on_existing_schedule_shift(shift):
        return denied('You are not allowed to save a TSR for this schedule.')

    if not online_tsr_has_serviced_signature(payload):
        return jsonify({
            'status': 'error',
            'message': 'Serviced By signature is required before saving the TSR.'
        }), 400

    preserve_uploaded_pdf = str(payload.get('_offline_queue_preserve_pdf') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
    is_legacy_offline_queue = preserve_uploaded_pdf and not clean_str(payload.get('_tsr_form_version'))
    missing_core_details = get_online_tsr_missing_core_details(shift, payload)
    if missing_core_details and not is_legacy_offline_queue:
        return jsonify({
            'status': 'error',
            'message': f"Complete these required TSR details before saving: {', '.join(missing_core_details)}.",
            'missing_core_details': missing_core_details
        }), 400
    if missing_core_details and is_legacy_offline_queue:
        payload['_legacy_core_validation_bypassed'] = missing_core_details

    equipment_inventory_result = None
    has_equipment_details = bool(
        clean_str(payload.get('tsr-equipment-model')) and
        clean_str(payload.get('tsr-serial-no'))
    )
    if has_equipment_details or not is_legacy_offline_queue:
        equipment_inventory_result = ensure_product_from_tsr_payload(shift, payload)
        if equipment_inventory_result.get('status') == 'blocked':
            reason = equipment_inventory_result.get('reason')
            if reason == 'serial_owned_by_other_client':
                message = f"Serial number {equipment_inventory_result.get('serial_number')} already belongs to another Medical Center."
                status_code = 409
            else:
                message = 'Equipment / Model and Serial No. are required because this schedule has no linked inventory equipment.'
                status_code = 400
            return jsonify({
                'status': 'error',
                'message': message,
                'equipment_inventory': equipment_inventory_result
            }), status_code
        payload['_equipment_inventory_result'] = equipment_inventory_result

    submitted_tsr_number = (clean_str(payload.get('tsr-number')) or clean_str(payload.get('tsr_number')) or '')[:120]
    sequence_date = (
        parse_online_tsr_sequence_date(payload.get('tsr-service-date')) or
        parse_online_tsr_sequence_date(payload.get('service_date')) or
        parse_online_tsr_sequence_date(selected_schedule.get('date_iso')) or
        parse_online_tsr_sequence_date(selected_schedule.get('date_label')) or
        online_tsr_daily_sequence_date()
    )
    is_vector_pdf_submission = clean_str(payload.get('_tsr_form_version')).lower() == 'vector-pdf-v2'
    if submitted_tsr_number and online_tsr_submitted_number_is_available(submitted_tsr_number, sequence_date):
        tsr_number = submitted_tsr_number.upper()
    elif submitted_tsr_number and (not preserve_uploaded_pdf or is_vector_pdf_submission):
        return jsonify({
            'status': 'error',
            'message': 'The previewed TSR number is no longer available. Please preview the TSR again before saving.'
        }), 409
    else:
        tsr_number = online_tsr_next_number_for_date(sequence_date)
    payload['tsr-number'] = tsr_number
    payload['tsr_number'] = tsr_number
    completion_scope = normalize_online_tsr_completion_scope(payload.get('completion_scope') or payload.get('_completion_scope') or 'linked_all')
    payload['completion_scope'] = completion_scope
    client_name = (clean_str(payload.get('tsr-customer-name')) or clean_str(selected_schedule.get('client_name')) or '')[:200]
    product_name = (clean_str(payload.get('tsr-equipment-model')) or clean_str(selected_schedule.get('product_name')) or '')[:200]
    serial_number = (clean_str(payload.get('tsr-serial-no')) or clean_str(selected_schedule.get('product_id')) or '')[:120]
    submitted_by = tsr_knowledge_current_engineer_name()[:120]
    previous_latest = get_latest_online_tsr_submission_for_shift(shift.id)
    next_revision_no = (clean_int(getattr(previous_latest, 'revision_no', None)) or 0) + 1 if previous_latest else 1
    mark_existing_online_tsr_submissions_superseded(shift.id)

    submission = OnlineTsrSubmission(
        shift_id=shift.id,
        tsr_number=tsr_number,
        client_name=client_name,
        product_name=product_name,
        serial_number=serial_number,
        submitted_by_user_id=getattr(current_user, 'id', None),
        submitted_by_name=submitted_by,
        status='received',
        payload_json=json.dumps(payload, ensure_ascii=False),
        revision_no=next_revision_no,
        parent_submission_id=getattr(previous_latest, 'id', None) if previous_latest else None,
        revision_reason=clean_str(payload.get('revision_reason')) or None,
        is_latest=True,
        revised_at=get_manila_time() if previous_latest else None,
        revised_by_user_id=getattr(current_user, 'id', None) if previous_latest else None
    )
    db.session.add(submission)
    db.session.flush()

    try:
        uploaded_pdf = None
        if request.files:
            uploaded_pdf = (
                request.files.get('tsr_pdf') or
                request.files.get('pdf') or
                request.files.get('file') or
                request.files.get('report_file')
            )

        if uploaded_pdf and getattr(uploaded_pdf, 'filename', '') and (preserve_uploaded_pdf or not submitted_tsr_number or submitted_tsr_number == tsr_number):
            pdf_filename = build_online_tsr_pdf_filename(submission, shift, tsr_number, payload=payload)
            attached_file = attach_uploaded_online_tsr_pdf_to_shift(shift, uploaded_pdf, display_filename=pdf_filename)
            pdf_source = 'frontend_blob'
        else:
            pdf_filename = generate_online_tsr_submission_pdf(submission, shift, payload)
            attached_file = attach_online_tsr_pdf_to_shift(shift, pdf_filename)
            pdf_source = 'backend_reportlab_fallback' if not submitted_tsr_number or submitted_tsr_number == tsr_number else 'backend_reportlab_number_refresh'

        extra_attached_files = attach_uploaded_online_tsr_extra_files_to_shift(
            shift,
            excluded_file_ids=[uploaded_pdf, attached_file]
        )
        schedule_time_updates = update_shift_time_from_online_tsr_payload(shift, payload)
        completed_shift_ids = complete_schedules_for_online_tsr(shift, completion_scope=completion_scope)
        try:
            direct_contact_emails = save_tsr_payload_contact_to_medical_center(
                shift,
                payload,
                source_label=f'online_tsr_save_{submission.id}'
            )
            legacy_contact_emails = auto_capture_tsr_client_contact_from_payload(shift, payload)
            auto_captured_contact_emails = list(dict.fromkeys(direct_contact_emails + legacy_contact_emails))
        except Exception as contact_capture_error:
            auto_captured_contact_emails = []
            print(
                f"[ONLINE-TSR] Contact capture did not block TSR save for submission #{submission.id}: {contact_capture_error}",
                flush=True
            )
        payload['_auto_captured_contact_emails'] = auto_captured_contact_emails
        payload['_schedule_time_updates'] = schedule_time_updates
        payload['_generated_pdf_filename'] = pdf_filename
        payload['_attached_file_id'] = attached_file.id
        payload['_attached_disk_filename'] = attached_file.filename
        payload['_attached_display_filename'] = get_shift_file_display_name(attached_file)
        payload['_extra_attachment_file_ids'] = [file_rec.id for file_rec in extra_attached_files]
        payload['_extra_attachment_filenames'] = [get_shift_file_display_name(file_rec) for file_rec in extra_attached_files]
        payload['_pdf_source'] = pdf_source
        payload['_completed_shift_ids'] = completed_shift_ids
        payload['_completion_scope'] = completion_scope
        payload['_generated_pdf_at'] = get_manila_time().isoformat()
        submission.payload_json = json.dumps(payload, ensure_ascii=False)
        submission.status = 'completed'
        db.session.add(ActivityLog(
            user=(getattr(current_user, 'username', '') or submitted_by or 'System').capitalize(),
            action=f"Generated online TSR PDF and completed schedule scope '{completion_scope}': {pdf_filename} for schedule #{shift.id} (+{len(extra_attached_files)} extra attachment(s))"
        ))
        db.session.commit()

        # Keep a second lightweight pass for old browsers/forms that may submit
        # contact data after the first payload normalization path.
        try:
            direct_contact_emails = save_tsr_payload_contact_to_medical_center(
                shift,
                payload,
                source_label=f'online_tsr_save_after_commit_{submission.id}'
            )
            legacy_contact_emails = auto_capture_tsr_client_contact_from_payload(shift, payload)
            auto_captured_contact_emails = list(dict.fromkeys(direct_contact_emails + legacy_contact_emails))
            if auto_captured_contact_emails:
                payload['_auto_captured_contact_emails'] = auto_captured_contact_emails
                submission.payload_json = json.dumps(payload, ensure_ascii=False)
                db.session.commit()
        except Exception as contact_capture_error:
            db.session.rollback()
            print(
                f"[ONLINE-TSR] Contact auto-capture skipped for submission #{submission.id}: {contact_capture_error}",
                flush=True
            )
    except Exception as pdf_error:
        submission.status = 'pdf_error'
        db.session.commit()
        print(f"[ONLINE-TSR] PDF generation/attachment failed for submission #{submission.id}: {pdf_error}", flush=True)
        return jsonify({
            'status': 'error',
            'message': 'TSR was received but PDF generation or attachment failed. Please try again.',
            'submission_id': submission.id,
            'phase': '3-step-3'
        }), 500

    return jsonify({
        'status': 'success',
        'success': True,
        'message': 'TSR saved online, PDF generated, attached to schedule, and linked schedule status completed.',
        'submission_id': submission.id,
        'schedule_id': shift.id,
        'completed_shift_ids': completed_shift_ids,
        'completion_scope': completion_scope,
        'schedule_time_updates': schedule_time_updates,
        'tsr_number': tsr_number,
        'pdf_filename': pdf_filename,
        'attached_file_id': attached_file.id,
        'attached_filename': get_shift_file_display_name(attached_file),
        'attached_disk_filename': attached_file.filename,
        'extra_attachment_count': len(extra_attached_files),
        'extra_attachment_file_ids': [file_rec.id for file_rec in extra_attached_files],
        'extra_attachment_filenames': [get_shift_file_display_name(file_rec) for file_rec in extra_attached_files],
        'auto_captured_contact_emails': payload.get('_auto_captured_contact_emails') or [],
        'equipment_inventory': payload.get('_equipment_inventory_result'),
        'pdf_source': pdf_source,
        'revision_no': clean_int(getattr(submission, 'revision_no', None)) or 1,
        'parent_submission_id': clean_int(getattr(submission, 'parent_submission_id', None)),
        'phase': '3-step-5-same-pdf'
    })


@app.route('/get_online_tsr_submission/<int:submission_id>', methods=['GET'])
@login_required
def get_online_tsr_submission(submission_id):
    """Return one saved online TSR payload for controlled edit/revision."""
    ensure_online_tsr_submission_table()
    submission = db.session.get(OnlineTsrSubmission, submission_id)
    if not submission:
        return jsonify({'status': 'error', 'message': 'TSR submission not found.'}), 404

    shift = db.session.get(Shift, submission.shift_id)
    if not shift:
        return jsonify({'status': 'error', 'message': 'Linked schedule not found.'}), 404

    if not can_work_on_existing_schedule_shift(shift):
        return denied('You are not allowed to view this TSR submission.')

    return jsonify({
        'status': 'success',
        'submission': online_tsr_submission_to_dict(submission, include_payload=True)
    })


@app.route('/get_latest_online_tsr_for_shift/<int:shift_id>', methods=['GET'])
@login_required
def get_latest_online_tsr_for_shift(shift_id):
    """Return the latest saved online TSR payload for a schedule."""
    shift = db.session.get(Shift, shift_id)
    if not shift:
        return jsonify({'status': 'error', 'message': 'Schedule not found.'}), 404

    if not can_work_on_existing_schedule_shift(shift):
        return denied('You are not allowed to view TSR for this schedule.')

    submission = get_latest_online_tsr_submission_for_shift(shift.id)
    if not submission:
        return jsonify({'status': 'error', 'message': 'No saved online TSR found for this schedule.'}), 404

    return jsonify({
        'status': 'success',
        'submission': online_tsr_submission_to_dict(submission, include_payload=True)
    })


@app.route('/revise_online_tsr_submission/<int:submission_id>', methods=['POST'])
@csrf.exempt
@login_required
def revise_online_tsr_submission(submission_id):
    """Create a corrected online TSR revision without overwriting the original."""
    if not (is_admin_authorized() or getattr(current_user, 'role', None) == 'engineer'):
        return denied()

    ensure_online_tsr_submission_table()

    original = db.session.get(OnlineTsrSubmission, submission_id)
    if not original:
        return jsonify({'status': 'error', 'message': 'Original TSR submission not found.'}), 404

    shift = db.session.get(Shift, original.shift_id)
    if not shift:
        return jsonify({'status': 'error', 'message': 'Linked schedule not found.'}), 404

    if not can_work_on_existing_schedule_shift(shift):
        return denied('You are not allowed to revise this TSR.')

    if request.is_json:
        payload = request.get_json(silent=True) or {}
    else:
        raw_payload = (
            request.form.get('payload_json') or
            request.form.get('payload') or
            request.form.get('tsr_payload') or
            request.form.get('data') or
            request.form.get('json') or
            ''
        )
        if raw_payload:
            try:
                payload = json.loads(raw_payload)
            except Exception:
                payload = {}
        else:
            payload = dict(request.form.items())

    if not isinstance(payload, dict):
        payload = {}

    for filename_key in ('pdf_filename', 'download_filename', 'tsr_pdf_filename'):
        if request.form.get(filename_key) and not payload.get(filename_key):
            payload[filename_key] = request.form.get(filename_key)

    if not online_tsr_has_serviced_signature(payload):
        return jsonify({
            'status': 'error',
            'message': 'Serviced By signature is required before saving the corrected TSR.'
        }), 400

    missing_core_details = get_online_tsr_missing_core_details(shift, payload)
    if missing_core_details:
        return jsonify({
            'status': 'error',
            'message': f"Complete these required TSR details before saving: {', '.join(missing_core_details)}.",
            'missing_core_details': missing_core_details
        }), 400

    equipment_inventory_result = ensure_product_from_tsr_payload(shift, payload)
    if equipment_inventory_result.get('status') == 'blocked':
        reason = equipment_inventory_result.get('reason')
        message = (
            f"Serial number {equipment_inventory_result.get('serial_number')} already belongs to another Medical Center."
            if reason == 'serial_owned_by_other_client'
            else 'Equipment / Model and Serial No. are required because this schedule has no linked inventory equipment.'
        )
        return jsonify({
            'status': 'error',
            'message': message,
            'equipment_inventory': equipment_inventory_result
        }), 409 if reason == 'serial_owned_by_other_client' else 400
    payload['_equipment_inventory_result'] = equipment_inventory_result

    revision_reason = (
        clean_str(payload.get('revision_reason')) or
        clean_str(request.form.get('revision_reason')) or
        'Corrected TSR'
    )[:500]
    payload['schedule_id'] = shift.id
    payload['selectedScheduleId'] = shift.id
    payload['revision_reason'] = revision_reason
    payload['_revision_of_submission_id'] = original.id

    selected_schedule = payload.get('selectedSchedule') if isinstance(payload.get('selectedSchedule'), dict) else {}
    tsr_number = (clean_str(payload.get('tsr-number')) or clean_str(payload.get('tsr_number')) or clean_str(original.tsr_number) or '')[:120]
    client_name = (clean_str(payload.get('tsr-customer-name')) or clean_str(selected_schedule.get('client_name')) or clean_str(original.client_name) or '')[:200]
    product_name = (clean_str(payload.get('tsr-equipment-model')) or clean_str(selected_schedule.get('product_name')) or clean_str(original.product_name) or '')[:200]
    serial_number = (clean_str(payload.get('tsr-serial-no')) or clean_str(selected_schedule.get('product_id')) or '')[:120]
    submitted_by = tsr_knowledge_current_engineer_name()[:120]
    latest_before_revision = get_latest_online_tsr_submission_for_shift(shift.id) or original
    next_revision_no = (clean_int(getattr(latest_before_revision, 'revision_no', None)) or 1) + 1

    equipment_correction = correct_product_from_tsr_revision(shift, payload)
    if equipment_correction and equipment_correction.get('status') == 'blocked':
        return jsonify({
            'status': 'error',
            'message': f"Serial number {equipment_correction.get('new_serial')} already exists in inventory.",
            'equipment_correction': equipment_correction
        }), 409

    if equipment_correction and equipment_correction.get('status') == 'updated':
        selected_schedule['product_id'] = equipment_correction.get('new_serial') or selected_schedule.get('product_id')
        selected_schedule['product_name'] = equipment_correction.get('new_name') or selected_schedule.get('product_name')
        payload['selectedSchedule'] = selected_schedule
        serial_number = (equipment_correction.get('new_serial') or serial_number or '')[:120]
        product_name = (equipment_correction.get('new_name') or product_name or '')[:200]

    mark_existing_online_tsr_submissions_superseded(shift.id)

    revision = OnlineTsrSubmission(
        shift_id=shift.id,
        tsr_number=tsr_number,
        client_name=client_name,
        product_name=product_name,
        serial_number=serial_number,
        submitted_by_user_id=getattr(current_user, 'id', None),
        submitted_by_name=submitted_by,
        status='received',
        payload_json=json.dumps(payload, ensure_ascii=False),
        revision_no=next_revision_no,
        parent_submission_id=original.id,
        revision_reason=revision_reason,
        is_latest=True,
        revised_at=get_manila_time(),
        revised_by_user_id=getattr(current_user, 'id', None)
    )
    db.session.add(revision)
    db.session.flush()

    try:
        uploaded_pdf = None
        if request.files:
            uploaded_pdf = (
                request.files.get('tsr_pdf') or
                request.files.get('pdf') or
                request.files.get('file') or
                request.files.get('report_file')
            )

        if uploaded_pdf and getattr(uploaded_pdf, 'filename', ''):
            pdf_filename = build_online_tsr_pdf_filename(revision, shift, tsr_number, payload=payload)
            base_name, ext = os.path.splitext(pdf_filename)
            pdf_filename = f"{base_name}_REV{next_revision_no}_CORRECTED{ext or '.pdf'}"
            attached_file = attach_uploaded_online_tsr_pdf_to_shift(shift, uploaded_pdf, display_filename=pdf_filename)
            pdf_source = 'frontend_blob_revision'
        else:
            pdf_filename = generate_online_tsr_submission_pdf(revision, shift, payload)
            base_name, ext = os.path.splitext(pdf_filename)
            revised_pdf_filename = f"{base_name}_REV{next_revision_no}_CORRECTED{ext or '.pdf'}"
            source_path = os.path.join(app.config['UPLOAD_FOLDER'], pdf_filename)
            revised_path = os.path.join(app.config['UPLOAD_FOLDER'], revised_pdf_filename)
            if os.path.exists(source_path):
                os.replace(source_path, revised_path)
                pdf_filename = revised_pdf_filename
            attached_file = attach_online_tsr_pdf_to_shift(shift, pdf_filename)
            pdf_source = 'backend_reportlab_revision'

        extra_attached_files = attach_uploaded_online_tsr_extra_files_to_shift(
            shift,
            excluded_file_ids=[uploaded_pdf, attached_file]
        )
        schedule_time_updates = update_shift_time_from_online_tsr_payload(shift, payload)
        completed_shift_ids = complete_linked_schedules_for_online_tsr(shift)
        try:
            direct_contact_emails = save_tsr_payload_contact_to_medical_center(
                shift,
                payload,
                source_label=f'online_tsr_revision_{revision.id}'
            )
            legacy_contact_emails = auto_capture_tsr_client_contact_from_payload(shift, payload)
            auto_captured_contact_emails = list(dict.fromkeys(direct_contact_emails + legacy_contact_emails))
        except Exception as contact_capture_error:
            auto_captured_contact_emails = []
            print(
                f"[ONLINE-TSR] Revision contact capture did not block TSR save for submission #{revision.id}: {contact_capture_error}",
                flush=True
            )
        payload['_auto_captured_contact_emails'] = auto_captured_contact_emails
        payload['_equipment_correction'] = equipment_correction
        payload['_schedule_time_updates'] = schedule_time_updates
        payload['_generated_pdf_filename'] = pdf_filename
        payload['_attached_file_id'] = attached_file.id
        payload['_attached_disk_filename'] = attached_file.filename
        payload['_attached_display_filename'] = get_shift_file_display_name(attached_file)
        payload['_extra_attachment_file_ids'] = [file_rec.id for file_rec in extra_attached_files]
        payload['_extra_attachment_filenames'] = [get_shift_file_display_name(file_rec) for file_rec in extra_attached_files]
        payload['_pdf_source'] = pdf_source
        payload['_completed_shift_ids'] = completed_shift_ids
        payload['_generated_pdf_at'] = get_manila_time().isoformat()
        revision.payload_json = json.dumps(payload, ensure_ascii=False)
        revision.status = 'completed'
        db.session.add(ActivityLog(
            user=(getattr(current_user, 'username', '') or submitted_by or 'System').capitalize(),
            action=f"Revised online TSR submission #{original.id} as REV{next_revision_no}: {revision_reason}"
        ))
        db.session.commit()

        try:
            direct_contact_emails = save_tsr_payload_contact_to_medical_center(
                shift,
                payload,
                source_label=f'online_tsr_revision_after_commit_{revision.id}'
            )
            legacy_contact_emails = auto_capture_tsr_client_contact_from_payload(shift, payload)
            auto_captured_contact_emails = list(dict.fromkeys(direct_contact_emails + legacy_contact_emails))
            if auto_captured_contact_emails:
                payload['_auto_captured_contact_emails'] = auto_captured_contact_emails
                revision.payload_json = json.dumps(payload, ensure_ascii=False)
                db.session.commit()
        except Exception as contact_capture_error:
            db.session.rollback()
            print(
                f"[ONLINE-TSR] Revision contact auto-capture skipped for submission #{revision.id}: {contact_capture_error}",
                flush=True
            )
    except Exception as pdf_error:
        revision.status = 'pdf_error'
        db.session.commit()
        print(f"[ONLINE-TSR] TSR revision failed for submission #{revision.id}: {pdf_error}", flush=True)
        return jsonify({
            'status': 'error',
            'message': 'Corrected TSR was received but PDF generation or attachment failed. Please try again.',
            'submission_id': revision.id
        }), 500

    return jsonify({
        'status': 'success',
        'success': True,
        'message': f'Corrected TSR saved as REV{next_revision_no}.',
        'submission_id': revision.id,
        'parent_submission_id': original.id,
        'schedule_id': shift.id,
        'revision_no': next_revision_no,
        'revision_reason': revision_reason,
        'pdf_filename': pdf_filename,
        'attached_file_id': attached_file.id,
        'attached_filename': get_shift_file_display_name(attached_file),
        'attached_disk_filename': attached_file.filename,
        'extra_attachment_count': len(extra_attached_files),
        'auto_captured_contact_emails': payload.get('_auto_captured_contact_emails') or [],
        'equipment_correction': equipment_correction,
        'equipment_inventory': payload.get('_equipment_inventory_result'),
        'completed_shift_ids': completed_shift_ids,
        'schedule_time_updates': schedule_time_updates,
        'pdf_source': pdf_source
    })


@app.route('/save_tsr_knowledge_entry', methods=['POST'])
@csrf.exempt
@login_required
def save_tsr_knowledge_entry():
    """Save current complaint/actions as reusable TSR knowledge."""
    if not (is_admin_authorized() or getattr(current_user, 'role', None) == 'engineer'):
        return denied()

    ensure_tsr_knowledge_entry_table()

    payload = request.get_json(silent=True) or {}
    complaint = clean_str(payload.get('complaint')) or ''
    actions_taken = clean_str(payload.get('actions_taken')) or ''

    if len(complaint) < 3 and len(actions_taken) < 3:
        return jsonify({'status': 'error', 'message': 'Please enter a complaint or action before saving.'}), 400

    client_name = (clean_str(payload.get('client_name')) or '')[:200]
    product_name = (clean_str(payload.get('product_name')) or '')[:200]
    serial_number = (clean_str(payload.get('serial_number')) or '')[:120]
    task = (clean_str(payload.get('task')) or '')[:200]
    service_category = (clean_str(payload.get('service_category')) or '')[:100]
    source_shift_id = clean_int(payload.get('schedule_id'))

    duplicate_query = TsrKnowledgeEntry.query.filter(
        func.lower(func.trim(TsrKnowledgeEntry.complaint)) == complaint.strip().lower(),
        func.lower(func.trim(TsrKnowledgeEntry.actions_taken)) == actions_taken.strip().lower()
    )

    if serial_number:
        duplicate_query = duplicate_query.filter(func.lower(func.trim(TsrKnowledgeEntry.serial_number)) == serial_number.strip().lower())
    elif product_name:
        duplicate_query = duplicate_query.filter(func.lower(func.trim(TsrKnowledgeEntry.product_name)) == product_name.strip().lower())

    existing_entry = duplicate_query.order_by(TsrKnowledgeEntry.created_at.desc()).first()
    if existing_entry:
        return jsonify({
            'status': 'success',
            'duplicate': True,
            'message': 'Knowledge base already has this complaint/actions pattern.',
            'entry': tsr_knowledge_entry_to_dict(existing_entry)
        })

    entry = TsrKnowledgeEntry(
        complaint=complaint[:5000],
        actions_taken=actions_taken[:7000],
        client_name=client_name,
        product_name=product_name,
        serial_number=serial_number,
        task=task,
        service_category=service_category,
        engineer_name=tsr_knowledge_current_engineer_name()[:120],
        source_shift_id=source_shift_id,
        created_by_user_id=getattr(current_user, 'id', None)
    )
    db.session.add(entry)
    db.session.commit()

    return jsonify({
        'status': 'success',
        'duplicate': False,
        'message': 'Complaint/actions saved to the TSR knowledge base.',
        'entry': tsr_knowledge_entry_to_dict(entry)
    })

@app.route('/service-worker.js')
def pwa_service_worker():
    """Service worker for PWA install shell, critical page caching, and offline fallback."""
    sw = r"""const CACHE_VERSION = 'medical-service-pwa-offline-navigation-v9-vector-tsr';
const APP_SHELL_CACHE = `${CACHE_VERSION}-shell`;
const RUNTIME_CACHE = `${CACHE_VERSION}-runtime`;

const APP_SHELL = [
  '/timeline',
  '/offline-tsr',
  '/offline',
  '/manifest.json',
  '/pwa-icon.svg',
  '/static/vendor/jspdf/jspdf.umd.min.js',
  '/static/fonts/liberation-sans/LiberationSans-Regular.ttf',
  '/static/fonts/liberation-sans/LiberationSans-Bold.ttf',
  'https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css',
  'https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js',
  'https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css'
];

const FIELD_SAFE_ROUTES = [
  '/timeline',
  '/offline-tsr',
  '/offline'
];

self.addEventListener('install', event => {
  self.skipWaiting();

  event.waitUntil(
    caches.open(APP_SHELL_CACHE).then(cache => {
      return Promise.allSettled(APP_SHELL.map(url => cache.add(url)));
    })
  );
});

self.addEventListener('activate', event => {
  event.waitUntil(
    caches.keys().then(keys => Promise.all(
      keys
        .filter(key => ![APP_SHELL_CACHE, RUNTIME_CACHE].includes(key))
        .map(key => caches.delete(key))
    )).then(() => self.clients.claim())
  );
});

function isLoginLikeResponse(request, response) {
  try {
    const requestUrl = new URL(request.url);
    const responseUrl = response && response.url ? new URL(response.url) : null;

    // Never cache a redirected login page under /timeline, /, or any protected route.
    if (response && response.redirected) return true;
    if (responseUrl && responseUrl.pathname === '/login') return true;
    if (requestUrl.pathname === '/login') return true;

    return false;
  } catch (err) {
    return false;
  }
}

async function networkFirst(request) {
  try {
    const response = await fetch(request);

    if (response && response.ok && !isLoginLikeResponse(request, response)) {
      const cache = await caches.open(RUNTIME_CACHE);
      cache.put(request, response.clone());
    }

    return response;
  } catch (err) {
    const runtimeCache = await caches.open(RUNTIME_CACHE);
    const runtimeCached = await runtimeCache.match(request);
    if (runtimeCached) return runtimeCached;

    const shellCache = await caches.open(APP_SHELL_CACHE);
    const shellCached = await shellCache.match(request);
    if (shellCached) return shellCached;

    const cached = await caches.match(request);
    if (cached) return cached;

    return caches.match('/offline');
  }
}

async function fieldNavigationFirst(request) {
  const requestUrl = new URL(request.url);

  // Login must remain network-only. Never show or cache a stale login page.
  if (requestUrl.pathname === '/login') {
    try {
      return await fetch(request, { cache: 'no-store', credentials: 'same-origin' });
    } catch (err) {
      return caches.match('/offline');
    }
  }

  try {
    const response = await fetch(request, { credentials: 'same-origin' });

    if (response && response.ok && !isLoginLikeResponse(request, response)) {
      const runtimeCache = await caches.open(RUNTIME_CACHE);
      await runtimeCache.put(request, response.clone());

      // Also store clean route keys so /timeline?source=pwa can fall back to /timeline.
      if (FIELD_SAFE_ROUTES.includes(requestUrl.pathname)) {
        await runtimeCache.put(requestUrl.pathname, response.clone());
      }
    }

    return response;
  } catch (err) {
    const runtimeCache = await caches.open(RUNTIME_CACHE);

    const exactCached = await runtimeCache.match(request);
    if (exactCached) return exactCached;

    if (FIELD_SAFE_ROUTES.includes(requestUrl.pathname)) {
      const routeCached = await runtimeCache.match(requestUrl.pathname);
      if (routeCached) return routeCached;
    }

    const shellCache = await caches.open(APP_SHELL_CACHE);
    const shellExact = await shellCache.match(request);
    if (shellExact) return shellExact;

    if (FIELD_SAFE_ROUTES.includes(requestUrl.pathname)) {
      const shellRoute = await shellCache.match(requestUrl.pathname);
      if (shellRoute) return shellRoute;
    }

    const cached = await caches.match(request);
    if (cached) return cached;

    return caches.match('/offline');
  }
}

async function cacheFirst(request) {
  const cached = await caches.match(request);
  if (cached) return cached;

  const response = await fetch(request);
  if (response && response.ok) {
    const cache = await caches.open(APP_SHELL_CACHE);
    cache.put(request, response.clone());
  }

  return response;
}

async function staleWhileRevalidate(request) {
  const cache = await caches.open(RUNTIME_CACHE);
  const cached = await cache.match(request);

  const networkPromise = fetch(request)
    .then(response => {
      if (response && response.ok) {
        cache.put(request, response.clone());
      }
      return response;
    })
    .catch(() => cached);

  return cached || networkPromise;
}

self.addEventListener('fetch', event => {
  const request = event.request;

  if (request.method !== 'GET') return;

  const url = new URL(request.url);
  const isSameOrigin = url.origin === self.location.origin;

  if (request.mode === 'navigate') {
    // Field navigation must work offline after the user opened the page online.
    // Login remains network-only inside fieldNavigationFirst(); protected pages are cached
    // only when the response is OK and not a login redirect/page.
    event.respondWith(fieldNavigationFirst(request));
    return;
  }

  // PRODUCT-2 INSTANT REFRESH FIX:
  // All dynamic JSON/API reads must be network-first so recent product/schedule
  // mutations are visible immediately instead of returning stale PWA runtime cache.
  if (isSameOrigin && (
      url.pathname.startsWith('/get_') ||
      url.pathname.startsWith('/api/') ||
      url.pathname.startsWith('/preview_tsr_archive') ||
      url.pathname.startsWith('/download_tsr_archive') ||
      url.pathname === '/search_products' ||
      url.pathname === '/search_clients'
  )) {
    event.respondWith(networkFirst(request));
    return;
  }

  if (
    isSameOrigin &&
    (
      url.pathname.startsWith('/static/') ||
      url.pathname === '/manifest.json' ||
      url.pathname === '/pwa-icon.svg' ||
      url.pathname === '/offline'
    )
  ) {
    event.respondWith(cacheFirst(request));
    return;
  }

  if (!isSameOrigin) {
    event.respondWith(cacheFirst(request));
    return;
  }

  event.respondWith(staleWhileRevalidate(request));
});

self.addEventListener('message', event => {
  if (!event.data) return;

  if (event.data.type === 'SKIP_WAITING') {
    self.skipWaiting();
  }

  if (event.data.type === 'CACHE_FIELD_ROUTES') {
    event.waitUntil(
      caches.open(RUNTIME_CACHE).then(cache => {
        return Promise.allSettled(
          FIELD_SAFE_ROUTES.map(route => {
            return fetch(route, { credentials: 'same-origin' }).then(response => {
              if (response && response.ok && !isLoginLikeResponse(new Request(route), response)) {
                return cache.put(route, response.clone());
              }
            }).catch(() => null);
          })
        );
      })
    );
    return;
  }
});
"""
    return Response(
        sw,
        mimetype="application/javascript",
        headers={
            "Cache-Control": "no-cache",
            "Service-Worker-Allowed": "/"
        }
    )


