@app.route('/settings/update-approval-user', methods=['POST'])
@csrf.exempt
@login_required
def settings_update_approval_user():
    """S1 backend API: enable/disable a user as an approver.

    Frontend will be added in S2. This keeps role assignment superadmin-only and
    does not change the existing User.role hierarchy.
    """
    if not is_superadmin_user():
        return denied('Only superadmins can manage approval users.')

    ensure_approval_routing_schema()

    payload = request.get_json(silent=True) or {}
    user_id = clean_int(payload.get('user_id'))
    target_user = db.session.get(User, user_id) if user_id else None
    if not target_user:
        return jsonify({'success': False, 'error': 'User not found.'}), 404

    approver_only_requested = bool(payload.get('approver_only'))
    target_user.can_approve_requests = bool(payload.get('can_approve_requests')) or approver_only_requested
    target_user.approval_scope = (clean_str(payload.get('approval_scope')) or '')[:50]
    target_user.approval_title = (clean_str(payload.get('approval_title')) or '')[:100]
    target_user.is_active = bool(payload.get('is_active', True))

    target_username = _username_of(target_user)
    target_raw_role = (getattr(target_user, 'role', '') or '').strip().lower()
    protected_business_roles = target_username in (MANAGER_USERNAMES | SCHEDULER_USERNAMES | {DEVELOPER_SUPERADMIN_USERNAME, REGIONAL_ADMIN_USERNAME})
    if approver_only_requested:
        if is_admin_authorized(target_user) or protected_business_roles:
            return jsonify({
                'success': False,
                'error': 'Approver-only view cannot be applied to protected management, scheduler, or superadmin accounts.'
            }), 400
        target_user.role = 'approver'
    elif target_raw_role == 'approver':
        # Reverting an approver-only account returns it to a regular personnel profile.
        target_user.role = 'engineer'

    db.session.add(target_user)
    db.session.add(ActivityLog(
        user=(getattr(current_user, 'username', '') or 'Superadmin').capitalize(),
        action=f"Updated approval user settings for {target_user.username}"
    ))
    db.session.commit()

    return jsonify({
        'success': True,
        'message': 'Approval user settings updated.',
        'user': approval_user_to_dict(target_user)
    })


@app.route('/settings/save-approval-route', methods=['POST'])
@csrf.exempt
@login_required
def settings_save_approval_route():
    """S1 backend API: assign requester -> approver routing."""
    if not is_superadmin_user():
        return denied('Only superadmins can manage approval routing.')

    ensure_approval_routing_schema()

    payload = request.get_json(silent=True) or {}
    requester_user_id = clean_int(payload.get('requester_user_id'))
    approver_user_id = clean_int(payload.get('approver_user_id'))
    request_scope = normalize_approval_scope(payload.get('request_scope') or 'all')
    active = bool(payload.get('active', True))

    requester = db.session.get(User, requester_user_id) if requester_user_id else None
    approver = db.session.get(User, approver_user_id) if approver_user_id else None

    if not requester:
        return jsonify({'success': False, 'error': 'Requester user not found.'}), 404
    if not approver:
        return jsonify({'success': False, 'error': 'Approver user not found.'}), 404
    if requester.id == approver.id:
        return jsonify({'success': False, 'error': 'A user cannot approve their own requests.'}), 400

    if not getattr(approver, 'can_approve_requests', False):
        approver.can_approve_requests = True
        if not clean_str(getattr(approver, 'approval_scope', None)):
            approver.approval_scope = 'approver'

    route = ApprovalRouting.query.filter_by(
        requester_user_id=requester.id,
        approver_user_id=approver.id,
        request_scope=request_scope
    ).first()

    if not route:
        route = ApprovalRouting(
            requester_user_id=requester.id,
            approver_user_id=approver.id,
            request_scope=request_scope,
            active=active
        )
    else:
        route.active = active
        route.updated_at = get_manila_time()

    db.session.add(route)
    db.session.add(approver)
    db.session.add(ActivityLog(
        user=(getattr(current_user, 'username', '') or 'Superadmin').capitalize(),
        action=f"Set approval route: {requester.username} -> {approver.username} ({request_scope})"
    ))
    db.session.commit()

    return jsonify({
        'success': True,
        'message': 'Approval route saved.',
        'route': approval_route_to_dict(route)
    })


@app.route('/settings/save-approval-routes-bulk', methods=['POST'])
@csrf.exempt
@login_required
def settings_save_approval_routes_bulk():
    """S6 backend API: bulk assign requester -> approver routes."""
    if not is_superadmin_user():
        return denied('Only superadmins can manage approval routing.')

    ensure_approval_routing_schema()

    payload = request.get_json(silent=True) or {}

    raw_requester_ids = payload.get('requester_user_ids')
    if raw_requester_ids is None:
        raw_requester_ids = payload.get('requester_ids')
    if raw_requester_ids is None:
        raw_requester_ids = payload.get('requesters')
    if raw_requester_ids is None and payload.get('requester_user_id') is not None:
        raw_requester_ids = [payload.get('requester_user_id')]

    if isinstance(raw_requester_ids, str):
        raw_requester_ids = re.split(r'[\s,;]+', raw_requester_ids.strip())

    requester_ids = []
    seen_requester_ids = set()
    for raw_id in raw_requester_ids or []:
        requester_id = clean_int(raw_id)
        if not requester_id or requester_id in seen_requester_ids:
            continue
        seen_requester_ids.add(requester_id)
        requester_ids.append(requester_id)

    approver_user_id = clean_int(payload.get('approver_user_id'))
    request_scope = normalize_approval_scope(payload.get('request_scope') or 'all')
    active = bool(payload.get('active', True))
    overwrite_existing = bool(payload.get('overwrite_existing', False))

    if not requester_ids:
        return jsonify({
            'success': False,
            'error': 'Please select at least one requester.'
        }), 400

    approver = db.session.get(User, approver_user_id) if approver_user_id else None
    if not approver:
        return jsonify({
            'success': False,
            'error': 'Approver user not found.'
        }), 404

    if not bool(getattr(approver, 'is_active', True)):
        return jsonify({
            'success': False,
            'error': 'Selected approver is inactive.'
        }), 400

    if not getattr(approver, 'can_approve_requests', False):
        approver.can_approve_requests = True
        if not clean_str(getattr(approver, 'approval_scope', None)):
            approver.approval_scope = 'approver'
        db.session.add(approver)

    created = []
    updated = []
    skipped = []
    preserved = []
    processed_routes = []

    requester_users = (
        User.query
        .filter(User.id.in_(requester_ids))
        .order_by(User.username.asc())
        .all()
    )
    requester_by_id = {user.id: user for user in requester_users}

    for requester_id in requester_ids:
        requester = requester_by_id.get(requester_id)

        if not requester:
            skipped.append({
                'user_id': requester_id,
                'reason': 'Requester user not found.'
            })
            continue

        if requester.id == approver.id:
            skipped.append({
                'user_id': requester.id,
                'username': requester.username,
                'reason': 'A user cannot approve their own requests.'
            })
            continue

        if not bool(getattr(requester, 'is_active', True)):
            skipped.append({
                'user_id': requester.id,
                'username': requester.username,
                'reason': 'Requester is inactive.'
            })
            continue

        other_active_routes = ApprovalRouting.query.filter(
            ApprovalRouting.requester_user_id == requester.id,
            ApprovalRouting.request_scope == request_scope,
            ApprovalRouting.approver_user_id != approver.id,
            ApprovalRouting.active.is_(True)
        ).all()
        if other_active_routes:
            preserved.append(requester.username)
            processed_routes.extend(other_active_routes)

        route = ApprovalRouting.query.filter_by(
            requester_user_id=requester.id,
            approver_user_id=approver.id,
            request_scope=request_scope
        ).first()

        if not route:
            route = ApprovalRouting(
                requester_user_id=requester.id,
                approver_user_id=approver.id,
                request_scope=request_scope,
                active=active
            )
            db.session.add(route)
            created.append(requester.username)
            processed_routes.append(route)
            continue

        if not bool(getattr(route, 'active', False)) or bool(route.active) != bool(active):
            route.active = active
            route.updated_at = get_manila_time()
            db.session.add(route)
            updated.append(requester.username)
        else:
            skipped.append({
                'user_id': requester.id,
                'username': requester.username,
                'reason': 'Duplicate route already exists for this requester, approver, and request type.'
            })
        processed_routes.append(route)

    db.session.add(ActivityLog(
        user=(getattr(current_user, 'username', '') or 'Superadmin').capitalize(),
        action=(
            f"Bulk approval routing: {len(created)} created, {len(updated)} updated, "
            f"{len(preserved)} preserved, {len(skipped)} skipped -> {approver.username} ({request_scope})"
        )[:255]
    ))

    db.session.commit()

    return jsonify({
        'success': True,
        'message': 'Bulk approval routes processed.',
        'request_scope': request_scope,
        'approver': approval_user_to_dict(approver),
        'created_count': len(created),
        'updated_count': len(updated),
        'skipped_count': len(skipped),
        'preserved_count': len(preserved),
        'overwrite_existing': overwrite_existing,
        'created_usernames': created,
        'updated_usernames': updated,
        'preserved_usernames': preserved,
        'skipped': skipped,
        'routes': [approval_route_to_dict(route) for route in dict.fromkeys(processed_routes)]
    })


@app.route('/settings/delete-all-approval-routes', methods=['POST'])
@csrf.exempt
@login_required
def settings_delete_all_approval_routes():
    """S11D.2 backend API: deactivate all approval routes safely.

    This is intentionally a soft delete. It preserves historical rows while
    clearing the active routing board so superadmins can rebuild routes cleanly.
    """
    if not is_superadmin_user():
        return denied('Only superadmins can manage approval routing.')

    ensure_approval_routing_schema()

    payload = request.get_json(silent=True) or {}
    confirm_text = (clean_str(payload.get('confirm_text')) or '').strip().upper()
    if confirm_text != 'DELETE ALL ROUTES':
        return jsonify({
            'success': False,
            'error': 'Confirmation failed. Type DELETE ALL ROUTES to continue.'
        }), 400

    active_routes = ApprovalRouting.query.filter(ApprovalRouting.active.is_(True)).all()
    affected_count = len(active_routes)
    now = get_manila_time()

    for route in active_routes:
        route.active = False
        route.updated_at = now
        db.session.add(route)

    db.session.add(ActivityLog(
        user=(getattr(current_user, 'username', '') or 'Superadmin').capitalize(),
        action=f"Deactivated all approval routes ({affected_count} route(s))"
    ))
    db.session.commit()

    return jsonify({
        'success': True,
        'message': f'Deactivated {affected_count} approval route(s).',
        'deactivated_count': affected_count
    })


@app.route('/settings/delete-approval-route', methods=['POST'])
@csrf.exempt
@login_required
def settings_delete_approval_route():
    """S1 backend API: deactivate an approval route without deleting history."""
    if not is_superadmin_user():
        return denied('Only superadmins can manage approval routing.')

    ensure_approval_routing_schema()
    payload = request.get_json(silent=True) or {}
    route_id = clean_int(payload.get('route_id'))
    route = db.session.get(ApprovalRouting, route_id) if route_id else None
