@app.route('/get_activity_logs')
@login_required
def get_activity_logs():
    """Full activity log API with search, category/action/branch filters, date range, and pagination."""
    if not is_admin_authorized():
        return denied()

    page = clean_int(request.args.get('page')) or 1
    per_page = clean_int(request.args.get('per_page')) or 25
    page = max(page, 1)
    per_page = min(max(per_page, 10), 100)

    query, type_filter, action_filter, severity_filter, branch_filter = build_activity_query()
    logs = query.order_by(ActivityLog.timestamp.desc()).all()
    logs = filter_activity_logs_by_derived_fields(logs, type_filter, action_filter, severity_filter, branch_filter)

    total = len(logs)
    start_idx = (page - 1) * per_page
    end_idx = start_idx + per_page
    page_logs = logs[start_idx:end_idx]

    category_counts = {}
    action_counts = {}
    severity_counts = {}
    for log in logs:
        category = classify_activity_action(log.action)
        action_type = classify_activity_verb(log.action)
        severity = classify_activity_severity(log.action)
        category_counts[category] = category_counts.get(category, 0) + 1
        action_counts[action_type] = action_counts.get(action_type, 0) + 1
        severity_counts[severity] = severity_counts.get(severity, 0) + 1

    return jsonify({
        'page': page,
        'per_page': per_page,
        'total': total,
        'pages': (total + per_page - 1) // per_page,
        'category_counts': dict(sorted(category_counts.items())),
        'action_counts': dict(sorted(action_counts.items())),
        'severity_counts': dict(sorted(severity_counts.items())),
        'logs': [activity_log_to_dict(log) for log in page_logs]
    })


@app.route('/export_activity_logs')
@login_required
def export_activity_logs():
    """CSV export for filtered activity logs."""
    if not is_admin_authorized():
        return denied()

    query, type_filter, action_filter, severity_filter, branch_filter = build_activity_query()
    logs = query.order_by(ActivityLog.timestamp.desc()).all()
    logs = filter_activity_logs_by_derived_fields(logs, type_filter, action_filter, severity_filter, branch_filter)

    output = io.StringIO()
    writer = csv.writer(output)
    writer.writerow(['Timestamp', 'User', 'Category', 'Action Type', 'Severity', 'Branch Hint', 'Display Action', 'Original Action'])

    for log in logs:
        writer.writerow([
            log.timestamp.strftime("%Y-%m-%d %H:%M"),
            log.user,
            classify_activity_action(log.action),
            classify_activity_verb(log.action),
            classify_activity_severity(log.action),
            infer_activity_branch(log.action),
            clean_activity_display_action(log.action),
            log.action
        ])

    output.seek(0)
    log_activity("Exported activity log report")
    filename = f"activity_logs_{get_manila_time().strftime('%Y%m%d_%H%M')}.csv"
    return Response(
        output.getvalue(),
        mimetype="text/csv",
        headers={"Content-disposition": f"attachment; filename={filename}"}
    )


@app.route('/get_engineers')
@login_required
def get_engineers():
    """ Personnel Retrieval API providing contact info and account metadata """
    engineers = Engineer.query.order_by(Engineer.name).all()
    results = []
    include_account_metadata = is_admin_authorized()

    for e in engineers:
        row = {
            'id': e.id,
            'employee_id': e.employee_id,
            'name': e.name,
            'initials': e.initials,
            'phone': e.phone or "",
            'email': e.email or "",
            'branch': e.branch or "",
        }

        if include_account_metadata:
            # Cross-reference engineer ID with user database (Hard Link v5.4)
            account = db.session.get(User, e.user_id) if e.user_id else None
            if not account:
                fname = e.name.split()[0].lower()
                account = User.query.filter_by(username=fname).first()

                # Do not let the special regional admin account attach by loose first-name match
                # to another technician named Kevin.
                if (
                    account and
                    account.username == REGIONAL_ADMIN_USERNAME and
                    e.employee_id != REGIONAL_ADMIN_EMPLOYEE_ID
                ):
                    account = None

            row.update({
                'account_role': account.role if account else None,
                'display_role': get_display_role(account) if account else None,
                'user_id': account.id if account else None
            })

        results.append(row)

    return jsonify(results)


@app.route('/get_clients')
@login_required
def get_clients():
    ensure_contact_designation_column()

    try:
        repair_recent_online_tsr_contacts_for_medical_centers()
    except Exception as contact_repair_error:
        db.session.rollback()
        print(f"[ONLINE-TSR] Medical Center contact repair skipped: {contact_repair_error}", flush=True)

    clients = Client.query.order_by(Client.name).all()
    results = []

    def add_client_contact_row(rows, seen, name='', phone='', email='', designation=''):
        name = clean_str(name)
        phone = clean_str(phone)
        email = clean_str(email)
        designation = clean_str(designation)
        if not (name or phone or email or designation):
            return

        email_key = (email or '').strip().lower()
        if email_key:
            key = ('email', email_key)
        else:
            key = ('row', (name or '').strip().lower(), (designation or '').strip().lower(), (phone or '').strip().lower())

        if key in seen:
            # D1A fix: legacy Client slots are merged first and do not have
            # designation. When the matching dynamic Contact row is seen later,
            # enrich the already-added row instead of hiding the saved designation.
            for row_idx, existing in enumerate(rows):
                existing_name, existing_phone, existing_email, existing_designation = existing
                existing_email_key = (existing_email or '').strip().lower()

                same_email = bool(email_key and existing_email_key == email_key)
                same_row = (
                    not email_key and
                    (existing_name or '').strip().lower() == (name or '').strip().lower() and
                    (existing_phone or '').strip().lower() == (phone or '').strip().lower()
                )

                if same_email or same_row:
                    rows[row_idx] = (
                        existing_name or name,
                        existing_phone or phone,
                        existing_email or email,
                        existing_designation or designation
                    )
                    break
            return

        seen.add(key)
        rows.append((name, phone, email, designation))

    for c in clients:
        merged_contacts = []
        seen_contacts = set()

        contacts = Contact.query.filter_by(client_id=c.id).order_by(Contact.id.asc()).all()

        if contacts:
            # D2B fix:
            # Once a client has Contact table rows, that table is the source of
            # truth for the editable contacts modal. Legacy Client contact slots
            # are only mirrors for old layouts. Reading legacy first can resurrect
            # deleted Contact #2/#3 rows after scheduler cleanup.
            for ct in contacts:
                add_client_contact_row(
                    merged_contacts, seen_contacts,
                    getattr(ct, 'name', ''),
                    getattr(ct, 'phone', ''),
                    getattr(ct, 'email', ''),
                    getattr(ct, 'designation', '')
                )
        else:
            # Backward compatibility for old client records that still only have
            # legacy cp/cn/ce slots and no Contact table rows yet.
            add_client_contact_row(
                merged_contacts, seen_contacts,
                getattr(c, 'contact_person_1', ''),
                getattr(c, 'contact_number_1', ''),
                getattr(c, 'email_address_1', '')
            )
            add_client_contact_row(
                merged_contacts, seen_contacts,
                getattr(c, 'contact_person_2', ''),
                getattr(c, 'contact_number_2', ''),
                getattr(c, 'email_address_2', '')
            )
            add_client_contact_row(
                merged_contacts, seen_contacts,
                getattr(c, 'contact_person_3', ''),
                getattr(c, 'contact_number_3', ''),
                getattr(c, 'email_address_3', '')
            )

        entry = {'id': c.id, 'name': c.name, 'address': c.address}
        for idx, contact_values in enumerate(merged_contacts, start=1):
            name, phone, email, designation = contact_values
            entry[f'cp{idx}'] = name
            entry[f'cn{idx}'] = phone
            entry[f'ce{idx}'] = email
            entry[f'cd{idx}'] = designation
        results.append(entry)

    return jsonify(results)



@app.route('/quick_add_timeline_client', methods=['POST'])
@login_required
def quick_add_timeline_client():
    """Timeline inline +Add client endpoint.

    Intended workflow:
    - scheduler/admin/manager types a missing client name in Timeline
    - frontend calls this endpoint in the background
    - backend checks duplicates using acronym/fuzzy matching
    - if no duplicate: creates Client(name=<typed>, address='')
    - returns the new/existing client for immediate auto-selection

    No modal. No page refresh. Pure engineer accounts are blocked.
    """
    if not can_quick_add_timeline_client():
        return denied('Only admin, scheduler, manager, or superadmin accounts can add clients from Timeline.')

    payload = request.get_json(silent=True) or {}
    client_name = (
        clean_str(request.form.get('name')) or
        clean_str(request.form.get('client_name')) or
        clean_str(payload.get('name')) or
        clean_str(payload.get('client_name')) or
        ''
    )
    client_name = re.sub(r'\s+', ' ', client_name).strip()

    if not client_name:
        return jsonify({
            'status': 'error',
            'message': 'Please type the medical center name first.'
        }), 400

    if len(client_name) < 3:
        return jsonify({
            'status': 'error',
            'message': 'Client name is too short.'
        }), 400

    if len(client_name) > 100:
        return jsonify({
            'status': 'error',
            'message': 'Client name must be 100 characters or less.'
        }), 400

    duplicate_client = check_for_timeline_quick_add_duplicate_client(client_name)
    if duplicate_client:
        print(f"[TIMELINE-CLIENT] Duplicate detected for typed '{client_name}' -> existing #{duplicate_client.id}: {duplicate_client.name}", flush=True)
        existing_client_payload = {
            'id': duplicate_client.id,
            'client_id': duplicate_client.id,
            'name': duplicate_client.name or '',
            'client_name': duplicate_client.name or '',
            'selected_client_name': duplicate_client.name or '',
            'address': duplicate_client.address or ''
        }
        return jsonify({
            'status': 'success',
            'duplicate': True,
            'existing': True,
            'created': False,
            'message': 'Client already exists. Existing client selected.',
            'client': existing_client_payload,
            'existing_client': existing_client_payload,
            'selected_client': existing_client_payload,
            'selected_client_id': duplicate_client.id,
            'selected_client_name': duplicate_client.name or '',
            'typed_name': client_name
        })

    new_client = Client(
        name=client_name,
        address=''
    )
    db.session.add(new_client)
    db.session.flush()

    db.session.add(ActivityLog(
        user=current_user.username.capitalize(),
        action=f"Quick added client from Timeline: {new_client.name}"
    ))
    db.session.commit()

    new_client_payload = {
        'id': new_client.id,
        'client_id': new_client.id,
        'name': new_client.name or '',
        'client_name': new_client.name or '',
        'selected_client_name': new_client.name or '',
        'address': new_client.address or ''
    }

    return jsonify({
        'status': 'success',
        'duplicate': False,
        'existing': False,
        'created': True,
        'message': 'Client added and selected.',
        'client': new_client_payload,
        'selected_client': new_client_payload,
        'selected_client_id': new_client.id,
        'selected_client_name': new_client.name or '',
        'typed_name': client_name
    })


