@app.route('/get_open_tasks')
@login_required
def get_open_tasks():
    """
    DASHBOARD CORE LOGIC API:
    Retrieves all technical visits where status is NOT 'Completed'.

    Engineer dashboard reliability:
    - Returns assigned engineer IDs for accurate frontend matching.
    - Falls back to Shift.engineer_id when ShiftEngineer rows are absent.
    - Includes product/serial so similar jobs do not merge incorrectly.
    """
    invalid_dashboard_categories = ['Completed', 'Training'] + LEAVE_CATEGORIES

    active_shifts = (
        Shift.query
        .options(
            joinedload(Shift.client),
            joinedload(Shift.product)
        )
        .filter(
            and_(
                Shift.status.notin_(invalid_dashboard_categories),
                Shift.client_id.isnot(None)
            )
        )
        .order_by(Shift.start_time.asc())
        .all()
    )

    results = []
    for s in active_shifts:
        assigned_engineer_ids = get_shift_assigned_engineer_ids(s)
        assigned_engineers = [
            db.session.get(Engineer, engineer_id)
            for engineer_id in assigned_engineer_ids
            if engineer_id
        ]
        assigned_engineers = [engineer for engineer in assigned_engineers if engineer]

        eng_names = [engineer.name for engineer in assigned_engineers]

        results.append({
            'id': s.id,
            'task_date': s.start_time.strftime("%Y-%m-%d") if s.start_time else '',
            'created_at': s.created_at.strftime("%Y-%m-%d %H:%M") if s.created_at else '',
            'engineer': ", ".join(eng_names) if eng_names else "None",
            'engineer_ids': assigned_engineer_ids,
            'engineer_names': eng_names,
            'client': s.client.name if s.client else "N/A",
            'client_id': s.client_id,
            'product': s.product.name if s.product else "",
            'product_name': s.product.name if s.product else "",
            'product_id': s.product_id or '',
            'serial': s.product.serial_number if s.product else (s.product_id or ''),
            'task': s.title,
            'status': s.status
        })


    return jsonify(results)


@app.route('/get_engineer_dashboard_summary')
@login_required
def get_engineer_dashboard_summary():
    """Engineer-focused dashboard summary cards.

    Phase 2 backend support:
    - avoids requiring engineer dashboards to load company-wide counters
    - calculates true pending TSR and completed-this-month counts
    - uses assigned engineer IDs instead of username text matching
    """
    if not has_engineer_profile():
        return denied('Engineer dashboard summary is only available to accounts with a linked engineer profile.')

    my_engineer_id = get_current_user_engineer_id()
    if not my_engineer_id:
        return jsonify({
            'status': 'success',
            'message': 'No linked engineer profile found for this account.',
            'engineer_id': None,
            'my_active_tasks': 0,
            'upcoming_visits': 0,
            'for_continuation': 0,
            'waiting_items': 0,
            'pending_tsr': 0,
            'completed_this_month': 0,
            'pending_tsr_rows': []
        })

    today = get_manila_today()
    month_start = today.replace(day=1)
    next_month = (month_start.replace(day=28) + timedelta(days=4)).replace(day=1)

    invalid_dashboard_categories = ['Completed', 'Training'] + LEAVE_CATEGORIES

    base_query = (
        Shift.query
        .options(
            joinedload(Shift.client),
            joinedload(Shift.product),
            selectinload(Shift.files)
        )
        .filter(Shift.client_id.isnot(None))
        .order_by(Shift.start_time.desc())
    )

    assigned_service_shifts = [
        shift for shift in base_query.limit(1000).all()
        if is_current_engineer_assigned_to_shift(shift)
    ]

    active_tasks = [
        shift for shift in assigned_service_shifts
        if (shift.status or '') not in invalid_dashboard_categories
    ]

    completed_this_month_shifts = [
        shift for shift in assigned_service_shifts
        if (
            (shift.status or '') == 'Completed' and
            shift.start_time and
            month_start <= shift.start_time.date() < next_month
        )
    ]

    pending_tsr_shifts = [
        shift for shift in assigned_service_shifts
        if (
            (shift.status or '') == 'Completed' and
            not shift_has_tsr_file(shift)
        )
    ]

    def pending_tsr_row(shift):
        engineers = get_shift_engineer_records(shift)
        return {
            'id': shift.id,
            'date': shift.start_time.strftime('%Y-%m-%d') if shift.start_time else '',
            'client': shift.client.name if shift.client else 'N/A',
            'product': shift.product.name if shift.product else '',
            'serial': shift.product.serial_number if shift.product else (shift.product_id or ''),
            'task': shift.title or '',
            'status': shift.status or '',
            'engineers': ', '.join([engineer.name for engineer in engineers]) or ''
        }

    return jsonify({
        'status': 'success',
        'engineer_id': my_engineer_id,
        'generated_at': get_manila_time().isoformat(),
        'my_active_tasks': len(active_tasks),
        'upcoming_visits': len([
            shift for shift in active_tasks
            if shift.start_time and shift.start_time.date() >= today
        ]),
        'for_continuation': len([
            shift for shift in active_tasks
            if (shift.status or '') == 'For Continuation'
        ]),
        'waiting_items': len([
            shift for shift in active_tasks
            if (shift.status or '') in {'Waiting for P.O', 'Waiting for Parts'}
        ]),
        'pending_tsr': len(pending_tsr_shifts),
        'completed_this_month': len(completed_this_month_shifts),
        'pending_tsr_rows': [pending_tsr_row(shift) for shift in pending_tsr_shifts[:10]]
    })


def dashboard_team_shift_row(shift):
    """Serialize one service schedule row for Hybrid Dashboard team intelligence."""
    engineers = get_shift_engineer_records(shift)
    start_date = shift.start_time.date() if getattr(shift, 'start_time', None) else None
    today = get_manila_today()
    age_days = (today - start_date).days if start_date else 0

    return {
        'id': shift.id,
        'date': shift.start_time.strftime('%Y-%m-%d') if shift.start_time else '',
        'age_days': max(age_days, 0),
        'client': shift.client.name if shift.client else 'N/A',
        'product': shift.product.name if shift.product else '',
        'serial': shift.product.serial_number if shift.product else (shift.product_id or ''),
        'task': shift.title or '',
        'status': shift.status or '',
        'engineers': ', '.join([engineer.name for engineer in engineers]) or 'N/A',
        'branches': ', '.join(sorted({engineer.branch or 'Unassigned' for engineer in engineers})) or 'Unassigned',
        'has_tsr': shift_has_tsr_file(shift)
    }


@app.route('/get_hybrid_dashboard_team_summary')
@login_required
def get_hybrid_dashboard_team_summary():
    """Hybrid Dashboard Phase 2: team intelligence for admin-capable users.

    Supports superadmin+engineer, regional_admin+engineer, manager-only,
    and scheduler-only accounts without changing the pure engineer speed path.
    """
    if not is_admin_authorized():
        return denied('Team dashboard intelligence is only available to authorized admin users.')

    ensure_shift_file_original_filename_column()

    today = get_manila_today()
    invalid_dashboard_categories = ['Completed', 'Training'] + LEAVE_CATEGORIES
    waiting_statuses = {'Waiting for P.O', 'Waiting for Parts'}

    base_query = (
        Shift.query
        .options(
            joinedload(Shift.client),
            joinedload(Shift.product),
            selectinload(Shift.files)
        )
        .filter(Shift.client_id.isnot(None))
        .order_by(Shift.start_time.desc())
    )

    if is_admin_authorized():
        base_query = analytics_scope_query(base_query)

    service_shifts = list({shift.id: shift for shift in base_query.limit(1200).all()}.values())

    open_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') not in invalid_dashboard_categories
    ]

    overdue_shifts = [
        shift for shift in open_shifts
        if shift.start_time and shift.start_time.date() < today
    ]

    waiting_shifts = [
        shift for shift in open_shifts
        if (shift.status or '') in waiting_statuses
    ]

    continuation_shifts = [
        shift for shift in open_shifts
        if (shift.status or '') == 'For Continuation'
    ]

    completed_missing_tsr = [
        shift for shift in service_shifts
        if (shift.status or '') == 'Completed' and not shift_has_tsr_file(shift)
    ]

    branch_counts = {}
    engineer_load = {}
    for shift in open_shifts:
        engineers = get_shift_engineer_records(shift)
        if not engineers:
            branch_counts['Unassigned'] = branch_counts.get('Unassigned', 0) + 1
            continue
        for engineer in engineers:
            branch = engineer.branch or 'Unassigned'
            branch_counts[branch] = branch_counts.get(branch, 0) + 1
            if engineer.name not in engineer_load:
                engineer_load[engineer.name] = {
                    'name': engineer.name,
                    'branch': branch,
                    'open_tasks': 0,
                    'waiting_items': 0,
                    'overdue': 0
                }
            engineer_load[engineer.name]['open_tasks'] += 1
            if (shift.status or '') in waiting_statuses:
                engineer_load[engineer.name]['waiting_items'] += 1
            if shift.start_time and shift.start_time.date() < today:
                engineer_load[engineer.name]['overdue'] += 1

    workload_rows = sorted(
        engineer_load.values(),
        key=lambda row: (-row['open_tasks'], -row['overdue'], row['name'])
    )[:12]

    def newest_rows(rows, limit=10):
        return [dashboard_team_shift_row(shift) for shift in rows[:limit]]

    return jsonify({
        'status': 'success',
        'generated_at': get_manila_time().isoformat(),
        'team_open_tasks': len(open_shifts),
        'overdue_tasks': len(overdue_shifts),
        'pending_tsr': len(completed_missing_tsr),
        'waiting_items': len(waiting_shifts),
        'for_continuation': len(continuation_shifts),
        'branch_counts': dict(sorted(branch_counts.items())),
        'workload_rows': workload_rows,
        'overdue_rows': newest_rows(sorted(overdue_shifts, key=lambda s: s.start_time or datetime.min), 10),
        'pending_tsr_rows': newest_rows(completed_missing_tsr, 10),
        'waiting_rows': newest_rows(waiting_shifts, 10)
    })




@app.route('/get_hybrid_dashboard_smart_monitoring')
@login_required
def get_hybrid_dashboard_smart_monitoring():
    """Hybrid Dashboard Phase 3: smart monitoring alerts for admin-capable users.

    Adds lightweight operational warning signals without changing existing
    schedules, reports, analytics, or Phase 2 team intelligence behavior.
    """
    if not is_admin_authorized():
        return denied('Smart monitoring is only available to authorized admin users.')

    ensure_shift_file_original_filename_column()

    today = get_manila_today()
    stale_threshold_days = 7
    tsr_aging_threshold_days = 3
    repeat_service_window_days = 180
    repeat_service_threshold = 3

    invalid_dashboard_categories = ['Completed', 'Training'] + LEAVE_CATEGORIES
    waiting_statuses = {'Waiting for P.O', 'Waiting for Parts'}

    window_start = today - timedelta(days=repeat_service_window_days)
    window_start_dt = datetime.combine(window_start, datetime.min.time())

    base_query = (
        Shift.query
        .options(
            joinedload(Shift.client),
            joinedload(Shift.product),
            selectinload(Shift.files)
        )
        .filter(Shift.client_id.isnot(None))
        .order_by(Shift.start_time.desc())
    )
    base_query = analytics_scope_query(base_query)

    service_shifts = list({shift.id: shift for shift in base_query.limit(1500).all()}.values())

    open_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') not in invalid_dashboard_categories
    ]

    stale_open_shifts = [
        shift for shift in open_shifts
        if (
            shift.start_time and
            shift.start_time.date() < today and
            (today - shift.start_time.date()).days >= stale_threshold_days
        )
    ]

    tsr_aging_shifts = [
        shift for shift in service_shifts
        if (
            (shift.status or '') == 'Completed' and
            shift.start_time and
            (today - shift.start_time.date()).days >= tsr_aging_threshold_days and
            not shift_has_tsr_file(shift)
        )
    ]

    waiting_shifts = [
        shift for shift in open_shifts
        if (shift.status or '') in waiting_statuses
    ]

    engineer_load = {}
    for shift in open_shifts:
        engineers = get_shift_engineer_records(shift)
        for engineer in engineers:
            if engineer.name not in engineer_load:
                engineer_load[engineer.name] = {
                    'name': engineer.name,
                    'branch': engineer.branch or 'Unassigned',
                    'open_tasks': 0,
                    'overdue': 0,
                    'waiting_items': 0,
                    'for_continuation': 0,
                    'risk_level': 'normal'
                }

            row = engineer_load[engineer.name]
            row['open_tasks'] += 1
            if shift.start_time and shift.start_time.date() < today:
                row['overdue'] += 1
            if (shift.status or '') in waiting_statuses:
                row['waiting_items'] += 1
            if (shift.status or '') == 'For Continuation':
                row['for_continuation'] += 1

    workload_alerts = []
    if engineer_load:
        load_values = [row['open_tasks'] for row in engineer_load.values()]
        average_load = sum(load_values) / max(len(load_values), 1)
        for row in engineer_load.values():
            if row['open_tasks'] >= max(5, average_load * 1.8) or row['overdue'] >= 2:
                row['risk_level'] = 'high' if row['overdue'] >= 3 or row['open_tasks'] >= 8 else 'warning'
                workload_alerts.append(row)

    workload_alerts.sort(key=lambda row: (-row['overdue'], -row['open_tasks'], row['name']))

    product_service_map = {}
    recent_service_shifts = [
        shift for shift in service_shifts
        if shift.start_time and shift.start_time >= window_start_dt and shift.product_id
    ]
    for shift in recent_service_shifts:
        key = shift.product_id or ''
        if key not in product_service_map:
            product_label = shift.product.name if shift.product else (shift.product_id or 'Unknown product')
            serial_label = shift.product.serial_number if shift.product else (shift.product_id or '')
            product_service_map[key] = {
                'product': product_label,
                'serial': serial_label,
                'client': shift.client.name if shift.client else 'N/A',
                'service_count': 0,
                'last_service': '',
                'latest_date': None,
                'tasks': set(),
                'engineers': set()
            }

        product_row = product_service_map[key]
        product_row['service_count'] += 1
        product_row['tasks'].add(shift.title or '')
        for engineer in get_shift_engineer_records(shift):
            product_row['engineers'].add(engineer.name)
        if not product_row['latest_date'] or shift.start_time > product_row['latest_date']:
            product_row['latest_date'] = shift.start_time
            product_row['last_service'] = shift.start_time.strftime('%Y-%m-%d')

    repeat_service_alerts = []
    for row in product_service_map.values():
        if row['service_count'] >= repeat_service_threshold:
            repeat_service_alerts.append({
                'product': row['product'],
                'serial': row['serial'],
                'client': row['client'],
                'service_count': row['service_count'],
                'last_service': row['last_service'],
                'tasks': ', '.join(sorted([task for task in row['tasks'] if task])[:4]),
                'engineers': ', '.join(sorted(row['engineers'])[:4])
            })

    repeat_service_alerts.sort(key=lambda row: (-row['service_count'], row['client'], row['product']))

    def alert_shift_row(shift, alert_type='monitoring'):
        row = dashboard_team_shift_row(shift)
        if shift.start_time:
            row['days_old'] = max((today - shift.start_time.date()).days, 0)
        else:
            row['days_old'] = 0
        row['alert_type'] = alert_type
        if alert_type == 'stale_task':
            row['alert_label'] = f"Open for {row['days_old']} day(s)"
        elif alert_type == 'tsr_aging':
            row['alert_label'] = f"Completed {row['days_old']} day(s), no TSR"
        elif alert_type == 'waiting_item':
            row['alert_label'] = row.get('status') or 'Waiting item'
        else:
            row['alert_label'] = 'Needs attention'
        return row

    needs_attention_rows = []
    needs_attention_rows.extend([alert_shift_row(shift, 'stale_task') for shift in sorted(stale_open_shifts, key=lambda s: s.start_time or datetime.min)[:8]])
    needs_attention_rows.extend([alert_shift_row(shift, 'tsr_aging') for shift in sorted(tsr_aging_shifts, key=lambda s: s.start_time or datetime.min)[:8]])
    needs_attention_rows.extend([alert_shift_row(shift, 'waiting_item') for shift in sorted(waiting_shifts, key=lambda s: s.start_time or datetime.min)[:6]])

    risk_score = (
        (len(stale_open_shifts) * 3) +
        (len(tsr_aging_shifts) * 3) +
        (len(workload_alerts) * 2) +
        (len(repeat_service_alerts) * 2) +
        len(waiting_shifts)
    )

    if risk_score >= 18:
        risk_level = 'critical'
        risk_label = 'Critical Attention Needed'
    elif risk_score >= 8:
        risk_level = 'warning'
        risk_label = 'Needs Monitoring'
    else:
        risk_level = 'healthy'
        risk_label = 'Stable'

    return jsonify({
        'status': 'success',
        'generated_at': get_manila_time().isoformat(),
        'risk_score': risk_score,
        'risk_level': risk_level,
        'risk_label': risk_label,
        'thresholds': {
            'stale_task_days': stale_threshold_days,
            'tsr_aging_days': tsr_aging_threshold_days,
            'repeat_service_window_days': repeat_service_window_days,
            'repeat_service_threshold': repeat_service_threshold
        },
        'counts': {
            'stale_tasks': len(stale_open_shifts),
            'tsr_aging': len(tsr_aging_shifts),
            'workload_alerts': len(workload_alerts),
            'repeat_service_alerts': len(repeat_service_alerts),
            'waiting_items': len(waiting_shifts)
        },
        'needs_attention_rows': needs_attention_rows[:18],
        'stale_task_rows': [alert_shift_row(shift, 'stale_task') for shift in sorted(stale_open_shifts, key=lambda s: s.start_time or datetime.min)[:10]],
        'tsr_aging_rows': [alert_shift_row(shift, 'tsr_aging') for shift in sorted(tsr_aging_shifts, key=lambda s: s.start_time or datetime.min)[:10]],
        'workload_alerts': workload_alerts[:10],
        'repeat_service_alerts': repeat_service_alerts[:10]
    })


def scheduler_dashboard_shift_row(shift):
    """Serialize one schedule row for Scheduler Dashboard Phase 1."""
    engineers = get_shift_engineer_records(shift)
    return {
        'id': shift.id,
        'date': shift.start_time.strftime('%Y-%m-%d') if shift.start_time else '',
        'time_start': shift.start_time.strftime('%I:%M %p') if shift.start_time else '',
        'time_end': shift.end_time.strftime('%I:%M %p') if shift.end_time else '',
        'client': shift.client.name if shift.client else 'N/A',
        'product': shift.product.name if shift.product else '',
        'serial': shift.product.serial_number if shift.product else (shift.product_id or ''),
        'task': shift.title or '',
        'status': shift.status or '',
        'engineers': ', '.join([engineer.name for engineer in engineers]) or 'Unassigned',
        'branches': ', '.join(sorted({engineer.branch or 'Unassigned' for engineer in engineers})) or 'Unassigned',
        'has_tsr': shift_has_tsr_file(shift)
    }


@app.route('/get_scheduler_dashboard_summary')
@login_required
def get_scheduler_dashboard_summary():
    """Scheduler Dashboard Phase 1 backend summary.

    This endpoint is intentionally scheduler-focused:
    - Hanna/Diary get schedule coordination counters and compact queues.
    - Engineer workflow and hybrid admin-engineer logic stay untouched.
    - Uses existing Shift/ActivityLog data only; no database schema change.
    """
    if not (is_scheduler_user() or developer_dashboard_view_is('scheduler')):
        return denied('Scheduler dashboard summary is only available to scheduler accounts.')

    ensure_shift_file_original_filename_column()

    today = get_manila_today()
    tomorrow = today + timedelta(days=1)
    week_end = today + timedelta(days=7)
    lookback_start = today - timedelta(days=30)
    lookahead_end = today + timedelta(days=60)
    start_dt, end_dt = build_shift_datetime_bounds(lookback_start, lookahead_end)

    invalid_dashboard_categories = ['Completed', 'Training'] + LEAVE_CATEGORIES
    waiting_statuses = {'Waiting for P.O', 'Waiting for Parts'}

    service_shifts = (
        Shift.query
        .options(
            joinedload(Shift.client),
            joinedload(Shift.product),
            selectinload(Shift.files)
        )
        .filter(Shift.client_id.isnot(None))
        .filter(Shift.start_time >= start_dt)
        .filter(Shift.start_time < end_dt)
        .order_by(Shift.start_time.asc())
        .all()
    )

    open_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') not in invalid_dashboard_categories
    ]

    today_shifts = [
        shift for shift in service_shifts
        if shift.start_time and shift.start_time.date() == today
    ]

    tomorrow_shifts = [
        shift for shift in service_shifts
        if shift.start_time and shift.start_time.date() == tomorrow
    ]

    upcoming_week_shifts = [
        shift for shift in service_shifts
        if shift.start_time and today <= shift.start_time.date() <= week_end
    ]

    overdue_open_shifts = [
        shift for shift in open_shifts
        if shift.start_time and shift.start_time.date() < today
    ]

    waiting_shifts = [
        shift for shift in open_shifts
        if (shift.status or '') in waiting_statuses
    ]

    pending_tsr_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') == 'Completed' and not shift_has_tsr_file(shift)
    ]

    unassigned_shifts = [
        shift for shift in open_shifts
        if not get_shift_engineer_records(shift)
    ]

    recent_schedule_logs = (
        activity_scope_query(ActivityLog.query)
        .filter(or_(
            ActivityLog.action.ilike('%schedule%'),
            ActivityLog.action.ilike('%calendar%'),
            ActivityLog.action.ilike('%technical record%'),
            ActivityLog.action.ilike('%wiped technical%'),
            ActivityLog.action.ilike('%bulk-purged%')
        ))
        .order_by(ActivityLog.timestamp.desc())
        .limit(8)
        .all()
    )

    def limited_rows(rows, limit=8):
        return [scheduler_dashboard_shift_row(shift) for shift in rows[:limit]]

    return jsonify({
        'status': 'success',
        'generated_at': get_manila_time().isoformat(),
        'scheduler': {
            'username': getattr(current_user, 'username', ''),
            'display_role': get_display_role(current_user)
        },
        'counts': {
            'today_schedules': len(today_shifts),
            'tomorrow_schedules': len(tomorrow_shifts),
            'upcoming_week': len(upcoming_week_shifts),
            'open_tasks': len(open_shifts),
            'overdue_open': len(overdue_open_shifts),
            'waiting_items': len(waiting_shifts),
            'pending_tsr': len(pending_tsr_shifts),
            'unassigned': len(unassigned_shifts)
        },
        'today_rows': limited_rows(today_shifts, 10),
        'tomorrow_rows': limited_rows(tomorrow_shifts, 8),
        'overdue_rows': limited_rows(sorted(overdue_open_shifts, key=lambda s: s.start_time or datetime.min), 10),
        'waiting_rows': limited_rows(waiting_shifts, 8),
        'pending_tsr_rows': limited_rows(pending_tsr_shifts, 8),
        'unassigned_rows': limited_rows(unassigned_shifts, 8),
        'recent_schedule_changes': [activity_log_to_dict(log) for log in recent_schedule_logs]
    })


@app.route('/get_scheduler_dispatch_intelligence')
@login_required
def get_scheduler_dispatch_intelligence():
    """Scheduler Dashboard Phase 2: dispatch intelligence.

    Scheduler-only operational intelligence for Hanna/Diary:
    - overdue schedules
    - next 7 days queue
    - unassigned priority list
    - engineer workload snapshot
    - pending TSR follow-ups
    - waiting P.O / parts blockers

    This reuses existing schedule/TSR tables only. No schema change.
    """
    if not (is_scheduler_user() or developer_dashboard_view_is('scheduler')):
        return denied('Scheduler dispatch intelligence is only available to scheduler accounts.')

    ensure_shift_file_original_filename_column()

    today = get_manila_today()
    week_end = today + timedelta(days=7)
    lookback_start = today - timedelta(days=45)
    lookahead_end = today + timedelta(days=30)
    start_dt, end_dt = build_shift_datetime_bounds(lookback_start, lookahead_end)

    invalid_dashboard_categories = ['Completed', 'Training'] + LEAVE_CATEGORIES
    waiting_statuses = {'Waiting for P.O', 'Waiting for Parts'}

    service_shifts = (
        Shift.query
        .options(
            joinedload(Shift.client),
            joinedload(Shift.product),
            selectinload(Shift.files)
        )
        .filter(Shift.client_id.isnot(None))
        .filter(Shift.start_time >= start_dt)
        .filter(Shift.start_time < end_dt)
        .order_by(Shift.start_time.asc())
        .all()
    )

    open_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') not in invalid_dashboard_categories
    ]

    overdue_schedules = [
        shift for shift in open_shifts
        if shift.start_time and shift.start_time.date() < today
    ]

    upcoming_7_days = [
        shift for shift in service_shifts
        if shift.start_time and today <= shift.start_time.date() <= week_end
    ]

    unassigned_schedules = [
        shift for shift in open_shifts
        if not get_shift_engineer_records(shift)
    ]

    waiting_po_parts = [
        shift for shift in open_shifts
        if (shift.status or '') in waiting_statuses
    ]

    pending_tsr_followups = [
        shift for shift in service_shifts
        if (shift.status or '') == 'Completed' and not shift_has_tsr_file(shift)
    ]

    engineer_workload_map = {}
    for shift in open_shifts:
        assigned_engineers = get_shift_engineer_records(shift)
        if not assigned_engineers:
            continue

        for engineer in assigned_engineers:
            if engineer.id not in engineer_workload_map:
                engineer_workload_map[engineer.id] = {
                    'engineer_id': engineer.id,
                    'name': engineer.name,
                    'branch': engineer.branch or 'Unassigned',
                    'open_tasks': 0,
                    'today_tasks': 0,
                    'next_7_days': 0,
                    'overdue': 0,
                    'waiting_items': 0,
                    'continuation': 0,
                    'load_level': 'normal'
                }

            row = engineer_workload_map[engineer.id]
            row['open_tasks'] += 1

            if shift.start_time:
                shift_date = shift.start_time.date()
                if shift_date == today:
                    row['today_tasks'] += 1
                if today <= shift_date <= week_end:
                    row['next_7_days'] += 1
                if shift_date < today:
                    row['overdue'] += 1

            if (shift.status or '') in waiting_statuses:
                row['waiting_items'] += 1
            if (shift.status or '') == 'For Continuation':
                row['continuation'] += 1

    engineer_workload = list(engineer_workload_map.values())
    if engineer_workload:
        average_open = sum(row['open_tasks'] for row in engineer_workload) / max(len(engineer_workload), 1)
        for row in engineer_workload:
            if row['overdue'] >= 3 or row['open_tasks'] >= max(7, average_open * 1.8):
                row['load_level'] = 'high'
            elif row['overdue'] >= 1 or row['waiting_items'] >= 2 or row['open_tasks'] >= max(4, average_open * 1.35):
                row['load_level'] = 'watch'

    engineer_workload.sort(key=lambda row: (-row['overdue'], -row['open_tasks'], row['name']))

    def priority_row(shift, reason=''):
        row = scheduler_dashboard_shift_row(shift)
        if shift.start_time:
            row['days_from_today'] = (shift.start_time.date() - today).days
            row['age_days'] = max((today - shift.start_time.date()).days, 0)
        else:
            row['days_from_today'] = 0
            row['age_days'] = 0
        row['priority_reason'] = reason
        return row

    overdue_rows = [
        priority_row(shift, f"Overdue by {max((today - shift.start_time.date()).days, 0)} day(s)")
        for shift in sorted(overdue_schedules, key=lambda s: s.start_time or datetime.min)[:15]
    ]

    upcoming_rows = [
        priority_row(shift, 'Scheduled within 7 days')
        for shift in sorted(upcoming_7_days, key=lambda s: s.start_time or datetime.max)[:20]
    ]

    unassigned_rows = [
        priority_row(shift, 'No engineer assigned')
        for shift in sorted(unassigned_schedules, key=lambda s: s.start_time or datetime.max)[:15]
    ]

    waiting_rows = [
        priority_row(shift, shift.status or 'Waiting item')
        for shift in sorted(waiting_po_parts, key=lambda s: s.start_time or datetime.min)[:15]
    ]

    pending_tsr_rows = [
        priority_row(shift, 'Completed schedule missing TSR')
        for shift in sorted(pending_tsr_followups, key=lambda s: s.start_time or datetime.min)[:15]
    ]

    dispatch_risk_score = (
        (len(overdue_schedules) * 3) +
        (len(unassigned_schedules) * 3) +
        (len(pending_tsr_followups) * 2) +
        (len(waiting_po_parts) * 2) +
        len([row for row in engineer_workload if row.get('load_level') == 'high'])
    )

    if dispatch_risk_score >= 18:
        dispatch_risk_level = 'critical'
        dispatch_risk_label = 'Dispatch attention needed'
    elif dispatch_risk_score >= 8:
        dispatch_risk_level = 'watch'
        dispatch_risk_label = 'Monitor workload and blockers'
    else:
        dispatch_risk_level = 'stable'
        dispatch_risk_label = 'Dispatch queue stable'

    return jsonify({
        'status': 'success',
        'phase': 'scheduler-phase-2-dispatch-intelligence',
        'generated_at': get_manila_time().isoformat(),
        'risk': {
            'score': dispatch_risk_score,
            'level': dispatch_risk_level,
            'label': dispatch_risk_label
        },
        'counts': {
            'overdue_schedules': len(overdue_schedules),
            'upcoming_7_days': len(upcoming_7_days),
            'unassigned_schedules': len(unassigned_schedules),
            'engineers_loaded': len(engineer_workload),
            'pending_tsr_followups': len(pending_tsr_followups),
            'waiting_po_parts': len(waiting_po_parts),
            'high_load_engineers': len([row for row in engineer_workload if row.get('load_level') == 'high']),
            'watch_load_engineers': len([row for row in engineer_workload if row.get('load_level') == 'watch'])
        },
        'overdue_rows': overdue_rows,
        'upcoming_rows': upcoming_rows,
        'unassigned_rows': unassigned_rows,
        'engineer_workload': engineer_workload[:20],
        'pending_tsr_rows': pending_tsr_rows,
        'waiting_rows': waiting_rows,
        'priority_queue': (overdue_rows[:6] + unassigned_rows[:6] + waiting_rows[:5] + pending_tsr_rows[:5])[:18]
    })




# --- SCHEDULER DASHBOARD PHASE 3: COORDINATION TOOLS ---

def can_use_scheduler_coordination_tools():
    """Return True for scheduler users and Jonamar's scheduler preview mode."""
    return bool(is_scheduler_user() or developer_dashboard_view_is('scheduler'))


def scheduler_parse_engineer_id_list(raw_value):
    """Parse quick-action engineer IDs from JSON/form payloads."""
    parsed = parse_engineer_ids(raw_value)
    return [engineer_id for engineer_id in parsed if db.session.get(Engineer, engineer_id)]


def scheduler_shift_conflict(engineer_id, start_dt, end_dt, ignore_shift_ids=None):
    """Return overlapping schedule for a quick scheduler action, ignoring selected linked rows."""
    if not engineer_id or not start_dt or not end_dt:
        return None

    ignore_shift_ids = [sid for sid in (ignore_shift_ids or []) if sid]
    query = (
        db.session.query(Shift)
        .join(ShiftEngineer, Shift.id == ShiftEngineer.shift_id)
        .filter(
            ShiftEngineer.engineer_id == engineer_id,
            func.date(Shift.start_time) == start_dt.date(),
            Shift.start_time < end_dt,
            Shift.end_time > start_dt
        )
    )
    if ignore_shift_ids:
        query = query.filter(~Shift.id.in_(ignore_shift_ids))

    return query.order_by(Shift.start_time.asc(), Shift.id.asc()).first()


def scheduler_engineer_availability_row(engineer, today, week_end, open_shifts):
    """Build a scheduler-friendly availability row for one engineer."""
    engineer_shifts = []
    for shift in open_shifts:
        assigned_ids = get_shift_assigned_engineer_ids(shift)
        if engineer.id in assigned_ids:
            engineer_shifts.append(shift)

    today_tasks = [shift for shift in engineer_shifts if shift.start_time and shift.start_time.date() == today]
    next_7_days = [shift for shift in engineer_shifts if shift.start_time and today <= shift.start_time.date() <= week_end]
    overdue = [shift for shift in engineer_shifts if shift.start_time and shift.start_time.date() < today]
    waiting = [shift for shift in engineer_shifts if (shift.status or '') in {'Waiting for P.O', 'Waiting for Parts'}]

    if len(today_tasks) >= 3 or len(overdue) >= 2:
        availability = 'busy'
        availability_label = 'Busy'
    elif len(today_tasks) >= 1 or len(next_7_days) >= 4 or waiting:
        availability = 'watch'
        availability_label = 'Watch'
    else:
        availability = 'available'
        availability_label = 'Available'

    return {
        'engineer_id': engineer.id,
        'name': engineer.name,
        'initials': engineer.initials or '',
        'branch': engineer.branch or 'Unassigned',
        'email': engineer.email or '',
        'today_tasks': len(today_tasks),
        'next_7_days': len(next_7_days),
        'open_tasks': len(engineer_shifts),
        'overdue': len(overdue),
        'waiting_items': len(waiting),
        'availability': availability,
        'availability_label': availability_label
    }


def scheduler_coordination_shift_row(shift):
    """Serialize one schedule row for Scheduler Phase 3 without loading attachment files.

    The coordination tools only need schedule/engineer/date metadata. Keeping this
    serializer file-free avoids attachment-table migration issues from blocking
    the scheduler quick tools panel.
    """
    engineers = get_shift_engineer_records(shift)
    assigned_ids = [engineer.id for engineer in engineers if engineer]

    return {
        'id': shift.id,
        'date': shift.start_time.strftime('%Y-%m-%d') if shift.start_time else '',
        'time_start': shift.start_time.strftime('%I:%M %p') if shift.start_time else '',
        'time_end': shift.end_time.strftime('%I:%M %p') if shift.end_time else '',
        'client': shift.client.name if shift.client else 'N/A',
        'product': shift.product.name if shift.product else '',
        'serial': shift.product.serial_number if shift.product else (shift.product_id or ''),
        'task': shift.title or '',
        'status': shift.status or '',
        'engineers': ', '.join([engineer.name for engineer in engineers]) or 'Unassigned',
        'branches': ', '.join(sorted({engineer.branch or 'Unassigned' for engineer in engineers})) or 'Unassigned',
        'engineer_ids': assigned_ids,
        'has_tsr': False
    }



@app.route('/get_scheduler_coordination_tools')
@login_required
def get_scheduler_coordination_tools():
    """Scheduler Dashboard Phase 3 backend: actionable coordination metadata.

    Safe patch:
    - Keeps this endpoint independent from attachment/file tables.
    - Returns a clear server-log message if unexpected production data causes an issue.
    """
    if not can_use_scheduler_coordination_tools():
        return denied('Scheduler coordination tools are only available to scheduler accounts.')

    try:
        today = get_manila_today()
        week_end = today + timedelta(days=7)
        lookback_start = today - timedelta(days=30)
        lookahead_end = today + timedelta(days=30)
        start_dt, end_dt = build_shift_datetime_bounds(lookback_start, lookahead_end)

        invalid_dashboard_categories = ['Completed', 'Training'] + LEAVE_CATEGORIES

        # Do not selectinload Shift.files here. Coordination tools do not need TSR
        # attachment metadata, and file-table migration should never block the
        # scheduler quick tools panel.
        service_shifts = (
            Shift.query
            .options(
                joinedload(Shift.client),
                joinedload(Shift.product)
            )
            .filter(Shift.client_id.isnot(None))
            .filter(Shift.start_time >= start_dt)
            .filter(Shift.start_time < end_dt)
            .order_by(Shift.start_time.asc())
            .all()
        )

        open_shifts = [
            shift for shift in service_shifts
            if (shift.status or '') not in invalid_dashboard_categories
        ]

        engineers = Engineer.query.order_by(Engineer.branch.asc(), Engineer.name.asc()).all()
        availability_rows = [
            scheduler_engineer_availability_row(engineer, today, week_end, open_shifts)
            for engineer in engineers
        ]

        availability_rank = {'available': 0, 'watch': 1, 'busy': 2}
        availability_rows.sort(
            key=lambda row: (
                availability_rank.get(row.get('availability'), 9),
                row.get('branch') or 'Unassigned',
                row.get('name') or ''
            )
        )

        branch_counts = {}
        for row in availability_rows:
            branch = row.get('branch') or 'Unassigned'
            branch_counts[branch] = branch_counts.get(branch, 0) + 1

        unassigned_rows = []
        action_rows = []

        for shift in open_shifts[:120]:
            row = scheduler_coordination_shift_row(shift)
            assigned_ids = row.get('engineer_ids') or []
            row['can_quick_assign'] = True
            row['can_quick_reschedule'] = True
            row['action_hint'] = 'Assign engineer' if not assigned_ids else 'Reschedule / reassign'

            if not assigned_ids and len(unassigned_rows) < 12:
                unassigned_rows.append(row)

            if len(action_rows) < 30:
                action_rows.append(row)

        return jsonify({
            'status': 'success',
            'phase': 'scheduler-phase-3-coordination-tools-safe',
            'generated_at': get_manila_time().isoformat(),
            'branches': sorted(branch_counts.keys()),
            'branch_counts': dict(sorted(branch_counts.items())),
            'availability': availability_rows,
            'assignable_engineers': [
                {
                    'id': row['engineer_id'],
                    'name': row['name'],
                    'initials': row['initials'],
                    'branch': row['branch'],
                    'availability': row['availability'],
                    'availability_label': row['availability_label'],
                    'today_tasks': row['today_tasks'],
                    'next_7_days': row['next_7_days']
                }
                for row in availability_rows
            ],
            'unassigned_rows': unassigned_rows,
            'action_rows': action_rows
        })

    except Exception as coordination_error:
        print(f"[SCHEDULER-PHASE3] Coordination tools failed: {coordination_error}", flush=True)
        return jsonify({
            'status': 'error',
            'message': 'Scheduler coordination tools could not be loaded. Please check server logs.',
            'phase': 'scheduler-phase-3-coordination-tools-safe'
        }), 500


@app.route('/scheduler_quick_assign_shift' , methods=['POST'])
@login_required
def scheduler_quick_assign_shift():
    """Scheduler Phase 3 quick assign/reassign action for one schedule row."""
    if not can_use_scheduler_coordination_tools():
        return denied('Only scheduler accounts can quick assign schedules.')

    payload = request.get_json(silent=True) or request.form
    shift_id = clean_int(payload.get('shift_id'))
    engineer_ids = scheduler_parse_engineer_id_list(payload.get('engineer_ids') or payload.get('engineers') or payload.get('engineer_id'))

    if not shift_id:
        return jsonify({'status': 'error', 'message': 'Missing schedule ID.'}), 400
    if not engineer_ids:
        return jsonify({'status': 'error', 'message': 'Select at least one engineer.'}), 400

    shift = db.session.get(Shift, shift_id)
    if not shift:
        return jsonify({'status': 'error', 'message': 'Schedule was not found.'}), 404
    if not shift.client_id:
        return jsonify({'status': 'error', 'message': 'Only service schedules can be quick-assigned.'}), 400

    start_dt = shift.start_time
    end_dt = shift.end_time
    if not start_dt or not end_dt:
        return jsonify({'status': 'error', 'message': 'Schedule date/time is incomplete.'}), 400

    ignore_ids = [shift.id]
    if shift.group_id:
        ignore_ids.extend([row.id for row in Shift.query.filter_by(group_id=shift.group_id).all()])

    for engineer_id in engineer_ids:
        collision = scheduler_shift_conflict(engineer_id, start_dt, end_dt, ignore_shift_ids=ignore_ids)
        if collision:
            engineer = db.session.get(Engineer, engineer_id)
            collision_response = handle_schedule_collision_or_travel_warning(collision, engineer, payload)
            if collision_response:
                return collision_response

    old_engineer_ids = get_shift_assigned_engineer_ids(shift)
    delete_shift_engineer_links(shift.id)
    for engineer_id in engineer_ids:
        db.session.add(ShiftEngineer(shift_id=shift.id, engineer_id=engineer_id))
    shift.engineer_id = engineer_ids[0]

    engineer_names = [db.session.get(Engineer, engineer_id).name for engineer_id in engineer_ids if db.session.get(Engineer, engineer_id)]
    db.session.add(ActivityLog(
        user=current_user.username.capitalize(),
        action=f"Quick assigned schedule: {shift.title} on {shift.start_time.strftime('%Y-%m-%d')} to {', '.join(engineer_names) or 'engineer(s)'}"
    ))
    db.session.commit()

    send_schedule_event_notification_async(
        app,
        shift.id,
        engineer_ids,
        'Updated',
        current_user.username if current_user and current_user.is_authenticated else 'Scheduler',
        'Scheduler quick-assigned this schedule.'
    )

    return jsonify({
        'status': 'success',
        'message': 'Schedule assignment updated.',
        'shift_id': shift.id,
        'old_engineer_ids': old_engineer_ids,
        'engineer_ids': engineer_ids,
        'engineers': engineer_names
    })


@app.route('/scheduler_quick_reschedule_shift', methods=['POST'])
@login_required
def scheduler_quick_reschedule_shift():
    """Scheduler Phase 3 quick reschedule action for one schedule row."""
    if not can_use_scheduler_coordination_tools():
        return denied('Only scheduler accounts can quick reschedule schedules.')

    payload = request.get_json(silent=True) or request.form
    shift_id = clean_int(payload.get('shift_id'))
    new_date = parse_date(payload.get('date') or payload.get('start_date'))
    new_start_time = clean_str(payload.get('start_time'))
    new_end_time = clean_str(payload.get('end_time'))

    if not shift_id:
        return jsonify({'status': 'error', 'message': 'Missing schedule ID.'}), 400
    if not new_date or not new_start_time:
        return jsonify({'status': 'error', 'message': 'Select a new date and start time.'}), 400

    shift = db.session.get(Shift, shift_id)
    if not shift:
        return jsonify({'status': 'error', 'message': 'Schedule was not found.'}), 404
    if not shift.client_id:
        return jsonify({'status': 'error', 'message': 'Only service schedules can be quick-rescheduled.'}), 400

    try:
        start_time_obj = datetime.strptime(new_start_time, '%H:%M').time()
        if new_end_time:
            end_time_obj = datetime.strptime(new_end_time, '%H:%M').time()
        else:
            original_duration = (shift.end_time - shift.start_time) if shift.start_time and shift.end_time else timedelta(hours=1)
            calculated_end = datetime.combine(new_date, start_time_obj) + original_duration
            end_time_obj = calculated_end.time()
    except Exception:
        return jsonify({'status': 'error', 'message': 'Invalid time format.'}), 400

    new_start_dt = datetime.combine(new_date, start_time_obj)
    new_end_dt = datetime.combine(new_date, end_time_obj)
    if new_end_dt <= new_start_dt:
        return jsonify({'status': 'error', 'message': 'End time must be later than start time.'}), 400

    assigned_engineer_ids = get_shift_assigned_engineer_ids(shift)
    if not assigned_engineer_ids:
        return jsonify({'status': 'error', 'message': 'Assign an engineer before rescheduling.'}), 400

    ignore_ids = [shift.id]
    if shift.group_id:
        ignore_ids.extend([row.id for row in Shift.query.filter_by(group_id=shift.group_id).all()])

    for engineer_id in assigned_engineer_ids:
        collision = scheduler_shift_conflict(engineer_id, new_start_dt, new_end_dt, ignore_shift_ids=ignore_ids)
        if collision:
            engineer = db.session.get(Engineer, engineer_id)
            collision_response = handle_schedule_collision_or_travel_warning(collision, engineer, payload)
            if collision_response:
                return collision_response

    old_date_label = shift.start_time.strftime('%Y-%m-%d %H:%M') if shift.start_time else 'old date'
    shift.start_time = new_start_dt
    shift.end_time = new_end_dt

    engineer_names = [db.session.get(Engineer, engineer_id).name for engineer_id in assigned_engineer_ids if db.session.get(Engineer, engineer_id)]
    db.session.add(ActivityLog(
        user=current_user.username.capitalize(),
        action=f"Quick rescheduled schedule: {shift.title} from {old_date_label} to {new_start_dt.strftime('%Y-%m-%d %H:%M')} for {', '.join(engineer_names) or 'engineer(s)'}"
    ))
    db.session.commit()

    send_schedule_event_notification_async(
        app,
        shift.id,
        assigned_engineer_ids,
        'Updated',
        current_user.username if current_user and current_user.is_authenticated else 'Scheduler',
        'Scheduler quick-rescheduled this schedule.'
    )

    return jsonify({
        'status': 'success',
        'message': 'Schedule rescheduled.',
        'shift_id': shift.id,
        'date': new_date.isoformat(),
        'start_time': new_start_time,
        'end_time': new_end_dt.strftime('%H:%M')
    })



# --- MANAGER DASHBOARD PHASE M1: EXECUTIVE FOUNDATION ---

def manager_shift_priority_row(shift, reason='', severity='info'):
    """Serialize a schedule row for manager executive dashboard alerts."""
    row = dashboard_team_shift_row(shift)
    row['reason'] = reason
    row['severity'] = severity
    if shift and getattr(shift, 'start_time', None):
        row['days_old'] = max((get_manila_today() - shift.start_time.date()).days, 0)
    else:
        row['days_old'] = 0
    return row


@app.route('/get_manager_dashboard_summary')
@login_required
def get_manager_dashboard_summary():
    """Manager Dashboard Phase M1 backend summary.

    Executive foundation endpoint:
    - company-wide operational KPIs
    - branch workload summary
    - engineer utilization snapshot
    - priority alerts for overdue, missing TSR, waiting P.O/parts, and unassigned work

    This is read-only and uses existing Shift/Engineer/Client/Product data only.
    No database schema changes.
    """
    if not can_view_manager_dashboard():
        return denied('Manager dashboard summary is only available to manager-authorized accounts.')

    ensure_shift_file_original_filename_column()

    today = get_manila_today()
    month_start = today.replace(day=1)
    next_month = (month_start.replace(day=28) + timedelta(days=4)).replace(day=1)
    lookback_start = today - timedelta(days=90)
    lookahead_end = today + timedelta(days=60)
    start_dt, end_dt = build_shift_datetime_bounds(lookback_start, lookahead_end)

    invalid_dashboard_categories = ['Completed', 'Training'] + LEAVE_CATEGORIES
    waiting_statuses = {'Waiting for P.O', 'Waiting for Parts'}

    base_query = (
        Shift.query
        .options(
            joinedload(Shift.client),
            joinedload(Shift.product),
            selectinload(Shift.files)
        )
        .filter(Shift.client_id.isnot(None))
        .filter(Shift.start_time >= start_dt)
        .filter(Shift.start_time < end_dt)
        .order_by(Shift.start_time.desc())
    )

    base_query = analytics_scope_query(base_query)

    service_shifts = list({shift.id: shift for shift in base_query.limit(2000).all()}.values())

    open_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') not in invalid_dashboard_categories
    ]

    overdue_shifts = [
        shift for shift in open_shifts
        if shift.start_time and shift.start_time.date() < today
    ]

    waiting_shifts = [
        shift for shift in open_shifts
        if (shift.status or '') in waiting_statuses
    ]

    completed_this_month = [
        shift for shift in service_shifts
        if (
            (shift.status or '') == 'Completed' and
            shift.start_time and
            month_start <= shift.start_time.date() < next_month
        )
    ]

    pending_tsr_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') == 'Completed' and not shift_has_tsr_file(shift)
    ]

    unassigned_shifts = [
        shift for shift in open_shifts
        if not get_shift_engineer_records(shift)
    ]

    branch_summary = {}
    engineer_load = {}

    def ensure_branch(branch_name):
        branch_name = branch_name or 'Unassigned'
        branch_summary.setdefault(branch_name, {
            'branch': branch_name,
            'open_tasks': 0,
            'overdue': 0,
            'waiting_items': 0,
            'pending_tsr': 0,
            'engineers': 0
        })
        return branch_summary[branch_name]

    for shift in open_shifts:
        engineers = get_shift_engineer_records(shift)
        if not engineers:
            branch_row = ensure_branch('Unassigned')
            branch_row['open_tasks'] += 1
            if shift.start_time and shift.start_time.date() < today:
                branch_row['overdue'] += 1
            if (shift.status or '') in waiting_statuses:
                branch_row['waiting_items'] += 1
            continue

        for engineer in engineers:
            branch = engineer.branch or 'Unassigned'
            branch_row = ensure_branch(branch)
            branch_row['open_tasks'] += 1
            if shift.start_time and shift.start_time.date() < today:
                branch_row['overdue'] += 1
            if (shift.status or '') in waiting_statuses:
                branch_row['waiting_items'] += 1

            if engineer.id not in engineer_load:
                engineer_load[engineer.id] = {
                    'engineer_id': engineer.id,
                    'name': engineer.name,
                    'branch': branch,
                    'open_tasks': 0,
                    'overdue': 0,
                    'waiting_items': 0,
                    'completed_this_month': 0,
                    'utilization_level': 'normal'
                }

            row = engineer_load[engineer.id]
            row['open_tasks'] += 1
            if shift.start_time and shift.start_time.date() < today:
                row['overdue'] += 1
            if (shift.status or '') in waiting_statuses:
                row['waiting_items'] += 1

    for shift in completed_this_month:
        for engineer in get_shift_engineer_records(shift):
            if engineer.id not in engineer_load:
                engineer_load[engineer.id] = {
                    'engineer_id': engineer.id,
                    'name': engineer.name,
                    'branch': engineer.branch or 'Unassigned',
                    'open_tasks': 0,
                    'overdue': 0,
                    'waiting_items': 0,
                    'completed_this_month': 0,
                    'utilization_level': 'normal'
                }
            engineer_load[engineer.id]['completed_this_month'] += 1

    for shift in pending_tsr_shifts:
        engineers = get_shift_engineer_records(shift)
        if not engineers:
            ensure_branch('Unassigned')['pending_tsr'] += 1
            continue
        for engineer in engineers:
            ensure_branch(engineer.branch or 'Unassigned')['pending_tsr'] += 1

    for engineer in Engineer.query.all():
        ensure_branch(engineer.branch or 'Unassigned')['engineers'] += 1

    engineer_rows = list(engineer_load.values())
    if engineer_rows:
        avg_open = sum(row['open_tasks'] for row in engineer_rows) / max(len(engineer_rows), 1)
        for row in engineer_rows:
            if row['overdue'] >= 3 or row['open_tasks'] >= max(8, avg_open * 1.8):
                row['utilization_level'] = 'high'
            elif row['overdue'] >= 1 or row['waiting_items'] >= 2 or row['open_tasks'] >= max(4, avg_open * 1.3):
                row['utilization_level'] = 'watch'

    engineer_rows.sort(key=lambda row: (-row['overdue'], -row['open_tasks'], -row['completed_this_month'], row['name']))

    priority_alerts = []
    priority_alerts.extend([
        manager_shift_priority_row(
            shift,
            f"Overdue by {max((today - shift.start_time.date()).days, 0)} day(s)" if shift.start_time else 'Overdue schedule',
            'danger'
        )
        for shift in sorted(overdue_shifts, key=lambda s: s.start_time or datetime.min)[:8]
    ])
    priority_alerts.extend([
        manager_shift_priority_row(shift, 'Completed schedule missing TSR', 'warning')
        for shift in sorted(pending_tsr_shifts, key=lambda s: s.start_time or datetime.min)[:8]
    ])
    priority_alerts.extend([
        manager_shift_priority_row(shift, shift.status or 'Waiting item', 'info')
        for shift in sorted(waiting_shifts, key=lambda s: s.start_time or datetime.min)[:6]
    ])
    priority_alerts.extend([
        manager_shift_priority_row(shift, 'No engineer assigned', 'danger')
        for shift in sorted(unassigned_shifts, key=lambda s: s.start_time or datetime.max)[:6]
    ])

    operational_risk_score = (
        (len(overdue_shifts) * 3) +
        (len(pending_tsr_shifts) * 2) +
        (len(waiting_shifts) * 2) +
        (len(unassigned_shifts) * 3) +
        len([row for row in engineer_rows if row.get('utilization_level') == 'high'])
    )

    if operational_risk_score >= 24:
        risk_level = 'critical'
        risk_label = 'Critical operational attention'
    elif operational_risk_score >= 10:
        risk_level = 'watch'
        risk_label = 'Management watch needed'
    else:
        risk_level = 'stable'
        risk_label = 'Operations stable'

    return jsonify({
        'status': 'success',
        'phase': 'manager-phase-m1-executive-foundation',
        'generated_at': get_manila_time().isoformat(),
        'manager': {
            'username': getattr(current_user, 'username', ''),
            'display_role': get_display_role(current_user)
        },
        'risk': {
            'score': operational_risk_score,
            'level': risk_level,
            'label': risk_label
        },
        'counts': {
            'open_schedules': len(open_shifts),
            'overdue_schedules': len(overdue_shifts),
            'pending_tsr': len(pending_tsr_shifts),
            'waiting_items': len(waiting_shifts),
            'completed_this_month': len(completed_this_month),
            'unassigned_schedules': len(unassigned_shifts),
            'active_engineers': len(engineer_rows),
            'clients': Client.query.count(),
            'products': Product.query.count()
        },
        'branch_summary': sorted(
            branch_summary.values(),
            key=lambda row: (-row.get('open_tasks', 0), row.get('branch') or '')
        ),
        'engineer_utilization': engineer_rows[:20],
        'priority_alerts': priority_alerts[:20],
        'overdue_rows': [
            manager_shift_priority_row(shift, 'Overdue schedule', 'danger')
            for shift in sorted(overdue_shifts, key=lambda s: s.start_time or datetime.min)[:12]
        ],
        'pending_tsr_rows': [
            manager_shift_priority_row(shift, 'Completed schedule missing TSR', 'warning')
            for shift in sorted(pending_tsr_shifts, key=lambda s: s.start_time or datetime.min)[:12]
        ],
        'waiting_rows': [
            manager_shift_priority_row(shift, shift.status or 'Waiting item', 'info')
            for shift in sorted(waiting_shifts, key=lambda s: s.start_time or datetime.min)[:12]
        ]
    })





# --- MANAGER DASHBOARD PHASE M2: CLEAN TSR INTELLIGENCE ---

def manager_tsr_signal_row(shift, signal_label='', severity='warning'):
    """Compact TSR intelligence row for manager dashboard."""
    row = manager_shift_priority_row(shift, signal_label, severity)
    # Keep manager TSR rows compact and frontend-safe.
    row['signal_label'] = signal_label
    row['severity'] = severity
    return row


@app.route('/get_manager_tsr_intelligence')
@login_required
def get_manager_tsr_intelligence():
    """Manager Dashboard Phase M2 backend: clean TSR intelligence.

    Intentionally compact:
    - Pending TSR aging
    - Repeat equipment/client service signals
    - Frequent complaint/service issue signals from TSR knowledge base
    - top 5 rows only per signal

    No schema changes. No large tables.
    """
    if not can_view_manager_dashboard():
        return denied('Manager TSR intelligence is only available to manager-authorized accounts.')

    ensure_shift_file_original_filename_column()
    ensure_tsr_knowledge_entry_table()

    today = get_manila_today()
    lookback_start = today - timedelta(days=180)
    lookahead_end = today + timedelta(days=30)
    start_dt, end_dt = build_shift_datetime_bounds(lookback_start, lookahead_end)

    service_query = (
        Shift.query
        .options(
            joinedload(Shift.client),
            joinedload(Shift.product),
            selectinload(Shift.files)
        )
        .filter(Shift.client_id.isnot(None))
        .filter(Shift.start_time >= start_dt)
        .filter(Shift.start_time < end_dt)
        .order_by(Shift.start_time.desc())
    )
    service_query = analytics_scope_query(service_query)
    service_shifts = list({shift.id: shift for shift in service_query.limit(2000).all()}.values())

    completed_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') == 'Completed'
    ]

    pending_tsr_shifts = [
        shift for shift in completed_shifts
        if not shift_has_tsr_file(shift)
    ]

    pending_tsr_shifts.sort(
        key=lambda shift: shift.start_time or datetime.min
    )

    aged_pending_tsr_rows = [
        manager_tsr_signal_row(
            shift,
            f"No TSR for {max((today - shift.start_time.date()).days, 0)} day(s)" if shift.start_time else 'Missing TSR',
            'danger' if shift.start_time and (today - shift.start_time.date()).days >= 7 else 'warning'
        )
        for shift in pending_tsr_shifts[:5]
    ]

    completed_with_tsr = [
        shift for shift in completed_shifts
        if shift_has_tsr_file(shift)
    ]
    completion_total = len(completed_shifts)
    completion_rate = round((len(completed_with_tsr) / completion_total) * 100, 1) if completion_total else 100.0

    # Repeat equipment/client service signal.
    repeat_map = {}
    for shift in service_shifts:
        if not shift.start_time or not shift.product_id:
            continue

        serial = shift.product.serial_number if shift.product else (shift.product_id or '')
        product_name = shift.product.name if shift.product else (shift.product_id or 'Unknown Equipment')
        client_name = shift.client.name if shift.client else 'N/A'
        key = f"{shift.client_id or 'no-client'}::{serial or shift.product_id}"

        if key not in repeat_map:
            repeat_map[key] = {
                'client': client_name,
                'product': product_name,
                'serial': serial,
                'service_count': 0,
                'last_service': '',
                'latest_date': None,
                'tasks': set()
            }

        row = repeat_map[key]
        row['service_count'] += 1
        row['tasks'].add(shift.title or '')
        if not row['latest_date'] or shift.start_time > row['latest_date']:
            row['latest_date'] = shift.start_time
            row['last_service'] = shift.start_time.strftime('%Y-%m-%d')

    repeat_equipment_rows = []
    for row in repeat_map.values():
        if row['service_count'] < 3:
            continue
        repeat_equipment_rows.append({
            'client': row['client'],
            'product': row['product'],
            'serial': row['serial'],
            'service_count': row['service_count'],
            'last_service': row['last_service'],
            'signal_label': f"{row['service_count']} services in 180 days",
            'tasks': ', '.join(sorted([task for task in row['tasks'] if task])[:3])
        })

    repeat_equipment_rows.sort(key=lambda row: (-row['service_count'], row['client'], row['product']))

    # Frequent issue signal from TSR Knowledge Base.
    knowledge_start_dt = datetime.combine(lookback_start, datetime.min.time())
    knowledge_entries = (
        TsrKnowledgeEntry.query
        .filter(TsrKnowledgeEntry.created_at >= knowledge_start_dt)
        .order_by(TsrKnowledgeEntry.created_at.desc())
        .limit(500)
        .all()
    )

    issue_map = {}
    for entry in knowledge_entries:
        complaint = clean_str(getattr(entry, 'complaint', None)) or ''
        if not complaint:
            continue

        # Compact grouping: normalize first 90 chars to avoid huge text blocks.
        issue_key = re.sub(r'\s+', ' ', complaint.strip().lower())[:90]
        if not issue_key:
            continue

        if issue_key not in issue_map:
            issue_map[issue_key] = {
                'issue': complaint[:180],
                'count': 0,
                'latest': getattr(entry, 'created_at', None),
                'clients': set(),
                'products': set()
            }

        row = issue_map[issue_key]
        row['count'] += 1
        if getattr(entry, 'client_name', None):
            row['clients'].add(entry.client_name)
        if getattr(entry, 'product_name', None):
            row['products'].add(entry.product_name)
        if getattr(entry, 'created_at', None) and (not row['latest'] or entry.created_at > row['latest']):
            row['latest'] = entry.created_at

    frequent_issue_rows = []
    for row in issue_map.values():
        if row['count'] < 2:
            continue
        frequent_issue_rows.append({
            'issue': row['issue'],
            'count': row['count'],
            'latest': row['latest'].strftime('%Y-%m-%d') if row['latest'] else '',
            'clients': ', '.join(sorted(row['clients'])[:3]),
            'products': ', '.join(sorted(row['products'])[:3]),
            'signal_label': f"{row['count']} similar TSR complaint(s)"
        })

    frequent_issue_rows.sort(key=lambda row: (-row['count'], row['issue']))

    risk_score = (
        len([shift for shift in pending_tsr_shifts if shift.start_time and (today - shift.start_time.date()).days >= 7]) * 3 +
        len([shift for shift in pending_tsr_shifts if shift.start_time and (today - shift.start_time.date()).days >= 3]) +
        len(repeat_equipment_rows) * 2 +
        len(frequent_issue_rows)
    )

    if risk_score >= 12:
        risk_level = 'critical'
        risk_label = 'TSR attention needed'
    elif risk_score >= 5:
        risk_level = 'watch'
        risk_label = 'TSR watchlist'
    else:
        risk_level = 'stable'
        risk_label = 'TSR stable'

    return jsonify({
        'status': 'success',
        'phase': 'manager-phase-m2-clean-tsr-intelligence',
        'generated_at': get_manila_time().isoformat(),
        'risk': {
            'score': risk_score,
            'level': risk_level,
            'label': risk_label
        },
        'counts': {
            'completed_services': completion_total,
            'completed_with_tsr': len(completed_with_tsr),
            'pending_tsr': len(pending_tsr_shifts),
            'tsr_completion_rate': completion_rate,
            'repeat_equipment_signals': len(repeat_equipment_rows),
            'frequent_issue_signals': len(frequent_issue_rows)
        },
        'signals': {
            'aged_pending_tsr': aged_pending_tsr_rows,
            'repeat_equipment': repeat_equipment_rows[:5],
            'frequent_issues': frequent_issue_rows[:5]
        }
    })





# --- MANAGER DASHBOARD PHASE M4: CLEAN BILLING & SERVICE VISIBILITY ---

def manager_billing_shift_row(shift, signal_label='', severity='info'):
    """Compact billing/service visibility row for manager dashboard."""
    row = manager_shift_priority_row(shift, signal_label, severity)
    row['signal_label'] = signal_label
    row['severity'] = severity
    row['billing_type'] = manager_infer_shift_billing_type(shift)
    return row


def manager_infer_shift_billing_type(shift):
    """Infer billing visibility from existing schedule status/title/attached TSR filename.

    This intentionally avoids schema changes. It uses current operational fields:
    - Waiting for P.O => PO / billable follow-up signal
    - Warranty / FOC text => non-billed exposure
    - TSR_B / billed filename convention => billed
    """
    status_text = (getattr(shift, 'status', '') or '').strip().lower()
    title_text = (getattr(shift, 'title', '') or '').strip().lower()
    combined = f"{status_text} {title_text}"

    file_names = []
    for file_rec in getattr(shift, 'files', []) or []:
        file_names.append((get_shift_file_display_name(file_rec) or '').lower())
        file_names.append((getattr(file_rec, 'filename', '') or '').lower())
    file_text = " ".join(file_names)
    combined_all = f"{combined} {file_text}"

    if 'waiting for p.o' in status_text or 'waiting for po' in status_text or ' purchase order' in combined_all or ' po ' in f" {combined_all} ":
        return 'po_followup'
    if 'warranty' in combined_all:
        return 'warranty'
    if 'foc' in combined_all or 'free of charge' in combined_all:
        return 'foc'
    if 'ncs_tsr_b' in combined_all or '_b_shimadzu' in combined_all or 'billable' in combined_all or 'billed' in combined_all:
        return 'billed'
    return 'standard'


@app.route('/get_manager_billing_visibility')
@login_required
def get_manager_billing_visibility():
    """Manager Dashboard Phase M4 backend: clean billing and service visibility.

    Intentionally compact:
    - billed vs non-billed signals
    - warranty / FOC exposure
    - waiting P.O jobs
    - service category mix via schedule title/status
    - top 5 rows only per signal

    No database schema changes.
    """
    if not can_view_manager_dashboard():
        return denied('Manager billing visibility is only available to manager-authorized accounts.')

    ensure_shift_file_original_filename_column()

    today = get_manila_today()
    lookback_start = today - timedelta(days=180)
    lookahead_end = today + timedelta(days=60)
    start_dt, end_dt = build_shift_datetime_bounds(lookback_start, lookahead_end)

    service_query = (
        Shift.query
        .options(
            joinedload(Shift.client),
            joinedload(Shift.product),
            selectinload(Shift.files)
        )
        .filter(Shift.client_id.isnot(None))
        .filter(Shift.start_time >= start_dt)
        .filter(Shift.start_time < end_dt)
        .order_by(Shift.start_time.desc())
    )
    service_query = analytics_scope_query(service_query)
    service_shifts = list({shift.id: shift for shift in service_query.limit(2000).all()}.values())

    open_status_exclusions = ['Completed', 'Training'] + LEAVE_CATEGORIES
    open_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') not in open_status_exclusions
    ]

    completed_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') == 'Completed'
    ]

    billing_rows = []
    warranty_rows = []
    foc_rows = []
    po_waiting_rows = []
    standard_rows = []

    billing_counts = {
        'billed_signals': 0,
        'standard_services': 0,
        'warranty': 0,
        'foc': 0,
        'waiting_po': 0
    }

    service_mix = {}
    status_mix = {}

    for shift in service_shifts:
        billing_type = manager_infer_shift_billing_type(shift)

        if billing_type == 'billed':
            billing_counts['billed_signals'] += 1
            billing_rows.append(manager_billing_shift_row(shift, 'Billed TSR / billable signal', 'success'))
        elif billing_type == 'warranty':
            billing_counts['warranty'] += 1
            warranty_rows.append(manager_billing_shift_row(shift, 'Warranty service exposure', 'warning'))
        elif billing_type == 'foc':
            billing_counts['foc'] += 1
            foc_rows.append(manager_billing_shift_row(shift, 'FOC / non-billed exposure', 'warning'))
        elif billing_type == 'po_followup':
            billing_counts['waiting_po'] += 1
            po_waiting_rows.append(manager_billing_shift_row(shift, 'Waiting for P.O follow-up', 'danger'))
        else:
            billing_counts['standard_services'] += 1
            standard_rows.append(manager_billing_shift_row(shift, 'Standard service', 'info'))

        task_label = clean_str(getattr(shift, 'title', None)) or 'Unspecified Service'
        service_mix[task_label] = service_mix.get(task_label, 0) + 1

        status_label = clean_str(getattr(shift, 'status', None)) or 'No Status'
        status_mix[status_label] = status_mix.get(status_label, 0) + 1

    non_billed_exposure = billing_counts['warranty'] + billing_counts['foc']
    total_visibility_rows = len(service_shifts)
    billed_signal_rate = round((billing_counts['billed_signals'] / total_visibility_rows) * 100, 1) if total_visibility_rows else 0.0
    non_billed_rate = round((non_billed_exposure / total_visibility_rows) * 100, 1) if total_visibility_rows else 0.0

    # Keep service category mix compact and useful.
    service_mix_rows = [
        {'label': label, 'count': count}
        for label, count in sorted(service_mix.items(), key=lambda item: (-item[1], item[0]))[:5]
    ]
    status_mix_rows = [
        {'label': label, 'count': count}
        for label, count in sorted(status_mix.items(), key=lambda item: (-item[1], item[0]))[:5]
    ]

    risk_score = (
        billing_counts['waiting_po'] * 3 +
        non_billed_exposure * 2 +
        len([shift for shift in open_shifts if manager_infer_shift_billing_type(shift) == 'po_followup'])
    )

    if risk_score >= 15:
        risk_level = 'critical'
        risk_label = 'Billing attention needed'
    elif risk_score >= 6:
        risk_level = 'watch'
        risk_label = 'Billing watchlist'
    else:
        risk_level = 'stable'
        risk_label = 'Billing stable'

    return jsonify({
        'status': 'success',
        'phase': 'manager-phase-m4-clean-billing-service-visibility',
        'generated_at': get_manila_time().isoformat(),
        'risk': {
            'score': risk_score,
            'level': risk_level,
            'label': risk_label
        },
        'counts': {
            'service_rows_reviewed': total_visibility_rows,
            'open_services': len(open_shifts),
            'completed_services': len(completed_shifts),
            'billed_signals': billing_counts['billed_signals'],
            'standard_services': billing_counts['standard_services'],
            'non_billed_exposure': non_billed_exposure,
            'warranty': billing_counts['warranty'],
            'foc': billing_counts['foc'],
            'waiting_po': billing_counts['waiting_po'],
            'billed_signal_rate': billed_signal_rate,
            'non_billed_rate': non_billed_rate
        },
        'signals': {
            'waiting_po': sorted(po_waiting_rows, key=lambda row: row.get('date') or '')[:5],
            'non_billed': (warranty_rows + foc_rows)[:5],
            'billed': billing_rows[:5],
            'service_mix': service_mix_rows,
            'status_mix': status_mix_rows
        }
    })





# --- MANAGER DASHBOARD PHASE M5: LIGHTWEIGHT EXECUTIVE WATCHLIST ---

def manager_watchlist_chip(label, value, tone='stable'):
    """Small executive insight chip for manager dashboard.

    Tones: stable, watch, critical, info
    """
    return {
        'label': label,
        'value': value,
        'tone': tone
    }


@app.route('/get_manager_executive_watchlist')
@login_required
def get_manager_executive_watchlist():
    """Manager Dashboard Phase M5 backend: lightweight executive watchlist.

    Final manager backend polish:
    - no noisy alert center
    - only top executive-level signals
    - top 5 watchlist rows maximum
    - insight chips instead of large tables
    - reuses existing Shift/TSR data only
    """
    if not can_view_manager_dashboard():
        return denied('Manager executive watchlist is only available to manager-authorized accounts.')

    ensure_shift_file_original_filename_column()
    ensure_tsr_knowledge_entry_table()

    today = get_manila_today()
    lookback_start = today - timedelta(days=180)
    lookahead_end = today + timedelta(days=60)
    start_dt, end_dt = build_shift_datetime_bounds(lookback_start, lookahead_end)

    invalid_dashboard_categories = ['Completed', 'Training'] + LEAVE_CATEGORIES
    waiting_statuses = {'Waiting for P.O', 'Waiting for Parts'}

    service_query = (
        Shift.query
        .options(
            joinedload(Shift.client),
            joinedload(Shift.product),
            selectinload(Shift.files)
        )
        .filter(Shift.client_id.isnot(None))
        .filter(Shift.start_time >= start_dt)
        .filter(Shift.start_time < end_dt)
        .order_by(Shift.start_time.desc())
    )
    service_query = analytics_scope_query(service_query)
    service_shifts = list({shift.id: shift for shift in service_query.limit(2000).all()}.values())

    open_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') not in invalid_dashboard_categories
    ]

    overdue_shifts = [
        shift for shift in open_shifts
        if shift.start_time and shift.start_time.date() < today
    ]

    severe_overdue_shifts = [
        shift for shift in overdue_shifts
        if shift.start_time and (today - shift.start_time.date()).days >= 7
    ]

    pending_tsr_shifts = [
        shift for shift in service_shifts
        if (shift.status or '') == 'Completed' and not shift_has_tsr_file(shift)
    ]

    severe_tsr_aging_shifts = [
        shift for shift in pending_tsr_shifts
        if shift.start_time and (today - shift.start_time.date()).days >= 7
    ]

    waiting_po_shifts = [
        shift for shift in open_shifts
        if (shift.status or '').strip().lower() in {'waiting for p.o', 'waiting for po'}
    ]

    waiting_blocker_shifts = [
        shift for shift in open_shifts
        if (shift.status or '') in waiting_statuses
    ]

    # Critical repeat equipment: same client + same product/serial with many visits.
    repeat_map = {}
    for shift in service_shifts:
        if not shift.start_time or not shift.product_id:
            continue

        product_label = shift.product.name if shift.product else (shift.product_id or 'Unknown Equipment')
        serial_label = shift.product.serial_number if shift.product else (shift.product_id or '')
        client_label = shift.client.name if shift.client else 'N/A'
        key = f"{shift.client_id or 'no-client'}::{serial_label or shift.product_id}"

        if key not in repeat_map:
            repeat_map[key] = {
                'client': client_label,
                'product': product_label,
                'serial': serial_label,
                'service_count': 0,
                'last_service': '',
                'latest_date': None,
                'tasks': set()
            }

        row = repeat_map[key]
        row['service_count'] += 1
        row['tasks'].add(shift.title or '')
        if not row['latest_date'] or shift.start_time > row['latest_date']:
            row['latest_date'] = shift.start_time
            row['last_service'] = shift.start_time.strftime('%Y-%m-%d')

    critical_repeat_equipment = []
    for row in repeat_map.values():
        if row['service_count'] >= 4:
            critical_repeat_equipment.append({
                'type': 'repeat_equipment',
                'title': row['product'] or 'Repeat equipment',
                'subtitle': row['client'],
                'detail': f"{row['service_count']} services in 180 days",
                'meta': row['serial'] or row['last_service'],
                'tone': 'critical' if row['service_count'] >= 6 else 'watch',
                'count': row['service_count']
            })

    critical_repeat_equipment.sort(key=lambda row: (-row['count'], row['subtitle'], row['title']))

    # High-risk clients: many overdue / pending TSR / waiting blockers.
    client_risk = {}
    for shift in service_shifts:
        if not shift.client:
            continue
        client_name = shift.client.name
        if client_name not in client_risk:
            client_risk[client_name] = {
                'client': client_name,
                'overdue': 0,
                'pending_tsr': 0,
                'waiting': 0,
                'open': 0,
                'score': 0,
                'latest_date': None
            }

        row = client_risk[client_name]
        if shift.start_time and (not row['latest_date'] or shift.start_time > row['latest_date']):
            row['latest_date'] = shift.start_time

        if shift in open_shifts:
            row['open'] += 1
        if shift in severe_overdue_shifts:
            row['overdue'] += 1
        if shift in severe_tsr_aging_shifts:
            row['pending_tsr'] += 1
        if shift in waiting_blocker_shifts:
            row['waiting'] += 1

    high_risk_clients = []
    for row in client_risk.values():
        row['score'] = (row['overdue'] * 3) + (row['pending_tsr'] * 2) + (row['waiting'] * 2) + row['open']
        if row['score'] < 5:
            continue

        high_risk_clients.append({
            'type': 'high_risk_client',
            'title': row['client'],
            'subtitle': 'Client watch signal',
            'detail': f"{row['open']} open • {row['overdue']} severe overdue • {row['pending_tsr']} aged TSR",
            'meta': f"Score {row['score']}",
            'tone': 'critical' if row['score'] >= 10 else 'watch',
            'count': row['score']
        })

    high_risk_clients.sort(key=lambda row: (-row['count'], row['title']))

    # Severe TSR pattern summary, compact only.
    severe_tsr_rows = [
        manager_tsr_signal_row(
            shift,
            f"TSR overdue {max((today - shift.start_time.date()).days, 0)} day(s)" if shift.start_time else 'TSR overdue',
            'danger'
        )
        for shift in sorted(severe_tsr_aging_shifts, key=lambda s: s.start_time or datetime.min)[:5]
    ]

    # Build one compact watchlist: highest executive value first.
    watchlist = []
    watchlist.extend(critical_repeat_equipment[:3])
    watchlist.extend(high_risk_clients[:3])

    for shift in severe_overdue_shifts[:3]:
        watchlist.append({
            'type': 'severe_overdue',
            'title': shift.client.name if shift.client else 'Overdue schedule',
            'subtitle': shift.title or '',
            'detail': f"Open for {max((today - shift.start_time.date()).days, 0)} day(s)" if shift.start_time else 'Severe overdue',
            'meta': shift.start_time.strftime('%Y-%m-%d') if shift.start_time else '',
            'tone': 'critical',
            'count': max((today - shift.start_time.date()).days, 0) if shift.start_time else 0
        })

    watchlist.sort(key=lambda row: (
        0 if row.get('tone') == 'critical' else 1,
        -int(row.get('count') or 0),
        row.get('title') or ''
    ))
    watchlist = watchlist[:5]

    chips = [
        manager_watchlist_chip(
            'Repeat equipment',
            len(critical_repeat_equipment),
            'critical' if len(critical_repeat_equipment) >= 3 else ('watch' if critical_repeat_equipment else 'stable')
        ),
        manager_watchlist_chip(
            'High-risk clients',
            len(high_risk_clients),
            'critical' if len(high_risk_clients) >= 3 else ('watch' if high_risk_clients else 'stable')
        ),
        manager_watchlist_chip(
            'Aged TSR',
            len(severe_tsr_aging_shifts),
            'critical' if len(severe_tsr_aging_shifts) >= 5 else ('watch' if severe_tsr_aging_shifts else 'stable')
        ),
        manager_watchlist_chip(
            'Waiting P.O',
            len(waiting_po_shifts),
            'watch' if waiting_po_shifts else 'stable'
        )
    ]

    executive_score = (
        len(critical_repeat_equipment) * 3 +
        len(high_risk_clients) * 3 +
        len(severe_tsr_aging_shifts) * 2 +
        len(severe_overdue_shifts) * 2 +
        len(waiting_po_shifts)
    )

    if executive_score >= 18:
        risk_level = 'critical'
        risk_label = 'Executive attention needed'
    elif executive_score >= 7:
        risk_level = 'watch'
        risk_label = 'Executive watchlist'
    else:
        risk_level = 'stable'
        risk_label = 'Executive view stable'

    return jsonify({
        'status': 'success',
        'phase': 'manager-phase-m5-lightweight-executive-watchlist',
        'generated_at': get_manila_time().isoformat(),
        'risk': {
            'score': executive_score,
            'level': risk_level,
            'label': risk_label
        },
        'chips': chips,
        'counts': {
            'watchlist_items': len(watchlist),
            'critical_repeat_equipment': len(critical_repeat_equipment),
            'high_risk_clients': len(high_risk_clients),
            'severe_overdue': len(severe_overdue_shifts),
            'aged_tsr': len(severe_tsr_aging_shifts),
            'waiting_po': len(waiting_po_shifts)
        },
        'watchlist': watchlist,
        'top_repeat_equipment': critical_repeat_equipment[:5],
        'top_high_risk_clients': high_risk_clients[:5],
        'severe_tsr_rows': severe_tsr_rows
    })





def reimbursement_parse_date(value, field_name):
    """Parse YYYY-MM-DD date strings for reimbursement filters."""
    value = (value or '').strip()
    if not value:
        raise ValueError(f"{field_name} is required")
    try:
        return datetime.strptime(value, '%Y-%m-%d').date()
    except ValueError as exc:
        raise ValueError(f"{field_name} must be YYYY-MM-DD") from exc


def reimbursement_is_work_expense_schedule(shift):
    """Return False for non-expense schedule rows such as holidays and leaves."""
    text_parts = [
        getattr(shift, 'title', '') or '',
        getattr(shift, 'task', '') or '',
        getattr(shift, 'status', '') or '',
        getattr(shift, 'type', '') or '',
        getattr(shift, 'category', '') or ''
    ]
    haystack = ' '.join(str(part).strip().lower() for part in text_parts if part)
    if not haystack:
        return True

    excluded_keywords = (
        'holiday',
        'leave',
        'vacation leave',
        'sick leave',
        'emergency leave',
        'birthday leave',
        'maternity leave',
        'paternity leave',
        'rest day',
        'day off',
        'offset',
        'official business leave'
    )
    return not any(keyword in haystack for keyword in excluded_keywords)


def reimbursement_shift_row(shift, display_engineer_names=None):
    """Build one reimbursement row from a schedule without changing schedule data.

    Phase 6 safety:
    - Reimbursement rows are personal documents, so engineer-facing views may pass
      display_engineer_names to avoid listing every engineer assigned to a shared schedule.
    - Admin/all-scope views can omit it and retain the original full assigned-engineer list.
    """
    client_name = shift.client.name if getattr(shift, 'client', None) else ''
    product_name = shift.product.name if getattr(shift, 'product', None) else ''
    serial_number = shift.product.serial_number if getattr(shift, 'product', None) else (shift.product_id or '')

    if display_engineer_names is not None:
        engineer_names = [name for name in display_engineer_names if name]
    else:
        engineer_names = []
        for engineer_id in get_shift_assigned_engineer_ids(shift):
            engineer = db.session.get(Engineer, engineer_id)
            if engineer and engineer.name:
                engineer_names.append(engineer.name)

    engineer_names = list(dict.fromkeys(engineer_names))

    return {
        'shift_id': shift.id,
        'date': shift.start_time.strftime('%Y-%m-%d') if shift.start_time else '',
        'start_time': shift.start_time.strftime('%H:%M') if shift.start_time else '',
        'end_time': shift.end_time.strftime('%H:%M') if shift.end_time else '',
        'client': client_name,
        'product': product_name,
        'serial_number': serial_number,
        'task': shift.title or '',
        'status': shift.status or '',
        'engineers': engineer_names,
        'remarks': ''
    }


REIMBURSEMENT_EXPENSE_FIELDS = (
    'representation',
    'car_repair',
    'toll_fee',
    'gasoline',
    'transpo',
    'office_supplies',
    'parking',
    'per_diem',
    'parking_coding',
    'others_misc'
)


def reimbursement_money_value(value):
    """Normalize reimbursement amount values from the frontend."""
    if value is None:
        return 0.0
    if isinstance(value, (int, float)):
        return float(value or 0)
    cleaned = str(value).replace(',', '').replace('₱', '').strip()
    if not cleaned:
        return 0.0
    try:
        return round(float(cleaned), 2)
    except (TypeError, ValueError):
        return 0.0


def reimbursement_row_has_claim_amount(row):
    """Return True when a reimbursement row has any positive claim amount."""
    if not row:
        return False

    if reimbursement_money_value(getattr(row, 'row_total', 0)) > 0:
        return True

    return any(
        reimbursement_money_value(getattr(row, field, 0)) > 0
        for field in REIMBURSEMENT_EXPENSE_FIELDS
    )


def reimbursement_get_personal_profile():
    """Return the logged-in engineer profile required for personal reimbursement."""
    profile = getattr(current_user, 'engineer_profile', None)
    if not profile:
        return None
    return profile



def reimbursement_is_approver_user():
    """Return True when user can enter reimbursement approval workflow.

    Rodito keeps legacy approval access. Any user promoted through Settings as
    an approver also gains access, but their queue/action permissions are filtered
    by ApprovalRouting.
    """
    return is_approval_center_user()


REIMBURSEMENT_EDITABLE_STATUSES = {'Draft', 'Rejected'}
REIMBURSEMENT_LOCKED_STATUSES = {'Submitted', 'Approved', 'Paid'}


def reimbursement_normalize_status(status_value):
    """Return a normalized reimbursement lifecycle status."""
    raw_status = (clean_str(status_value) or 'Draft').strip()
    known = {
        'draft': 'Draft',
        'submitted': 'Submitted',
        'approved': 'Approved',
        'paid': 'Paid',
        'rejected': 'Rejected',
        'paid': 'Paid',
        'released': 'Paid',
        'payment released': 'Paid',
        'returned': 'Rejected',
        'returned for correction': 'Rejected'
    }
    return known.get(raw_status.lower(), raw_status)


def reimbursement_header_is_editable(header):
    """Return True when the engineer may still change rows/receipts."""
    if not header:
        return True
    return reimbursement_normalize_status(getattr(header, 'status', None)) in REIMBURSEMENT_EDITABLE_STATUSES


def reimbursement_header_lock_message(header, action_label='edited'):
    """Human-readable backend lock message for protected lifecycle states."""
    status_value = reimbursement_normalize_status(getattr(header, 'status', None))
    if status_value == 'Submitted':
        return f'Reimbursement is already Submitted and cannot be {action_label} while waiting for manager review.'
    if status_value == 'Paid':
        return f'Reimbursement is already Paid and cannot be {action_label}.'
    if status_value == 'Approved':
        return f'Reimbursement is already Approved and cannot be {action_label}.'
    return f'Reimbursement is already {status_value} and cannot be {action_label}.'


def reimbursement_edit_lock_response(header, action_label='edited'):
    """JSON response used by all reimbursement edit/upload/delete endpoints."""
    return jsonify({
        'success': False,
        'locked': True,
        'status': reimbursement_normalize_status(getattr(header, 'status', None)),
        'editable': False,
        'error': reimbursement_header_lock_message(header, action_label)
    }), 409


def reimbursement_header_lock_state(header):
    """Serialize editability flags for frontend status/lock display."""
    status_value = reimbursement_normalize_status(getattr(header, 'status', None))
    editable = status_value in REIMBURSEMENT_EDITABLE_STATUSES
    if status_value == 'Paid':
        lock_reason = 'Payment released. This reimbursement is completed and permanently locked.'
        lifecycle_label = 'Paid / Completed'
    elif status_value == 'Approved':
        lock_reason = 'Approved by manager. This reimbursement is locked while waiting for payment release.'
        lifecycle_label = 'Approved / Waiting for Payment'
    elif status_value == 'Submitted':
        lock_reason = 'Submitted for manager review. This reimbursement is locked until manager action.'
        lifecycle_label = 'Submitted / Waiting for Approval'
    elif status_value == 'Rejected':
        lock_reason = 'Returned by manager. You may edit and resubmit this reimbursement.'
        lifecycle_label = 'Returned for Correction'
    else:
        lock_reason = 'Draft reimbursement. You may edit, save, and submit.'
        lifecycle_label = 'Draft'

    return {
        'status': status_value,
        'editable': editable,
        'locked': not editable,
        'lock_reason': lock_reason,
        'lifecycle_label': lifecycle_label
    }


def reimbursement_header_approval_meta(header):
    """Serialize approval state without requiring model relationships."""
    approved_by = db.session.get(User, header.approved_by_id) if getattr(header, 'approved_by_id', None) else None
    rejected_by = db.session.get(User, header.rejected_by_id) if getattr(header, 'rejected_by_id', None) else None
    approval_meta = {
        'approved_at': header.approved_at.isoformat() if getattr(header, 'approved_at', None) else None,
        'approved_by': getattr(approved_by, 'username', '') if approved_by else '',
        'rejected_at': header.rejected_at.isoformat() if getattr(header, 'rejected_at', None) else None,
        'rejected_by': getattr(rejected_by, 'username', '') if rejected_by else '',
        'paid_at': header.paid_at.isoformat() if getattr(header, 'paid_at', None) else None,
        'paid_by': getattr(db.session.get(User, header.paid_by_id), 'username', '') if getattr(header, 'paid_by_id', None) else '',
        'payment_reference': getattr(header, 'payment_reference', '') or '',
        'payment_remarks': getattr(header, 'payment_remarks', '') or '',
        'approval_remarks': getattr(header, 'approval_remarks', '') or '',
        'approval_action': getattr(header, 'approval_action', '') or '',
        'approval_name_snapshot': getattr(header, 'approval_name_snapshot', '') or '',
        'approval_title_snapshot': getattr(header, 'approval_title_snapshot', '') or '',
        'approval_signature_snapshot': getattr(header, 'approval_signature_snapshot', '') or '',
        'approval_signature_layout': getattr(header, 'approval_signature_layout', '') or 'signature_over_printed_name',
        'approval_signed_at': header.approval_signed_at.isoformat() if getattr(header, 'approval_signed_at', None) else None,
        'approval_has_signature_snapshot': bool(getattr(header, 'approval_signature_snapshot', None))
    }
    approval_meta.update(reimbursement_header_lock_state(header))
    return approval_meta


def reimbursement_receipts_for_header_all(header_id):
    """Manager approval helper: load all receipts for a reimbursement, regardless of uploader."""
    receipts = (
        ReimbursementReceipt.query
        .filter_by(reimbursement_id=header_id)
        .order_by(ReimbursementReceipt.created_at.asc(), ReimbursementReceipt.id.asc())
        .all()
    )
    grouped = {}
    for receipt in receipts:
        group_key = receipt.shift_id
        if group_key is None:
            group_key = 'additional'
        elif isinstance(group_key, int) and group_key < 0:
            group_key = f"manual_{abs(group_key)}"
        try:
            grouped.setdefault(group_key, []).append(reimbursement_receipt_to_dict(receipt))
        except Exception as exc:
            print(f"[Reimbursement] Skipping unreadable receipt {getattr(receipt, 'id', '')}: {exc}")
    return grouped


def reimbursement_header_to_manager_dict(header, include_rows=False):
    """Serialize one reimbursement header for Rodito approval queue/details."""
    user = db.session.get(User, header.user_id) if header.user_id else None
    engineer = db.session.get(Engineer, header.engineer_id) if header.engineer_id else None
    rows = []
    receipts_by_shift = {}
    if include_rows:
        receipts_by_shift = reimbursement_receipts_for_header_all(header.id)
        rows = [
            reimbursement_row_to_dict(row, receipts_by_shift)
            for row in sorted(header.rows, key=lambda r: (r.row_date or header.start_date, r.id))
        ]

    payload = {
        'id': header.id,
        'user_id': header.user_id,
        'username': getattr(user, 'username', '') if user else '',
        'engineer_id': header.engineer_id,
        'engineer_name': getattr(engineer, 'name', '') if engineer else '',
        'start': header.start_date.isoformat() if header.start_date else '',
        'end': header.end_date.isoformat() if header.end_date else '',
        'status': header.status,
        'created_at': header.created_at.isoformat() if header.created_at else None,
        'updated_at': header.updated_at.isoformat() if header.updated_at else None,
        'submitted_at': header.submitted_at.isoformat() if header.submitted_at else None,
        'grand_total': round(sum(reimbursement_money_value(row.row_total) for row in header.rows), 2),
        'row_count': len(header.rows or []),
    }
    payload.update(reimbursement_header_approval_meta(header))
    if include_rows:
        payload['rows'] = rows
        payload['additional_receipts'] = receipts_by_shift.get('additional', [])
    return payload



def reimbursement_excel_period_label(start_date, end_date):
    """Format the reimbursement date range like the accounting workbook title."""
    try:
        if start_date.year == end_date.year and start_date.month == end_date.month:
            return f"{start_date.strftime('%b').upper()} {start_date.day} - {end_date.day}, {end_date.year}"
        if start_date.year == end_date.year:
            return f"{start_date.strftime('%b').upper()} {start_date.day} - {end_date.strftime('%b').upper()} {end_date.day}, {end_date.year}"
        return f"{start_date.strftime('%b').upper()} {start_date.day}, {start_date.year} - {end_date.strftime('%b').upper()} {end_date.day}, {end_date.year}"
    except Exception:
        return f"{start_date} - {end_date}"


def reimbursement_excel_work_details(row):
    """Build the read-only schedule context used in the reimbursement Excel."""
    client_name = clean_str(getattr(row, 'client_name', None)) or ''
    task_name = clean_str(getattr(row, 'task_name', None)) or ''
    product_name = clean_str(getattr(row, 'product_name', None)) or ''
    serial_number = clean_str(getattr(row, 'serial_number', None)) or ''

    details = []
    if client_name:
        details.append(f'Client: {client_name}')
    if task_name:
        details.append(f'Task: {task_name}' if client_name else task_name)
    equipment = ' / '.join(part for part in [product_name, serial_number] if part)
    if equipment:
        details.append(f'Equipment: {equipment}')
    return '\n'.join(details)


def reimbursement_excel_row_remarks(row):
    """Return manual remarks while suppressing exact legacy generated text."""
    remarks = clean_str(getattr(row, 'remarks', None)) or ''
    if not remarks:
        return ''

    legacy_parts = [
        clean_str(getattr(row, 'client_name', None)) or '',
        clean_str(getattr(row, 'task_name', None)) or '',
        clean_str(getattr(row, 'product_name', None)) or ''
    ]
    legacy_generated = ' - '.join(part for part in legacy_parts if part)
    if not getattr(row, 'shift_id', None):
        legacy_generated = clean_str(getattr(row, 'task_name', None)) or ''

    normalize = lambda value: ' '.join(str(value or '').split()).casefold()
    if legacy_generated and normalize(remarks) == normalize(legacy_generated):
        return ''
    return remarks


def reimbursement_excel_filename(header, engineer_name=''):
    """Safe filename for generated reimbursement workbook."""
    safe_name = secure_filename(engineer_name or 'reimbursement') or 'reimbursement'
    period = f"{header.start_date.strftime('%m%d%Y')}_{header.end_date.strftime('%m%d%Y')}"
    return f"Reimbursement_{safe_name}_{period}.xlsx"


def build_reimbursement_excel_workbook(header):
    """Generate the SPC reimbursement Excel file matching the sample layout."""
    from openpyxl import Workbook
    from openpyxl.styles import Font, PatternFill, Border, Side, Alignment
    from openpyxl.utils import get_column_letter

    engineer = db.session.get(Engineer, header.engineer_id) if header.engineer_id else None
    user = db.session.get(User, header.user_id) if header.user_id else None
    employee_name = (
        getattr(engineer, 'name', '') or
        getattr(user, 'username', '') or
        getattr(current_user, 'username', '') or
        'Employee'
    )

    wb = Workbook()
    ws = wb.active
    ws.title = 'Format'

    expense_fields = list(REIMBURSEMENT_EXPENSE_FIELDS)
    headers = [
        'Date',
        'Representation',
        'Car Repair',
        'Toll Fee',
        'Gasoline',
        'Transpo',
        'Office Supplies',
        'Parking',
        'Per Diem',
        'Parking Coding',
        'Others / Misc',
        'Work Details',
        'Remarks'
    ]

    max_col = len(headers)
    ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=max_col)
    ws.merge_cells(start_row=2, start_column=1, end_row=2, end_column=max_col)
    ws.merge_cells(start_row=3, start_column=1, end_row=3, end_column=4)
    ws.merge_cells(start_row=4, start_column=1, end_row=4, end_column=4)

    ws.cell(1, 1).value = 'SHIMADZU PHILIPPINES CORP.'
    ws.cell(2, 1).value = f"REIMBURSEMENT FOR {reimbursement_excel_period_label(header.start_date, header.end_date)}"
    ws.cell(3, 1).value = f"Name: {employee_name}"
    ws.cell(4, 1).value = f"Date: {get_manila_time().strftime('%m-%d-%Y')}"

    ws.cell(1, 1).font = Font(bold=True, size=14)
    ws.cell(2, 1).font = Font(bold=True, size=12)
    ws.cell(3, 1).font = Font(bold=True)
    ws.cell(4, 1).font = Font(bold=True)

    header_row = 6
    for col, label in enumerate(headers, start=1):
        cell = ws.cell(header_row, col)
        cell.value = label
        cell.font = Font(bold=True, color='FFFFFF')
        cell.fill = PatternFill('solid', fgColor='1F4E78')
        cell.alignment = Alignment(horizontal='center', vertical='center', wrap_text=True)

    thin = Side(style='thin', color='B7B7B7')
    border = Border(left=thin, right=thin, top=thin, bottom=thin)
    money_fmt = '#,##0.00'
    date_fmt = 'mm-dd-yyyy'

    rows = sorted(header.rows, key=lambda r: (r.row_date or header.start_date, r.id))
    start_data_row = header_row + 1

    if not rows:
        rows = []

    for idx, row in enumerate(rows, start=start_data_row):
        ws.cell(idx, 1).value = row.row_date if row.row_date else None
        ws.cell(idx, 1).number_format = date_fmt

        for offset, field in enumerate(expense_fields, start=2):
            amount_value = reimbursement_money_value(getattr(row, field, 0))
            ws.cell(idx, offset).value = amount_value if amount_value else None
            ws.cell(idx, offset).number_format = money_fmt

        ws.cell(idx, 12).value = reimbursement_excel_work_details(row)
        ws.cell(idx, 13).value = reimbursement_excel_row_remarks(row)

        for col in range(1, max_col + 1):
            c = ws.cell(idx, col)
            c.border = border
            c.alignment = Alignment(vertical='top', wrap_text=True)
        for col in range(2, 12):
            ws.cell(idx, col).alignment = Alignment(horizontal='right', vertical='top')

    last_data_row = start_data_row + max(len(rows), 1) - 1
    total_row = last_data_row + 1
    grand_row = total_row + 1

    ws.cell(total_row, 1).value = 'TOTAL'
    ws.cell(total_row, 1).font = Font(bold=True)
    ws.cell(total_row, 1).fill = PatternFill('solid', fgColor='D9EAF7')

    for col in range(2, 12):
        col_letter = get_column_letter(col)
        ws.cell(total_row, col).value = f"=SUM({col_letter}{start_data_row}:{col_letter}{last_data_row})"
        ws.cell(total_row, col).number_format = money_fmt
        ws.cell(total_row, col).font = Font(bold=True)
        ws.cell(total_row, col).fill = PatternFill('solid', fgColor='D9EAF7')
        ws.cell(total_row, col).alignment = Alignment(horizontal='right')

    ws.merge_cells(start_row=grand_row, start_column=1, end_row=grand_row, end_column=10)
    ws.cell(grand_row, 1).value = 'GRAND TOTAL'
    ws.cell(grand_row, 1).font = Font(bold=True, size=12)
    ws.cell(grand_row, 1).fill = PatternFill('solid', fgColor='FFF2CC')
    ws.cell(grand_row, 1).alignment = Alignment(horizontal='right')

    ws.cell(grand_row, 11).value = f"=SUM(B{total_row}:K{total_row})"
    ws.cell(grand_row, 11).number_format = money_fmt
    ws.cell(grand_row, 11).font = Font(bold=True, size=12)
    ws.cell(grand_row, 11).fill = PatternFill('solid', fgColor='FFF2CC')
    ws.cell(grand_row, 11).alignment = Alignment(horizontal='right')

    for col in (12, 13):
        ws.cell(grand_row, col).value = ''
        ws.cell(grand_row, col).fill = PatternFill('solid', fgColor='FFF2CC')

    for row_idx in range(header_row, grand_row + 1):
        for col in range(1, max_col + 1):
            ws.cell(row_idx, col).border = border

    widths = {
        1: 13, 2: 15, 3: 13, 4: 12, 5: 12, 6: 12,
        7: 16, 8: 12, 9: 12, 10: 15, 11: 14, 12: 38, 13: 32
    }
    for col, width in widths.items():
        ws.column_dimensions[get_column_letter(col)].width = width

    ws.row_dimensions[1].height = 22
    ws.row_dimensions[2].height = 22
    ws.row_dimensions[header_row].height = 32
    for row_idx in range(start_data_row, max(start_data_row, last_data_row) + 1):
        ws.row_dimensions[row_idx].height = 36

    ws.freeze_panes = 'B7'
    ws.sheet_view.showGridLines = False
    ws.print_title_rows = f'${header_row}:${header_row}'
    ws.page_setup.orientation = 'landscape'
    ws.page_setup.fitToWidth = 1
    ws.page_setup.fitToHeight = 0
    ws.sheet_properties.pageSetUpPr.fitToPage = True
    ws.page_margins.left = 0.25
    ws.page_margins.right = 0.25
    ws.page_margins.top = 0.5
    ws.page_margins.bottom = 0.5
    ws.print_area = f'A1:M{grand_row}'

    return wb



def reimbursement_amount_to_words(amount):
    """Convert a peso amount to capitalized English words for the PCV."""
    ones = [
        'zero', 'one', 'two', 'three', 'four', 'five', 'six', 'seven',
        'eight', 'nine', 'ten', 'eleven', 'twelve', 'thirteen', 'fourteen',
        'fifteen', 'sixteen', 'seventeen', 'eighteen', 'nineteen'
    ]
    tens = ['', '', 'twenty', 'thirty', 'forty', 'fifty', 'sixty', 'seventy', 'eighty', 'ninety']

    def words_under_1000(n):
        n = int(n)
        parts = []
        if n >= 100:
            parts.append(ones[n // 100])
            parts.append('hundred')
            n %= 100
        if n >= 20:
            parts.append(tens[n // 10])
            n %= 10
        if n > 0:
            parts.append(ones[n])
        return ' '.join(parts) if parts else 'zero'

    try:
        amount = round(float(amount or 0), 2)
    except Exception:
        amount = 0.0

    pesos = int(amount)
    centavos = int(round((amount - pesos) * 100))

    if pesos == 0:
        peso_words = 'zero'
    else:
        scales = [
            (1_000_000_000, 'billion'),
            (1_000_000, 'million'),
            (1_000, 'thousand'),
            (1, '')
        ]
        parts = []
        remaining = pesos
        for scale_value, scale_name in scales:
            if remaining >= scale_value:
                chunk = remaining // scale_value
                remaining %= scale_value
                chunk_words = words_under_1000(chunk)
                parts.append(f"{chunk_words} {scale_name}".strip())
        peso_words = ' '.join(parts)

    result = f"{peso_words} peso{'s' if pesos != 1 else ''}"
    if centavos:
        result += f" and {words_under_1000(centavos)} centavo{'s' if centavos != 1 else ''}"
    result += " only"
    return result.title()


