def reimbursement_fetch_download_header_from_request():
    """Fetch reimbursement header for download routes by ID or selected date range."""
    header_id = clean_int(request.args.get('id') or request.args.get('reimbursement_id'))
    if header_id:
        header = db.session.get(ReimbursementHeader, header_id)
        if not header:
            raise ValueError('Reimbursement record not found.')
        if header.user_id != current_user.id and not reimbursement_is_approver_user() and not can_access_accounting_center(current_user):
            raise PermissionError('You are not allowed to download this reimbursement form.')
        return header

    start_date = reimbursement_parse_date(request.args.get('start') or request.args.get('start_date'), 'start')
    end_date = reimbursement_parse_date(request.args.get('end') or request.args.get('end_date'), 'end')
    header = reimbursement_find_header(start_date, end_date, create=False)
    if not header:
        raise LookupError('Please save a reimbursement draft before downloading the form.')
    return header


def reimbursement_pcv_line_items(header):
    """Flatten reimbursement rows into PCV particular rows.

    Each non-zero expense category becomes one line item. This keeps PCV
    Particulars as a detailed table rather than a summarized grouping.
    """
    category_labels = {
        'representation': 'Representation',
        'car_repair': 'Car Repair',
        'toll_fee': 'Toll Fee',
        'gasoline': 'Gasoline',
        'transpo': 'Transpo',
        'office_supplies': 'Office Supplies',
        'parking': 'Parking',
        'per_diem': 'Per Diem',
        'parking_coding': 'Parking Coding',
        'others_misc': 'Others / Misc',
    }

    items = []
    rows = sorted(header.rows, key=lambda r: (r.row_date or header.start_date, r.id))
    for row in rows:
        date_label = row.row_date.strftime('%m/%d/%Y') if row.row_date else ''
        manual_context = (row.remarks or '').strip()
        schedule_context = ' / '.join(
            part for part in [
                (row.client_name or '').strip(),
                (row.task_name or '').strip(),
                (row.product_name or '').strip()
            ] if part
        )

        for field in REIMBURSEMENT_EXPENSE_FIELDS:
            amount = reimbursement_money_value(getattr(row, field, 0))
            if not amount:
                continue

            if field == 'others_misc':
                item_name = (row.task_name or '').strip() or 'Others / Misc'
                label = item_name if item_name.lower() not in {'manual item', 'others', 'others / misc'} else category_labels[field]
            else:
                label = category_labels.get(field, field.replace('_', ' ').title())

            context = manual_context or schedule_context
            particular = ' - '.join(part for part in [date_label, label] if part)
            if context:
                particular = f"{particular} / {context}" if particular else context

            items.append({
                'particular': particular or label,
                'amount': round(float(amount), 2)
            })
    return items


def build_reimbursement_pcv_pdf(header):
    """Generate the Petty Cash Voucher PDF based on the approved sample layout."""
    from reportlab.lib import colors
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT, TA_LEFT
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.units import mm
    from reportlab.platypus import (
        SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, KeepTogether
    )

    engineer = db.session.get(Engineer, header.engineer_id) if header.engineer_id else None
    user = db.session.get(User, header.user_id) if header.user_id else None
    employee_name = (
        getattr(engineer, 'name', '') or
        getattr(user, 'username', '') or
        getattr(current_user, 'username', '') or
        'Employee'
    )
    employee_name = str(employee_name or 'Employee').upper()

    items = reimbursement_pcv_line_items(header)
    total_amount = round(sum(item['amount'] for item in items), 2)

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=A4,
        rightMargin=14 * mm,
        leftMargin=14 * mm,
        topMargin=12 * mm,
        bottomMargin=12 * mm
    )

    styles = getSampleStyleSheet()
    normal = ParagraphStyle('PCVNormal', parent=styles['Normal'], fontName='Helvetica', fontSize=9, leading=11)
    small = ParagraphStyle('PCVSmall', parent=normal, fontSize=8, leading=10)
    title = ParagraphStyle('PCVTitle', parent=normal, fontName='Helvetica-Bold', fontSize=13, alignment=TA_CENTER, leading=16)
    center_bold = ParagraphStyle('PCVCenterBold', parent=normal, fontName='Helvetica-Bold', alignment=TA_CENTER)
    right_style = ParagraphStyle('PCVRight', parent=normal, alignment=TA_RIGHT)
    amount_words_style = ParagraphStyle('PCVAmountWords', parent=normal, fontName='Helvetica-Bold', fontSize=9.5, leading=12)

    story = []

    # Header copied in structure from the sample: company identity + PCV title.
    story.append(Paragraph('SHIMADZU PHILIPPINES CORPORATION', title))
    story.append(Paragraph('PETTY CASH VOUCHER', center_bold))
    story.append(Spacer(1, 4 * mm))

    meta_data = [
        [
            Paragraph('<b>PCV No.:</b> ____________________', normal),
            Paragraph(f"<b>Date:</b> {get_manila_time().strftime('%m-%d-%Y')}", normal)
        ],
        [
            Paragraph(f"<b>Paid To:</b> {html.escape(employee_name)}", normal),
            Paragraph('', normal)
        ],
    ]
    meta_table = Table(meta_data, colWidths=[115 * mm, 55 * mm])
    meta_table.setStyle(TableStyle([
        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 4),
    ]))
    story.append(meta_table)
    story.append(Spacer(1, 3 * mm))

    amount_words = reimbursement_amount_to_words(total_amount)
    amount_block = Table([
        [Paragraph('<b>Amount in Words:</b>', normal), Paragraph(html.escape(amount_words), amount_words_style)],
        ['', Paragraph(f"<b>P {total_amount:,.2f}</b>", right_style)]
    ], colWidths=[38 * mm, 132 * mm])
    amount_block.setStyle(TableStyle([
        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
        ('LINEBELOW', (1, 0), (1, 0), 0.6, colors.black),
        ('LINEBELOW', (1, 1), (1, 1), 0.6, colors.black),
        ('TOPPADDING', (0, 0), (-1, -1), 3),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 3),
    ]))
    story.append(amount_block)
    story.append(Spacer(1, 4 * mm))

    table_rows = [[Paragraph('<b>PARTICULARS</b>', center_bold), Paragraph('<b>AMOUNT</b>', center_bold)]]
    if items:
        for item in items:
            table_rows.append([
                Paragraph(html.escape(item['particular']), normal),
                Paragraph(f"P {item['amount']:,.2f}", right_style)
            ])
    else:
        table_rows.append([Paragraph('No reimbursement items encoded.', normal), Paragraph('P 0.00', right_style)])

    table_rows.append([Paragraph('<b>TOTAL</b>', right_style), Paragraph(f"<b>P {total_amount:,.2f}</b>", right_style)])

    particulars_table = Table(table_rows, colWidths=[132 * mm, 38 * mm], repeatRows=1)
    particulars_table.setStyle(TableStyle([
        ('GRID', (0, 0), (-1, -1), 0.6, colors.black),
        ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#EDEDED')),
        ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
        ('ALIGN', (1, 1), (1, -1), 'RIGHT'),
        ('BACKGROUND', (0, -1), (-1, -1), colors.HexColor('#F7F7F7')),
        ('FONTNAME', (0, -1), (-1, -1), 'Helvetica-Bold'),
        ('TOPPADDING', (0, 0), (-1, -1), 5),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 5),
    ]))
    story.append(particulars_table)
    story.append(Spacer(1, 8 * mm))

    # Bottom section kept simple/as-is for now; names/signatures will be expanded later.
    signature_table = Table([
        [
            Paragraph('<b>Prepared by:</b><br/><br/><br/>____________________________', small),
            Paragraph('<b>Checked by:</b><br/><br/><br/>____________________________', small),
            Paragraph('<b>Approved by:</b><br/><br/><br/>____________________________', small),
        ],
        [
            Paragraph('<b>Received by:</b><br/><br/><br/>____________________________', small),
            Paragraph('<b>Paid by:</b><br/><br/><br/>____________________________', small),
            Paragraph('', small),
        ]
    ], colWidths=[56.5 * mm, 56.5 * mm, 57 * mm])
    signature_table.setStyle(TableStyle([
        ('GRID', (0, 0), (-1, -1), 0.6, colors.black),
        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
        ('TOPPADDING', (0, 0), (-1, -1), 6),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 10),
    ]))
    story.append(signature_table)

    doc.build(story)
    buffer.seek(0)
    return buffer




def reimbursement_find_rfp_template_path():
    """Locate the official fillable Request for Payment PDF template."""
    candidates = [
        os.path.join(app.root_path, 'forms', 'Request for Payment Form..pdf'),
        os.path.join(app.root_path, 'forms', 'Request for Payment Form. - Copy.pdf'),
        os.path.join(app.root_path, 'forms', 'REQUEST FOR PAYMENT FORM.pdf'),
        os.path.join(app.root_path, 'static', 'forms', 'Request for Payment Form..pdf'),
        os.path.join(app.root_path, 'static', 'forms', 'Request for Payment Form. - Copy.pdf'),
        os.path.join(app.root_path, 'templates', 'forms', 'Request for Payment Form..pdf'),
        os.path.join(app.root_path, 'Request for Payment Form..pdf'),
    ]
    for candidate in candidates:
        try:
            if candidate and os.path.exists(candidate):
                return candidate
        except Exception:
            continue
    raise FileNotFoundError('RFP template PDF not found. Place Request for Payment Form..pdf in app/forms/.')


