def reimbursement_find_pdf_field_rect(writer, target_field_name):
    """Find the first widget rectangle for a named PDF form field."""
    target = (target_field_name or '').strip().upper()
    if not target:
        return None

    def _field_name(field_obj, inherited_name=''):
        try:
            return str(field_obj.get('/T', '') or inherited_name or '').strip()
        except Exception:
            return inherited_name or ''

    def _walk_field_ref(field_ref, inherited_name=''):
        try:
            field_obj = field_ref.get_object()
        except Exception:
            return None

        field_name = _field_name(field_obj, inherited_name)
        if field_name.upper() == target:
            rect = field_obj.get('/Rect')
            if rect and len(rect) == 4:
                return [float(v) for v in rect]

        try:
            for kid_ref in field_obj.get('/Kids', []) or []:
                try:
                    kid_obj = kid_ref.get_object()
                    kid_name = _field_name(kid_obj, field_name)
                    if kid_name.upper() == target:
                        rect = kid_obj.get('/Rect')
                        if rect and len(rect) == 4:
                            return [float(v) for v in rect]
                except Exception:
                    pass
                found = _walk_field_ref(kid_ref, field_name)
                if found:
                    return found
        except Exception:
            pass

        return None

    try:
        acroform = writer._root_object.get('/AcroForm')
        fields = acroform.get('/Fields', []) if acroform else []
        for field_ref in fields:
            found = _walk_field_ref(field_ref)
            if found:
                return found
    except Exception:
        pass

    # Fallback: scan page annotations directly.
    try:
        for page in writer.pages:
            for annot_ref in page.get('/Annots', []) or []:
                annot = annot_ref.get_object()
                name = str(annot.get('/T', '') or '').strip()
                if name.upper() == target:
                    rect = annot.get('/Rect')
                    if rect and len(rect) == 4:
                        return [float(v) for v in rect]
    except Exception:
        pass

    return None


def reimbursement_approval_signature_overlay_pdf(header, page_width, page_height, box, label='APPROVED BY'):
    """Create a transparent approval block overlay: signature over printed name.

    S12A3B:
    The underlying PCV/RFP templates already contain the visible APPROVED BY
    label/underline. This overlay intentionally does not draw another label and
    does not fill the AcroForm APPROVED BY field, preventing duplicate text and
    stacked signatures in PDF viewers.
    """
    from PIL import Image
    from reportlab.lib.utils import ImageReader
    from reportlab.pdfgen import canvas

    if not reimbursement_is_approved_for_stamp(header):
        return None

    approver_name = reimbursement_approval_printed_name(header)
    if not approver_name:
        return None

    signature_data = reimbursement_approval_signature_data(header)
    approver_title = reimbursement_approval_title(header)
    signed_at = reimbursement_approval_signed_at_label(header)

    try:
        x, y, width, height = [float(v) for v in box]
    except Exception:
        return None

    buffer = io.BytesIO()
    c = canvas.Canvas(buffer, pagesize=(page_width, page_height))

    # Compact enterprise stamp:
    # Signature sits above the printed-name line. Name/title/date remain below.
    # No duplicate "APPROVED BY" label is drawn because the template already has it.
    printed_name_y = y + 15.0
    title_y = printed_name_y - 7.5
    date_y = title_y - 6.8
    signature_bottom = printed_name_y + 5.0
    signature_top = y + height - 3.0
    sig_area_height = max(signature_top - signature_bottom, 10.0)

    png_bytes = reimbursement_signature_data_url_to_png_bytes(signature_data) if signature_data else None
    if png_bytes:
        try:
            with Image.open(io.BytesIO(png_bytes)) as signature_image:
                image_width, image_height = signature_image.size

            if image_width and image_height:
                box_width = width * 0.82
                box_height = sig_area_height
                fit_scale = min(box_width / float(image_width), box_height / float(image_height), 1.0)
                draw_width = image_width * fit_scale
                draw_height = image_height * fit_scale
                draw_x = x + ((width - draw_width) / 2.0)
                draw_y = signature_bottom + ((sig_area_height - draw_height) / 2.0)
                c.drawImage(
                    ImageReader(io.BytesIO(png_bytes)),
                    draw_x,
                    draw_y,
                    width=draw_width,
                    height=draw_height,
                    preserveAspectRatio=True,
                    mask='auto'
                )
        except Exception as image_error:
            print(f"[Reimbursement] Approval signature image skipped: {image_error}", flush=True)

    c.setFillColorRGB(0, 0, 0)
    c.setFont('Helvetica-Bold', 7.0)
    c.drawCentredString(x + width / 2.0, printed_name_y, str(approver_name)[:34])

    if approver_title:
        c.setFont('Helvetica', 5.8)
        c.drawCentredString(x + width / 2.0, title_y, str(approver_title)[:38])

    if signed_at:
        c.setFont('Helvetica', 5.4)
        c.drawCentredString(x + width / 2.0, date_y, f"Approved: {signed_at}")

    c.showPage()
    c.save()
    buffer.seek(0)
    return buffer.getvalue()

def reimbursement_stamp_approval_signature(writer, header, field_name='APPROVED BY', fallback_box=None, force_fallback=False):
    """Merge approver signature block onto the first page of a generated PDF.

    S12A4H layout correction:
    - S12A4G moved the entire approval stamp too far down.
    - This version reuses the template APPROVED BY field rectangle again and
      only offsets the stamp moderately below the field line.
    - The signature area stays near the template underline while the printed
      name/title/date remain readable underneath it.
    """
    if not reimbursement_is_approved_for_stamp(header):
        return False

    try:
        from pypdf import PdfReader

        first_page = writer.pages[0]
        media_box = first_page.mediabox
        page_width = float(media_box.width)
        page_height = float(media_box.height)

        rect = None if force_fallback else reimbursement_find_pdf_field_rect(writer, field_name)
        if rect:
            x1, y1, x2, y2 = rect
            field_width = max(x2 - x1, 80.0)
            # Moderate offset: lower than the template field, but not as low as S12A4G.
            # This avoids cutting through the line while keeping the stamp inside
            # the official APPROVED BY area.
            box = [x1, max(y1 - 22.0, 8.0), field_width, 56.0]
        else:
            box = fallback_box or [page_width - 175.0, 34.0, 135.0, 60.0]

        overlay_bytes = reimbursement_approval_signature_overlay_pdf(header, page_width, page_height, box)
        if not overlay_bytes:
            return False

        overlay_reader = PdfReader(io.BytesIO(overlay_bytes))
        first_page.merge_page(overlay_reader.pages[0])
        return True
    except Exception as approval_stamp_error:
        print(f"[Reimbursement] Approval signature stamp skipped: {approval_stamp_error}", flush=True)
        return False


def reimbursement_rfp_signature_overlay_pdf(signature_data, page_width, page_height):
    """Create a transparent one-page PDF overlay containing the engineer signature."""
    from PIL import Image
    from reportlab.lib.utils import ImageReader
    from reportlab.pdfgen import canvas

    png_bytes = reimbursement_signature_data_url_to_png_bytes(signature_data)
    if not png_bytes:
        return None

    with Image.open(io.BytesIO(png_bytes)) as signature_image:
        image_width, image_height = signature_image.size

    if not image_width or not image_height:
        return None

    # RFP template is 612 x 936 points. Signature underline is beside SUBMITTED BY.
    # Coordinates below place the image centered just above the underline.
    scale_x = float(page_width) / 612.0
    scale_y = float(page_height) / 936.0
    box_x = 462.0 * scale_x
    box_y = (936.0 - 148.0 + 2.0) * scale_y
    box_width = 91.0 * scale_x
    box_height = 24.0 * scale_y

    fit_scale = min(box_width / float(image_width), box_height / float(image_height))
    draw_width = image_width * fit_scale
    draw_height = image_height * fit_scale
    draw_x = box_x + ((box_width - draw_width) / 2.0)
    draw_y = box_y + ((box_height - draw_height) / 2.0)

    buffer = io.BytesIO()
    c = canvas.Canvas(buffer, pagesize=(page_width, page_height))
    c.drawImage(
        ImageReader(io.BytesIO(png_bytes)),
        draw_x,
        draw_y,
        width=draw_width,
        height=draw_height,
        preserveAspectRatio=True,
        mask='auto'
    )
    c.showPage()
    c.save()
    buffer.seek(0)
    return buffer.getvalue()


def reimbursement_stamp_rfp_signature(writer, header):
    """Stamp the saved engineer signature onto the RFP signature underline."""
    signature_data = reimbursement_get_rfp_signature_data(header)
    if not signature_data:
        return False

    try:
        from pypdf import PdfReader

        first_page = writer.pages[0]
        media_box = first_page.mediabox
        page_width = float(media_box.width)
        page_height = float(media_box.height)
        overlay_bytes = reimbursement_rfp_signature_overlay_pdf(signature_data, page_width, page_height)
        if not overlay_bytes:
            return False

        overlay_reader = PdfReader(io.BytesIO(overlay_bytes))
        first_page.merge_page(overlay_reader.pages[0])
        return True
    except Exception as signature_stamp_error:
        print(f"[Reimbursement] RFP signature stamp skipped: {signature_stamp_error}", flush=True)
        return False


def reimbursement_apply_rfp_field_formatting(writer):
    """Normalize RFP generated field appearance without changing static template fields."""
    try:
        from pypdf.generic import NameObject, NumberObject, TextStringObject
    except Exception:
        return

    dynamic_fields = {
        'CHECK PAYABLE TO',
        'DATE',
        'SUBMITTED BY',
        'COVERING',
        'Textfield',
        'BRANCH',
        'Branch',
        'branch',
        'Branch Code',
        'BRANCH CODE',
        'CLASS',
        'Class',
        'class',
        'Class Code',
        'CLASS CODE',
        'DEPT',
        'Dept',
        'DEPARTMENT',
        'Department',
        'dept',
        'Dept Code',
        'DEPT CODE',
        'PRODUCT',
        'Product',
        'product',
        'Product Code',
        'PRODUCT CODE',
        'APPROVED BY',
        'Approved By',
        'approved_by',
        'APPROVED_BY',
    }

    try:
        acroform = writer._root_object.get('/AcroForm')
        if not acroform:
            return

        try:
            acroform.update({NameObject('/DA'): TextStringObject('/Helv 10 Tf 0 g')})
        except Exception:
            pass

        fields = acroform.get('/Fields', [])

        def _walk(field_ref, inherited_name=''):
            try:
                field = field_ref.get_object()
            except Exception:
                return

            name = str(field.get('/T', '') or inherited_name or '')
            if name in dynamic_fields:
                try:
                    font_size = 9 if name == 'COVERING' else 10
                    field.update({NameObject('/DA'): TextStringObject(f'/Helv {font_size} Tf 0 g')})
                    # Use left alignment for text-heavy RFP fields and center align the amount.
                    if name == 'Textfield':
                        field.update({NameObject('/Q'): NumberObject(1)})
                    else:
                        field.update({NameObject('/Q'): NumberObject(0)})
                except Exception:
                    pass

            try:
                for kid in field.get('/Kids', []) or []:
                    try:
                        kid_obj = kid.get_object()
                        if name in dynamic_fields:
                            font_size = 9 if name == 'COVERING' else 10
                            kid_obj.update({NameObject('/DA'): TextStringObject(f'/Helv {font_size} Tf 0 g')})
                            kid_obj.update({NameObject('/Q'): NumberObject(1 if name == 'Textfield' else 0)})
                    except Exception:
                        pass
                    _walk(kid, name)
            except Exception:
                pass

        for ref in fields:
            _walk(ref)
    except Exception as exc:
        print(f"[Reimbursement] RFP field formatting skipped: {exc}")


def build_reimbursement_rfp_template_pdf(header):
    """Fill the official Request for Payment PDF template using AcroForm fields."""
    try:
        from pypdf import PdfReader, PdfWriter
        from pypdf.generic import BooleanObject, NameObject
    except Exception as exc:
        raise ImportError('pypdf is required to fill the RFP PDF template.') from exc

    template_path = reimbursement_find_rfp_template_path()
    field_values = reimbursement_prepare_rfp_field_values(header)

    reader = PdfReader(template_path)
    writer = PdfWriter()
    writer.clone_document_from_reader(reader)

    reimbursement_apply_rfp_field_formatting(writer)

    try:
        writer.set_need_appearances_writer(True)
    except Exception:
        try:
            if '/AcroForm' in writer._root_object:
                writer._root_object['/AcroForm'].update({NameObject('/NeedAppearances'): BooleanObject(True)})
        except Exception:
            pass

    for page in writer.pages:
        writer.update_page_form_field_values(page, field_values)

    reimbursement_stamp_rfp_signature(writer, header)
    reimbursement_stamp_approval_signature(
        writer,
        header,
        field_name='APPROVED BY',
        fallback_box=[44.65, 535.0, 213.85, 56.0],
        force_fallback=False
    )

    output = io.BytesIO()
    writer.write(output)
    pdf_bytes = output.getvalue()

    compressed_pdf_bytes = reimbursement_compress_pdf_bytes_best_effort(pdf_bytes)

    final_output = io.BytesIO(compressed_pdf_bytes)
    final_output.seek(0)
    return final_output


def reimbursement_rfp_filename(header, engineer_name=''):
    """Safe filename for generated Request for Payment filled PDF."""
    safe_name = secure_filename(engineer_name or 'reimbursement') or 'reimbursement'
    period = f"{header.start_date.strftime('%m%d%Y')}_{header.end_date.strftime('%m%d%Y')}"
    return f"RFP_{safe_name}_{period}.pdf"


def reimbursement_find_header(start_date, end_date, create=False):
    """Find or optionally create the current user's reimbursement header for a date range."""
    profile = reimbursement_get_personal_profile()
    if not profile:
        return None

    header = (
        ReimbursementHeader.query
        .filter_by(
            user_id=current_user.id,
            engineer_id=profile.id,
            start_date=start_date,
            end_date=end_date
        )
        .order_by(ReimbursementHeader.id.desc())
        .first()
    )

    if header or not create:
        return header

    header = ReimbursementHeader(
        user_id=current_user.id,
        engineer_id=profile.id,
        start_date=start_date,
        end_date=end_date,
        status='Draft'
    )
    db.session.add(header)
    db.session.flush()
    return header


def reimbursement_shift_allowed_for_current_user(shift, profile, start_date=None, end_date=None):
    """Validate that a shift can be used on the current user's personal reimbursement."""
    if not shift or not profile:
        return False
    if not reimbursement_is_work_expense_schedule(shift):
        return False
    if start_date and shift.start_time and shift.start_time.date() < start_date:
        return False
    if end_date and shift.start_time and shift.start_time.date() > end_date:
        return False

    assigned_ids = get_shift_assigned_engineer_ids(shift)
    return profile.id in assigned_ids or getattr(shift, 'engineer_id', None) == profile.id


def reimbursement_claimed_schedule_scope_for_user(profile, start_date, end_date, exclude_header_id=None):
    """Return exact schedule rows already claimed by submitted/approved/paid reimbursements.

    A submitted monthly worksheet may contain saved schedule rows with no
    amount and no receipt. Date-level blocking is also too broad because one
    claimed item on a day should not hide every other valid schedule on that day.
    """
    if not profile or not start_date or not end_date:
        return {'shift_ids': set(), 'dates': set()}

    amount_claim_filters = [
        func.coalesce(getattr(ReimbursementRow, field), 0) > 0
        for field in REIMBURSEMENT_EXPENSE_FIELDS
    ]
    receipt_claim_exists = (
        db.session.query(ReimbursementReceipt.id)
        .filter(ReimbursementReceipt.reimbursement_id == ReimbursementRow.reimbursement_id)
        .filter(or_(
            and_(
                ReimbursementRow.shift_id.isnot(None),
                ReimbursementReceipt.shift_id == ReimbursementRow.shift_id
            ),
            and_(
                ReimbursementRow.shift_id.is_(None),
                ReimbursementReceipt.shift_id == -ReimbursementRow.id
            )
        ))
        .exists()
    )

    query = (
        db.session.query(ReimbursementRow.shift_id, ReimbursementRow.row_date)
        .join(ReimbursementHeader, ReimbursementRow.reimbursement_id == ReimbursementHeader.id)
        .filter(ReimbursementHeader.user_id == current_user.id)
        .filter(ReimbursementHeader.engineer_id == profile.id)
        .filter(ReimbursementRow.row_date >= start_date)
        .filter(ReimbursementRow.row_date <= end_date)
        .filter(func.lower(func.trim(ReimbursementHeader.status)).in_(['submitted', 'approved', 'paid']))
        .filter(or_(
            ReimbursementRow.row_total > 0,
            *amount_claim_filters,
            receipt_claim_exists
        ))
    )
    if clean_int(exclude_header_id):
        query = query.filter(ReimbursementHeader.id != clean_int(exclude_header_id))

    claimed_shift_ids = set()
    claimed_dates = set()
    for shift_id, row_date in query.all():
        if clean_int(shift_id):
            claimed_shift_ids.add(clean_int(shift_id))
        if row_date:
            claimed_dates.add(row_date)
    return {'shift_ids': claimed_shift_ids, 'dates': claimed_dates}


def reimbursement_row_to_dict(row, receipts_by_shift=None):
    """Serialize a saved reimbursement row for frontend reload."""
    amounts = {field: reimbursement_money_value(getattr(row, field, 0)) for field in REIMBURSEMENT_EXPENSE_FIELDS}
    receipts_by_shift = receipts_by_shift or {}
    is_manual = not bool(row.shift_id)
    manual_key = f"manual_{row.id}" if is_manual and row.id else ''
    receipt_key = manual_key if is_manual else row.shift_id
    receipts = receipts_by_shift.get(receipt_key)
    if receipts is None:
        receipts = receipts_by_shift.get(str(receipt_key), [])
    return {
        'id': row.id,
        'shift_id': row.shift_id,
        'manual': is_manual,
        'manual_key': manual_key,
        'date': row.row_date.isoformat() if row.row_date else '',
        'start_time': row.start_time or '',
        'end_time': row.end_time or '',
        'client': row.client_name or '',
        'product': row.product_name or '',
        'serial_number': row.serial_number or '',
        'task': row.task_name or '',
        'engineers': [row.engineer_name] if row.engineer_name else [],
        'remarks': reimbursement_excel_row_remarks(row),
        'amounts': amounts,
        'row_total': reimbursement_money_value(row.row_total),
        'receipts': receipts
    }


def reimbursement_is_manual_row_payload(row_payload):
    """Return True when the frontend is saving an extra/manual reimbursement item."""
    if not isinstance(row_payload, dict):
        return False
    return bool(row_payload.get('manual') or row_payload.get('is_manual') or row_payload.get('manual_item')) or not clean_int(row_payload.get('shift_id'))


def reimbursement_apply_manual_row_payload(header, row_payload, profile, start_date, end_date):
    """Create one manual reimbursement row not linked to a schedule.

    Manual rows are for weekend/day-off purchases and are intentionally stored
    without a Shift link. The amount is placed under Others/Misc.
    """
    try:
        row_date = reimbursement_parse_date(row_payload.get('date') or row_payload.get('row_date'), 'date')
    except ValueError:
        return None

    if row_date < start_date or row_date > end_date:
        return None

    item_name = (
        row_payload.get('item_name') or
        row_payload.get('description') or
        row_payload.get('remarks') or
        'Manual reimbursement item'
    )
    item_name = str(item_name).strip()[:150] or 'Manual reimbursement item'

    amounts_payload = row_payload.get('amounts') if isinstance(row_payload.get('amounts'), dict) else {}
    manual_amount = reimbursement_money_value(
        row_payload.get('amount') or
        row_payload.get('price') or
        amounts_payload.get('others_misc') or
        row_payload.get('others_misc') or
        0
    )
    if manual_amount <= 0:
        return None

    amounts = {field: 0.0 for field in REIMBURSEMENT_EXPENSE_FIELDS}
    amounts['others_misc'] = manual_amount

    row = ReimbursementRow(
        reimbursement_id=header.id,
        shift_id=None,
        row_date=row_date,
        start_time='',
        end_time='',
        client_name='',
        product_name='',
        serial_number='',
        task_name=item_name,
        engineer_name=getattr(profile, 'name', '') or getattr(current_user, 'username', '') or '',
        remarks=(clean_str(row_payload.get('remarks')) or ''),
        row_total=round(manual_amount, 2)
    )

    for field, amount in amounts.items():
        setattr(row, field, amount)

    db.session.add(row)
    return row


def reimbursement_apply_row_payload(header, row_payload, profile, start_date, end_date):
    """Create one saved reimbursement row from a frontend row payload."""
    if reimbursement_is_manual_row_payload(row_payload):
        return reimbursement_apply_manual_row_payload(header, row_payload, profile, start_date, end_date)

    shift_id = clean_int(row_payload.get('shift_id')) if isinstance(row_payload, dict) else None
    shift = db.session.get(Shift, shift_id) if shift_id else None
    if not reimbursement_shift_allowed_for_current_user(shift, profile, start_date, end_date):
        return None

    schedule_row = reimbursement_shift_row(
        shift,
        display_engineer_names=[getattr(profile, 'name', '') or getattr(current_user, 'username', '') or '']
    )

    amounts_payload = row_payload.get('amounts') if isinstance(row_payload, dict) else {}
    if not isinstance(amounts_payload, dict):
        amounts_payload = {}

    amounts = {}
    row_total = 0.0
    for field in REIMBURSEMENT_EXPENSE_FIELDS:
        amount = reimbursement_money_value(
            amounts_payload.get(field, row_payload.get(field) if isinstance(row_payload, dict) else 0)
        )
        amounts[field] = amount
        row_total += amount

    row = ReimbursementRow(
        reimbursement_id=header.id,
        shift_id=shift.id,
        row_date=shift.start_time.date() if shift.start_time else None,
        start_time=schedule_row.get('start_time') or '',
        end_time=schedule_row.get('end_time') or '',
        client_name=schedule_row.get('client') or '',
        product_name=schedule_row.get('product') or '',
        serial_number=schedule_row.get('serial_number') or '',
        task_name=schedule_row.get('task') or '',
        engineer_name=(schedule_row.get('engineers') or [''])[0],
        # Keep remarks manual-only. Do not auto-fill from schedule/client/task,
        # because that duplicates remarks in saved drafts and generated Excel.
        remarks=(row_payload.get('remarks') if isinstance(row_payload, dict) else '') or '',
        row_total=round(row_total, 2)
    )

    for field, amount in amounts.items():
        setattr(row, field, amount)

    db.session.add(row)
    return row


def reimbursement_manual_receipt_match_key_from_values(row_date, item_name, amount):
    """Stable key used to keep manual-item receipts attached across draft saves."""
    date_text = row_date.isoformat() if hasattr(row_date, 'isoformat') else str(row_date or '')
    item_text = clean_str(item_name).strip().lower()
    return (date_text, item_text, round(reimbursement_money_value(amount), 2))


def reimbursement_manual_receipt_match_key_from_row(row):
    if not row:
        return None
    return reimbursement_manual_receipt_match_key_from_values(
        getattr(row, 'row_date', None),
        getattr(row, 'task_name', None) or getattr(row, 'remarks', None) or '',
        getattr(row, 'others_misc', None) or getattr(row, 'row_total', None) or 0
    )


def reimbursement_manual_receipt_match_key_from_payload(row_payload):
    if not isinstance(row_payload, dict):
        return None
    amounts_payload = row_payload.get('amounts') if isinstance(row_payload.get('amounts'), dict) else {}
    amount = (
        row_payload.get('amount') or
        row_payload.get('price') or
        amounts_payload.get('others') or
        amounts_payload.get('others_misc') or
        row_payload.get('others') or
        row_payload.get('others_misc') or
        0
    )
    return reimbursement_manual_receipt_match_key_from_values(
        row_payload.get('date') or row_payload.get('row_date'),
        row_payload.get('item_name') or row_payload.get('description') or row_payload.get('task') or row_payload.get('remarks') or '',
        amount
    )


@app.route('/get_reimbursement_schedule_rows')
@login_required
def get_reimbursement_schedule_rows():
    """Phase 6 foundation: return schedule rows for reimbursement date range.

    Engineers and hybrid users receive their own assigned schedules by default.
    Scheduler/admin users without an engineer profile can view all schedule rows
    for the selected range so the page remains usable for office-side validation.
    """
    try:
        start_date = reimbursement_parse_date(request.args.get('start'), 'start')
        end_date = reimbursement_parse_date(request.args.get('end'), 'end')
    except ValueError as exc:
        return jsonify({'success': False, 'error': str(exc)}), 400

    if end_date < start_date:
        return jsonify({'success': False, 'error': 'End date must be after start date'}), 400

    if (end_date - start_date).days > 62:
        return jsonify({'success': False, 'error': 'Date range is limited to 63 days for performance'}), 400

    try:
        start_dt = datetime.combine(start_date, datetime.min.time())
        end_dt = datetime.combine(end_date + timedelta(days=1), datetime.min.time())

        profile = getattr(current_user, 'engineer_profile', None)
        if not profile:
            return jsonify({
                'success': False,
                'error': 'Your account is not linked to an engineer profile, so reimbursement schedules cannot be loaded. Please ask a superadmin to link your Personnel record.',
                'rows': [],
                'count': 0,
                'start': start_date.isoformat(),
                'end': end_date.isoformat(),
                'scope': 'own',
                'can_view_all': False
            }), 400

        claimed_scope = reimbursement_claimed_schedule_scope_for_user(profile, start_date, end_date)
        claimed_shift_ids = claimed_scope.get('shift_ids') or set()
        claimed_dates = claimed_scope.get('dates') or set()

        shifts = (
            Shift.query
            .options(
                joinedload(Shift.client),
                joinedload(Shift.product)
            )
            .filter(Shift.start_time >= start_dt)
            .filter(Shift.start_time < end_dt)
            .order_by(Shift.start_time.asc(), Shift.id.asc())
            .all()
        )

        rows = []
        excluded_dates_seen = set()
        row_warnings = []
        for shift in shifts:
            try:
                if not reimbursement_is_work_expense_schedule(shift):
                    continue

                assigned_ids = get_shift_assigned_engineer_ids(shift)
                if profile.id not in assigned_ids and getattr(shift, 'engineer_id', None) != profile.id:
                    continue

                shift_date = shift.start_time.date() if shift.start_time else None
                if clean_int(getattr(shift, 'id', None)) in claimed_shift_ids:
                    excluded_dates_seen.add(shift_date)
                    continue

                row_engineers = [getattr(profile, 'name', '') or getattr(current_user, 'username', '') or '']
                rows.append(reimbursement_shift_row(shift, display_engineer_names=row_engineers))
            except Exception as row_error:
                row_warnings.append({
                    'shift_id': getattr(shift, 'id', None),
                    'message': clean_str(row_error) or 'Unable to build schedule row.'
                })
                print(f"[Reimbursement] Skipped schedule row {getattr(shift, 'id', None)}: {row_error}", flush=True)

        excluded_date_labels = [item.isoformat() for item in sorted(item for item in excluded_dates_seen if item)]
        claimed_date_labels = [item.isoformat() for item in sorted(item for item in claimed_dates if item)]
        return jsonify({
            'success': True,
            'rows': rows,
            'count': len(rows),
            'start': start_date.isoformat(),
            'end': end_date.isoformat(),
            'excluded_dates': excluded_date_labels,
            'excluded_count': len(excluded_date_labels),
            'claimed_dates': claimed_date_labels,
            'claimed_date_count': len(claimed_date_labels),
            'excluded_shift_ids': sorted(claimed_shift_ids),
            'warnings': row_warnings,
            'warning_count': len(row_warnings),
            'scope': 'own',
            'can_view_all': False
        })
    except Exception as exc:
        print(f"[Reimbursement] Schedule row load failed: {exc}", flush=True)
        return jsonify({
            'success': False,
            'error': 'Unable to load reimbursement schedules. Please refresh and try again.',
            'detail': clean_str(exc)[:240],
            'rows': [],
            'count': 0,
            'start': start_date.isoformat(),
            'end': end_date.isoformat(),
            'scope': 'own',
            'can_view_all': False
        }), 500



REIMBURSEMENT_RECEIPT_EXTENSIONS = {'pdf', 'png', 'jpg', 'jpeg'}
REIMBURSEMENT_RECEIPT_MAX_BYTES = 2 * 1024 * 1024
REIMBURSEMENT_RECEIPT_INTAKE_MAX_BYTES = 35 * 1024 * 1024
REIMBURSEMENT_RECEIPT_ALLOWED_LABEL = 'PDF, JPG, JPEG, or PNG up to 35MB'


def reimbursement_receipt_upload_root():
    """Railway-safe persistent receipt storage."""
    if os.environ.get('RAILWAY_ENVIRONMENT'):
        root = '/data/uploads/reimbursements'
    else:
        root = os.path.join(basedir, 'static', 'uploads', 'reimbursements')
    os.makedirs(root, exist_ok=True)
    return root


def reimbursement_receipt_extension(filename):
    if not filename or '.' not in filename:
        return ''
    return filename.rsplit('.', 1)[1].lower().strip()


def reimbursement_receipt_allowed(filename):
    return reimbursement_receipt_extension(filename) in REIMBURSEMENT_RECEIPT_EXTENSIONS


def reimbursement_receipt_size_label(max_bytes=REIMBURSEMENT_RECEIPT_MAX_BYTES):
    return f"{max_bytes // (1024 * 1024)}MB"


def reimbursement_receipt_intake_size_label():
    return reimbursement_receipt_size_label(REIMBURSEMENT_RECEIPT_INTAKE_MAX_BYTES)


def reimbursement_optimize_image_receipt_bytes(file_bytes, target_bytes=REIMBURSEMENT_RECEIPT_MAX_BYTES):
    """Compress uploaded receipt photos to fit the stored reimbursement limit."""
    if not file_bytes or len(file_bytes) <= target_bytes:
        return file_bytes, None, None

    from PIL import Image, ImageOps

    with Image.open(io.BytesIO(file_bytes)) as source_img:
        try:
            img = ImageOps.exif_transpose(source_img)
        except Exception:
            img = source_img.copy()

        if img.mode in ('RGBA', 'LA') or ('transparency' in img.info):
            background = Image.new('RGB', img.size, 'white')
            background.paste(img.convert('RGBA'), mask=img.convert('RGBA').getchannel('A'))
            img = background
        else:
            img = img.convert('RGB')

        try:
            resample_filter = Image.Resampling.LANCZOS
        except AttributeError:
            resample_filter = Image.LANCZOS

        best_bytes = None
        best_size = None
        max_sides = [2200, 1800, 1600, 1400, 1200, 1000, 850]
        qualities = [86, 80, 74, 68, 62, 56, 50, 44]

        for max_side in max_sides:
            candidate = img
            width, height = candidate.size
            largest_side = max(width, height)
            if largest_side > max_side:
                scale = max_side / float(largest_side)
                new_size = (max(1, int(width * scale)), max(1, int(height * scale)))
                candidate = img.resize(new_size, resample_filter)

            for quality in qualities:
                output = io.BytesIO()
                candidate.save(
                    output,
                    format='JPEG',
                    quality=quality,
                    optimize=True,
                    progressive=True
                )
                optimized = output.getvalue()
                optimized_size = len(optimized)
                if best_size is None or optimized_size < best_size:
                    best_bytes = optimized
                    best_size = optimized_size
                if optimized_size <= target_bytes:
                    return optimized, 'jpg', 'image/jpeg'

        if best_bytes and best_size and best_size < len(file_bytes):
            return best_bytes, 'jpg', 'image/jpeg'

    return file_bytes, None, None


def reimbursement_rasterize_pdf_receipt_bytes(pdf_bytes, target_bytes=REIMBURSEMENT_RECEIPT_MAX_BYTES):
    """Last-resort compression for scanned receipt PDFs uploaded by engineers."""
    if not pdf_bytes or len(pdf_bytes) <= target_bytes:
        return pdf_bytes

    try:
        import fitz
        from PIL import Image
        from reportlab.lib.pagesizes import A4
        from reportlab.lib.units import mm
        from reportlab.lib.utils import ImageReader
        from reportlab.pdfgen import canvas
    except Exception as import_error:
        print(f"[Reimbursement] PDF raster compression unavailable: {import_error}", flush=True)
        return pdf_bytes

    try:
        source_doc = fitz.open(stream=pdf_bytes, filetype='pdf')
    except Exception as open_error:
        print(f"[Reimbursement] PDF raster compression skipped: {open_error}", flush=True)
        return pdf_bytes

    if source_doc.needs_pass:
        source_doc.close()
        return pdf_bytes

    page_count = len(source_doc)
    if page_count <= 0:
        source_doc.close()
        return pdf_bytes

    settings = [
        (1.20, 76),
        (1.00, 70),
        (0.85, 64),
        (0.72, 58),
        (0.60, 52),
        (0.50, 46),
    ]
    best_bytes = None
    best_size = None

    try:
        for zoom, jpeg_quality in settings:
            output = io.BytesIO()
            pdf_canvas = canvas.Canvas(output, pagesize=A4, pageCompression=1)
            page_width, page_height = A4
            margin = 10 * mm
            max_width = page_width - (2 * margin)
            max_height = page_height - (2 * margin)

            for page in source_doc:
                pix = page.get_pixmap(matrix=fitz.Matrix(zoom, zoom), alpha=False)
                image = Image.open(io.BytesIO(pix.tobytes('png'))).convert('RGB')
                image_buffer = io.BytesIO()
                image.save(
                    image_buffer,
                    format='JPEG',
                    quality=jpeg_quality,
                    optimize=True,
                    progressive=True
                )
                image_buffer.seek(0)

                image_width, image_height = image.size
                scale = min(max_width / float(image_width), max_height / float(image_height))
                draw_width = image_width * scale
                draw_height = image_height * scale
                x_pos = (page_width - draw_width) / 2
                y_pos = (page_height - draw_height) / 2

                pdf_canvas.drawImage(
                    ImageReader(image_buffer),
                    x_pos,
                    y_pos,
                    width=draw_width,
                    height=draw_height,
                    preserveAspectRatio=True,
                    mask='auto'
                )
                pdf_canvas.showPage()

            pdf_canvas.save()
            optimized = output.getvalue()
            optimized_size = len(optimized)
            if optimized and (best_size is None or optimized_size < best_size):
                best_bytes = optimized
                best_size = optimized_size
            if optimized and optimized_size <= target_bytes:
                print(
                    f"[Reimbursement] Uploaded receipt PDF raster-optimized: {len(pdf_bytes)} bytes -> {optimized_size} bytes.",
                    flush=True
                )
                return optimized
    except Exception as raster_error:
        print(f"[Reimbursement] PDF raster compression failed: {raster_error}", flush=True)
    finally:
        source_doc.close()

    if best_bytes and best_size and best_size < len(pdf_bytes):
        return best_bytes
    return pdf_bytes


def reimbursement_optimize_pdf_receipt_bytes(pdf_bytes, target_bytes=REIMBURSEMENT_RECEIPT_MAX_BYTES):
    """Compress uploaded reimbursement receipt PDFs, including scanned PDFs."""
    if not pdf_bytes or len(pdf_bytes) <= target_bytes:
        return pdf_bytes

    optimized = reimbursement_compress_pdf_bytes_best_effort(pdf_bytes, target_bytes)
    if optimized and len(optimized) <= target_bytes:
        return optimized

    return reimbursement_rasterize_pdf_receipt_bytes(optimized or pdf_bytes, target_bytes)


def reimbursement_prepare_receipt_upload_bytes(file_obj, original_filename):
    """Validate and optimize one reimbursement receipt upload before persistence."""
    ext = reimbursement_receipt_extension(original_filename)
    file_bytes = file_obj.read()

    if not file_bytes:
        raise ValueError(f'Receipt file is empty: {original_filename}.')

    if len(file_bytes) > REIMBURSEMENT_RECEIPT_INTAKE_MAX_BYTES:
        raise ValueError(
            f"Receipt file is too large: {original_filename}. "
            f"Maximum upload size is {reimbursement_receipt_intake_size_label()} per file."
        )

    stored_ext = ext
    content_type = file_obj.mimetype or ''

    if ext in {'jpg', 'jpeg', 'png'}:
        try:
            optimized_bytes, optimized_ext, optimized_content_type = reimbursement_optimize_image_receipt_bytes(file_bytes)
        except Exception:
            raise ValueError(
                'Receipt image could not be processed. Please upload a clearer JPG, JPEG, or PNG file.'
            )
        if optimized_ext:
            file_bytes = optimized_bytes
            stored_ext = optimized_ext
            content_type = optimized_content_type
    elif ext == 'pdf' and len(file_bytes) > REIMBURSEMENT_RECEIPT_MAX_BYTES:
        file_bytes = reimbursement_optimize_pdf_receipt_bytes(file_bytes, REIMBURSEMENT_RECEIPT_MAX_BYTES)
        content_type = 'application/pdf'

    if len(file_bytes) > REIMBURSEMENT_RECEIPT_MAX_BYTES:
        raise ValueError(
            'Receipt could not be reduced below 2MB. Please upload a smaller or clearer file.'
        )

    return file_bytes, stored_ext, content_type


def reimbursement_receipt_path(receipt):
    return os.path.join(reimbursement_receipt_upload_root(), receipt.stored_filename)


def reimbursement_receipt_to_dict(receipt):
    return {
        'id': receipt.id,
        'shift_id': receipt.shift_id,
        'filename': receipt.original_filename or receipt.stored_filename,
        'content_type': receipt.content_type or '',
        'size': receipt.file_size or 0,
        'created_at': receipt.created_at.isoformat() if receipt.created_at else None,
        # Separate URLs for Approval Center receipt modal:
        # preview_url is inline for iframe/image preview; download_url forces download.
        'preview_url': url_for('preview_reimbursement_receipt', receipt_id=receipt.id),
        'download_url': url_for('download_reimbursement_receipt', receipt_id=receipt.id, download=1)
    }


def reimbursement_get_receipts_for_header(header_id):
    receipts = (
        ReimbursementReceipt.query
        .filter_by(reimbursement_id=header_id, uploaded_by_id=current_user.id)
        .order_by(ReimbursementReceipt.created_at.asc(), ReimbursementReceipt.id.asc())
        .all()
    )
    grouped = {}
    for receipt in receipts:
        # Schedule rows use their real positive shift_id.
        # Manual reimbursement rows are stored as negative row ids to avoid a DB migration.
        # Header-level additional receipts are stored with shift_id=None.
        group_key = receipt.shift_id
        if group_key is None:
            group_key = 'additional'
        elif isinstance(group_key, int) and group_key < 0:
            group_key = f"manual_{abs(group_key)}"
        try:
            grouped.setdefault(group_key, []).append(reimbursement_receipt_to_dict(receipt))
        except Exception as exc:
            print(f"[Reimbursement] Skipping unreadable receipt {getattr(receipt, 'id', '')}: {exc}")
    return grouped


def reimbursement_flatten_receipt_groups(receipts_by_shift):
    seen = set()
    flat = []
    for receipt_list in (receipts_by_shift or {}).values():
        for receipt in receipt_list or []:
            receipt_id = receipt.get('id') if isinstance(receipt, dict) else None
            dedupe_key = receipt_id or (
                receipt.get('filename', '') if isinstance(receipt, dict) else '',
                receipt.get('created_at', '') if isinstance(receipt, dict) else ''
            )
            if dedupe_key in seen:
                continue
            seen.add(dedupe_key)
            flat.append(receipt)
    return flat


def reimbursement_get_receipt_records_for_header(header_id):
    """Load all physical receipt records for a reimbursement package.

    This intentionally uses the reimbursement header only, not uploaded_by_id,
    so the generated accounting package includes every receipt attached to the
    reimbursement, including row receipts and header-level additional receipts.
    """
    return (
        ReimbursementReceipt.query
        .filter_by(reimbursement_id=header_id)
        .order_by(ReimbursementReceipt.created_at.asc(), ReimbursementReceipt.id.asc())
        .all()
    )


def reimbursement_receipt_records_grouped_for_package(header):
    """Group receipt DB records by worksheet row for the consolidated receipt PDF."""
    receipts = reimbursement_get_receipt_records_for_header(header.id)
    grouped = {}
    additional = []

    for receipt in receipts:
        if receipt.shift_id is None:
            additional.append(receipt)
            continue
        grouped.setdefault(receipt.shift_id, []).append(receipt)

    return grouped, additional


def reimbursement_receipt_pdf_safe_text(value, fallback=''):
    """Return short one-line text safe for divider pages."""
    text_value = clean_str(value) or fallback or ''
    text_value = re.sub(r'\s+', ' ', str(text_value)).strip()
    return text_value[:140]


def reimbursement_receipt_divider_pdf_bytes(title, detail_rows=None):
    """Create a one-page divider PDF for the consolidated receipt bundle."""
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.units import mm
    from reportlab.lib.utils import ImageReader
    from reportlab.pdfgen import canvas

    buffer = io.BytesIO()
    c = canvas.Canvas(buffer, pagesize=A4)
    page_width, page_height = A4

    margin_x = 22 * mm
    y = page_height - 32 * mm

    c.setFont('Helvetica-Bold', 15)
    c.drawString(margin_x, y, reimbursement_receipt_pdf_safe_text(title, 'RECEIPTS'))
    y -= 8 * mm
    c.setLineWidth(1)
    c.line(margin_x, y, page_width - margin_x, y)
    y -= 12 * mm

    c.setFont('Helvetica', 10)
    for label, value in (detail_rows or []):
        label_text = reimbursement_receipt_pdf_safe_text(label)
        value_text = reimbursement_receipt_pdf_safe_text(value, '—')
        c.setFont('Helvetica-Bold', 10)
        c.drawString(margin_x, y, f'{label_text}:')
        c.setFont('Helvetica', 10)
        c.drawString(margin_x + 42 * mm, y, value_text)
        y -= 7 * mm

        if y < 28 * mm:
            break

    c.setFont('Helvetica-Oblique', 8)
    c.drawString(margin_x, 18 * mm, 'Generated by MEDICAL SERVICE reimbursement package.')
    c.showPage()
    c.save()
    buffer.seek(0)
    return buffer.getvalue()


def reimbursement_append_pdf_bytes(writer, pdf_bytes):
    """Append all pages from PDF bytes into a pypdf PdfWriter."""
    from pypdf import PdfReader

    reader = PdfReader(io.BytesIO(pdf_bytes))
    if getattr(reader, 'is_encrypted', False):
        try:
            reader.decrypt('')
        except Exception:
            raise ValueError('Receipt PDF is encrypted and cannot be merged.')

    for page in reader.pages:
        writer.add_page(page)


def reimbursement_receipt_image_to_pdf_bytes(image_path):
    """Convert one JPG/PNG receipt image into a compressed one-page PDF.

    S12A4:
    Receipt photos are the biggest contributor to reimbursement package size.
    Downscale the image before embedding it in the consolidated All Receipts PDF.
    Original uploaded receipt files remain untouched.
    """
    from PIL import Image
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.units import mm
    from reportlab.lib.utils import ImageReader
    from reportlab.pdfgen import canvas

    max_side = int(os.environ.get('REIMBURSEMENT_RECEIPT_IMAGE_MAX_SIDE', '1600') or 1600)
    jpeg_quality = int(os.environ.get('REIMBURSEMENT_RECEIPT_IMAGE_QUALITY', '78') or 78)
    jpeg_quality = max(45, min(jpeg_quality, 92))

    with Image.open(image_path) as img:
        # Respect phone orientation metadata when Pillow supports it.
        try:
            from PIL import ImageOps
            img = ImageOps.exif_transpose(img)
        except Exception:
            pass

        # Flatten transparency onto a white page-friendly background.
        if img.mode in ('RGBA', 'LA') or ('transparency' in img.info):
            background = Image.new('RGB', img.size, 'white')
            alpha = img.getchannel('A') if img.mode in ('RGBA', 'LA') else None
            background.paste(img.convert('RGBA'), mask=alpha)
            img = background
        else:
            img = img.convert('RGB')

        # Resize high-megapixel receipt photos. A4 display does not need the
        # full phone camera resolution, and this keeps email package size low.
        width, height = img.size
        largest_side = max(width, height)
        if largest_side > max_side:
            scale = max_side / float(largest_side)
            new_size = (max(1, int(width * scale)), max(1, int(height * scale)))
            try:
                resample_filter = Image.Resampling.LANCZOS
            except AttributeError:
                resample_filter = Image.LANCZOS
            img = img.resize(new_size, resample_filter)

        temp_image = io.BytesIO()
        img.save(
            temp_image,
            format='JPEG',
            quality=jpeg_quality,
            optimize=True,
            progressive=True
        )
        temp_image.seek(0)

    buffer = io.BytesIO()
    c = canvas.Canvas(buffer, pagesize=A4, pageCompression=1)
    page_width, page_height = A4
    margin = 12 * mm
    max_width = page_width - (2 * margin)
    max_height = page_height - (2 * margin)

    with Image.open(io.BytesIO(temp_image.getvalue())) as pdf_img:
        image_width, image_height = pdf_img.size

    scale = min(max_width / float(image_width), max_height / float(image_height))
    draw_width = image_width * scale
    draw_height = image_height * scale
    x = (page_width - draw_width) / 2
    y = (page_height - draw_height) / 2

    c.drawImage(
        ImageReader(io.BytesIO(temp_image.getvalue())),
        x,
        y,
        width=draw_width,
        height=draw_height,
        preserveAspectRatio=True,
        mask='auto'
    )
    c.showPage()
    c.save()
    buffer.seek(0)
    return buffer.getvalue()


def reimbursement_append_receipt_file_to_writer(writer, receipt):
    """Append a stored receipt PDF/image file to the consolidated receipt writer."""
    from reportlab.lib.utils import ImageReader

    receipt_path = reimbursement_receipt_path(receipt)
    if not os.path.exists(receipt_path):
        print(f"[Reimbursement] Receipt missing, skipped from merged PDF: {receipt_path}", flush=True)
        return False

    ext = reimbursement_receipt_extension(receipt.original_filename or receipt.stored_filename)
    if ext == 'pdf':
        with open(receipt_path, 'rb') as file_obj:
            reimbursement_append_pdf_bytes(writer, file_obj.read())
        return True

    if ext in {'jpg', 'jpeg', 'png'}:
        pdf_bytes = reimbursement_receipt_image_to_pdf_bytes(receipt_path)
        reimbursement_append_pdf_bytes(writer, pdf_bytes)
        return True

    print(f"[Reimbursement] Unsupported receipt type skipped from merged PDF: {receipt_path}", flush=True)
    return False


def reimbursement_compress_pdf_bytes_best_effort(pdf_bytes, target_bytes=None):
    """Best-effort compression for generated All Receipts PDF.

    This keeps the official accounting output small without touching original
    uploaded receipt files. Exact 2 MB is not guaranteed for many pages or
    already-optimized PDFs, but image receipts are downscaled before this step.
    """
    if not pdf_bytes:
        return pdf_bytes

    target_bytes = clean_int(target_bytes) or int(os.environ.get('REIMBURSEMENT_RECEIPT_PDF_TARGET_MB', '2') or 2) * 1024 * 1024
    if len(pdf_bytes) <= target_bytes:
        return pdf_bytes

    try:
        from pypdf import PdfReader, PdfWriter

        reader = PdfReader(io.BytesIO(pdf_bytes))
        if getattr(reader, 'is_encrypted', False):
            try:
                reader.decrypt('')
            except Exception:
                return pdf_bytes

        writer = PdfWriter()
        for page in reader.pages:
            try:
                page.compress_content_streams()
            except Exception:
                pass
            writer.add_page(page)

        try:
            writer.add_metadata({})
        except Exception:
            pass

        output = io.BytesIO()
        writer.write(output)
        compressed = output.getvalue()

        if compressed and len(compressed) < len(pdf_bytes):
            print(
                f"[Reimbursement] All Receipts PDF optimized: {len(pdf_bytes)} bytes -> {len(compressed)} bytes.",
                flush=True
            )
            return compressed

    except Exception as compression_error:
        print(f"[Reimbursement] All Receipts PDF compression skipped: {compression_error}", flush=True)

    return pdf_bytes


def build_reimbursement_all_receipts_pdf(header):
    """Build one consolidated All Receipts PDF for the reimbursement package.

    The output groups receipts by reimbursement row and inserts a divider page
    before each row's receipt pages. Original receipt files are not added
    separately to the ZIP because this PDF is the accounting-ready copy.
    """
    from pypdf import PdfWriter

    writer = PdfWriter()
    grouped, additional_receipts = reimbursement_receipt_records_grouped_for_package(header)
    appended_count = 0

    rows = sorted(header.rows, key=lambda row: (row.row_date or header.start_date, row.id))
    for row in rows:
        receipt_key = -row.id if not row.shift_id else row.shift_id
        row_receipts = grouped.get(receipt_key, [])
        if not row_receipts:
            continue

        row_date = row.row_date.strftime('%m-%d-%Y') if row.row_date else ''
        divider_details = [
            ('Date', row_date),
            ('Client / Item', row.client_name or ('Manual Item' if not row.shift_id else '')),
            ('Product / Serial', ' / '.join([part for part in [row.product_name, row.serial_number] if part])),
            ('Task / Purpose', row.task_name or row.remarks or ''),
            ('Row Total', f"PHP {float(row.row_total or 0):,.2f}"),
        ]
        reimbursement_append_pdf_bytes(
            writer,
            reimbursement_receipt_divider_pdf_bytes('REIMBURSEMENT RECEIPTS', divider_details)
        )

        for receipt in row_receipts:
            try:
                if reimbursement_append_receipt_file_to_writer(writer, receipt):
                    appended_count += 1
            except Exception as receipt_error:
                print(
                    f"[Reimbursement] Receipt merge skipped ({receipt.original_filename or receipt.stored_filename}): {receipt_error}",
                    flush=True
                )

    if additional_receipts:
        reimbursement_append_pdf_bytes(
            writer,
            reimbursement_receipt_divider_pdf_bytes(
                'ADDITIONAL RECEIPTS',
                [
                    ('Period', f"{header.start_date.strftime('%m-%d-%Y')} to {header.end_date.strftime('%m-%d-%Y')}"),
                    ('Receipt Count', str(len(additional_receipts))),
                ]
            )
        )
        for receipt in additional_receipts:
            try:
                if reimbursement_append_receipt_file_to_writer(writer, receipt):
                    appended_count += 1
            except Exception as receipt_error:
                print(
                    f"[Reimbursement] Additional receipt merge skipped ({receipt.original_filename or receipt.stored_filename}): {receipt_error}",
                    flush=True
                )

    if appended_count <= 0:
        return None

    output = io.BytesIO()
    writer.write(output)
    output.seek(0)
    return output


def reimbursement_all_receipts_filename(header, engineer_name=''):
    safe_name = secure_filename((engineer_name or 'Engineer').replace(' ', '_')) or 'Engineer'
    period = f"{header.start_date.strftime('%Y%m%d')}_{header.end_date.strftime('%Y%m%d')}"
    return f"All_Receipts_{safe_name}_{period}.pdf"


def reimbursement_find_owned_header_or_404(start_date, end_date, create=False):
    profile = reimbursement_get_personal_profile()
    if not profile:
        return None, jsonify({'success': False, 'error': 'Your account is not linked to an engineer profile.'}), 403
    header = reimbursement_find_header(start_date, end_date, create=create)
    if not header:
        return None, jsonify({'success': False, 'error': 'Reimbursement draft was not found.'}), 404
    if header.user_id != current_user.id or header.engineer_id != profile.id:
        return None, jsonify({'success': False, 'error': 'Not allowed.'}), 403
    return header, None, None



@app.route('/get_reimbursement_draft')
@login_required
def get_reimbursement_draft():
    """Step 3: Reload a saved reimbursement draft/submission for the selected date range."""
    try:
        start_date = reimbursement_parse_date(request.args.get('start'), 'start')
        end_date = reimbursement_parse_date(request.args.get('end'), 'end')
    except ValueError as exc:
        return jsonify({'success': False, 'error': str(exc)}), 400

    if end_date < start_date:
        return jsonify({'success': False, 'error': 'End date must be after start date'}), 400

    profile = reimbursement_get_personal_profile()
    if not profile:
        return jsonify({
            'success': True,
            'exists': False,
            'rows': [],
            'status': None,
            'message': 'No engineer profile linked to this account.'
        })

    header = reimbursement_find_header(start_date, end_date, create=False)
    if not header:
        return jsonify({
            'success': True,
            'exists': False,
            'rows': [],
            'status': None,
            'start': start_date.isoformat(),
            'end': end_date.isoformat()
        })

    receipt_warning = ''
    try:
        receipts_by_shift = reimbursement_get_receipts_for_header(header.id)
    except Exception as exc:
        print(f"[Reimbursement] Draft receipt load failed for header {header.id}: {exc}")
        receipts_by_shift = {}
        receipt_warning = 'Saved reimbursement rows loaded, but receipt attachments could not be loaded.'
    rows = [reimbursement_row_to_dict(row, receipts_by_shift) for row in sorted(header.rows, key=lambda r: (r.row_date or start_date, r.id))]
    payload = {
        'success': True,
        'exists': True,
        'id': header.id,
        'status': header.status,
        'additional_receipts': receipts_by_shift.get('additional', []),
        'start': header.start_date.isoformat(),
        'end': header.end_date.isoformat(),
        'created_at': header.created_at.isoformat() if header.created_at else None,
        'updated_at': header.updated_at.isoformat() if header.updated_at else None,
        'submitted_at': header.submitted_at.isoformat() if header.submitted_at else None,
        **reimbursement_header_approval_meta(header),
        'rows': rows,
        'grand_total': round(sum(reimbursement_money_value(row.row_total) for row in header.rows), 2)
    }
    if receipt_warning:
        payload['receipt_warning'] = receipt_warning
    return jsonify(payload)




@app.route('/get_my_reimbursement_statuses')
@login_required
def get_my_reimbursement_statuses():
    """Return the logged-in user's reimbursement history for the status window.

    Used by reimbursement.html to show a quick status section without requiring
    the engineer to remember and manually load every date range.
    """
    ensure_reimbursement_approval_columns()

    profile = reimbursement_get_personal_profile()
    if not profile:
        return jsonify({
            'success': True,
            'items': [],
            'count': 0,
            'message': 'No linked engineer profile found for this account.'
        })

    requested_status = (request.args.get('status') or 'all').strip().lower()
    status_map = {
        'all': None,
        'draft': 'Draft',
        'drafts': 'Draft',
        'submitted': 'Submitted',
        'pending': 'Submitted',
        'approved': 'Approved',
        'rejected': 'Rejected',
        'returned': 'Rejected'
    }
    status_filter = status_map.get(requested_status, None)

    limit = clean_int(request.args.get('limit')) or 20
    limit = min(max(limit, 1), 100)

    query = (
        ReimbursementHeader.query
        .filter(
            ReimbursementHeader.user_id == current_user.id,
            ReimbursementHeader.engineer_id == profile.id
        )
    )

    if status_filter:
        query = query.filter(func.lower(func.trim(ReimbursementHeader.status)) == status_filter.lower())

    headers = (
        query
        .order_by(
            ReimbursementHeader.updated_at.desc(),
            ReimbursementHeader.submitted_at.desc(),
            ReimbursementHeader.id.desc()
        )
        .limit(limit)
        .all()
    )

    items = []
    status_counts = {
        'Draft': 0,
        'Submitted': 0,
        'Approved': 0,
        'Rejected': 0
    }

    for header in headers:
        status_value = (header.status or 'Draft').strip() or 'Draft'
        if status_value in status_counts:
            status_counts[status_value] += 1

        items.append({
            'id': header.id,
            'start': header.start_date.isoformat() if header.start_date else '',
            'end': header.end_date.isoformat() if header.end_date else '',
            'status': status_value,
            'created_at': header.created_at.isoformat() if header.created_at else None,
            'updated_at': header.updated_at.isoformat() if header.updated_at else None,
            'submitted_at': header.submitted_at.isoformat() if header.submitted_at else None,
            'grand_total': round(sum(reimbursement_money_value(row.row_total) for row in header.rows), 2),
            'row_count': len(header.rows or []),
            **reimbursement_header_approval_meta(header)
        })

    # Counts should represent all of the user's records, not only the limited list.
    try:
        all_status_rows = (
            db.session.query(ReimbursementHeader.status, func.count(ReimbursementHeader.id))
            .filter(
                ReimbursementHeader.user_id == current_user.id,
                ReimbursementHeader.engineer_id == profile.id
            )
            .group_by(ReimbursementHeader.status)
            .all()
        )
        status_counts = {'Draft': 0, 'Submitted': 0, 'Approved': 0, 'Rejected': 0}
        for raw_status, count_value in all_status_rows:
            normalized_status = (raw_status or 'Draft').strip() or 'Draft'
            for known_status in list(status_counts.keys()):
                if normalized_status.lower() == known_status.lower():
                    status_counts[known_status] += int(count_value or 0)
                    break
    except Exception as count_error:
        print(f"[Reimbursement] Status count fallback used: {count_error}", flush=True)

    return jsonify({
        'success': True,
        'items': items,
        'count': len(items),
        'status_filter': requested_status,
        'status_counts': status_counts
    })

@app.route('/save_reimbursement_draft', methods=['POST'])
@csrf.exempt
@login_required
def save_reimbursement_draft():
    """Step 3: Save personal reimbursement entries as Draft."""
    ensure_reimbursement_approval_columns()
    payload = request.get_json(silent=True) or {}

    try:
        start_date = reimbursement_parse_date(payload.get('start') or payload.get('start_date'), 'start')
        end_date = reimbursement_parse_date(payload.get('end') or payload.get('end_date'), 'end')
    except ValueError as exc:
        return jsonify({'success': False, 'error': str(exc)}), 400

    if end_date < start_date:
        return jsonify({'success': False, 'error': 'End date must be after start date'}), 400

    if (end_date - start_date).days > 62:
        return jsonify({'success': False, 'error': 'Date range is limited to 63 days for performance'}), 400

    profile = reimbursement_get_personal_profile()
    if not profile:
        return jsonify({'success': False, 'error': 'Your account is not linked to an engineer profile.'}), 403

    rows_payload = payload.get('rows') or []
    if not isinstance(rows_payload, list):
        return jsonify({'success': False, 'error': 'Rows must be a list.'}), 400

    try:
        header = reimbursement_find_header(start_date, end_date, create=True)
        if not header:
            return jsonify({'success': False, 'error': 'Unable to create reimbursement draft.'}), 400

        if not reimbursement_header_is_editable(header):
            return reimbursement_edit_lock_response(header, 'edited as draft')

        # Rejected/returned reimbursements stay Rejected while the engineer edits.
        # They move back to Submitted only after the engineer clicks Submit again.
        if reimbursement_normalize_status(header.status) == 'Draft':
            header.status = 'Draft'
        header.updated_at = get_manila_time()

        manual_receipts_by_key = {}
        for existing_row in ReimbursementRow.query.filter_by(reimbursement_id=header.id, shift_id=None).all():
            manual_key = reimbursement_manual_receipt_match_key_from_row(existing_row)
            if not manual_key:
                continue
            manual_receipts = ReimbursementReceipt.query.filter_by(
                reimbursement_id=header.id,
                shift_id=-existing_row.id
            ).all()
            if manual_receipts:
                manual_receipts_by_key.setdefault(manual_key, []).extend(manual_receipts)

        # Replace draft rows with the latest worksheet state.
        ReimbursementRow.query.filter_by(reimbursement_id=header.id).delete()

        saved_count = 0
        seen_schedule_ids = set()
        seen_manual_keys = set()
        for row_payload in rows_payload:
            if not isinstance(row_payload, dict):
                continue

            # Frontend has both desktop rows and mobile cards. Depending on the
            # viewport/state, the same reimbursement row can be present twice in
            # the submitted payload. De-dupe here so totals do not double after
            # Save Draft.
            if reimbursement_is_manual_row_payload(row_payload):
                amounts_payload = row_payload.get('amounts') if isinstance(row_payload.get('amounts'), dict) else {}
                manual_amount = reimbursement_money_value(
                    row_payload.get('amount') or
                    row_payload.get('price') or
                    amounts_payload.get('others_misc') or
                    row_payload.get('others_misc') or
                    0
                )
                manual_key = (
                    'manual',
                    str(row_payload.get('date') or row_payload.get('row_date') or '').strip(),
                    str(row_payload.get('item_name') or row_payload.get('description') or row_payload.get('remarks') or '').strip().lower(),
                    round(manual_amount, 2)
                )
                if manual_key in seen_manual_keys:
                    continue
                seen_manual_keys.add(manual_key)
            else:
                shift_id = clean_int(row_payload.get('shift_id'))
                if shift_id:
                    if shift_id in seen_schedule_ids:
                        continue
                    seen_schedule_ids.add(shift_id)

            saved_row = reimbursement_apply_row_payload(header, row_payload, profile, start_date, end_date)
            if saved_row:
                db.session.flush()
                if reimbursement_is_manual_row_payload(row_payload) and not saved_row.shift_id:
                    manual_key = reimbursement_manual_receipt_match_key_from_payload(row_payload)
                    for receipt in manual_receipts_by_key.pop(manual_key, []):
                        receipt.shift_id = -saved_row.id
                saved_count += 1

        if rows_payload and saved_count <= 0:
            db.session.rollback()
            return jsonify({
                'success': False,
                'error': 'No valid reimbursement rows were saved. Please reload schedules and try again.'
            }), 400

        db.session.commit()
        print(f"[Reimbursement] Draft saved header #{header.id}; status={header.status}; rows={saved_count}", flush=True)

        try:
            log_activity(f"Saved reimbursement draft {start_date.isoformat()} to {end_date.isoformat()} ({saved_count} rows)")
        except Exception as log_err:
            print(f"[Reimbursement] Activity log skipped: {log_err}")

        return jsonify({
            'success': True,
            'id': header.id,
            'status': reimbursement_normalize_status(header.status),
            'rows_saved': saved_count,
            'message': 'Reimbursement draft saved.',
            **reimbursement_header_approval_meta(header)
        })

    except Exception as exc:
        db.session.rollback()
        print(f"[Reimbursement] Save draft failed: {exc}")
        return jsonify({'success': False, 'error': 'Unable to save reimbursement draft.'}), 500


@app.route('/upload_reimbursement_receipt', methods=['POST'])
@csrf.exempt
@login_required
def upload_reimbursement_receipt():
    """Step 4: Upload receipt/photo for one personal reimbursement schedule row."""
    try:
        start_date = reimbursement_parse_date(request.form.get('start') or request.form.get('start_date'), 'start')
        end_date = reimbursement_parse_date(request.form.get('end') or request.form.get('end_date'), 'end')
    except ValueError as exc:
        return jsonify({'success': False, 'error': str(exc)}), 400

    shift_id = clean_int(request.form.get('shift_id'))
    manual_row_id = clean_int(
        request.form.get('manual_row_id') or
        request.form.get('row_id') or
        request.form.get('reimbursement_row_id')
    )
    receipt_group_id = None

    header, err_resp, err_code = reimbursement_find_owned_header_or_404(start_date, end_date, create=True)
    if err_resp:
        return err_resp, err_code

    if not reimbursement_header_is_editable(header):
        return reimbursement_edit_lock_response(header, 'updated with receipt uploads')

    profile = reimbursement_get_personal_profile()

    is_additional_receipt = str(
        request.form.get('additional_receipt') or
        request.form.get('header_receipt') or
        request.form.get('extra_receipt') or
        ''
    ).strip().lower() in {'1', 'true', 'yes', 'on'}

    if is_additional_receipt:
        # Reimbursement-level receipt not tied to a specific schedule/manual row.
        receipt_group_id = None
    elif manual_row_id:
        manual_row = db.session.get(ReimbursementRow, manual_row_id)
        if (
            not manual_row or
            manual_row.reimbursement_id != header.id or
            manual_row.shift_id
        ):
            return jsonify({'success': False, 'error': 'Manual reimbursement row is not valid.'}), 403
        receipt_group_id = -manual_row.id
    else:
        if not shift_id:
            return jsonify({'success': False, 'error': 'Missing schedule row.'}), 400
        shift = db.session.get(Shift, shift_id)
        if not reimbursement_shift_allowed_for_current_user(shift, profile, start_date, end_date):
            return jsonify({'success': False, 'error': 'Schedule is not valid for your reimbursement.'}), 403
        receipt_group_id = shift_id

    files = request.files.getlist('receipt_file') or request.files.getlist('receipt_files')
    files = [f for f in files if f and f.filename]
    if not files:
        return jsonify({'success': False, 'error': 'No receipt file selected.'}), 400

    saved = []
    try:
        root = reimbursement_receipt_upload_root()
        for file_obj in files:
            if not reimbursement_receipt_allowed(file_obj.filename):
                return jsonify({
                    'success': False,
                    'error': f"Unsupported receipt file type: {file_obj.filename}. Allowed: {REIMBURSEMENT_RECEIPT_ALLOWED_LABEL}."
                }), 400

            original = secure_filename(file_obj.filename) or 'receipt'
            ext = reimbursement_receipt_extension(original)
            if not ext:
                return jsonify({'success': False, 'error': f'Invalid receipt filename: {file_obj.filename}'}), 400

            try:
                prepared_bytes, stored_ext, content_type = reimbursement_prepare_receipt_upload_bytes(file_obj, original)
            except ValueError as prep_error:
                return jsonify({'success': False, 'error': str(prep_error)}), 400

            receipt_group_label = 'additional' if receipt_group_id is None else str(receipt_group_id)
            stored = f"reimb_{header.id}_{receipt_group_label}_{secrets.token_hex(8)}.{stored_ext}"
            target_path = os.path.join(root, stored)

            with open(target_path, 'wb') as target_file:
                target_file.write(prepared_bytes)
            size = os.path.getsize(target_path)

            receipt = ReimbursementReceipt(
                reimbursement_id=header.id,
                shift_id=receipt_group_id,
                uploaded_by_id=current_user.id,
                stored_filename=stored,
                original_filename=original,
                content_type=content_type or '',
                file_size=size
            )
            db.session.add(receipt)
            saved.append(receipt)

        header.updated_at = get_manila_time()
        db.session.commit()

        receipt_dicts = [reimbursement_receipt_to_dict(r) for r in saved]
        try:
            log_activity(f"Uploaded {len(saved)} reimbursement receipt(s) for {start_date.isoformat()} to {end_date.isoformat()}")
        except Exception as log_err:
            print(f"[Reimbursement] Receipt activity log skipped: {log_err}")

        return jsonify({'success': True, 'receipts': receipt_dicts, 'message': 'Receipt uploaded.'})

    except Exception as exc:
        db.session.rollback()
        print(f"[Reimbursement] Receipt upload failed: {exc}", flush=True)
        print(traceback.format_exc(), flush=True)
        return jsonify({'success': False, 'error': 'Unable to upload receipt.'}), 500


@app.route('/get_reimbursement_receipts')
@login_required
def get_reimbursement_receipts():
    """Step 4: List receipts for a personal reimbursement date range."""
    try:
        start_date = reimbursement_parse_date(request.args.get('start'), 'start')
        end_date = reimbursement_parse_date(request.args.get('end'), 'end')
    except ValueError as exc:
        return jsonify({'success': False, 'error': str(exc)}), 400

    profile = reimbursement_get_personal_profile()
    if not profile:
        return jsonify({
            'success': True,
            'receipts_by_shift': {},
            'additional_receipts': [],
            'all_receipts': []
        })

