def approval_center_reimbursement_counts():
    """Return reimbursement approval counts filtered for the current approver."""
    ensure_reimbursement_approval_columns()

    query = db.session.query(
        func.lower(func.trim(ReimbursementHeader.status)).label('status_key'),
        func.count(ReimbursementHeader.id)
    )
    query = apply_assigned_approver_filter(query, ReimbursementHeader, current_user, 'reimbursement')

    rows = (
        query
        .group_by(func.lower(func.trim(ReimbursementHeader.status)))
        .all()
    )

    raw_counts = {status_key or 'draft': count for status_key, count in rows}
    return {
        'draft': int(raw_counts.get('draft', 0)),
        'submitted': int(raw_counts.get('submitted', 0)),
        'approved': int(raw_counts.get('approved', 0)),
        'rejected': int(raw_counts.get('rejected', 0)),
        'pending': int(raw_counts.get('submitted', 0)),
        'total': int(sum(raw_counts.values()))
    }



TRAVEL_REQUEST_EDITABLE_STATUSES = {'Draft', 'Rejected'}
TRAVEL_REQUEST_PENDING_MANAGER_STATUS = 'Submitted'

# S12B6E: Supported Travel Request purpose types.
TRAVEL_REQUEST_TYPES = (
    'Client Visit / Service',
    'Training / Seminar - RHQ',
    'Training / Seminar - GHQ',
    'Meeting'
)


def normalize_travel_request_type(value):
    """Return a stable Travel Request type for storage and frontend reload.

    Older records may only contain this inside purpose/notes text, so this helper
    also scans longer text and falls back to Client Visit / Service.
    """
    raw_value = clean_str(value) or ''
    normalized = raw_value.strip().lower()

    for request_type in TRAVEL_REQUEST_TYPES:
        if normalized == request_type.lower():
            return request_type

    if normalized:
        for request_type in TRAVEL_REQUEST_TYPES:
            if request_type.lower() in normalized:
                return request_type

    return 'Client Visit / Service'


def travel_request_normalize_status(status_value):
    status = clean_str(status_value) or 'Draft'
    known = {
        'draft': 'Draft',
        'submitted': 'Submitted',
        'approved': 'Approved',
        'rejected': 'Rejected',
        'sent_to_accounting': 'Sent to Accounting',
        'accounting_approved': 'Accounting Approved',
        'accounting_rejected': 'Accounting Rejected',
        'funds_received': 'Funds Received',
        'travel_completed': 'Travel Completed',
        'ready_for_liquidation': 'Ready for Liquidation',
        'liquidation_pending': 'Liquidation Pending',
        'liquidation_started': 'Liquidation Started',
        'liquidation_submitted': 'Liquidation Submitted',
        'liquidation_completed': 'Liquidation Completed',
        'completed': 'Completed'
    }
    return known.get(status.strip().lower().replace(' ', '_').replace('-', '_'), status)


def travel_request_money(value):
    try:
        return round(float(value or 0), 2)
    except Exception:
        return 0.0


SUPPORTED_TRAVEL_CURRENCIES = {'PHP', 'USD'}


def normalize_travel_currency_code(value, default='PHP'):
    code = (clean_str(value) or default or 'PHP').strip().upper()
    return code if code in SUPPORTED_TRAVEL_CURRENCIES else (default if default in SUPPORTED_TRAVEL_CURRENCIES else 'PHP')


def travel_exchange_rate(value, source_currency='PHP', target_currency='PHP'):
    source_currency = normalize_travel_currency_code(source_currency)
    target_currency = normalize_travel_currency_code(target_currency)
    if source_currency == target_currency:
        return 1.0
    try:
        rate = float(value or 0)
    except Exception:
        rate = 0
    return round(rate if rate > 0 else 1.0, 6)


def travel_usd_to_php_rate(value):
    try:
        rate = float(value or 0)
    except Exception:
        rate = 0
    return round(rate, 6) if rate > 0 else 0


def travel_liquidation_direct_exchange_rate(source_currency='PHP', target_currency='PHP', usd_to_php_rate=0, fallback_rate=None):
    source_currency = normalize_travel_currency_code(source_currency)
    target_currency = normalize_travel_currency_code(target_currency)
    if source_currency == target_currency:
        return 1.0

    rate = travel_usd_to_php_rate(usd_to_php_rate)
    if rate > 0:
        if source_currency == 'PHP' and target_currency == 'USD':
            return round(1 / rate, 6)
        if source_currency == 'USD' and target_currency == 'PHP':
            return rate

    return travel_exchange_rate(fallback_rate, source_currency, target_currency)


def travel_converted_amount(source_amount, source_currency='PHP', target_currency='PHP', exchange_rate=1):
    source_currency = normalize_travel_currency_code(source_currency)
    target_currency = normalize_travel_currency_code(target_currency)
    amount = travel_request_money(source_amount)
    if source_currency == target_currency:
        return amount
    return travel_request_money(amount * travel_exchange_rate(exchange_rate, source_currency, target_currency))


def format_travel_currency_amount(value, currency_code='PHP'):
    code = normalize_travel_currency_code(currency_code)
    return f"{code} {travel_request_money(value):,.2f}"


def travel_request_date(value):
    return parse_date(value)


def travel_request_generate_request_no(record_id=None):
    today_label = get_manila_today().strftime('%Y%m%d')
    suffix = str(record_id or '').strip() or 'NEW'
    return f"TR-{today_label}-{suffix}"


def travel_request_strict_user_profile(user=None):
    """Return the Engineer profile explicitly linked to a User account.

    S12B6M:
    Travel Request identity must never use first-name / username-prefix
    fallback matching because accounts such as john can incorrectly resolve to
    the first personnel record named John. Only the hard User.id -> Engineer.user_id
    link is accepted here.
    """
    target = user or current_user
    if not target or not getattr(target, 'is_authenticated', False):
        return None

    user_id = clean_int(getattr(target, 'id', None))
    if not user_id:
        return None

    # Prefer the direct relationship when it is backed by Engineer.user_id.
    linked = getattr(target, 'engineer_rel', None)
    if linked and clean_int(getattr(linked, 'user_id', None)) == user_id:
        return linked

    return Engineer.query.filter(Engineer.user_id == user_id).first()


def travel_request_user_display_name(user=None, fallback=''):
    """Travel Request-safe user display name without prefix matching."""
    profile = travel_request_strict_user_profile(user)
    return (
        clean_str(getattr(profile, 'name', None)) or
        clean_str(fallback) or
        clean_str(getattr(user, 'username', None)) or
        ''
    )


def travel_request_current_profile():
    return travel_request_strict_user_profile(current_user)


def travel_dates_overlap(start_a, end_a, start_b, end_b):
    """Return True when two inclusive date ranges overlap."""
    if not start_a or not end_a or not start_b or not end_b:
        return False
    return start_a <= end_b and start_b <= end_a


def travel_request_conflict_statuses():
    """Statuses that should reserve a travel period."""
    return ['Draft', 'Submitted', 'Approved']


def travel_request_conflict_item_to_dict(request_rec):
    return {
        'id': request_rec.id,
        'request_no': request_rec.request_no or travel_request_generate_request_no(request_rec.id),
        'status': travel_request_normalize_status(request_rec.status),
        'departure_date': request_rec.departure_date.isoformat() if getattr(request_rec, 'departure_date', None) else '',
        'return_date': request_rec.return_date.isoformat() if getattr(request_rec, 'return_date', None) else '',
        'destination': request_rec.destination or '',
        'client_name': request_rec.client_name or '',
        'requested_amount': travel_request_money(getattr(request_rec, 'requested_amount', 0))
    }


def travel_request_schedule_conflict_to_dict(shift):
    client_name = getattr(getattr(shift, 'client', None), 'name', '') or ''
    product = getattr(shift, 'product', None)
    product_label = ''
    if product:
        product_label = travel_request_product_label(product, getattr(shift, 'product_id', '') or '')
    return {
        'id': shift.id,
        'title': shift.title or '',
        'status': shift.status or '',
        'date': shift.start_time.date().isoformat() if getattr(shift, 'start_time', None) else '',
        'start_time': shift.start_time.strftime('%H:%M') if getattr(shift, 'start_time', None) else '',
        'end_time': shift.end_time.strftime('%H:%M') if getattr(shift, 'end_time', None) else '',
        'client_name': client_name,
        'product': product_label
    }


def find_travel_request_conflicts_for_user(user_id, engineer_id, departure_date, return_date, exclude_request_id=None):
    """Find travel-period conflicts for the selected requester/engineer."""
    start_date = departure_date
    end_date = return_date or departure_date

    if not start_date or not end_date:
        return {
            'ok': True,
            'has_conflicts': False,
            'blocking': False,
            'message': '',
            'travel_request_conflicts': [],
            'schedule_conflicts': []
        }

    if end_date < start_date:
        start_date, end_date = end_date, start_date

    user_id = clean_int(user_id)
    engineer_id = clean_int(engineer_id)
    exclude_request_id = clean_int(exclude_request_id)

    travel_query = (
        TravelRequest.query
        .filter(TravelRequest.user_id == user_id)
        .filter(TravelRequest.departure_date.isnot(None))
        .filter(TravelRequest.return_date.isnot(None))
        .filter(TravelRequest.status.in_(travel_request_conflict_statuses()))
        .filter(TravelRequest.departure_date <= end_date)
        .filter(TravelRequest.return_date >= start_date)
    )

    if engineer_id:
        travel_query = travel_query.filter(or_(TravelRequest.engineer_id == engineer_id, TravelRequest.engineer_id.is_(None)))

    if exclude_request_id:
        travel_query = travel_query.filter(TravelRequest.id != exclude_request_id)

    travel_conflicts = travel_query.order_by(TravelRequest.departure_date.asc(), TravelRequest.id.asc()).all()

    schedule_conflicts = []
    if engineer_id:
        start_dt, end_dt = build_shift_datetime_bounds(start_date, end_date)
        schedule_conflicts = (
            Shift.query
            .options(joinedload(Shift.client), joinedload(Shift.product))
            .filter(Shift.start_time < end_dt)
            .filter(Shift.end_time >= start_dt)
            .filter(or_(
                Shift.engineer_id == engineer_id,
                Shift.override_engineer_id == engineer_id,
                Shift.id.in_(
                    db.session.query(ShiftEngineer.shift_id)
                    .filter(ShiftEngineer.engineer_id == engineer_id)
                )
            ))
            .order_by(Shift.start_time.asc(), Shift.id.asc())
            .all()
        )

    conflict_payload = {
        'ok': not bool(travel_conflicts or schedule_conflicts),
        'has_conflicts': bool(travel_conflicts or schedule_conflicts),
        'blocking': bool(travel_conflicts or schedule_conflicts),
        'message': '',
        'travel_request_conflicts': [travel_request_conflict_item_to_dict(item) for item in travel_conflicts],
        'schedule_conflicts': [travel_request_schedule_conflict_to_dict(item) for item in schedule_conflicts]
    }

    if conflict_payload['has_conflicts']:
        parts = []
        if travel_conflicts:
            parts.append(f"{len(travel_conflicts)} existing travel request(s)")
        if schedule_conflicts:
            parts.append(f"{len(schedule_conflicts)} existing calendar schedule(s)")
        conflict_payload['message'] = (
            'Selected travel period has conflict with ' + ' and '.join(parts) + '.'
        )

    return conflict_payload


def travel_request_conflict_response(conflicts, status_code=409):
    """Return standard conflict JSON used by save/submit/check endpoints."""
    message = conflicts.get('message') or 'Selected travel period has existing conflict.'
    return jsonify({
        'success': False,
        'status': 'conflict',
        'error': message,
        'message': message,
        'has_conflicts': True,
        'blocking_conflicts': True,
        'conflicts': conflicts
    }), status_code


def travel_request_json_list(value):
    if not clean_str(value):
        return []
    try:
        parsed = json.loads(value)
        return parsed if isinstance(parsed, list) else []
    except Exception:
        return []


def travel_request_product_label(product_rec, fallback_id=''):
    if not product_rec:
        return clean_str(fallback_id) or ''
    product_name = clean_str(getattr(product_rec, 'name', None)) or ''
    serial_number = clean_str(getattr(product_rec, 'serial_number', None)) or clean_str(fallback_id) or ''
    if product_name and serial_number:
        return f"{product_name} / {serial_number}"
    return product_name or serial_number


def travel_request_route_visit_to_dict(visit):
    product_ids = travel_request_json_list(getattr(visit, 'product_ids_json', None))
    product_names = travel_request_json_list(getattr(visit, 'product_names_json', None))

    if not product_ids and (visit.product_id or getattr(visit, 'product', None)):
        product_ids = [visit.product_id or getattr(visit.product, 'serial_number', '')]
    if not product_names and (visit.product_name or getattr(visit, 'product', None)):
        product_names = [visit.product_name or travel_request_product_label(getattr(visit, 'product', None), visit.product_id)]

    return {
        'id': visit.id,
        'route_id': visit.route_id,
        'sequence_no': visit.sequence_no or 1,
        'client_id': visit.client_id,
        'client_name': visit.client_name or (visit.client.name if getattr(visit, 'client', None) else ''),
        'product_id': visit.product_id or '',
        'product_name': visit.product_name or (visit.product.name if getattr(visit, 'product', None) else ''),
        'product_ids': product_ids,
        'product_names': product_names,
        'products': [
            {'product_id': product_id, 'product_name': product_names[index] if index < len(product_names) else product_id}
            for index, product_id in enumerate(product_ids)
        ],
        'purpose_tags': visit.purpose_tags or '',
        'visit_purpose': visit.visit_purpose or '',
        'notes': visit.notes or '',
        'remarks': visit.notes or ''
    }


def travel_request_route_to_dict(route):
    visits = sorted(
        getattr(route, 'visits', []) or [],
        key=lambda visit: (visit.sequence_no or 1, visit.id or 0)
    )
    return {
        'id': route.id,
        'sequence_no': route.sequence_no or 1,
        'from_location': route.from_location or '',
        'to_location': route.to_location or '',
        'travel_type': route.travel_type or '',
        'route_summary': route.route_summary or '',
        'visits': [travel_request_route_visit_to_dict(visit) for visit in visits]
    }


def normalize_travel_request_visit_products(raw_visit):
    """Normalize one visit's selected products.

    S10B9A supports multiple equipment selections per client visit.
    The older product_id/product_name fields are still populated from the first
    selected equipment so old screens/PDFs remain compatible.
    """
    products = []

    raw_products = raw_visit.get('products')
    if isinstance(raw_products, list):
        for raw_product in raw_products:
            if isinstance(raw_product, dict):
                product_id = clean_str(
                    raw_product.get('product_id') or
                    raw_product.get('serial_number') or
                    raw_product.get('product_serial') or
                    raw_product.get('id')
                ) or ''
                product_name = clean_str(
                    raw_product.get('product_name') or
                    raw_product.get('name') or
                    raw_product.get('equipment')
                ) or ''
            else:
                product_id = clean_str(raw_product) or ''
                product_name = ''
            if product_id or product_name:
                products.append({'product_id': product_id[:100], 'product_name': product_name[:200]})

    raw_ids = raw_visit.get('product_ids')
    if isinstance(raw_ids, list):
        for product_id_raw in raw_ids:
            product_id = clean_str(product_id_raw) or ''
            if product_id and not any(item.get('product_id') == product_id for item in products):
                products.append({'product_id': product_id[:100], 'product_name': ''})

    raw_names = raw_visit.get('product_names')
    if isinstance(raw_names, list):
        for index, product_name_raw in enumerate(raw_names):
            product_name = clean_str(product_name_raw) or ''
            if not product_name:
                continue
            if index < len(products):
                if not products[index].get('product_name'):
                    products[index]['product_name'] = product_name[:200]
            elif not any(item.get('product_name') == product_name for item in products):
                products.append({'product_id': '', 'product_name': product_name[:200]})

    legacy_product_id = clean_str(
        raw_visit.get('product_id') or
        raw_visit.get('product_serial') or
        raw_visit.get('serial_number')
    ) or ''
    legacy_product_name = clean_str(raw_visit.get('product_name') or raw_visit.get('equipment')) or ''

    if (legacy_product_id or legacy_product_name) and not products:
        products.append({'product_id': legacy_product_id[:100], 'product_name': legacy_product_name[:200]})

    normalized = []
    seen_keys = set()
    for item in products:
        product_id = clean_str(item.get('product_id')) or ''
        product_name = clean_str(item.get('product_name')) or ''
        product_rec = db.session.get(Product, product_id) if product_id else None

        if product_rec:
            product_id = clean_str(getattr(product_rec, 'serial_number', None)) or product_id
            if not product_name:
                product_name = travel_request_product_label(product_rec, product_id)

        if not product_name and product_id:
            product_name = product_id

        key = (product_id.lower(), product_name.lower())
        if key in seen_keys:
            continue
        seen_keys.add(key)

        if product_id or product_name:
            normalized.append({
                'product_id': product_id[:100] if product_id else '',
                'product_name': product_name[:200] if product_name else ''
            })

    return normalized


def build_travel_visit_purpose(product_names, purpose_tags):
    """Autofill visit purpose from selected products and purpose tags.

    Example:
    PM of MobileArt / SN123 - Warranty
    PM of Equipment A, Equipment B - Warranty
    """
    tags = [clean_str(tag) for tag in (purpose_tags or []) if clean_str(tag)]
    if not tags:
        return ''

    primary_actions = [tag for tag in tags if tag in {'PM', 'Repair', 'Installation'}]
    suffix_tags = [tag for tag in tags if tag not in {'PM', 'Repair', 'Installation'}]

    action = ' / '.join(primary_actions) if primary_actions else tags[0]
    equipment_label = ', '.join([clean_str(name) for name in product_names if clean_str(name)]) or 'selected equipment'

    purpose = f"{action} of {equipment_label}"
    if suffix_tags:
        purpose += f" - {', '.join(suffix_tags)}"
    elif primary_actions and len(tags) > len(primary_actions):
        purpose += f" - {', '.join(tags[len(primary_actions):])}"
    return purpose


def normalize_travel_request_routes_payload(payload):
    """Return sanitized route plans from frontend payload.

    Supports the new routes[] shape and falls back to the older single-route
    fields so old drafts/UI versions keep working.
    """
    raw_routes = payload.get('routes')
    routes = raw_routes if isinstance(raw_routes, list) else []

    if not routes:
        legacy_client_id = clean_int(payload.get('client_id'))
        legacy_client_name = clean_str(payload.get('client_name')) or ''
        legacy_product_id = clean_str(payload.get('product_id') or payload.get('product_serial')) or ''
        legacy_product_name = clean_str(payload.get('equipment') or payload.get('product_name')) or ''
        legacy_purpose = clean_str(payload.get('purpose')) or ''
        legacy_visit = None

        if legacy_client_id or legacy_client_name or legacy_product_id or legacy_product_name:
            legacy_visit = {
                'client_id': legacy_client_id,
                'client_name': legacy_client_name,
                'product_id': legacy_product_id,
                'product_name': legacy_product_name,
                'products': [{'product_id': legacy_product_id, 'product_name': legacy_product_name}] if (legacy_product_id or legacy_product_name) else [],
                'purpose_tags': '',
                'visit_purpose': legacy_purpose,
                'notes': '',
                'remarks': ''
            }

        routes = [{
            'from_location': payload.get('from_location'),
            'to_location': payload.get('to_location'),
            'travel_type': payload.get('travel_type'),
            'route_summary': payload.get('destination') or payload.get('route_summary'),
            'visits': [legacy_visit] if legacy_visit else []
        }]

    normalized_routes = []
    for route_index, raw_route in enumerate(routes, start=1):
        if not isinstance(raw_route, dict):
            continue

        visits_payload = raw_route.get('visits') if isinstance(raw_route.get('visits'), list) else []
        normalized_visits = []

        for visit_index, raw_visit in enumerate(visits_payload, start=1):
            if not isinstance(raw_visit, dict):
                continue

            client_id = clean_int(raw_visit.get('client_id'))
            client_rec = db.session.get(Client, client_id) if client_id else None

            products = normalize_travel_request_visit_products(raw_visit)
            first_product = products[0] if products else {}
            product_id = first_product.get('product_id') or ''
            product_name = first_product.get('product_name') or ''

            client_name = (
                clean_str(raw_visit.get('client_name')) or
                clean_str(getattr(client_rec, 'name', None)) or
                ''
            )[:200]

            purpose_tags_raw = raw_visit.get('purpose_tags') or raw_visit.get('tags') or []
            if isinstance(purpose_tags_raw, list):
                purpose_tags_list = [clean_str(tag) for tag in purpose_tags_raw if clean_str(tag)]
                purpose_tags = ', '.join(purpose_tags_list)
            else:
                purpose_tags = clean_str(purpose_tags_raw) or ''
                purpose_tags_list = [tag.strip() for tag in purpose_tags.split(',') if tag.strip()]

            product_names = [item.get('product_name') or item.get('product_id') for item in products if item.get('product_name') or item.get('product_id')]
            visit_purpose = clean_str(raw_visit.get('visit_purpose') or raw_visit.get('purpose')) or ''
            if not visit_purpose and purpose_tags_list:
                visit_purpose = build_travel_visit_purpose(product_names, purpose_tags_list)

            notes = clean_str(raw_visit.get('remarks') or raw_visit.get('notes')) or ''

            if not (client_id or client_name or product_id or product_name or products or purpose_tags or visit_purpose or notes):
                continue

            normalized_visits.append({
                'sequence_no': visit_index,
                'client_id': client_id,
                'client_name': client_name,
                'product_id': product_id[:100] if product_id else None,
                'product_name': product_name[:200] if product_name else '',
                'product_ids_json': json.dumps([item.get('product_id') for item in products if item.get('product_id')], ensure_ascii=False),
                'product_names_json': json.dumps([item.get('product_name') for item in products if item.get('product_name')], ensure_ascii=False),
                'products': products,
                'purpose_tags': purpose_tags[:255],
                'visit_purpose': visit_purpose,
                'notes': notes,
                'remarks': notes
            })

        from_location = clean_str(raw_route.get('from_location') or raw_route.get('origin')) or ''
        to_location = clean_str(raw_route.get('to_location') or raw_route.get('destination')) or ''
        travel_type = clean_str(raw_route.get('travel_type')) or ''
        route_summary = clean_str(raw_route.get('route_summary') or raw_route.get('summary') or '') or ''

        if not (from_location or to_location or travel_type or route_summary or normalized_visits):
            continue

        normalized_routes.append({
            'sequence_no': route_index,
            'from_location': from_location[:150],
            'to_location': to_location[:150],
            'travel_type': travel_type[:50],
            'route_summary': route_summary,
            'visits': normalized_visits
        })

    return normalized_routes


def apply_travel_request_routes(request_rec, payload):
    """Replace stored route plans/client visits from the current payload."""
    routes_payload = normalize_travel_request_routes_payload(payload)

    TravelRequestRouteVisit.query.filter_by(travel_request_id=request_rec.id).delete(synchronize_session=False)
    TravelRequestRoute.query.filter_by(travel_request_id=request_rec.id).delete(synchronize_session=False)
    db.session.flush()

    for route_data in routes_payload:
        route = TravelRequestRoute(
            travel_request_id=request_rec.id,
            sequence_no=route_data.get('sequence_no') or 1,
            from_location=route_data.get('from_location') or '',
            to_location=route_data.get('to_location') or '',
            travel_type=route_data.get('travel_type') or '',
            route_summary=route_data.get('route_summary') or ''
        )
        db.session.add(route)
        db.session.flush()

        for visit_data in route_data.get('visits') or []:
            db.session.add(TravelRequestRouteVisit(
                route_id=route.id,
                travel_request_id=request_rec.id,
                sequence_no=visit_data.get('sequence_no') or 1,
                client_id=visit_data.get('client_id'),
                client_name=visit_data.get('client_name') or '',
                product_id=visit_data.get('product_id'),
                product_name=visit_data.get('product_name') or '',
                product_ids_json=visit_data.get('product_ids_json') or json.dumps([], ensure_ascii=False),
                product_names_json=visit_data.get('product_names_json') or json.dumps([], ensure_ascii=False),
                purpose_tags=visit_data.get('purpose_tags') or '',
                visit_purpose=visit_data.get('visit_purpose') or '',
                notes=visit_data.get('remarks') or visit_data.get('notes') or ''
            ))

    return routes_payload


def summarize_travel_request_routes_for_header(routes_payload):
    """Build compact legacy header fields from structured route plans."""
    route_labels = []
    client_names = []

    for route_data in routes_payload or []:
        from_location = clean_str(route_data.get('from_location')) or ''
        to_location = clean_str(route_data.get('to_location')) or ''
        route_summary = clean_str(route_data.get('route_summary')) or ''

        if from_location or to_location:
            route_labels.append(f"{from_location or '—'} → {to_location or '—'}")
        elif route_summary:
            route_labels.append(route_summary.split('\n')[0][:80])

        for visit in route_data.get('visits') or []:
            client_name = clean_str(visit.get('client_name')) or ''
            if client_name and client_name not in client_names:
                client_names.append(client_name)

    return {
        'destination': '; '.join(route_labels)[:255],
        'client_name': '; '.join(client_names[:5])[:200]
    }



def resolve_travel_participant_user_from_payload(item):
    """Resolve a participant payload item to User/Engineer without requiring frontend DB IDs."""
    item = item or {}
    user_id = clean_int(item.get('user_id') or item.get('id'))
    engineer_id = clean_int(item.get('engineer_id'))
    username = (clean_str(item.get('username')) or '').strip()
    display_name = (clean_str(item.get('name') or item.get('display_name') or item.get('engineer_name')) or '').strip()

    user_rec = db.session.get(User, user_id) if user_id else None
    engineer_rec = db.session.get(Engineer, engineer_id) if engineer_id else None

    if not user_rec and username:
        user_rec = User.query.filter(func.lower(User.username) == username.lower()).first()

    if not engineer_rec and user_rec:
        engineer_rec = travel_request_strict_user_profile(user_rec)

    if not engineer_rec and display_name:
        engineer_rec = Engineer.query.filter(func.lower(Engineer.name) == display_name.lower()).first()

    if not user_rec and engineer_rec and clean_int(getattr(engineer_rec, 'user_id', None)):
        user_rec = db.session.get(User, engineer_rec.user_id)

    resolved_username = clean_str(getattr(user_rec, 'username', None)) or username
    resolved_display = (
        clean_str(getattr(engineer_rec, 'name', None)) or
        travel_request_user_display_name(user_rec) or
        display_name or
        resolved_username
    )

    return {
        'user': user_rec,
        'engineer': engineer_rec,
        'username': (resolved_username or '')[:100],
        'display_name': (resolved_display or '')[:150]
    }


def normalize_travel_request_participants_payload(payload, request_rec=None):
    """Return normalized Travel Request participants including the lead requester."""
    payload = payload or {}
    raw_items = payload.get('participants') or payload.get('travel_participants') or []
    if not isinstance(raw_items, list):
        raw_items = []

    lead_user = getattr(request_rec, 'requester', None) if request_rec else current_user
    lead_engineer = travel_request_strict_user_profile(lead_user) if lead_user else travel_request_current_profile()
    lead_username = clean_str(getattr(lead_user, 'username', None)) or clean_str(payload.get('lead_username')) or clean_str(payload.get('lead_requester')) or ''
    lead_display = clean_str(getattr(lead_engineer, 'name', None)) or approval_user_display_name(lead_user) or lead_username

    normalized = []
    seen = set()

    def add_participant(user_rec=None, engineer_rec=None, username='', display_name='', role='participant'):
        user_id = clean_int(getattr(user_rec, 'id', None))
        engineer_id = clean_int(getattr(engineer_rec, 'id', None))
        username_clean = (clean_str(getattr(user_rec, 'username', None)) or clean_str(username) or '').strip()
        display_clean = (
            clean_str(getattr(engineer_rec, 'name', None)) or
            travel_request_user_display_name(user_rec) or
            clean_str(display_name) or
            username_clean
        )
        key = (user_id or 0, engineer_id or 0, username_clean.lower(), display_clean.lower())
        if not (user_id or engineer_id or username_clean or display_clean) or key in seen:
            return
        seen.add(key)
        normalized.append({
            'user_id': user_id,
            'engineer_id': engineer_id,
            'username': username_clean[:100],
            'display_name': display_clean[:150],
            'role': role if role in {'lead', 'participant'} else 'participant'
        })

    add_participant(lead_user, lead_engineer, lead_username, lead_display, 'lead')

    for raw_item in raw_items:
        if not isinstance(raw_item, dict):
            continue
        resolved = resolve_travel_participant_user_from_payload(raw_item)
        add_participant(
            resolved.get('user'),
            resolved.get('engineer'),
            resolved.get('username'),
            resolved.get('display_name'),
            clean_str(raw_item.get('role')) or 'participant'
        )

    return normalized


def sync_travel_request_participants(request_rec, payload):
    """Replace participants for a Travel Request while preserving lead compatibility fields."""
    if not request_rec:
        return []

    participants = normalize_travel_request_participants_payload(payload, request_rec)
    TravelRequestParticipant.query.filter_by(travel_request_id=request_rec.id).delete(synchronize_session=False)
    db.session.flush()

    for item in participants:
        db.session.add(TravelRequestParticipant(
            travel_request_id=request_rec.id,
            user_id=item.get('user_id'),
            engineer_id=item.get('engineer_id'),
            username=item.get('username') or '',
            display_name=item.get('display_name') or '',
            role=item.get('role') or 'participant',
            created_at=get_manila_time()
        ))

    return participants


def travel_request_participant_to_dict(participant):
    user_rec = getattr(participant, 'user', None)
    engineer_rec = getattr(participant, 'engineer', None)
    username = clean_str(getattr(participant, 'username', None)) or clean_str(getattr(user_rec, 'username', None)) or ''
    display_name = (
        clean_str(getattr(participant, 'display_name', None)) or
        clean_str(getattr(engineer_rec, 'name', None)) or
        travel_request_user_display_name(user_rec) or
        username
    )
    return {
        'id': participant.id,
        'user_id': clean_int(getattr(participant, 'user_id', None)),
        'engineer_id': clean_int(getattr(participant, 'engineer_id', None)),
        'username': username,
        'name': display_name,
        'display_name': display_name,
        'role': clean_str(getattr(participant, 'role', None)) or 'participant'
    }


def get_travel_request_participants(request_rec):
    """Return saved participants or a generated lead participant for legacy records."""
    if not request_rec:
        return []
    participants = sorted(
        list(getattr(request_rec, 'participants', None) or []),
        key=lambda item: (0 if (item.role or '') == 'lead' else 1, item.id or 0)
    )
    if participants:
        return participants

    requester = getattr(request_rec, 'requester', None)
    engineer = db.session.get(Engineer, request_rec.engineer_id) if clean_int(getattr(request_rec, 'engineer_id', None)) else None
    return [TravelRequestParticipant(
        travel_request_id=request_rec.id,
        user_id=getattr(request_rec, 'user_id', None),
        engineer_id=getattr(request_rec, 'engineer_id', None),
        username=clean_str(getattr(requester, 'username', None)) or '',
        display_name=clean_str(getattr(engineer, 'name', None)) or travel_request_user_display_name(requester),
        role='lead'
    )]


def get_travel_request_participant_user_ids(request_rec):
    ids = []
    for participant in get_travel_request_participants(request_rec):
        user_id = clean_int(getattr(participant, 'user_id', None))
        if user_id and user_id not in ids:
            ids.append(user_id)
    owner_id = clean_int(getattr(request_rec, 'user_id', None)) if request_rec else None
    if owner_id and owner_id not in ids:
        ids.insert(0, owner_id)
    return ids




def get_travel_request_notification_user_ids(request_rec):
    """Return requester + all participant user IDs for Travel Request status emails."""
    return get_travel_request_participant_user_ids(request_rec)


def get_travel_request_signature_people(request_rec):
    """Return deduped requester/participant people for Travel Request signature checks and PDF stamping.

    S12B6O:
    Travel Request submission requires the requester and every selected
    participant to have a saved Engineer signature. This helper resolves each
    participant through the strict User.id -> Engineer.user_id link when
    possible, then falls back to the participant.engineer_id stored on the
    request. It intentionally does not use username/first-name prefix matching.
    """
    if not request_rec:
        return []

    people = []
    seen = set()

    def add_person(user_id=None, engineer_id=None, username='', display_name='', role='participant'):
        resolved_user_id = clean_int(user_id)
        resolved_engineer_id = clean_int(engineer_id)
        user_rec = db.session.get(User, resolved_user_id) if resolved_user_id else None
        engineer_rec = db.session.get(Engineer, resolved_engineer_id) if resolved_engineer_id else None

        if user_rec:
            strict_profile = travel_request_strict_user_profile(user_rec)
            if strict_profile:
                engineer_rec = strict_profile
                resolved_engineer_id = clean_int(getattr(strict_profile, 'id', None))

        key = (resolved_user_id or 0, resolved_engineer_id or 0, (clean_str(username) or '').strip().lower(), (clean_str(display_name) or '').strip().lower())
        if key in seen:
            return
        seen.add(key)

        name = (
            clean_str(getattr(engineer_rec, 'name', None)) or
            travel_request_user_display_name(user_rec) or
            clean_str(display_name) or
            clean_str(username) or
            'Participant'
        )
        signature_data = clean_str(getattr(engineer_rec, 'signature_data', None)) if engineer_rec else ''

        people.append({
            'user': user_rec,
            'user_id': resolved_user_id,
            'engineer': engineer_rec,
            'engineer_id': resolved_engineer_id,
            'username': clean_str(username) or clean_str(getattr(user_rec, 'username', None)) or '',
            'name': name,
            'role': clean_str(role) or 'participant',
            'signature_data': signature_data or ''
        })

    add_person(
        user_id=getattr(request_rec, 'user_id', None),
        engineer_id=getattr(request_rec, 'engineer_id', None),
        username=clean_str(getattr(getattr(request_rec, 'requester', None), 'username', None)) or '',
        display_name=travel_request_user_display_name(getattr(request_rec, 'requester', None)),
        role='lead'
    )

    for participant in get_travel_request_participants(request_rec):
        add_person(
            user_id=getattr(participant, 'user_id', None),
            engineer_id=getattr(participant, 'engineer_id', None),
            username=getattr(participant, 'username', ''),
            display_name=getattr(participant, 'display_name', ''),
            role=getattr(participant, 'role', 'participant')
        )

    return people


def get_travel_request_missing_signature_people(request_rec):
    """Return people on a Travel Request who do not have saved signatures."""
    missing = []
    for person in get_travel_request_signature_people(request_rec):
        if not clean_str(person.get('signature_data')):
            missing.append(person)
    return missing


def create_travel_request_lifecycle_notifications(request_rec, recipient_user_ids, event, title, message, actor_user=None, extra_metadata=None, exclude_user_ids=None):
    """S12B6J: Notify requester/participants for Travel Request lifecycle events.

    This is intentionally in-app only. Approval emails and Accounting handoff
    remain handled by their existing email workers.
    """
    if not request_rec:
        return []

    actor = actor_user or current_user
    metadata = {
        'event': clean_str(event) or 'travel_request_update',
        'request_no': clean_str(getattr(request_rec, 'request_no', None)) or f"TR-{getattr(request_rec, 'id', '')}",
        'travel_request_id': clean_int(getattr(request_rec, 'id', None)),
        'request_type': clean_str(getattr(request_rec, 'request_type', None)) or 'Client Visit / Service',
        'actor_user_id': clean_int(getattr(actor, 'id', None)),
        'actor_name': universal_approval_actor_name(actor) if actor else 'System'
    }
    if extra_metadata:
        metadata.update(extra_metadata)

    return create_system_notifications_for_users(
        recipient_user_ids,
        title=title,
        message=message,
        module='travel_request',
        record_id=getattr(request_rec, 'id', None),
        target_url=travel_request_notification_url(request_rec),
        metadata=metadata,
        exclude_user_ids=exclude_user_ids
    )


def get_travel_request_participant_engineer_ids(request_rec):
    ids = []
    for participant in get_travel_request_participants(request_rec):
        engineer_id = clean_int(getattr(participant, 'engineer_id', None))
        if engineer_id and engineer_id not in ids:
            ids.append(engineer_id)
    lead_engineer_id = clean_int(getattr(request_rec, 'engineer_id', None)) if request_rec else None
    if lead_engineer_id and lead_engineer_id not in ids:
        ids.insert(0, lead_engineer_id)
    return ids


def is_current_user_travel_request_participant(request_rec):
    if not current_user or not getattr(current_user, 'is_authenticated', False) or not request_rec:
        return False
    current_user_id = clean_int(getattr(current_user, 'id', None))
    current_engineer_id = clean_int(getattr(travel_request_current_profile(), 'id', None))
    if current_user_id and current_user_id in get_travel_request_participant_user_ids(request_rec):
        return True
    if current_engineer_id and current_engineer_id in get_travel_request_participant_engineer_ids(request_rec):
        return True
    return False


def can_current_user_submit_travel_request(request_rec):
    """Return True when the logged-in user is the requester or listed participant.

    S12B6P:
    Participants already have edit access to shared Travel Requests. Submission
    must follow the same team rule, while admin/approver visibility alone must
    not let a non-participant submit the request.
    """
    if not current_user or not getattr(current_user, 'is_authenticated', False) or not request_rec:
        return False
    if clean_int(getattr(request_rec, 'user_id', None)) == clean_int(getattr(current_user, 'id', None)):
        return True
    return is_current_user_travel_request_participant(request_rec)


def is_current_user_missing_travel_signature(missing_people):
    """Return True if the missing-signature list includes the logged-in user."""
    current_user_id = clean_int(getattr(current_user, 'id', None))
    current_engineer_id = clean_int(getattr(travel_request_current_profile(), 'id', None))
    for person in missing_people or []:
        if current_user_id and clean_int(person.get('user_id')) == current_user_id:
            return True
        if current_engineer_id and clean_int(person.get('engineer_id')) == current_engineer_id:
            return True
    return False

def travel_request_to_dict(request_rec, include_lines=False, include_audit=False):
    requester = db.session.get(User, request_rec.user_id) if request_rec and request_rec.user_id else None
    engineer = db.session.get(Engineer, request_rec.engineer_id) if request_rec and request_rec.engineer_id else None
    approver = db.session.get(User, request_rec.approved_by_id) if request_rec and request_rec.approved_by_id else None
    rejector = db.session.get(User, request_rec.rejected_by_id) if request_rec and request_rec.rejected_by_id else None
    request_type = normalize_travel_request_type(
        getattr(request_rec, 'request_type', None) or
        getattr(request_rec, 'purpose', None) or
        getattr(request_rec, 'client_name', None)
    )
    currency_code = normalize_travel_currency_code(getattr(request_rec, 'currency_code', None) or 'PHP')

    data = {
        'id': request_rec.id,
        'request_no': request_rec.request_no or travel_request_generate_request_no(request_rec.id),
        'requester_user_id': request_rec.user_id,
        'requester_name': (clean_str(getattr(engineer, 'name', None)) or travel_request_user_display_name(requester) or getattr(requester, 'username', '') or ''),
        'assigned_approver_user_id': getattr(get_assigned_approver_for_requester(request_rec.user_id, 'travel_request'), 'id', None),
        'assigned_approver_name': approval_user_display_name(get_assigned_approver_for_requester(request_rec.user_id, 'travel_request')),
        'assigned_approvers': [approval_user_to_dict(user) for user in get_assigned_approvers_for_requester(request_rec.user_id, 'travel_request')],
        'assigned_approver_names': [approval_user_display_name(user) for user in get_assigned_approvers_for_requester(request_rec.user_id, 'travel_request')],
        'engineer_id': request_rec.engineer_id,
        'engineer_name': getattr(engineer, 'name', '') if engineer else '',
        'participants': [travel_request_participant_to_dict(participant) for participant in get_travel_request_participants(request_rec)],
        'participant_names': ', '.join([travel_request_participant_to_dict(participant).get('display_name') or '' for participant in get_travel_request_participants(request_rec) if travel_request_participant_to_dict(participant).get('display_name')]),
        'participant_count': len(get_travel_request_participants(request_rec)),
        'request_type': request_type,
        'travel_type': request_type,
        'purpose': request_rec.purpose or '',
        'destination': request_rec.destination or '',
        'client_name': request_rec.client_name or '',
        'schedule_id': request_rec.schedule_id,
        'departure_date': request_rec.departure_date.isoformat() if request_rec.departure_date else '',
        'return_date': request_rec.return_date.isoformat() if request_rec.return_date else '',
        'arrival_date': request_rec.arrival_date.isoformat() if request_rec.arrival_date else '',
        'requested_amount': travel_request_money(request_rec.requested_amount),
        'approved_amount': travel_request_money(request_rec.approved_amount),
        'total_expenses': travel_request_money(request_rec.total_expenses),
        'liquidation_balance': travel_request_money(request_rec.liquidation_balance),
        'currency_code': currency_code,
        'requested_amount_label': format_travel_currency_amount(request_rec.requested_amount, currency_code),
        'approved_amount_label': format_travel_currency_amount(request_rec.approved_amount, currency_code),
        'total_expenses_label': format_travel_currency_amount(request_rec.total_expenses, currency_code),
        'liquidation_balance_label': format_travel_currency_amount(request_rec.liquidation_balance, currency_code),
        'status': request_rec.status or 'Draft',
        'accounting_status': request_rec.accounting_status or '',
        'created_at': request_rec.created_at.isoformat() if request_rec.created_at else None,
        'updated_at': request_rec.updated_at.isoformat() if request_rec.updated_at else None,
        'submitted_at': request_rec.submitted_at.isoformat() if request_rec.submitted_at else None,
        'approved_at': request_rec.approved_at.isoformat() if request_rec.approved_at else None,
        'approved_by': approval_user_display_name(approver) if approver else '',
        'rejected_at': request_rec.rejected_at.isoformat() if request_rec.rejected_at else None,
        'rejected_by': approval_user_display_name(rejector) if rejector else '',
        'approval_remarks': request_rec.approval_remarks or '',
        'sent_to_accounting_at': request_rec.sent_to_accounting_at.isoformat() if request_rec.sent_to_accounting_at else None,
        'accounting_approved_at': request_rec.accounting_approved_at.isoformat() if request_rec.accounting_approved_at else None,
        'accounting_rejected_at': request_rec.accounting_rejected_at.isoformat() if request_rec.accounting_rejected_at else None,
        'accounting_remarks': request_rec.accounting_remarks or '',
        'funds_received_at': request_rec.funds_received_at.isoformat() if request_rec.funds_received_at else None,
        'liquidation_due_at': request_rec.liquidation_due_at.isoformat() if request_rec.liquidation_due_at else None,
        'liquidation_started_at': request_rec.liquidation_started_at.isoformat() if request_rec.liquidation_started_at else None,
        'liquidation_completed_at': request_rec.liquidation_completed_at.isoformat() if request_rec.liquidation_completed_at else None,
        'approval_action': getattr(request_rec, 'approval_action', '') or '',
        'approval_name_snapshot': getattr(request_rec, 'approval_name_snapshot', '') or '',
        'approval_title_snapshot': getattr(request_rec, 'approval_title_snapshot', '') or '',
        'approval_signature_snapshot': getattr(request_rec, 'approval_signature_snapshot', '') or '',
        'approval_signature_layout': getattr(request_rec, 'approval_signature_layout', '') or '',
        'approval_signed_at': request_rec.approval_signed_at.isoformat() if getattr(request_rec, 'approval_signed_at', None) else None,
    }

    if include_lines:
        allow_airfare_c_o_note = travel_request_allows_airfare_c_o(request_rec)
        data['lines'] = [
            {
                'id': line.id,
                'date': line.line_date.isoformat() if line.line_date else '',
                'line_type': line.line_type or '',
                'description': line.description or '',
                'origin': line.origin or '',
                'destination': line.destination or '',
                'amount': travel_request_money(line.amount),
                'currency_code': currency_code,
                'amount_label': format_travel_currency_amount(line.amount, currency_code),
                'source_currency_code': normalize_travel_currency_code(getattr(line, 'source_currency_code', None) or currency_code, currency_code),
                'source_amount': travel_request_money(getattr(line, 'source_amount', 0) if travel_request_money(getattr(line, 'source_amount', 0)) > 0 else line.amount),
                'exchange_rate': travel_exchange_rate(getattr(line, 'exchange_rate', None), getattr(line, 'source_currency_code', None) or currency_code, currency_code),
                'remarks': (line.remarks or '') if allow_airfare_c_o_note else remove_travel_airfare_c_o_label(line.remarks)
            }
            for line in sorted(request_rec.lines or [], key=lambda item: (item.line_date or datetime.min.date(), item.id or 0))
        ]
        data['routes'] = [
            travel_request_route_to_dict(route)
            for route in sorted(getattr(request_rec, 'routes', []) or [], key=lambda item: (item.sequence_no or 1, item.id or 0))
        ]

    if include_audit:
        data['audit_trail'] = [
            universal_approval_audit_to_dict(entry)
            for entry in get_strict_travel_request_audit_entries(request_rec.id)
        ]

    return data


def can_user_access_travel_request(request_rec):
    if not request_rec:
        return False
    if is_admin_authorized() or is_approval_center_user():
        return True
    return (
        getattr(request_rec, 'user_id', None) == getattr(current_user, 'id', None) or
        is_current_user_travel_request_participant(request_rec)
    )


def can_user_approve_travel_request(approver_user, request_rec):
    """Return True only for the Settings-assigned Travel Request approver.

    Reimbursement keeps its legacy Rodito compatibility separately. Travel
    Request must not fall back to hardcoded Rodito logic because Rodito may also
    be a submitter and must be routed to an alternate approver in Settings.
    """
    if not request_rec:
        return False
    if not is_configured_approver_user(approver_user):
        return False
    return can_user_approve_for_requester(approver_user, request_rec.user_id, 'travel_request')


def travel_request_query_for_current_approver(status_filter='Submitted'):
    query = TravelRequest.query
    query = apply_assigned_approver_filter(query, TravelRequest, current_user, 'travel_request')
    if status_filter and status_filter != 'All':
        query = query.filter(func.lower(func.trim(TravelRequest.status)) == status_filter.lower())
    return query.order_by(TravelRequest.submitted_at.asc(), TravelRequest.updated_at.asc(), TravelRequest.id.asc())


TRAVEL_AIRFARE_C_O_LABEL = 'c/o Diary Dizon/Mildred Zaide'


def travel_request_travel_type_allows_airfare_c_o(value):
    travel_type = clean_str(value).lower()
    if not travel_type:
        return False
    return any(keyword in travel_type for keyword in ('air', 'plane', 'flight', 'mixed'))


def travel_request_routes_allow_airfare_c_o(routes):
    for route in routes or []:
        if isinstance(route, dict):
            travel_type = route.get('travel_type')
        else:
            travel_type = getattr(route, 'travel_type', None)
        if travel_request_travel_type_allows_airfare_c_o(travel_type):
            return True
    return False


def travel_request_allows_airfare_c_o(request_rec):
    return travel_request_routes_allow_airfare_c_o(getattr(request_rec, 'routes', None) or [])


def remove_travel_airfare_c_o_label(value):
    text_value = clean_str(value) or ''
    if not text_value:
        return ''
    pattern = re.compile(re.escape(TRAVEL_AIRFARE_C_O_LABEL), flags=re.I)
    cleaned = pattern.sub('', text_value)
    cleaned = re.sub(r'\s*(?:[,;|/\\-]+)\s*$', '', cleaned).strip()
    cleaned = re.sub(r'^\s*(?:[,;|/\\-]+)\s*', '', cleaned).strip()
    cleaned = re.sub(r'\s{2,}', ' ', cleaned).strip()
    return cleaned


def travel_request_line_text(line):
    return (
        clean_str(getattr(line, 'line_type', None)) + ' ' +
        clean_str(getattr(line, 'description', None))
    ).strip().lower()


def travel_request_line_is_airfare_text(text_value):
    text_value = clean_str(text_value).lower()
    if not text_value:
        return False
    air_keywords = (
        'plane fare',
        'air fare',
        'airfare',
        'air ticket',
        'air tickets',
        'airline',
        'flight'
    )
    return any(keyword in text_value for keyword in air_keywords)


def travel_request_line_is_landfare_text(text_value):
    text_value = clean_str(text_value).lower()
    if not text_value:
        return False
    land_keywords = (
        'bus',
        'land',
        'land fare',
        'transport',
        'transportation',
        'transpo',
        'taxi',
        'grab',
        'car',
        'van',
        'jeep',
        'tricycle',
        'toll',
        'parking',
        'gas',
        'fuel',
        'fare'
    )
    return any(keyword in text_value for keyword in land_keywords)


def clean_travel_request_airfare_c_o_remarks(request_rec):
    if not request_rec or travel_request_allows_airfare_c_o(request_rec):
        return 0
    cleaned_count = 0
    for line in getattr(request_rec, 'lines', None) or []:
        original_remarks = clean_str(getattr(line, 'remarks', None)) or ''
        if not original_remarks or TRAVEL_AIRFARE_C_O_LABEL.lower() not in original_remarks.lower():
            continue
        cleaned_remarks = remove_travel_airfare_c_o_label(original_remarks)
        if cleaned_remarks != original_remarks:
            line.remarks = cleaned_remarks
            line.updated_at = get_manila_time()
            cleaned_count += 1
    return cleaned_count


def normalize_travel_request_line_payload(item, allow_airfare_c_o_note=True):
    """Normalize one travel request cash advance line.

    S10B9A: when Air/Plane fare is zero, keep a printable note instead of
    silently dropping it so the future PDF can show:
        c/o Diary Dizon/Mildred Zaide
    """
    desc = clean_str(item.get('description')) or clean_str(item.get('particulars')) or ''
    line_type = clean_str(item.get('line_type')) or clean_str(item.get('type')) or ''
    target_currency = normalize_travel_currency_code(item.get('target_currency_code') or item.get('currency_code') or 'PHP')
    source_currency = normalize_travel_currency_code(item.get('source_currency_code') or item.get('receipt_currency') or target_currency, target_currency)
    source_amount_raw = item.get('source_amount')
    if source_amount_raw is None:
        source_amount_raw = item.get('receipt_amount')
    if source_amount_raw is None:
        source_amount_raw = item.get('amount')
    source_amount = travel_request_money(source_amount_raw)
    exchange_rate = travel_exchange_rate(item.get('exchange_rate'), source_currency, target_currency)
    amount = travel_converted_amount(source_amount, source_currency, target_currency, exchange_rate)
    line_date = travel_request_date(item.get('date') or item.get('line_date'))
    remarks = clean_str(item.get('remarks') or item.get('notes')) or ''

    is_airfare = any(
        keyword in (f"{line_type} {desc}" or '').lower()
        for keyword in ('air', 'plane', 'airfare', 'air tickets')
    )

    if is_airfare and amount == 0 and allow_airfare_c_o_note:
        remarks = remarks or TRAVEL_AIRFARE_C_O_LABEL
        if not desc:
            desc = 'Plane Fare / Air Tickets'
        if not line_type:
            line_type = 'Plane Fare'
    elif not allow_airfare_c_o_note and remarks:
        remarks = remove_travel_airfare_c_o_label(remarks)

    return {
        'description': desc,
        'line_type': line_type,
        'amount': amount,
        'source_currency_code': source_currency,
        'source_amount': source_amount,
        'exchange_rate': exchange_rate,
        'line_date': line_date,
        'remarks': remarks
    }


@app.route('/check_travel_request_conflicts', methods=['POST'])
@csrf.exempt
@login_required
def check_travel_request_conflicts():
    """S11G18: Check Travel Request period conflicts without saving."""
    ensure_travel_request_tables()
    payload = request.get_json(silent=True) or {}

    request_id = clean_int(payload.get('id') or payload.get('travel_request_id'))
    profile = travel_request_current_profile()

    departure_date = travel_request_date(payload.get('departure_date') or payload.get('start_date'))
    return_date = travel_request_date(payload.get('return_date') or payload.get('end_date')) or departure_date

    conflicts = find_travel_request_conflicts_for_user(
        current_user.id,
        getattr(profile, 'id', None),
        departure_date,
        return_date,
        exclude_request_id=request_id
    )

    return jsonify({
        'success': True,
        'ok': not conflicts.get('has_conflicts'),
        'has_conflicts': bool(conflicts.get('has_conflicts')),
        'blocking_conflicts': bool(conflicts.get('blocking')),
        'message': conflicts.get('message') or '',
        'conflicts': conflicts
    })


@app.route('/save_travel_request_draft', methods=['POST'])
@csrf.exempt
@login_required
def save_travel_request_draft():
    """S10A API: create/update a Travel Request draft.

    Frontend comes next. This endpoint is intentionally JSON-only and minimal.
    """
    ensure_travel_request_tables()
    payload = request.get_json(silent=True) or {}

    request_id = clean_int(payload.get('id') or payload.get('travel_request_id'))
    request_rec = db.session.get(TravelRequest, request_id) if request_id else None

    if request_rec:
        can_edit_existing_request = (
            request_rec.user_id == current_user.id or
            is_current_user_travel_request_participant(request_rec) or
            is_admin_authorized()
        )
        if not can_edit_existing_request:
            return jsonify({'success': False, 'error': 'You are not allowed to edit this travel request.'}), 403

    if request_rec:
        current_status = travel_request_normalize_status(request_rec.status)
        if current_status not in TRAVEL_REQUEST_EDITABLE_STATUSES:
            return jsonify({'success': False, 'error': f'Travel request is already {current_status} and cannot be edited.'}), 409

    purpose = clean_str(payload.get('purpose')) or clean_str(payload.get('reason')) or ''
    if len(purpose) < 3:
        return jsonify({'success': False, 'error': 'Purpose is required.'}), 400

    request_type = normalize_travel_request_type(
        payload.get('request_type') or
        payload.get('travel_type') or
        purpose
    )

    profile = travel_request_current_profile()
    now = get_manila_time()
    previous_participant_user_ids = get_travel_request_notification_user_ids(request_rec) if request_rec else []

    if not request_rec:
        request_rec = TravelRequest(
            user_id=current_user.id,
            engineer_id=getattr(profile, 'id', None),
            request_type=request_type,
            purpose=purpose[:255],
            status='Draft',
            created_at=now,
            updated_at=now
        )
        db.session.add(request_rec)
        db.session.flush()
        request_rec.request_no = travel_request_generate_request_no(request_rec.id)

    routes_payload = normalize_travel_request_routes_payload(payload)
    header_summary = summarize_travel_request_routes_for_header(routes_payload)

    request_rec.request_type = request_type
    request_rec.purpose = purpose[:255]
    request_rec.destination = header_summary.get('destination') or (clean_str(payload.get('destination')) or '')[:255]
    request_rec.client_name = header_summary.get('client_name') or (clean_str(payload.get('client_name')) or '')[:200]
    request_rec.schedule_id = clean_int(payload.get('schedule_id'))
    request_rec.departure_date = travel_request_date(payload.get('departure_date') or payload.get('start_date'))
    request_rec.return_date = travel_request_date(payload.get('return_date') or payload.get('end_date'))
    request_rec.arrival_date = travel_request_date(payload.get('arrival_date')) or request_rec.return_date
    request_rec.currency_code = normalize_travel_currency_code(payload.get('currency_code') or getattr(request_rec, 'currency_code', None) or 'PHP')
    request_rec.requested_amount = travel_request_money(payload.get('requested_amount') or payload.get('amount'))
    request_rec.updated_at = now

    travel_conflicts = find_travel_request_conflicts_for_user(
        current_user.id,
        getattr(profile, 'id', None),
        request_rec.departure_date,
        request_rec.return_date,
        exclude_request_id=request_rec.id
    )

    apply_travel_request_routes(request_rec, payload)
    participants_payload = sync_travel_request_participants(request_rec, payload)
    allow_airfare_c_o_note = travel_request_routes_allow_airfare_c_o(routes_payload)

    TravelRequestLine.query.filter_by(travel_request_id=request_rec.id).delete()
    lines_payload = payload.get('lines') or []
    calculated_request_total = 0.0
    if isinstance(lines_payload, list):
        for item in lines_payload:
            if not isinstance(item, dict):
                continue
            item['target_currency_code'] = request_rec.currency_code
            normalized_line = normalize_travel_request_line_payload(item, allow_airfare_c_o_note=allow_airfare_c_o_note)
            desc = normalized_line['description']
            amount = normalized_line['amount']
            line_date = normalized_line['line_date']
            remarks = normalized_line['remarks']
            if not (desc or amount or line_date or remarks):
                continue
            db.session.add(TravelRequestLine(
                travel_request_id=request_rec.id,
                line_date=line_date,
                line_type=(normalized_line['line_type'] or '')[:60],
                description=desc[:255],
                origin=(clean_str(item.get('origin')) or '')[:150],
                destination=(clean_str(item.get('destination')) or '')[:150],
                amount=amount,
                source_currency_code=normalized_line['source_currency_code'],
                source_amount=normalized_line['source_amount'],
                exchange_rate=normalized_line['exchange_rate'],
                remarks=remarks
            ))
            calculated_request_total = travel_request_money(calculated_request_total + amount)
    if calculated_request_total or isinstance(lines_payload, list):
        request_rec.requested_amount = calculated_request_total

    current_participant_user_ids = get_travel_request_notification_user_ids(request_rec)
    newly_added_participant_user_ids = [
        user_id for user_id in current_participant_user_ids
        if user_id and user_id not in previous_participant_user_ids and user_id != current_user.id
    ]
    if newly_added_participant_user_ids:
        actor_name = approval_user_display_name(current_user) or getattr(current_user, 'username', 'Requester')
        create_travel_request_lifecycle_notifications(
            request_rec,
            newly_added_participant_user_ids,
            'participant_added',
            'Added to Travel Request',
            f"{actor_name} added you as a participant to {request_rec.request_no or 'a travel request'}.",
            actor_user=current_user,
            extra_metadata={
                'added_participant_user_ids': newly_added_participant_user_ids,
                'participant_count': len(current_participant_user_ids)
            }
        )

    record_universal_approval_audit(
        'travel_request',
        request_rec.id,
        'draft_saved',
        actor_user=current_user,
        status_from=request_rec.status,
        status_to='Draft',
        remarks='Saved travel request draft.',
        metadata={
            'request_no': request_rec.request_no,
            'travel_request_id': request_rec.id,
            'request_record_id': request_rec.id,
            'route_count': len(routes_payload),
            'participant_count': len(participants_payload)
        }
    )
    db.session.commit()

    return jsonify({
        'success': True,
        'message': 'Travel request draft saved.' + ((' Warning: ' + travel_conflicts.get('message')) if travel_conflicts.get('has_conflicts') else ''),
        'has_conflicts': bool(travel_conflicts.get('has_conflicts')),
        'blocking_conflicts': bool(travel_conflicts.get('blocking')),
        'conflicts': travel_conflicts,
        'travel_request': travel_request_to_dict(request_rec, include_lines=True, include_audit=True)
    })



@app.route('/delete_travel_request_draft/<int:travel_request_id>', methods=['POST', 'DELETE'])
@app.route('/delete_travel_request_draft', methods=['POST', 'DELETE'])
@csrf.exempt
@login_required
def delete_travel_request_draft(travel_request_id=None):
    """S11G16: Delete an editable Travel Request draft/rejected request.

    Safety rules:
    - requester-owned records only, unless superadmin/admin
    - only Draft / Rejected records are deletable
    - Submitted / Approved records are protected
    - child routes, visits, and lines are removed with the parent
    """
    ensure_travel_request_tables()

    payload = request.get_json(silent=True) or {}
    target_id = clean_int(travel_request_id) or clean_int(payload.get('id') or payload.get('travel_request_id'))

    if not target_id:
        return jsonify({'success': False, 'error': 'Travel request ID is required.'}), 400

    request_rec = db.session.get(TravelRequest, target_id)
    if not request_rec:
        return jsonify({'success': False, 'error': 'Travel request draft was not found.'}), 404

    if request_rec.user_id != current_user.id and not is_admin_authorized():
        return jsonify({'success': False, 'error': 'You are not allowed to delete this travel request.'}), 403

    current_status = travel_request_normalize_status(request_rec.status)
    if current_status not in TRAVEL_REQUEST_EDITABLE_STATUSES:
        return jsonify({
            'success': False,
            'error': f'Travel request is already {current_status} and cannot be deleted.'
        }), 409

    request_no = clean_str(getattr(request_rec, 'request_no', None)) or f'TR-{request_rec.id}'

    try:
        # Attachments are not included in the TravelRequest relationship cascade yet.
        # Delete DB rows and best-effort physical files when they exist.
        removed_files = 0
        attachments = TravelRequestAttachment.query.filter_by(travel_request_id=request_rec.id).all()
        for attachment in attachments:
            stored_name = clean_str(getattr(attachment, 'stored_filename', None))
            if stored_name:
                try:
                    candidate_paths = [
                        os.path.join(app.config['UPLOAD_FOLDER'], os.path.basename(stored_name)),
                        os.path.join(basedir, 'static', 'uploads', 'travel_requests', os.path.basename(stored_name)),
                    ]
                    for candidate_path in candidate_paths:
                        if candidate_path and os.path.exists(candidate_path):
                            os.remove(candidate_path)
                            removed_files += 1
                            break
                except Exception as file_err:
                    print(f"[TravelRequest] Draft attachment delete skipped: {file_err}", flush=True)
            db.session.delete(attachment)

        record_universal_approval_audit(
            'travel_request',
            request_rec.id,
            'draft_deleted',
            actor_user=current_user,
            status_from=current_status,
            status_to='Deleted',
            remarks=f'Deleted travel request draft {request_no}.',
            metadata={
                'request_no': request_no,
                'travel_request_id': request_rec.id,
                'request_record_id': request_rec.id
            }
        )

        db.session.delete(request_rec)
        db.session.commit()

        try:
            log_activity(f"Deleted travel request draft {request_no}")
        except Exception as log_err:
            print(f"[TravelRequest] Delete draft activity log skipped: {log_err}", flush=True)

        response = jsonify({
            'success': True,
            'deleted': True,
            'id': target_id,
            'request_no': request_no,
            'files_removed': removed_files,
            'message': 'Travel request draft deleted.'
        })
        response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
        return response

    except Exception as exc:
        db.session.rollback()
        print(f"[TravelRequest] Delete draft failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to delete travel request draft.'}), 500


@app.route('/submit_travel_request/<int:travel_request_id>', methods=['POST'])
@csrf.exempt
@login_required
def submit_travel_request(travel_request_id):
    """S10A API: submit Travel Request to assigned approver."""
    ensure_travel_request_tables()
    request_rec = db.session.get(TravelRequest, travel_request_id)
    if not request_rec:
        return jsonify({'success': False, 'error': 'Travel request not found.'}), 404
    if not can_current_user_submit_travel_request(request_rec):
        return jsonify({'success': False, 'error': 'Only the requester or listed participants can submit this travel request.'}), 403

    current_status = travel_request_normalize_status(request_rec.status)
    if current_status not in TRAVEL_REQUEST_EDITABLE_STATUSES:
        return jsonify({'success': False, 'error': f'Travel request is already {current_status}.'}), 409

    clean_travel_request_airfare_c_o_remarks(request_rec)

    submit_profile = travel_request_current_profile()
    submit_conflicts = find_travel_request_conflicts_for_user(
        current_user.id,
        getattr(submit_profile, 'id', None),
        request_rec.departure_date,
        request_rec.return_date,
        exclude_request_id=request_rec.id
    )
    if submit_conflicts.get('has_conflicts'):
        return travel_request_conflict_response(submit_conflicts, status_code=409)

    # S11G7 Requester Signature Enforcement:
    # Match the reimbursement submit behavior. A Travel Request may be saved as
    # draft first, but it cannot be submitted until the requester has a saved
    # signature in Settings / My Signature. This backend guard prevents direct
    # API submits from bypassing the frontend prompt.
    requester_profile = travel_request_current_profile()
    if not requester_profile:
        return jsonify({
            'success': False,
            'signature_required': True,
            'requires_signature': True,
            'error': 'Saved signature is required before submitting travel request. Your account is not linked to an engineer profile. Please ask a superadmin to link your account, then add your signature in Settings.',
            'message': 'Saved signature is required before submitting travel request.',
            'status': current_status,
            'draft_saved': True,
            'settings_target': 'my_signature'
        }), 428

    if not get_user_signature_snapshot(current_user):
        print(
            f"[TravelRequest] Submit blocked: missing saved signature for user={current_user.id} request_id={request_rec.id}",
            flush=True
        )
        return jsonify({
            'success': False,
            'signature_required': True,
            'requires_signature': True,
            'error': 'Saved signature is required before submitting travel request. Please add your signature in Settings, then return here and continue submit.',
            'message': 'Saved signature is required before submitting travel request.',
            'status': current_status,
            'draft_saved': True,
            'settings_target': 'my_signature'
        }), 428

    missing_signature_people = get_travel_request_missing_signature_people(request_rec)
    if missing_signature_people:
        missing_names = [person.get('name') or 'Participant' for person in missing_signature_people]
        missing_label = ', '.join(dict.fromkeys(missing_names))
        current_user_missing_signature = is_current_user_missing_travel_signature(missing_signature_people)
        if current_user_missing_signature:
            error_message = (
                f"Cannot submit yet. Your saved signature is missing. Missing signatures: {missing_label}. "
                "Please add your signature in Settings, then return here and continue submit."
            )
        else:
            error_message = (
                f"Cannot submit yet. Missing signature from: {missing_label}. "
                "Please ask them to log in and save their signature first."
            )
        print(
            f"[TravelRequest] Submit blocked: missing participant signatures for request_id={request_rec.id}: {missing_label}",
            flush=True
        )
        payload = {
            'success': False,
            # S12B6Q:
            # Only trigger the frontend Settings / My Signature modal when the
            # logged-in user's own signature is missing. If another participant
            # is missing a signature, show the blocking message only because the
            # current user cannot save another engineer's signature.
            'signature_required': bool(current_user_missing_signature),
            'requires_signature': bool(current_user_missing_signature),
            'error': error_message,
            'message': error_message,
            'missing_signatures': missing_names,
            'current_user_missing_signature': current_user_missing_signature,
            'status': current_status,
            'draft_saved': True
        }
        if current_user_missing_signature:
            payload['settings_target'] = 'my_signature'
        return jsonify(payload), 428

    approvers = [
        approver for approver in get_assigned_approvers_for_requester(request_rec.user_id, 'travel_request')
        if getattr(approver, 'id', None) != current_user.id
    ]
    if not approvers:
        return jsonify({'success': False, 'error': "No valid approver is configured for this travel request. Please ask a superadmin to set the original requester's Travel Request approval route in Settings."}), 400
    approver = approvers[0]

    now = get_manila_time()
    previous_status = request_rec.status or 'Draft'
    request_rec.status = 'Submitted'
    request_rec.submitted_at = now
    request_rec.approved_at = None
    request_rec.approved_by_id = None
    request_rec.rejected_at = None
    request_rec.rejected_by_id = None
    request_rec.approval_remarks = None
    request_rec.updated_at = now

    record_universal_approval_audit(
        'travel_request',
        request_rec.id,
        'submitted',
        actor_user=current_user,
        status_from=previous_status,
        status_to='Submitted',
        remarks='Submitted travel request for manager approval.',
        metadata={
            'request_no': request_rec.request_no,
            'travel_request_id': request_rec.id,
            'request_record_id': request_rec.id,
            'assigned_approver_id': getattr(approver, 'id', None),
            'assigned_approver': approval_user_display_name(approver),
            'assigned_approver_ids': [getattr(item, 'id', None) for item in approvers],
            'assigned_approvers': [approval_user_display_name(item) for item in approvers]
        }
    )

    submitter_name = approval_user_display_name(current_user) or getattr(current_user, 'username', 'Requester')
    clear_existing_pending_approval_notifications('travel_request', request_rec.id)
    create_system_notifications_for_users(
        approvers,
        title='New Travel Request Awaiting Approval',
        message=f"{submitter_name} submitted {request_rec.request_no or 'a travel request'} for approval.",
        module='travel_request',
        record_id=request_rec.id,
        target_url=travel_request_notification_url(request_rec),
        metadata={
            'event': 'submitted',
            'request_no': request_rec.request_no,
            'requester_user_id': current_user.id,
            'requester_name': submitter_name,
            'requested_amount': request_rec.requested_amount
        },
        exclude_user_ids=[current_user.id]
    )

    participant_submit_recipient_ids = [
        user_id for user_id in get_travel_request_notification_user_ids(request_rec)
        if user_id and user_id != current_user.id
    ]
    if participant_submit_recipient_ids:
        create_travel_request_lifecycle_notifications(
            request_rec,
            participant_submit_recipient_ids,
            'submitted_to_participants',
            'Travel Request Submitted',
            f"{submitter_name} submitted {request_rec.request_no or 'a travel request'} for approval. You are listed as a participant.",
            actor_user=current_user,
            extra_metadata={
                'requester_user_id': current_user.id,
                'requester_name': submitter_name,
                'requested_amount': request_rec.requested_amount,
                'participant_recipients': participant_submit_recipient_ids
            }
        )

    add_activity_log_entry(
        f"Travel Request Submitted: {request_rec.request_no or f'TR-{request_rec.id}'} by {submitter_name}"
    )
    db.session.commit()

    send_travel_request_notification_email_async(
        app,
        [getattr(item, 'id', None) for item in approvers],
        request_rec.id,
        'submitted',
        actor_user_id=current_user.id
    )

    return jsonify({
        'success': True,
        'message': 'Travel request submitted for approval.',
        'travel_request': travel_request_to_dict(request_rec, include_lines=True, include_audit=True)
    })


@app.route('/get_my_travel_requests')
@login_required
def get_my_travel_requests():
    """S10A API: list current user's Travel Requests."""
    ensure_travel_request_tables()
    requested_status = clean_str(request.args.get('status')) or 'all'
    limit = clean_int(request.args.get('limit')) or 50
    limit = min(max(limit, 1), 100)

    my_engineer_id = clean_int(getattr(travel_request_current_profile(), 'id', None))
    participant_subquery = TravelRequestParticipant.query.with_entities(TravelRequestParticipant.travel_request_id).filter(or_(
        TravelRequestParticipant.user_id == current_user.id,
        TravelRequestParticipant.engineer_id == my_engineer_id if my_engineer_id else db.text('0 = 1')
    ))
    query = TravelRequest.query.filter(or_(
        TravelRequest.user_id == current_user.id,
        TravelRequest.id.in_(participant_subquery)
    ))
    if requested_status.lower() != 'all':
        status_filter = travel_request_normalize_status(requested_status)
        query = query.filter(func.lower(func.trim(TravelRequest.status)) == status_filter.lower())

    items = (
        query
        .order_by(TravelRequest.updated_at.desc(), TravelRequest.id.desc())
        .limit(limit)
        .all()
    )

    return jsonify({
        'success': True,
        'items': [travel_request_to_dict(item, include_lines=False) for item in items],
        'count': len(items)
    })


