@app.route('/get_travel_request_approval_queue')
@login_required
def get_travel_request_approval_queue():
    """S10A API: Travel Request approval queue foundation."""
    if not is_approval_center_user():
        return jsonify({'success': False, 'error': 'You are not assigned as an approver.'}), 403

    requested_status = (request.args.get('status') or 'Submitted').strip().lower()
    status_map = {
        'submitted': 'Submitted',
        'pending': 'Submitted',
        'approved': 'Approved',
        'rejected': 'Rejected',
        'all': 'All'
    }
    status_filter = status_map.get(requested_status, 'Submitted')
    items = travel_request_query_for_current_approver(status_filter).all()

    return jsonify({
        'success': True,
        'status': status_filter,
        'items': [travel_request_to_dict(item, include_lines=False) for item in items],
        'count': len(items)
    })


def build_travel_block_title(request_rec):
    """S11H1B: Build a compact timeline title for approved Travel Request blocks."""
    destination = clean_str(getattr(request_rec, 'destination', None)) or 'Travel'
    purpose = clean_str(getattr(request_rec, 'purpose', None)) or ''
    title = f"TRAVEL - {destination}"
    if purpose:
        title = f"{title} - {purpose}"
    return title[:100]


def resolve_travel_request_engineer_id(request_rec):
    """S11H1B: Resolve the lead engineer row that should receive legacy Travel Blocks."""
    engineer_ids = resolve_travel_request_engineer_ids(request_rec)
    return engineer_ids[0] if engineer_ids else None


def resolve_travel_request_engineer_ids(request_rec):
    """S12B6B: Resolve all engineer rows assigned to one Travel Request."""
    engineer_ids = get_travel_request_participant_engineer_ids(request_rec)
    if engineer_ids:
        return engineer_ids

    engineer_id = clean_int(getattr(request_rec, 'engineer_id', None))
    if engineer_id:
        return [engineer_id]

    requester = getattr(request_rec, 'requester', None)
    requester_profile = getattr(requester, 'engineer_profile', None) if requester else None
    fallback_id = clean_int(getattr(requester_profile, 'id', None))
    return [fallback_id] if fallback_id else []


def create_or_get_travel_blocks_for_approved_request(request_rec, approved_by_user=None, approved_at=None):
    """S11H1B: Auto-create timeline Travel Block rows after manager approval.

    Design notes:
    - Duplicate-safe: one active travel block set per Travel Request.
    - Uses one Shift row per travel date so the existing Timeline day-based data
      model can show/block every day later without changing normal service rows.
    - Uses schedule_type='travel' so future Timeline UI, conflict checks,
      accounting, and liquidation can identify these rows cleanly.
    """
    ensure_shift_travel_block_columns()

    if not request_rec:
        return {'created_count': 0, 'existing_count': 0, 'first_shift_id': None, 'error': 'missing_request'}

    existing_blocks = (
        Shift.query
        .filter(Shift.travel_request_id == request_rec.id)
        .filter(Shift.schedule_type == 'travel')
        .filter(or_(Shift.travel_block_status.is_(None), Shift.travel_block_status != 'cancelled'))
        .order_by(Shift.start_time.asc(), Shift.id.asc())
        .all()
    )
    if existing_blocks:
        return {
            'created_count': 0,
            'existing_count': len(existing_blocks),
            'first_shift_id': existing_blocks[0].id,
            'group_id': existing_blocks[0].group_id or f"TRAVEL-{request_rec.id}"
        }

    engineer_ids = resolve_travel_request_engineer_ids(request_rec)
    if not engineer_ids:
        return {'created_count': 0, 'existing_count': 0, 'first_shift_id': None, 'error': 'missing_engineer'}

    start_date = getattr(request_rec, 'departure_date', None)
    end_date = getattr(request_rec, 'return_date', None) or getattr(request_rec, 'arrival_date', None) or start_date
    if not start_date:
        return {'created_count': 0, 'existing_count': 0, 'first_shift_id': None, 'error': 'missing_travel_dates'}
    if not end_date or end_date < start_date:
        end_date = start_date

    # Safety guard: prevent accidental creation of very large date ranges.
    max_travel_days = 90
    total_days = (end_date - start_date).days + 1
    if total_days > max_travel_days:
        end_date = start_date + timedelta(days=max_travel_days - 1)
        total_days = max_travel_days

    group_id = f"TRAVEL-{request_rec.id}"
    title = build_travel_block_title(request_rec)
    created_blocks = []

    for engineer_id in engineer_ids:
        for day_offset in range(total_days):
            block_date = start_date + timedelta(days=day_offset)
            block_start = datetime.combine(block_date, datetime.min.time()).replace(hour=8, minute=0, second=0, microsecond=0)
            block_end = datetime.combine(block_date, datetime.min.time()).replace(hour=17, minute=0, second=0, microsecond=0)

            travel_shift = Shift(
                title=title,
                start_time=block_start,
                end_time=block_end,
                engineer_id=engineer_id,
                client_id=None,
                product_id=None,
                status='Approved',
                created_at=approved_at or get_manila_time(),
                group_id=group_id,
                schedule_type='travel',
                travel_request_id=request_rec.id,
                travel_block_status='active'
            )
            db.session.add(travel_shift)
            db.session.flush()

            db.session.add(ShiftEngineer(
                shift_id=travel_shift.id,
                engineer_id=engineer_id
            ))
            created_blocks.append(travel_shift)

    first_shift_id = created_blocks[0].id if created_blocks else None
    if first_shift_id and not clean_int(getattr(request_rec, 'schedule_id', None)):
        request_rec.schedule_id = first_shift_id

    approver_name = universal_approval_actor_name(approved_by_user) if approved_by_user else 'System'
    request_label = clean_str(getattr(request_rec, 'request_no', None)) or f"TR-{request_rec.id}"
    db.session.add(ActivityLog(
        user=approver_name,
        action=f"Auto-created {len(created_blocks)} travel block day(s) for {request_label}"
    ))

    return {
        'created_count': len(created_blocks),
        'existing_count': 0,
        'first_shift_id': first_shift_id,
        'group_id': group_id
    }


def restore_missing_travel_blocks_for_request(request_rec, restored_by_user=None, restore_converted=True):
    """S11H2C: Restore approved Travel Request blocks from the master request.

    Timeline travel blocks are operational copies. The Travel Request remains the
    source of truth for the approved date range and assigned engineer. This
    helper recreates missing active travel-block days without duplicating days
    that already have an active travel block.

    Converted/deleted travel block rows are not treated as active travel blocks.
    If a converted normal schedule still exists for the same date, the restored
    travel block will appear above it and the Timeline warning badge will surface
    the overlap for scheduler review.
    """
    ensure_shift_travel_block_columns()

    if not request_rec:
        return {'success': False, 'message': 'Travel request not found.', 'created_count': 0, 'skipped_count': 0}

    if travel_request_normalize_status(getattr(request_rec, 'status', '')) != 'Approved':
        return {
            'success': False,
            'message': 'Only approved Travel Requests can restore travel blocks.',
            'created_count': 0,
            'skipped_count': 0
        }

    engineer_ids = resolve_travel_request_engineer_ids(request_rec)
    if not engineer_ids:
        return {
            'success': False,
            'message': 'No assigned engineer was found for this Travel Request.',
            'created_count': 0,
            'skipped_count': 0
        }

    if not can_modify_schedule_for_engineer_ids(engineer_ids):
        return {
            'success': False,
            'message': 'You are not authorized to restore travel blocks for this engineer.',
            'created_count': 0,
            'skipped_count': 0
        }

    start_date = getattr(request_rec, 'departure_date', None)
    end_date = getattr(request_rec, 'return_date', None) or getattr(request_rec, 'arrival_date', None) or start_date
    if not start_date:
        return {
            'success': False,
            'message': 'This Travel Request has no travel date range.',
            'created_count': 0,
            'skipped_count': 0
        }
    if not end_date or end_date < start_date:
        end_date = start_date

    max_travel_days = 90
    total_days = (end_date - start_date).days + 1
    if total_days > max_travel_days:
        end_date = start_date + timedelta(days=max_travel_days - 1)
        total_days = max_travel_days

    group_id = f"TRAVEL-{request_rec.id}"
    title = build_travel_block_title(request_rec)
    now = get_manila_time()

    existing_linked_rows = (
        Shift.query
        .filter(Shift.travel_request_id == request_rec.id)
        .order_by(Shift.start_time.asc(), Shift.id.asc())
        .all()
    )

    active_travel_pairs = set()
    converted_dates = set()
    cancelled_dates = set()

    for shift in existing_linked_rows:
        if not getattr(shift, 'start_time', None):
            continue
        shift_date = shift.start_time.date()
        status_key = (clean_str(getattr(shift, 'travel_block_status', None)) or '').lower()
        type_key = (clean_str(getattr(shift, 'schedule_type', None)) or '').lower()

        if type_key == 'travel' and status_key != 'cancelled':
            active_travel_pairs.add((shift_date, clean_int(getattr(shift, 'engineer_id', None))))
        elif type_key != 'travel' or status_key == 'converted':
            converted_dates.add(shift_date)
        elif status_key == 'cancelled':
            cancelled_dates.add(shift_date)

    created_blocks = []
    skipped_dates = []
    restored_dates = []
    converted_overlap_dates = []

    for engineer_id in engineer_ids:
        for day_offset in range(total_days):
            block_date = start_date + timedelta(days=day_offset)
            if (block_date, engineer_id) in active_travel_pairs:
                skipped_dates.append(block_date.isoformat())
                continue

            if block_date in converted_dates:
                converted_overlap_dates.append(block_date.isoformat())

            block_start = datetime.combine(block_date, datetime.min.time()).replace(hour=8, minute=0, second=0, microsecond=0)
            block_end = datetime.combine(block_date, datetime.min.time()).replace(hour=17, minute=0, second=0, microsecond=0)

            travel_shift = Shift(
                title=title,
                start_time=block_start,
                end_time=block_end,
                engineer_id=engineer_id,
                client_id=None,
                product_id=None,
                status='Approved',
                created_at=now,
                group_id=group_id,
                schedule_type='travel',
                travel_request_id=request_rec.id,
                travel_block_status='active'
            )
            db.session.add(travel_shift)
            db.session.flush()

            db.session.add(ShiftEngineer(
                shift_id=travel_shift.id,
                engineer_id=engineer_id
            ))

            created_blocks.append(travel_shift)
            restored_dates.append(block_date.isoformat())

    first_active_or_created = (
        created_blocks[0] if created_blocks else
        next((shift for shift in existing_linked_rows if (clean_str(getattr(shift, 'schedule_type', None)) or '').lower() == 'travel'), None)
    )
    if first_active_or_created:
        request_rec.schedule_id = first_active_or_created.id
        request_rec.updated_at = now

    actor_name = universal_approval_actor_name(restored_by_user) if restored_by_user else 'System'
    request_label = clean_str(getattr(request_rec, 'request_no', None)) or f"TR-{request_rec.id}"

    db.session.add(ActivityLog(
        user=actor_name,
        action=f"Restored {len(created_blocks)} travel block day(s) for {request_label}; skipped {len(skipped_dates)} existing day(s)"
    ))

    record_universal_approval_audit(
        'travel_request',
        request_rec.id,
        'travel_blocks_restored',
        actor_user=restored_by_user or current_user,
        status_from=getattr(request_rec, 'status', None),
        status_to=getattr(request_rec, 'status', None),
        remarks=f"Restored {len(created_blocks)} missing travel block day(s).",
        metadata={
            'travel_request_id': request_rec.id,
            'request_record_id': request_rec.id,
            'created_count': len(created_blocks),
            'skipped_count': len(skipped_dates),
            'restored_dates': restored_dates,
            'skipped_dates': skipped_dates,
            'converted_overlap_dates': converted_overlap_dates,
            'group_id': group_id
        }
    )

    return {
        'success': True,
        'message': f"Restored {len(created_blocks)} travel block day(s). Skipped {len(skipped_dates)} existing day(s).",
        'created_count': len(created_blocks),
        'skipped_count': len(skipped_dates),
        'restored_dates': restored_dates,
        'skipped_dates': skipped_dates,
        'converted_overlap_dates': converted_overlap_dates,
        'first_shift_id': first_active_or_created.id if first_active_or_created else None,
        'group_id': group_id
    }


@app.route('/restore_travel_blocks/<int:travel_request_id>', methods=['POST'])
@csrf.exempt
@login_required
def restore_travel_blocks(travel_request_id):
    """S11H2C API: Rebuild missing Travel Blocks from an approved request."""
    request_rec = db.session.get(TravelRequest, travel_request_id)
    if not request_rec:
        return jsonify({'success': False, 'error': 'Travel request not found.'}), 404

    result = restore_missing_travel_blocks_for_request(
        request_rec,
        restored_by_user=current_user
    )

    if not result.get('success'):
        return jsonify({
            'success': False,
            'error': result.get('message') or 'Travel blocks could not be restored.',
            'message': result.get('message') or 'Travel blocks could not be restored.'
        }), 400

    db.session.commit()

    return jsonify({
        'success': True,
        'status': 'success',
        'message': result.get('message'),
        'created_count': result.get('created_count', 0),
        'skipped_count': result.get('skipped_count', 0),
        'restored_dates': result.get('restored_dates', []),
        'skipped_dates': result.get('skipped_dates', []),
        'converted_overlap_dates': result.get('converted_overlap_dates', []),
        'first_shift_id': result.get('first_shift_id'),
        'group_id': result.get('group_id')
    })


@app.route('/approve_travel_request/<int:travel_request_id>', methods=['POST'])
@csrf.exempt
@login_required
def approve_travel_request(travel_request_id):
    """S10A API: manager approves Travel Request before accounting handoff."""
    if not is_approval_center_user():
        return jsonify({'success': False, 'error': 'You are not assigned as an approver.'}), 403

    payload = request.get_json(silent=True) or {}
    remarks = clean_str(payload.get('remarks') or payload.get('approval_remarks') or '')
    approved_amount = payload.get('approved_amount')

    request_rec = db.session.get(TravelRequest, travel_request_id)
    if not request_rec:
        return jsonify({'success': False, 'error': 'Travel request not found.'}), 404
    if not can_user_approve_travel_request(current_user, request_rec):
        return jsonify({'success': False, 'error': 'This travel request is not assigned to you for approval.'}), 403
    if travel_request_normalize_status(request_rec.status) != 'Submitted':
        return jsonify({'success': False, 'error': f'Travel request is already {request_rec.status}.'}), 409

    signature_required_response = approval_signature_required_response(current_user, 'travel request')
    if signature_required_response:
        return signature_required_response

    clean_travel_request_airfare_c_o_remarks(request_rec)

    now = get_manila_time()
    previous_status = request_rec.status or ''
    request_rec.status = 'Approved'
    request_rec.approved_at = now
    request_rec.approved_by_id = current_user.id
    request_rec.approved_amount = travel_request_money(approved_amount if approved_amount is not None else request_rec.requested_amount)
    request_rec.rejected_at = None
    request_rec.rejected_by_id = None
    request_rec.approval_remarks = remarks
    request_rec.updated_at = now
    apply_approval_signature_snapshot(request_rec, current_user, action_label='Approved', signed_at=now)

    # S11H1B Travel Block Foundation:
    # Manager approval now creates duplicate-safe timeline Travel Block rows.
    travel_block_result = create_or_get_travel_blocks_for_approved_request(
        request_rec,
        approved_by_user=current_user,
        approved_at=now
    )

    record_universal_approval_audit(
        'travel_request',
        request_rec.id,
        'approved',
        actor_user=current_user,
        status_from=previous_status,
        status_to='Approved',
        remarks=remarks or 'Approved travel request.',
        metadata={
            'travel_request_id': request_rec.id,
            'request_record_id': request_rec.id,
            'approved_amount': request_rec.approved_amount,
            'approved_by': universal_approval_actor_name(current_user),
            'signature_snapshot_saved': bool(clean_str(getattr(request_rec, 'approval_signature_snapshot', None))),
            'travel_block_created_count': travel_block_result.get('created_count', 0),
            'travel_block_existing_count': travel_block_result.get('existing_count', 0),
            'travel_block_first_shift_id': travel_block_result.get('first_shift_id'),
            'travel_block_group_id': travel_block_result.get('group_id', '')
        }
    )

    resolve_pending_approval_notifications(
        module='travel_request',
        record_id=request_rec.id,
        event='submitted',
        exclude_user_ids=[request_rec.user_id]
    )

    # S12B6I: Notify requester + all Travel Request participants in-app.
    create_system_notifications_for_users(
        get_travel_request_notification_user_ids(request_rec),
        title='Travel Request Approved',
        message=f"{request_rec.request_no or 'Your travel request'} was approved by {universal_approval_actor_name(current_user)}.",
        module='travel_request',
        record_id=request_rec.id,
        target_url=travel_request_notification_url(request_rec),
        metadata={
            'event': 'approved',
            'request_no': request_rec.request_no,
            'approved_by_user_id': current_user.id,
            'approved_by': universal_approval_actor_name(current_user),
            'approved_amount': request_rec.approved_amount,
            'travel_block_first_shift_id': travel_block_result.get('first_shift_id'),
            'travel_block_created_count': travel_block_result.get('created_count', 0),
            'notification_recipients': get_travel_request_notification_user_ids(request_rec)
        }
    )

    accounting_emails = get_travel_accounting_recipient_emails()
    accounting_warning = None
    accounting_email_queued = False

    if accounting_emails:
        request_rec.accounting_status = 'Accounting Email Queued'
        request_rec.accounting_remarks = None
    else:
        request_rec.accounting_status = 'Accounting Email Not Configured'
        request_rec.accounting_remarks = (
            'No active Settings → Email Recipients → Travel Request Accounting email address configured.'
        )
        accounting_warning = travel_request_accounting_settings_warning_payload()
        add_activity_log_entry(
            f"Travel Request Accounting email not sent: no Accounting recipients configured for {request_rec.request_no or f'TR-{request_rec.id}'}"
        )

    add_activity_log_entry(
        f"Travel Request Approved: {request_rec.request_no or f'TR-{request_rec.id}'} by {universal_approval_actor_name(current_user)}"
    )
    db.session.commit()

    send_travel_request_notification_email_async(
        app,
        get_travel_request_notification_user_ids(request_rec),
        request_rec.id,
        'approved',
        actor_user_id=current_user.id,
        remarks=remarks
    )

    if accounting_emails:
        accounting_email_queued = send_travel_request_accounting_email_async(
            app,
            request_rec.id,
            accounting_emails,
            approved_by_user_id=current_user.id,
            remarks=remarks
        )

    response_payload = {
        'success': True,
        'message': 'Travel request approved.',
        'travel_block': travel_block_result,
        'travel_request': travel_request_to_dict(request_rec, include_lines=True, include_audit=True),
        'accounting_email': {
            'queued': bool(accounting_email_queued),
            'recipient_count': len(accounting_emails),
            'recipients': accounting_emails if is_superadmin_user() else [],
            'status': request_rec.accounting_status or ''
        }
    }

    if accounting_warning:
        response_payload['warning'] = accounting_warning
        response_payload['accounting_warning'] = accounting_warning
        response_payload['message'] = 'Travel request approved. Accounting email was not sent because no Accounting recipients are configured.'

    return jsonify(response_payload)


@app.route('/reject_travel_request/<int:travel_request_id>', methods=['POST'])
@csrf.exempt
@login_required
def reject_travel_request(travel_request_id):
    """S10A API: manager rejects/returns Travel Request."""
    if not is_approval_center_user():
        return jsonify({'success': False, 'error': 'You are not assigned as an approver.'}), 403

    payload = request.get_json(silent=True) or {}
    remarks = clean_str(payload.get('remarks') or payload.get('approval_remarks') or payload.get('reason') or '')
    if not remarks:
        return jsonify({'success': False, 'error': 'Rejection remarks are required.'}), 400

    request_rec = db.session.get(TravelRequest, travel_request_id)
    if not request_rec:
        return jsonify({'success': False, 'error': 'Travel request not found.'}), 404
    if not can_user_approve_travel_request(current_user, request_rec):
        return jsonify({'success': False, 'error': 'This travel request is not assigned to you for approval.'}), 403
    if travel_request_normalize_status(request_rec.status) != 'Submitted':
        return jsonify({'success': False, 'error': f'Travel request is already {request_rec.status}.'}), 409

    signature_required_response = approval_signature_required_response(current_user, 'travel request')
    if signature_required_response:
        return signature_required_response

    now = get_manila_time()
    previous_status = request_rec.status or ''
    request_rec.status = 'Rejected'
    request_rec.rejected_at = now
    request_rec.rejected_by_id = current_user.id
    request_rec.approved_at = None
    request_rec.approved_by_id = None
    request_rec.approval_remarks = remarks
    request_rec.updated_at = now
    clear_approval_signature_snapshot(request_rec)

    record_universal_approval_audit(
        'travel_request',
        request_rec.id,
        'rejected',
        actor_user=current_user,
        status_from=previous_status,
        status_to='Rejected',
        remarks=remarks,
        metadata={
            'travel_request_id': request_rec.id,
            'request_record_id': request_rec.id,
            'rejected_by': universal_approval_actor_name(current_user),
            'signature_snapshot_saved': False,
            'approval_signature_cleared': True
        }
    )

    resolve_pending_approval_notifications(
        module='travel_request',
        record_id=request_rec.id,
        event='submitted',
        exclude_user_ids=[request_rec.user_id]
    )

    # S12B6I: Notify requester + all Travel Request participants in-app.
    create_system_notifications_for_users(
        get_travel_request_notification_user_ids(request_rec),
        title='Travel Request Rejected',
        message=f"{request_rec.request_no or 'Your travel request'} was rejected by {universal_approval_actor_name(current_user)}. Remarks: {remarks}",
        module='travel_request',
        record_id=request_rec.id,
        target_url=travel_request_notification_url(request_rec),
        metadata={
            'event': 'rejected',
            'request_no': request_rec.request_no,
            'rejected_by_user_id': current_user.id,
            'rejected_by': universal_approval_actor_name(current_user),
            'remarks': remarks,
            'notification_recipients': get_travel_request_notification_user_ids(request_rec)
        }
    )

    add_activity_log_entry(
        f"Travel Request Rejected: {request_rec.request_no or f'TR-{request_rec.id}'} by {universal_approval_actor_name(current_user)}"
    )
    db.session.commit()

    send_travel_request_notification_email_async(
        app,
        get_travel_request_notification_user_ids(request_rec),
        request_rec.id,
        'rejected',
        actor_user_id=current_user.id,
        remarks=remarks
    )

    return jsonify({
        'success': True,
        'message': 'Travel request rejected and returned for correction.',
        'travel_request': travel_request_to_dict(request_rec, include_lines=True, include_audit=True)
    })


@app.route('/get_approval_center_summary')
@login_required
def get_approval_center_summary():
    """M2A backend summary for Rodito-only consolidated Approval Center."""
    denied_response = require_approval_center_user()
    if denied_response:
        return denied_response

    reimbursement_counts = approval_center_reimbursement_counts()
    liquidation_counts = approval_center_travel_liquidation_counts()
    cash_advance_counts = approval_center_cash_advance_counts()
    cash_advance_liquidation_counts = approval_center_cash_advance_liquidation_counts()
    modules = approval_center_module_catalog()

    travel_counts = {
        'draft': 0,
        'submitted': 0,
        'approved': 0,
        'rejected': 0,
        'pending': 0,
        'total': 0
    }
    try:
        travel_query = TravelRequest.query
        travel_query = apply_assigned_approver_filter(travel_query, TravelRequest, current_user, 'travel_request')
        travel_status_rows = (
            db.session.query(TravelRequest.status, func.count(TravelRequest.id))
            .select_from(travel_query.subquery())
            .group_by(db.text('status'))
            .all()
        )
    except Exception:
        travel_status_rows = []

    try:
        travel_query = TravelRequest.query
        travel_query = apply_assigned_approver_filter(travel_query, TravelRequest, current_user, 'travel_request')
        for raw_status, count_value in db.session.query(TravelRequest.status, func.count(TravelRequest.id)).filter(TravelRequest.id.in_([item.id for item in travel_query.all()])).group_by(TravelRequest.status).all():
            normalized = travel_request_normalize_status(raw_status)
            count_int = int(count_value or 0)
            travel_counts['total'] += count_int
            if normalized == 'Submitted':
                travel_counts['submitted'] += count_int
                travel_counts['pending'] += count_int
            elif normalized == 'Approved':
                travel_counts['approved'] += count_int
            elif normalized == 'Rejected':
                travel_counts['rejected'] += count_int
            elif normalized == 'Draft':
                travel_counts['draft'] += count_int
    except Exception as travel_count_error:
        print(f"[TravelRequest] Approval summary counts unavailable: {travel_count_error}", flush=True)

    for module in modules:
        if module['key'] == 'reimbursement':
            module['counts'] = reimbursement_counts
        elif module['key'] == 'travel_request':
            module['status'] = 'active'
            module['enabled'] = True
            module['counts'] = travel_counts
        elif module['key'] == 'travel_liquidation':
            module['status'] = 'active'
            module['enabled'] = True
            module['counts'] = liquidation_counts
        elif module['key'] == 'cash_advance':
            module['status'] = 'active'
            module['enabled'] = True
            module['counts'] = cash_advance_counts
        elif module['key'] == 'cash_advance_liquidation':
            module['status'] = 'active'
            module['enabled'] = True
            module['counts'] = cash_advance_liquidation_counts
        else:
            module['counts'] = {
                'draft': 0,
                'submitted': 0,
                'approved': 0,
                'rejected': 0,
                'pending': 0,
                'total': 0
            }

    return jsonify({
        'success': True,
        'approver': getattr(current_user, 'username', ''),
        'legacy_manager_view': is_legacy_reimbursement_approval_user(),
        'generated_at': get_manila_time().isoformat(),
        'modules': modules,
        'summary': {
            'pending_total': reimbursement_counts['pending'] + travel_counts['pending'] + liquidation_counts['pending'] + cash_advance_counts['pending'] + cash_advance_liquidation_counts['pending'],
            'active_modules': 5,
            'coming_soon_modules': 0
        }
    })


@app.route('/get_approval_center_items')
@login_required
def get_approval_center_items():
    """M2A generic item API for Rodito's Approval Center.

    Current supported module: reimbursement.
    Future modules will plug into this same endpoint.
    """
    denied_response = require_approval_center_user()
    if denied_response:
        return denied_response

    module_key = (request.args.get('module') or 'reimbursement').strip().lower()
    if module_key not in {'reimbursement', 'travel_request', 'travel_liquidation', 'cash_advance', 'cash_advance_liquidation', 'liquidation'}:
        return jsonify({'success': False, 'error': 'Unknown approval module.'}), 400

    requested_status = (request.args.get('status') or 'Submitted').strip().lower()
    status_map = {
        'submitted': 'Submitted',
        'pending': 'Submitted',
        'approved': 'Approved',
        'rejected': 'Rejected',
        'returned': 'Rejected',
        'draft': 'Draft',
        'all': 'All'
    }
    status_filter = status_map.get(requested_status, 'Submitted')

    if module_key == 'travel_request':
        items = travel_request_query_for_current_approver(status_filter).limit(300).all()
        return jsonify({
            'success': True,
            'module': 'travel_request',
            'enabled': True,
            'status': status_filter,
            'items': [travel_request_to_dict(item, include_lines=False) for item in items],
            'count': len(items)
        })

    if module_key in {'travel_liquidation', 'liquidation'}:
        items = travel_liquidation_query_for_current_approver(status_filter).limit(300).all()
        return jsonify({
            'success': True,
            'module': 'travel_liquidation',
            'enabled': True,
            'status': status_filter,
            'items': [travel_liquidation_to_dict(item, include_rows=False) for item in items],
            'count': len(items)
        })

    if module_key == 'cash_advance':
        items = cash_advance_query_for_current_approver(status_filter).limit(300).all()
        return jsonify({
            'success': True,
            'module': 'cash_advance',
            'enabled': True,
            'status': status_filter,
            'items': [cash_advance_to_dict(item, include_audit=False) for item in items],
            'count': len(items)
        })

    if module_key == 'cash_advance_liquidation':
        items = cash_advance_liquidation_query_for_current_approver(status_filter).limit(300).all()
        return jsonify({
            'success': True,
            'module': 'cash_advance_liquidation',
            'enabled': True,
            'status': status_filter,
            'items': [cash_advance_liquidation_to_dict(item, include_rows=False) for item in items],
            'count': len(items)
        })

    if module_key not in {'reimbursement'}:
        return jsonify({
            'success': True,
            'module': module_key,
            'enabled': False,
            'status': 'coming_soon',
            'items': [],
            'count': 0
        })

    query = ReimbursementHeader.query
    query = apply_assigned_approver_filter(query, ReimbursementHeader, current_user, 'reimbursement')
    if status_filter != 'All':
        query = query.filter(func.lower(func.trim(ReimbursementHeader.status)) == status_filter.lower())

    if status_filter in {'Submitted', 'All'}:
        query = query.order_by(
            ReimbursementHeader.submitted_at.asc(),
            ReimbursementHeader.updated_at.asc(),
            ReimbursementHeader.id.asc()
        )
    else:
        query = query.order_by(
            ReimbursementHeader.updated_at.desc(),
            ReimbursementHeader.id.desc()
        )

    headers = query.limit(300).all()
    items = [reimbursement_header_to_manager_dict(header, include_rows=False) for header in headers]

    return jsonify({
        'success': True,
        'module': 'reimbursement',
        'enabled': True,
        'status': status_filter,
        'items': items,
        'count': len(items)
    })


@app.route('/get_approval_audit_trail')
@login_required
def get_approval_audit_trail():
    """S9 API: return universal approval audit timeline for one request."""
    module = normalize_approval_scope(request.args.get('module') or request.args.get('request_module') or 'reimbursement')
    record_id = clean_int(
        request.args.get('record_id') or
        request.args.get('request_id') or
        request.args.get('reimbursement_id') or
        request.args.get('id')
    )

    if not record_id:
        return jsonify({'success': False, 'error': 'Missing record_id.'}), 400

    if not can_view_universal_approval_audit(module, record_id):
        return jsonify({'success': False, 'error': 'You are not allowed to view this audit trail.'}), 403

    entries = get_universal_approval_audit_entries(module, record_id)
    return jsonify({
        'success': True,
        'module': module,
        'record_id': record_id,
        'items': [universal_approval_audit_to_dict(entry) for entry in entries],
        'count': len(entries)
    })



