def travel_liquidation_accounting_package_filename(liquidation):
    """Safe ZIP filename for the approved liquidation Accounting package."""
    liquidation_no = clean_str(getattr(liquidation, 'liquidation_no', None)) or f"TL-{getattr(liquidation, 'id', '')}"
    request_rec = getattr(liquidation, 'travel_request', None)
    request_no = clean_str(getattr(request_rec, 'request_no', None)) or f"TR-{getattr(liquidation, 'travel_request_id', '')}"
    safe_name = secure_filename(f"Liquidation_Accounting_Package_{liquidation_no}_{request_no}.zip")
    return safe_name or f"Liquidation_Accounting_Package_TL-{getattr(liquidation, 'id', '')}.zip"


def build_travel_liquidation_accounting_package_zip_bytes(liquidation, approved_by_user=None, remarks=''):
    """Build the complete approved liquidation package ZIP for Accounting.

    Includes:
    - Official/approved Travel Request PDF
    - Summary of Liquidation Excel form
    - Receipt Compilation PDF, when receipts exist
    - RFP PDF, only when Due to Employee > 0
    """
    if not liquidation:
        return '', b''

    request_rec = getattr(liquidation, 'travel_request', None)
    if not request_rec:
        request_rec = db.session.get(TravelRequest, clean_int(getattr(liquidation, 'travel_request_id', None)))

    travel_liquidation_recalculate_totals(liquidation)
    package_filename = travel_liquidation_accounting_package_filename(liquidation)

    zip_buffer = io.BytesIO()
    with zipfile.ZipFile(zip_buffer, 'w', compression=zipfile.ZIP_DEFLATED) as package:
        if request_rec:
            travel_pdf_bytes = build_travel_request_accounting_pdf_bytes(
                request_rec,
                approved_by_user=approved_by_user,
                remarks=remarks
            )
            package.writestr(travel_request_pdf_filename(request_rec), travel_pdf_bytes)

        liquidation_excel_bytes = build_travel_liquidation_excel_bytes(liquidation)
        package.writestr(travel_liquidation_excel_filename(liquidation), liquidation_excel_bytes)

        receipt_pdf_bytes = build_travel_liquidation_receipt_compilation_pdf_bytes(liquidation)
        if receipt_pdf_bytes:
            package.writestr(travel_liquidation_receipt_compilation_filename(liquidation), receipt_pdf_bytes)

        if travel_liquidation_money(getattr(liquidation, 'due_to_employee', 0)) > 0:
            rfp_buffer = build_travel_liquidation_rfp_template_pdf(liquidation)
            rfp_buffer.seek(0)
            package.writestr(travel_liquidation_rfp_filename(liquidation), rfp_buffer.read())

    zip_buffer.seek(0)
    return package_filename, zip_buffer.getvalue()


def format_travel_liquidation_accounting_email(liquidation, approved_by_user=None, remarks=''):
    """Return subject/text/html for Accounting handoff after liquidation approval."""
    request_rec = getattr(liquidation, 'travel_request', None)
    engineer = getattr(liquidation, 'engineer', None)
    requester = getattr(liquidation, 'requester', None)
