    """Return subject/text/html for Travel Liquidation workflow notification emails.

    These are normal notification emails only. They intentionally have no file
    attachments. Managers review forms inside Approval Center; Accounting receives
    the package only after manager approval.
    """
    ctx = travel_liquidation_email_context(liquidation)
    actor_name = universal_approval_actor_name(actor_user) if actor_user else ctx['employee_name']
