@app.route('/approve_reimbursement/<int:reimbursement_id>', methods=['POST'])
@csrf.exempt
@login_required
def approve_reimbursement(reimbursement_id):
    """Approve an assigned reimbursement request."""
    if not reimbursement_is_approver_user():
        return jsonify({'success': False, 'error': 'You are not assigned as a reimbursement approver.'}), 403

    payload = request.get_json(silent=True) or {}
    remarks = clean_str(payload.get('remarks') or payload.get('approval_remarks') or '')

    header = db.session.get(ReimbursementHeader, reimbursement_id)
    if not header:
        return jsonify({'success': False, 'error': 'Reimbursement not found.'}), 404
    if not can_user_approve_reimbursement_header(current_user, header):
        return jsonify({'success': False, 'error': 'This reimbursement is not assigned to you for approval.'}), 403
    if header.status != 'Submitted':
        return jsonify({'success': False, 'error': f'Reimbursement is already {header.status}.'}), 409

    signature_required_response = approval_signature_required_response(current_user, module_label='reimbursement')
    if signature_required_response:
        return signature_required_response

    accounting_emails = get_reimbursement_accounting_recipient_emails()
    accounting_warning = None if accounting_emails else reimbursement_accounting_settings_warning_payload()

    try:
        now = get_manila_time()
        previous_status = header.status or ''
        header.status = 'Approved'
        header.approved_at = now
        header.approved_by_id = current_user.id
        header.rejected_at = None
        header.rejected_by_id = None
        header.approval_remarks = remarks
        apply_approval_signature_snapshot(header, current_user, action_label='Approved', signed_at=now)
        header.updated_at = now
        record_universal_approval_audit(
            'reimbursement',
            header.id,
            'approved',
            actor_user=current_user,
            status_from=previous_status,
            status_to='Approved',
            remarks=remarks or 'Approved reimbursement request.',
            metadata={
                'approved_by_id': current_user.id,
                'approved_by': universal_approval_actor_name(current_user),
                'signature_snapshot_saved': bool(clean_str(getattr(header, 'approval_signature_snapshot', None)))
            }
        )

        resolve_pending_approval_notifications('reimbursement', header.id, event='submitted')
        create_system_notification(
            user_id=header.user_id,
            title='Reimbursement Approved',
            message=f"Reimbursement #{header.id} was approved by {universal_approval_actor_name(current_user)}.",
            module='reimbursement',
            record_id=header.id,
            target_url=reimbursement_notification_url(header),
            metadata={
                'event': 'approved',
                'reimbursement_id': header.id,
                'approved_by_user_id': current_user.id,
                'approved_by': universal_approval_actor_name(current_user)
            }
        )
        db.session.commit()

        send_reimbursement_notification_email_async(
            app,
            [header.user_id],
            header.id,
            'approved',
            actor_user_id=current_user.id,
            remarks=remarks
        )

        accounting_email_queued = False
        if accounting_emails:
            accounting_email_queued = send_reimbursement_accounting_email_async(
                app,
                header.id,
                accounting_emails,
                approved_by_user_id=current_user.id,
                remarks=remarks
            )
        else:
            try:
                header.accounting_status = 'Accounting Recipients Missing'
                header.accounting_remarks = accounting_warning.get('message') if accounting_warning else ''
                header.updated_at = get_manila_time()
                db.session.add(ActivityLog(
                    user=current_user.username.capitalize(),
                    action=f"Reimbursement accounting email skipped - no recipients configured: reimbursement #{header.id}"
                ))
                db.session.commit()
            except Exception as accounting_warn_error:
                db.session.rollback()
                print(f"[Reimbursement] Accounting missing-recipient log skipped: {accounting_warn_error}", flush=True)

        try:
            log_activity(f"Approved reimbursement #{header.id} ({header.start_date.isoformat()} to {header.end_date.isoformat()})")
        except Exception as log_err:
            print(f"[Reimbursement] Approval activity log skipped: {log_err}")

        response_payload = {
            'success': True,
            'status': header.status,
            'message': 'Reimbursement approved.',
            'accounting_email': {
                'queued': bool(accounting_email_queued),
                'recipient_count': len(accounting_emails or [])
            },
            **reimbursement_header_approval_meta(header)
        }
        if accounting_warning:
            response_payload['warning'] = accounting_warning
            response_payload['accounting_warning'] = accounting_warning
            response_payload['message'] = 'Reimbursement approved. Accounting email was not sent because no Reimbursement Accounting recipient is configured.'
        elif accounting_email_queued:
            response_payload['message'] = 'Reimbursement approved. Accounting email queued.'

        return jsonify(response_payload)
    except Exception as exc:
        db.session.rollback()
        print(f"[Reimbursement] Approve failed: {exc}")
        return jsonify({'success': False, 'error': 'Unable to approve reimbursement.'}), 500




# --- S12B4 MY ACCOUNTING CENTER ACCESS BACKEND ---

def can_access_accounting_center(user=None):
    """Return True for users allowed to view My Requests / Accounting Center.

    S12B4 access model change:
    Accounting Center is a personal request/accounting workspace for normal
    authenticated users. Approver-only executive accounts are intentionally
    excluded because they approve assigned requests only and should not access
    requester/liquidation completion tools.
    """
    target = user or current_user
    if not (target and getattr(target, 'is_authenticated', False)):
        return False
    if is_approver_only_user(target):
        return False
    return True


def require_accounting_center_access():
    if can_access_accounting_center(current_user):
        return None
    if is_approver_only_user():
        return jsonify({
            'success': False,
            'error': 'Approver-only accounts do not use My Requests. Please use the Approval Center.'
        }), 403
    return jsonify({
        'success': False,
        'error': 'Please log in to access My Requests.'
    }), 403


def apply_my_accounting_owner_filter(query, model_cls):
    """Limit Accounting Center queues to the logged-in user's own records.

    S12B4: Manager decision changed Accounting Center from a central accounting
    staff queue into a user-facing personal workspace. Do not expose other
    requesters' reimbursements/travel/cash advance/liquidation records here.
    """
    if model_cls is TravelRequest:
        my_engineer_id = clean_int(getattr(travel_request_current_profile(), 'id', None))
        participant_filters = [TravelRequestParticipant.user_id == current_user.id]
        if my_engineer_id:
            participant_filters.append(TravelRequestParticipant.engineer_id == my_engineer_id)
        participant_subquery = (
            TravelRequestParticipant.query
            .with_entities(TravelRequestParticipant.travel_request_id)
            .filter(or_(*participant_filters))
        )
        return query.filter(or_(TravelRequest.user_id == current_user.id, TravelRequest.id.in_(participant_subquery)))

    if model_cls is TravelLiquidationHeader:
        my_engineer_id = clean_int(getattr(travel_request_current_profile(), 'id', None))
        participant_filters = [TravelRequestParticipant.user_id == current_user.id]
        if my_engineer_id:
            participant_filters.append(TravelRequestParticipant.engineer_id == my_engineer_id)
        participant_subquery = (
            TravelRequestParticipant.query
            .with_entities(TravelRequestParticipant.travel_request_id)
            .filter(or_(*participant_filters))
        )
        return query.filter(or_(
            TravelLiquidationHeader.user_id == current_user.id,
            TravelLiquidationHeader.travel_request_id.in_(participant_subquery)
        ))

    return query.filter(getattr(model_cls, 'user_id') == current_user.id)


def can_current_user_manage_my_accounting_record(record):
    """Return True when current user owns the accounting record.

    Users mark their own request as Paid/Received because they are the requester
    and the one confirming release/receipt.
    """
    if not (current_user and getattr(current_user, 'is_authenticated', False) and record):
        return False

    if clean_int(getattr(record, 'user_id', None)) == clean_int(getattr(current_user, 'id', None)):
        return True

    # Travel Request is a team request. Any saved participant can confirm their
    # own cash advance receipt from My Accounting Center, matching edit/submit access.
    if isinstance(record, TravelRequest):
        current_user_id = clean_int(getattr(current_user, 'id', None))
        current_engineer_id = clean_int(getattr(travel_request_current_profile(), 'id', None))
        for participant in get_travel_request_participants(record):
            participant_user_id = clean_int(getattr(participant, 'user_id', None))
            participant_engineer_id = clean_int(getattr(participant, 'engineer_id', None))
            if current_user_id and participant_user_id == current_user_id:
                return True
            if current_engineer_id and participant_engineer_id == current_engineer_id:
                return True

    return False


@app.route('/accounting_center')
@login_required
def accounting_center_page():
    """S12B2 Accounting Center shell page.

    The dedicated frontend template will be added next. Until then, this route
    returns a small safe placeholder instead of raising TemplateNotFound.
    """
    if is_approver_only_user():
        flash('Approver-only accounts should use the Approval Center.')
        return redirect(url_for('approvals_page'))

    if not can_access_accounting_center(current_user):
        flash('Please log in to access My Requests.')
        return redirect(url_for('login'))

    template_path = os.path.join(app.root_path, app.template_folder or 'templates', 'accounting_center.html')
    if os.path.exists(template_path):
        return render_template('accounting_center.html')

    placeholder_html = """
    <!doctype html>
    <html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Accounting Center</title>
    <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" rel="stylesheet">
    </head><body class="bg-light"><main class="container py-5">
    <div class="card border-0 shadow-sm"><div class="card-body p-4">
    <h1 class="h4 fw-bold mb-2">My Accounting Center</h1>
    <p class="text-muted mb-0">Your personal reimbursement and request records will appear here.</p>
    </div></div></main></body></html>
    """
    return Response(placeholder_html, mimetype='text/html')


@app.route('/travel_liquidation')
@login_required
def travel_liquidation_page():
    if is_approver_only_user():
        return redirect(url_for('dashboard_page'))
    """S13B hidden Travel Liquidation workflow page.

    This page is intentionally not linked in the sidebar. Users should open it
    from My Requests / My Accounting Center only. If someone directly opens the
    route without a valid accessible liquidation_id, redirect back to My
    Requests instead of exposing a standalone blank page.
    """
    if not can_access_accounting_center(current_user):
        flash('Please log in to access My Requests.')
        return redirect(url_for('login'))

    ensure_travel_liquidation_tables()
    liquidation_id = clean_int(request.args.get('liquidation_id') or request.args.get('id'))
    if not liquidation_id:
        flash('Open liquidation records from My Requests.')
        return redirect(url_for('accounting_center_page'))

    liquidation = get_travel_liquidation_for_requester_page(liquidation_id=liquidation_id)
    if not liquidation:
        flash('Liquidation record not found or not accessible.')
        return redirect(url_for('accounting_center_page'))

    template_path = os.path.join(app.root_path, app.template_folder or 'templates', 'travel_liquidation.html')
    if os.path.exists(template_path):
        return render_template('travel_liquidation.html', liquidation_id=liquidation_id)

    return redirect(url_for('accounting_center_page'))


