    try:
        data = travel_liquidation_parse_row_payload(
            request.get_json(silent=True) or {},
            normalize_travel_currency_code(getattr(liquidation, 'currency_code', None) or getattr(getattr(liquidation, 'travel_request', None), 'currency_code', None) or 'PHP'),
            travel_usd_to_php_rate(getattr(liquidation, 'usd_to_php_rate', 0))
        )
        if data['expense_date'] is not None:
            row.expense_date = data['expense_date']
        row.expense_type = data['expense_type']
        row.particulars = data['particulars']
        row.branch_code = data['branch_code']
        row.class_code = data['class_code']
        row.dept_code = data['dept_code']
        row.product_code = data['product_code']
        row.actual_amount = data['actual_amount']
        row.source_currency_code = data['source_currency_code']
        row.source_amount = data['source_amount']
        row.exchange_rate = data['exchange_rate']
        row.remarks = data['remarks']
        if data['sort_order'] is not None:
            row.sort_order = data['sort_order']
        row.updated_at = get_manila_time()

        travel_liquidation_recalculate_totals(liquidation)
        liquidation.updated_at = get_manila_time()

        record_universal_approval_audit(
            'travel_request',
            liquidation.travel_request_id,
            'liquidation_row_updated',
            actor_user=current_user,
            status_from=liquidation.status,
            status_to=liquidation.status,
            remarks=f"Updated liquidation row: {row.particulars}",
            metadata={
                'liquidation_id': liquidation.id,
                'liquidation_no': liquidation.liquidation_no,
                'row_id': row.id,
                'actual_amount': row.actual_amount
            }
        )
        db.session.commit()

        return jsonify({
            'success': True,
            'message': 'Liquidation row updated.',
            'row': travel_liquidation_row_to_dict(row),
            'liquidation': travel_liquidation_to_dict(liquidation, include_rows=True)
        })
    except ValueError as exc:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(exc)}), 400
    except Exception as exc:
        db.session.rollback()
        print(f"[TravelLiquidation] Save row failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to save liquidation row.'}), 500


