@app.route('/upload_travel_liquidation_receipt/<int:row_id>', methods=['POST'])
@app.route('/attach_travel_liquidation_receipt/<int:row_id>', methods=['POST'])
@csrf.exempt
@login_required
def upload_travel_liquidation_receipt(row_id):
    """S13C1: Attach receipt/proof file to one liquidation row."""
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_travel_liquidation_tables()
    row = db.session.get(TravelLiquidationRow, clean_int(row_id))
    if not row:
        return jsonify({'success': False, 'error': 'Liquidation row not found.'}), 404

    liquidation = getattr(row, 'liquidation', None)
    allowed, message = can_edit_travel_liquidation(liquidation)
    if not allowed:
        return jsonify({'success': False, 'error': message}), 403

    file_obj = request.files.get('receipt') or request.files.get('file') or request.files.get('attachment')
    if not file_obj or not getattr(file_obj, 'filename', None):
        return jsonify({'success': False, 'error': 'Please select a receipt file to upload.'}), 400

    valid_receipt, receipt_error = validate_travel_liquidation_receipt_upload(file_obj)
    if not valid_receipt:
        return jsonify({'success': False, 'error': receipt_error or 'Unsupported receipt file type.'}), 400

    try:
        stored_filename, original_filename = travel_liquidation_secure_receipt_filename(file_obj, row.id)
        prepared_bytes, stored_ext, content_type = reimbursement_prepare_receipt_upload_bytes(file_obj, original_filename)
        stored_filename = os.path.splitext(stored_filename)[0] + f'.{stored_ext}'
        folder = travel_liquidation_receipt_folder()
        file_path = os.path.join(folder, stored_filename)
        with open(file_path, 'wb') as target_file:
            target_file.write(prepared_bytes)

        receipt = TravelLiquidationReceipt(
            liquidation_id=liquidation.id,
            row_id=row.id,
            uploaded_by_id=current_user.id,
            stored_filename=stored_filename,
            original_filename=original_filename,
            content_type=content_type or clean_str(getattr(file_obj, 'mimetype', None)) or '',
            file_size=os.path.getsize(file_path) if os.path.exists(file_path) else 0,
            created_at=get_manila_time()
        )
        db.session.add(receipt)
        liquidation.updated_at = get_manila_time()

        record_universal_approval_audit(
            'travel_request',
            liquidation.travel_request_id,
            'liquidation_receipt_uploaded',
            actor_user=current_user,
            status_from=liquidation.status,
            status_to=liquidation.status,
            remarks=f"Uploaded liquidation receipt: {original_filename}",
            metadata={
                'liquidation_id': liquidation.id,
                'liquidation_no': liquidation.liquidation_no,
                'row_id': row.id,
                'receipt_filename': original_filename
            }
        )
        db.session.commit()

        return jsonify({
            'success': True,
            'message': 'Receipt uploaded.',
            'receipt': travel_liquidation_receipt_to_dict(receipt),
            'row': travel_liquidation_row_to_dict(row),
            'liquidation': travel_liquidation_to_dict(liquidation, include_rows=True)
        })
    except Exception as exc:
        db.session.rollback()
        print(f"[TravelLiquidation] Receipt upload failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to upload receipt.'}), 500


@app.route('/delete_travel_liquidation_receipt/<int:receipt_id>', methods=['POST'])
@app.route('/remove_travel_liquidation_receipt/<int:receipt_id>', methods=['POST'])
@csrf.exempt
@login_required
def delete_travel_liquidation_receipt(receipt_id):
    """S13C11: Delete one uploaded liquidation receipt.

    Frontend already supports per-receipt delete. This backend endpoint removes
    both the database record and the stored file, while returning the refreshed
    liquidation payload so the page updates without a manual refresh.
    """
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_travel_liquidation_tables()
    receipt = db.session.get(TravelLiquidationReceipt, clean_int(receipt_id))
    if not receipt:
        return jsonify({'success': False, 'error': 'Receipt not found.'}), 404

    row = db.session.get(TravelLiquidationRow, clean_int(getattr(receipt, 'row_id', None)))
    liquidation = getattr(row, 'liquidation', None) if row else None
    if not liquidation:
        liquidation = get_travel_liquidation_for_current_user(liquidation_id=getattr(receipt, 'liquidation_id', None))

    if not liquidation:
        return jsonify({'success': False, 'error': 'Liquidation draft not found or not accessible.'}), 404

    allowed, message = can_edit_travel_liquidation(liquidation)
    if not allowed:
        return jsonify({'success': False, 'error': message}), 403

    original_filename = clean_str(getattr(receipt, 'original_filename', None)) or clean_str(getattr(receipt, 'stored_filename', None)) or 'receipt'
    stored_filename = os.path.basename(clean_str(getattr(receipt, 'stored_filename', None)) or '')
    file_deleted = False

    try:
        if stored_filename:
            file_path = os.path.join(travel_liquidation_receipt_folder(), stored_filename)
            if os.path.exists(file_path) and os.path.isfile(file_path):
                os.remove(file_path)
                file_deleted = True

        db.session.delete(receipt)
        liquidation.updated_at = get_manila_time()

        record_universal_approval_audit(
            'travel_request',
            liquidation.travel_request_id,
            'liquidation_receipt_deleted',
            actor_user=current_user,
            status_from=liquidation.status,
            status_to=liquidation.status,
            remarks=f"Deleted liquidation receipt: {original_filename}",
            metadata={
                'liquidation_id': liquidation.id,
                'liquidation_no': liquidation.liquidation_no,
                'row_id': clean_int(getattr(row, 'id', None)),
                'receipt_id': clean_int(receipt_id),
                'receipt_filename': original_filename,
                'file_deleted': file_deleted
            }
        )

        travel_liquidation_recalculate_totals(liquidation)
        db.session.commit()

        return jsonify({
            'success': True,
            'message': 'Receipt deleted.',
            'deleted_receipt_id': clean_int(receipt_id),
            'file_deleted': file_deleted,
            'liquidation': travel_liquidation_to_dict(liquidation, include_rows=True)
        })

    except Exception as exc:
        db.session.rollback()
        print(f"[TravelLiquidation] Receipt delete failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to delete receipt.'}), 500



