def preview_travel_liquidation_receipt(receipt_id):
    """F3C: Preview one liquidation receipt inline for manager review."""
    ensure_travel_liquidation_tables()

    receipt = db.session.get(TravelLiquidationReceipt, clean_int(receipt_id))
    if not receipt:
        return jsonify({'success': False, 'error': 'Receipt not found.'}), 404

    liquidation = db.session.get(TravelLiquidationHeader, clean_int(getattr(receipt, 'liquidation_id', None)))
    if not liquidation:
        return jsonify({'success': False, 'error': 'Linked liquidation not found.'}), 404

    if not can_current_user_view_travel_liquidation_form(liquidation):
        return jsonify({'success': False, 'error': 'You are not allowed to view this receipt.'}), 403

    folder = travel_liquidation_receipt_folder()
    file_path = os.path.join(folder, os.path.basename(clean_str(getattr(receipt, 'stored_filename', None)) or ''))
    if not os.path.exists(file_path):
        return jsonify({'success': False, 'error': 'Receipt file is missing.'}), 404

    filename = clean_str(getattr(receipt, 'original_filename', None)) or os.path.basename(file_path)
    response = send_file(
        file_path,
        as_attachment=False,
        download_name=filename,
        mimetype=travel_liquidation_receipt_mimetype(receipt, file_path),
        max_age=0
    )
    return force_inline_file_response(response, filename)


@app.route('/download_travel_liquidation_receipt/<int:receipt_id>')
@login_required
def download_travel_liquidation_receipt(receipt_id):
    """Download one liquidation receipt with the normal permission gate."""
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_travel_liquidation_tables()
    receipt = db.session.get(TravelLiquidationReceipt, clean_int(receipt_id))
    if not receipt:
        return redirect(url_for('accounting_center'))

    liquidation = get_travel_liquidation_for_current_user(liquidation_id=getattr(receipt, 'liquidation_id', None))
    if not liquidation:
        return redirect(url_for('accounting_center'))

    folder = travel_liquidation_receipt_folder()
    file_path = os.path.join(folder, os.path.basename(clean_str(getattr(receipt, 'stored_filename', None)) or ''))
    if not os.path.exists(file_path):
        return redirect(url_for('accounting_center'))

    filename = clean_str(getattr(receipt, 'original_filename', None)) or os.path.basename(file_path)
    force_download = (
        (request.args.get('force_download') or '').strip().lower() in {'1', 'true', 'yes', 'on'} or
        (request.args.get('download') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
    )
    response = send_file(
        file_path,
        as_attachment=bool(force_download),
        download_name=filename,
        mimetype=travel_liquidation_receipt_mimetype(receipt, file_path),
        max_age=0
    )
    if not force_download:
        return force_inline_file_response(response, filename)
    return response



def cash_advance_my_requests_stage_label(header):
    """Return the My Requests status label for a standalone Cash Advance."""
    status = cash_advance_normalize_status(getattr(header, 'status', None))
    accounting_status = clean_str(getattr(header, 'accounting_status', None)) or ''
    accounting_key = accounting_status.strip().lower().replace('_', ' ')

    combined_liq_key = f"{status} {accounting_status}".strip().lower().replace('_', ' ')
    if 'liquidation completed' in combined_liq_key or 'completed' == combined_liq_key:
        return 'Liquidation Completed'
    if 'liquidation approved' in combined_liq_key:
        return 'Liquidation Approved'
    if 'liquidation submitted' in combined_liq_key:
        return 'Liquidation Submitted'
    if 'liquidation returned' in combined_liq_key or 'liquidation rejected' in combined_liq_key:
        return 'Liquidation Returned'
    if 'liquidation draft' in combined_liq_key:
        return 'Liquidation Draft'
    if getattr(header, 'received_at', None) or status == 'Ready for Liquidation' or accounting_key in {'received', 'ready for liquidation'}:
        return 'Ready for Liquidation'
    if status == 'Submitted':
        return 'Pending Manager Approval'
    if status == 'Approved':
        if accounting_key in {'sent to accounting', 'accounting email queued', 'accounting email sent'} or getattr(header, 'sent_to_accounting_at', None):
            return accounting_status or 'Sent to Accounting'
        if accounting_key in {'accounting email missing recipients', 'accounting email failed'}:
            return accounting_status
        return 'Approved'
    if status == 'Rejected':
        return 'Rejected'
    return accounting_status or status or 'Draft'


def cash_advance_my_requests_status_bucket(header):
    """Return pending/processing/paid/rejected/draft bucket for My Requests."""
    status = cash_advance_normalize_status(getattr(header, 'status', None))
    accounting_status = (clean_str(getattr(header, 'accounting_status', None)) or '').strip().lower().replace('_', ' ')

    if getattr(header, 'received_at', None) or status == 'Ready for Liquidation' or accounting_status in {'received', 'ready for liquidation'}:
        return 'paid'
    if status == 'Submitted':
        return 'pending'
    if status == 'Approved':
        return 'processing'
    if status == 'Rejected':
        return 'rejected'
    return 'draft'


def get_cash_advance_my_requests_summary_counts():
    """Return My Requests counts for standalone Cash Advances only."""
    try:
        ensure_cash_advance_tables()
    except Exception:
        # Module metadata must not break the entire My Requests page if SQLite is briefly locked.
        return {'pending': 0, 'processing': 0, 'paid': 0, 'rejected': 0, 'total_active': 0, 'total': 0}

    base_query = apply_my_accounting_owner_filter(CashAdvanceHeader.query, CashAdvanceHeader)
    normalized_status = func.lower(func.trim(func.coalesce(CashAdvanceHeader.status, '')))
    normalized_accounting_status = func.lower(func.trim(func.coalesce(CashAdvanceHeader.accounting_status, '')))

    paid_filter = or_(
        CashAdvanceHeader.received_at.isnot(None),
        normalized_status.in_(['ready for liquidation', 'ready_for_liquidation', 'received']),
        normalized_accounting_status.in_(['received', 'ready for liquidation', 'ready_for_liquidation'])
    )
    pending_count = base_query.filter(normalized_status == 'submitted').count()
    processing_count = base_query.filter(normalized_status == 'approved').filter(~paid_filter).count()
    paid_count = base_query.filter(paid_filter).count()
    rejected_count = base_query.filter(normalized_status.in_(['rejected', 'returned'])).count()
    total_count = base_query.filter(normalized_status != 'draft').count()

    return {
        'pending': pending_count,
        'processing': processing_count,
        'paid': paid_count,
        'rejected': rejected_count,
        'total_active': pending_count + processing_count,
        'total': total_count
    }


def accounting_center_cash_advance_item_to_dict(header):
    """Serialize one standalone Cash Advance for My Requests."""
    item = cash_advance_to_dict(header, include_audit=False)
    status_label = cash_advance_my_requests_stage_label(header)
    bucket = cash_advance_my_requests_status_bucket(header)

    amount_requested = cash_advance_money(getattr(header, 'amount_requested', 0))
    approved_amount = cash_advance_money(getattr(header, 'approved_amount', None) or amount_requested)
    approved_at = getattr(header, 'approved_at', None)
    sent_to_accounting_at = getattr(header, 'sent_to_accounting_at', None)
    received_at = getattr(header, 'received_at', None)
    request_date = getattr(header, 'request_date', None)
    needed_date = getattr(header, 'needed_date', None)

    item.update({
        'module': 'cash_advances',
        'queue': 'cash_advances',
        'record_label': clean_str(getattr(header, 'cash_advance_no', None)) or f"CA-{getattr(header, 'id', '')}",
        'record_no': clean_str(getattr(header, 'cash_advance_no', None)) or f"CA-{getattr(header, 'id', '')}",
        'stage_label': status_label,
        'status_bucket': bucket,
        'request_status': cash_advance_normalize_status(getattr(header, 'status', None)),
        'accounting_status': status_label,
        'request_date_label': request_date.strftime('%m/%d/%Y') if request_date else '',
        'needed_date_label': needed_date.strftime('%m/%d/%Y') if needed_date else '',
        'period': needed_date.strftime('%m/%d/%Y') if needed_date else (request_date.strftime('%m/%d/%Y') if request_date else ''),
        'amount': amount_requested,
        'amount_requested': amount_requested,
        'approved_amount': approved_amount,
        'grand_total': approved_amount,
        'approved_at_label': approved_at.strftime('%m/%d/%Y %I:%M %p') if approved_at else '',
        'sent_to_accounting_at_label': sent_to_accounting_at.strftime('%m/%d/%Y %I:%M %p') if sent_to_accounting_at else '',
        'received_at_label': received_at.strftime('%m/%d/%Y %I:%M %p') if received_at else '',
        'paid_at': received_at.isoformat() if received_at else '',
        'paid_at_label': received_at.strftime('%m/%d/%Y %I:%M %p') if received_at else '',
        'payment_method': clean_str(getattr(header, 'payment_method', None)) or '',
        'payment_reference': clean_str(getattr(header, 'payment_reference', None)) or '',
        'payment_remarks': clean_str(getattr(header, 'payment_remarks', None)) or '',
        'detail_url': f"/cash_advance?cash_advance_id={getattr(header, 'id', '')}",
        'cash_advance_url': f"/cash_advance?cash_advance_id={getattr(header, 'id', '')}",
        'can_confirm_received': bool(bucket == 'processing' and cash_advance_normalize_status(getattr(header, 'status', None)) == 'Approved'),
        'can_mark_paid': bool(bucket == 'processing' and cash_advance_normalize_status(getattr(header, 'status', None)) == 'Approved'),
        'can_mark_cash_advance_received': bool(bucket == 'processing' and cash_advance_normalize_status(getattr(header, 'status', None)) == 'Approved'),
        'received_note': 'Ready for Liquidation' if bucket == 'paid' else '',
        'reference_label': clean_str(getattr(header, 'payment_reference', None)) or clean_str(getattr(header, 'accounting_remarks', None)) or clean_str(getattr(header, 'cash_advance_no', None)) or f"CA-{getattr(header, 'id', '')}"
    })

    try:
        ensure_cash_advance_liquidation_tables()
        liquidation = CashAdvanceLiquidationHeader.query.filter_by(cash_advance_id=header.id).first()
    except Exception:
        liquidation = None

    ready_for_liquidation = bool(
        getattr(header, 'received_at', None) or
        cash_advance_normalize_status(getattr(header, 'status', None)) in {
            'Ready for Liquidation',
            'Liquidation Draft',
            'Liquidation Submitted',
            'Liquidation Approved',
            'Liquidation Returned',
            'Liquidation Completed'
        }
    )
    liquidation_status = cash_advance_liquidation_normalize_status(getattr(liquidation, 'status', None)) if liquidation else ''
    liquidation_accounting_status = clean_str(getattr(liquidation, 'accounting_status', None)) if liquidation else ''
    liquidation_completed_at = getattr(liquidation, 'completed_at', None) if liquidation else None
    can_complete_liquidation = bool(
        liquidation and
        int(getattr(liquidation, 'user_id', 0) or 0) == int(getattr(current_user, 'id', 0) or 0) and
        liquidation_status == 'Approved' and
        not liquidation_completed_at
    )
    item.update({
        'liquidation_id': clean_int(getattr(liquidation, 'id', None)) if liquidation else None,
        'liquidation_no': clean_str(getattr(liquidation, 'liquidation_no', None)) if liquidation else '',
        'liquidation_status': liquidation_status,
        'liquidation_accounting_status': liquidation_accounting_status,
        'liquidation_sent_to_accounting_at_label': getattr(liquidation, 'sent_to_accounting_at', None).strftime('%m/%d/%Y %I:%M %p') if liquidation and getattr(liquidation, 'sent_to_accounting_at', None) else '',
        'liquidation_completed_at': liquidation_completed_at.isoformat() if liquidation_completed_at else '',
        'liquidation_completed_at_label': liquidation_completed_at.strftime('%m/%d/%Y %I:%M %p') if liquidation_completed_at else '',
        'can_complete_liquidation': can_complete_liquidation,
        'complete_liquidation_url': f"/complete_cash_advance_liquidation/{liquidation.id}" if can_complete_liquidation else '',
        'liquidation_url': f"/cash_advance_liquidation?liquidation_id={liquidation.id}" if liquidation else '',
        'can_create_liquidation': bool(ready_for_liquidation and not liquidation),
        'can_open_liquidation': bool(liquidation),
        'create_liquidation_url': f"/create_cash_advance_liquidation_draft/{header.id}" if ready_for_liquidation and not liquidation else '',
        'open_liquidation_url': f"/cash_advance_liquidation?liquidation_id={liquidation.id}" if liquidation else ''
    })
    return item


@app.route('/get_accounting_cash_advance_queue')
@app.route('/get_accounting_cash_advances_queue')
@login_required
def get_accounting_cash_advance_queue():
    """F4A4: My Requests queue for standalone Cash Advances."""
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_cash_advance_tables()

    requested_status = (request.args.get('status') or 'pending').strip().lower()
    if requested_status not in {'pending', 'processing', 'paid', 'rejected', 'all'}:
        requested_status = 'pending'

    query = apply_my_accounting_owner_filter(CashAdvanceHeader.query, CashAdvanceHeader)
    normalized_status = func.lower(func.trim(func.coalesce(CashAdvanceHeader.status, '')))
    normalized_accounting_status = func.lower(func.trim(func.coalesce(CashAdvanceHeader.accounting_status, '')))
    paid_filter = or_(
        CashAdvanceHeader.received_at.isnot(None),
        normalized_status.in_(['ready for liquidation', 'ready_for_liquidation', 'received']),
        normalized_accounting_status.in_(['received', 'ready for liquidation', 'ready_for_liquidation'])
    )

    if requested_status == 'pending':
        query = query.filter(normalized_status == 'submitted')
    elif requested_status == 'processing':
        query = query.filter(normalized_status == 'approved').filter(~paid_filter)
    elif requested_status == 'paid':
        query = query.filter(paid_filter)
    elif requested_status == 'rejected':
        query = query.filter(normalized_status.in_(['rejected', 'returned']))
    else:
        query = query.filter(normalized_status != 'draft')

    items = (
        query
        .order_by(CashAdvanceHeader.updated_at.desc(), CashAdvanceHeader.id.desc())
        .limit(500)
        .all()
    )

    return jsonify({
        'success': True,
        'module': 'accounting_center',
        'queue': 'cash_advances',
        'status': requested_status,
        'items': [accounting_center_cash_advance_item_to_dict(item) for item in items],
        'count': len(items),
        'summary': get_cash_advance_my_requests_summary_counts(),
        'message': f'{len(items)} standalone Cash Advance record(s) shown.'
    })


@app.route('/accounting_mark_cash_advance_received/<int:cash_advance_id>', methods=['POST'])
@app.route('/accounting_mark_cash_advance_paid/<int:cash_advance_id>', methods=['POST'])
@app.route('/mark_cash_advance_received/<int:cash_advance_id>', methods=['POST'])
@csrf.exempt
@login_required
def accounting_mark_cash_advance_received(cash_advance_id):
    """F4A4: Requester confirms standalone Cash Advance money was received.

    Accounting releases money outside this user-facing page after receiving the
    handoff email. The requester then confirms receipt here, and the system moves
    the standalone Cash Advance to Ready for Liquidation.
    """
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_cash_advance_tables()
    payload = request.get_json(silent=True) or {}
    payment_reference = clean_str(payload.get('payment_reference') or payload.get('reference') or payload.get('transaction_reference') or '') or ''
    payment_method = clean_str(payload.get('payment_method') or payload.get('method') or '') or ''
    payment_remarks = clean_str(payload.get('payment_remarks') or payload.get('remarks') or '') or ''

    header = db.session.get(CashAdvanceHeader, clean_int(cash_advance_id))
    if not header:
        return jsonify({'success': False, 'error': 'Cash Advance request not found.'}), 404
    if not can_current_user_manage_my_accounting_record(header):
        return jsonify({'success': False, 'error': 'You can only confirm receipt for your own Cash Advance request.'}), 403

    current_status = cash_advance_normalize_status(getattr(header, 'status', None))
    if getattr(header, 'received_at', None) or current_status == 'Ready for Liquidation':
        return jsonify({'success': False, 'error': 'This Cash Advance is already marked as received / ready for liquidation.'}), 409
    if current_status != 'Approved':
        return jsonify({'success': False, 'error': f'Cash Advance must be Approved before it can be confirmed received. Current status: {current_status}.'}), 409

    try:
        now = get_manila_time()
        previous_status = current_status
        previous_accounting_status = clean_str(getattr(header, 'accounting_status', None)) or 'Pending Accounting Release'
        request_label = clean_str(getattr(header, 'cash_advance_no', None)) or f'CA-{header.id}'

        header.status = 'Ready for Liquidation'
        header.accounting_status = 'Received'
        header.received_at = now
        header.received_by_id = current_user.id
        header.ready_for_liquidation_at = now
        header.payment_method = payment_method[:80]
        header.payment_reference = payment_reference[:150]
        header.payment_remarks = payment_remarks
        header.accounting_remarks = payment_remarks or payment_reference or previous_accounting_status
        header.updated_at = now

        cash_advance_add_audit(header, 'received', payment_remarks or payment_reference or 'Cash Advance receipt confirmed.')
        record_universal_approval_audit(
            'cash_advance',
            header.id,
            'received',
            actor_user=current_user,
            status_from=previous_status,
            status_to='Ready for Liquidation',
            remarks=payment_remarks or payment_reference or 'Cash Advance receipt confirmed and ready for liquidation.',
            metadata={
                'cash_advance_id': header.id,
                'cash_advance_no': request_label,
                'received_by_user_id': current_user.id,
                'received_by': universal_approval_actor_name(current_user),
                'previous_accounting_status': previous_accounting_status,
                'accounting_status_to': 'Received',
                'payment_reference': payment_reference,
                'payment_method': payment_method,
                'payment_remarks': payment_remarks,
                'ready_for_liquidation_at': now.isoformat()
            }
        )

        create_system_notification(
            current_user.id,
            title='Cash Advance Ready for Liquidation',
            message=f'{request_label} was confirmed received and is now ready for liquidation.',
            module='cash_advance',
            record_id=header.id,
            target_url=cash_advance_notification_url(header),
            metadata={
                'event': 'received',
                'cash_advance_id': header.id,
                'cash_advance_no': request_label,
                'payment_reference': payment_reference,
                'payment_method': payment_method
            }
        )
        add_activity_log_entry(f'Confirmed Cash Advance received / ready for liquidation: {request_label}')
        db.session.commit()

        item = accounting_center_cash_advance_item_to_dict(header)
        return jsonify({
            'success': True,
            'message': 'Cash Advance marked as received and ready for liquidation.',
            'status': 'Ready for Liquidation',
            'accounting_status': 'Received',
            'item': item,
            'cash_advance': item
        })
    except Exception as exc:
        db.session.rollback()
        print(f'[CashAdvance] Confirm received failed: {exc}', flush=True)
        return jsonify({'success': False, 'error': 'Unable to confirm Cash Advance receipt.'}), 500


