_cash_advance_tables_ready = False
_cash_advance_liquidation_tables_ready = False


def ensure_cash_advance_tables():
    """Create and safely migrate standalone Cash Advance tables."""
    global _cash_advance_tables_ready

    if _cash_advance_tables_ready:
        return

    try:
        CashAdvanceHeader.__table__.create(db.engine, checkfirst=True)
        CashAdvanceAttachment.__table__.create(db.engine, checkfirst=True)
        CashAdvanceAudit.__table__.create(db.engine, checkfirst=True)

        # Safe live SQLite migration for columns added after F4A1 foundation.
        with db.engine.begin() as connection:
            columns = {row[1] for row in connection.exec_driver_sql("PRAGMA table_info(cash_advance_header)").fetchall()}
            if 'liquidation_days' not in columns:
                connection.exec_driver_sql("ALTER TABLE cash_advance_header ADD COLUMN liquidation_days INTEGER DEFAULT 30")
                print("[DB MIGRATION] Added cash_advance_header.liquidation_days", flush=True)

            # F4A3B manager approval metadata for standalone Cash Advance.
            cash_advance_column_migrations = {
                'requester_name_snapshot': 'ALTER TABLE cash_advance_header ADD COLUMN requester_name_snapshot VARCHAR(150)',
                'requester_signature_snapshot': 'ALTER TABLE cash_advance_header ADD COLUMN requester_signature_snapshot TEXT',
                'requester_signature_layout': 'ALTER TABLE cash_advance_header ADD COLUMN requester_signature_layout VARCHAR(50)',
                'requester_signed_at': 'ALTER TABLE cash_advance_header ADD COLUMN requester_signed_at DATETIME',
                'approved_by_id': 'ALTER TABLE cash_advance_header ADD COLUMN approved_by_id INTEGER',
                'approved_amount': 'ALTER TABLE cash_advance_header ADD COLUMN approved_amount FLOAT DEFAULT 0',
                'rejected_at': 'ALTER TABLE cash_advance_header ADD COLUMN rejected_at DATETIME',
                'rejected_by_id': 'ALTER TABLE cash_advance_header ADD COLUMN rejected_by_id INTEGER',
                'approval_remarks': 'ALTER TABLE cash_advance_header ADD COLUMN approval_remarks TEXT',
                'approval_action': 'ALTER TABLE cash_advance_header ADD COLUMN approval_action VARCHAR(20)',
                'approval_name_snapshot': 'ALTER TABLE cash_advance_header ADD COLUMN approval_name_snapshot VARCHAR(150)',
                'approval_title_snapshot': 'ALTER TABLE cash_advance_header ADD COLUMN approval_title_snapshot VARCHAR(150)',
                'approval_signature_snapshot': 'ALTER TABLE cash_advance_header ADD COLUMN approval_signature_snapshot TEXT',
                'approval_signature_layout': 'ALTER TABLE cash_advance_header ADD COLUMN approval_signature_layout VARCHAR(50)',
                'approval_signed_at': 'ALTER TABLE cash_advance_header ADD COLUMN approval_signed_at DATETIME',
                'accounting_status': 'ALTER TABLE cash_advance_header ADD COLUMN accounting_status VARCHAR(40)',
                'sent_to_accounting_at': 'ALTER TABLE cash_advance_header ADD COLUMN sent_to_accounting_at DATETIME',
                'accounting_remarks': 'ALTER TABLE cash_advance_header ADD COLUMN accounting_remarks TEXT',
                'released_at': 'ALTER TABLE cash_advance_header ADD COLUMN released_at DATETIME',
                'released_by_id': 'ALTER TABLE cash_advance_header ADD COLUMN released_by_id INTEGER',
                'received_at': 'ALTER TABLE cash_advance_header ADD COLUMN received_at DATETIME',
                'received_by_id': 'ALTER TABLE cash_advance_header ADD COLUMN received_by_id INTEGER',
                'ready_for_liquidation_at': 'ALTER TABLE cash_advance_header ADD COLUMN ready_for_liquidation_at DATETIME',
                'payment_method': 'ALTER TABLE cash_advance_header ADD COLUMN payment_method VARCHAR(80)',
                'payment_reference': 'ALTER TABLE cash_advance_header ADD COLUMN payment_reference VARCHAR(150)',
                'payment_remarks': 'ALTER TABLE cash_advance_header ADD COLUMN payment_remarks TEXT'
            }
            for column_name, statement in cash_advance_column_migrations.items():
                if column_name not in columns:
                    connection.exec_driver_sql(statement)
                    print(f"[DB MIGRATION] Added cash_advance_header.{column_name}", flush=True)

            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_header_user ON cash_advance_header (user_id)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_header_status ON cash_advance_header (status)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_header_no ON cash_advance_header (cash_advance_no)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_header_approved_by ON cash_advance_header (approved_by_id)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_header_rejected_by ON cash_advance_header (rejected_by_id)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_header_accounting_status ON cash_advance_header (accounting_status)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_sent_to_accounting_at ON cash_advance_header (sent_to_accounting_at)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_released_at ON cash_advance_header (released_at)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_received_at ON cash_advance_header (received_at)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_ready_liquidation_at ON cash_advance_header (ready_for_liquidation_at)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_audit_record ON cash_advance_audit (cash_advance_id)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_cash_advance_attachment_record ON cash_advance_attachment (cash_advance_id)")

        _cash_advance_tables_ready = True
    except Exception as table_error:
        # SQLite can temporarily lock during local browser refresh / service worker parallel calls.
        # If the base Cash Advance tables already exist, allow the page/API to continue and retry
        # index creation on the next request instead of crashing the page.
        try:
            message = str(table_error).lower()
            with db.engine.connect() as connection:
                existing_tables = {
                    row[0] for row in connection.exec_driver_sql(
                        "SELECT name FROM sqlite_master WHERE type='table'"
                    ).fetchall()
                }
            if 'database is locked' in message and {'cash_advance_header', 'cash_advance_attachment', 'cash_advance_audit'}.issubset(existing_tables):
                print(f"[CashAdvance] Table ensure deferred because SQLite is locked: {table_error}", flush=True)
                _cash_advance_tables_ready = True
                return
        except Exception:
            pass

        print(f"[CashAdvance] Unable to ensure tables: {table_error}", flush=True)
        raise


def ensure_cash_advance_liquidation_tables():
    """F4A5A create standalone Cash Advance Liquidation tables and indexes.

    Kept separate from Travel Liquidation to avoid coupling standalone Cash
    Advance workflows to Travel Request records.
    """
    global _cash_advance_liquidation_tables_ready

    if _cash_advance_liquidation_tables_ready:
        return

    try:
        CashAdvanceLiquidationHeader.__table__.create(db.engine, checkfirst=True)
        CashAdvanceLiquidationRow.__table__.create(db.engine, checkfirst=True)
        CashAdvanceLiquidationReceipt.__table__.create(db.engine, checkfirst=True)

        index_statements = [
            "CREATE INDEX IF NOT EXISTS idx_ca_liq_header_cash_advance ON cash_advance_liquidation_header (cash_advance_id)",
            "CREATE INDEX IF NOT EXISTS idx_ca_liq_header_user_status ON cash_advance_liquidation_header (user_id, status)",
            "CREATE INDEX IF NOT EXISTS idx_ca_liq_header_status_updated ON cash_advance_liquidation_header (status, updated_at)",
            "CREATE INDEX IF NOT EXISTS idx_ca_liq_header_accounting_status ON cash_advance_liquidation_header (accounting_status)",
            "CREATE INDEX IF NOT EXISTS idx_ca_liq_header_approved_by ON cash_advance_liquidation_header (approved_by_id)",
            "CREATE INDEX IF NOT EXISTS idx_ca_liq_header_rejected_by ON cash_advance_liquidation_header (rejected_by_id)",
            "CREATE INDEX IF NOT EXISTS idx_ca_liq_row_header ON cash_advance_liquidation_row (liquidation_id)",
            "CREATE INDEX IF NOT EXISTS idx_ca_liq_row_date ON cash_advance_liquidation_row (expense_date)",
            "CREATE INDEX IF NOT EXISTS idx_ca_liq_receipt_header ON cash_advance_liquidation_receipt (liquidation_id)",
            "CREATE INDEX IF NOT EXISTS idx_ca_liq_receipt_row ON cash_advance_liquidation_receipt (row_id)"
        ]

        with db.engine.begin() as connection:
            header_columns = {row[1] for row in connection.exec_driver_sql("PRAGMA table_info(cash_advance_liquidation_header)").fetchall()}
            cash_advance_liquidation_column_migrations = {
                'sent_to_accounting_at': 'ALTER TABLE cash_advance_liquidation_header ADD COLUMN sent_to_accounting_at DATETIME',
                'accounting_remarks': 'ALTER TABLE cash_advance_liquidation_header ADD COLUMN accounting_remarks TEXT',
                'completed_by_id': 'ALTER TABLE cash_advance_liquidation_header ADD COLUMN completed_by_id INTEGER',
                'completion_remarks': 'ALTER TABLE cash_advance_liquidation_header ADD COLUMN completion_remarks TEXT'
            }
            for column_name, ddl in cash_advance_liquidation_column_migrations.items():
                if column_name not in header_columns:
                    connection.exec_driver_sql(ddl)
                    print(f"[DB MIGRATION] Added cash_advance_liquidation_header.{column_name}", flush=True)
            for statement in index_statements:
                connection.exec_driver_sql(statement)
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_ca_liq_sent_to_accounting_at ON cash_advance_liquidation_header (sent_to_accounting_at)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_ca_liq_completed_by_id ON cash_advance_liquidation_header (completed_by_id)")
            connection.exec_driver_sql("CREATE INDEX IF NOT EXISTS idx_ca_liq_completed_at ON cash_advance_liquidation_header (completed_at)")

        _cash_advance_liquidation_tables_ready = True
    except Exception as table_error:
        try:
            message = str(table_error).lower()
            with db.engine.connect() as connection:
                existing_tables = {
                    row[0] for row in connection.exec_driver_sql(
                        "SELECT name FROM sqlite_master WHERE type='table'"
                    ).fetchall()
                }
            expected_tables = {
                'cash_advance_liquidation_header',
                'cash_advance_liquidation_row',
                'cash_advance_liquidation_receipt'
            }
            if 'database is locked' in message and expected_tables.issubset(existing_tables):
                print(f"[CashAdvanceLiquidation] Table ensure deferred because SQLite is locked: {table_error}", flush=True)
                _cash_advance_liquidation_tables_ready = True
                return
        except Exception:
            pass

        print(f"[CashAdvanceLiquidation] Unable to ensure tables: {table_error}", flush=True)
        raise


def cash_advance_parse_date(value):
    value = str(value or '').strip()
    if not value:
        return None
    try:
        return datetime.strptime(value, '%Y-%m-%d').date()
    except Exception:
        return None


def cash_advance_format_date(value):
    if not value:
        return ''
    try:
        return value.isoformat()
    except Exception:
        return str(value)


def cash_advance_money(value):
    try:
        return round(float(value or 0), 2)
    except Exception:
        return 0.0


def cash_advance_generate_no(record_id=None):
    today = get_manila_today().strftime('%Y%m%d')
    suffix = str(record_id or '').strip() or 'NEW'
    return f"CA-{today}-{suffix}"


def cash_advance_user_display_name(user_obj=None):
    user_obj = user_obj or current_user
    for attr in ['full_name', 'name', 'display_name', 'username']:
        value = getattr(user_obj, attr, None)
        if value:
            return str(value)
    return 'User'


def cash_advance_normalize_status(status_value):
    """Return stable display status for standalone Cash Advance."""
    status = clean_str(status_value) or 'Draft'
    known = {
        'draft': 'Draft',
        'submitted': 'Submitted',
        'approved': 'Approved',
        'rejected': 'Rejected',
        'returned': 'Rejected',
        'released': 'Released',
        'received': 'Received',
        'ready_for_liquidation': 'Ready for Liquidation',
        'ready for liquidation': 'Ready for Liquidation',
        'liquidation_draft': 'Liquidation Draft',
        'liquidation draft': 'Liquidation Draft',
        'liquidation_submitted': 'Liquidation Submitted',
        'liquidation submitted': 'Liquidation Submitted',
        'liquidation_approved': 'Liquidation Approved',
        'liquidation approved': 'Liquidation Approved',
        'liquidation_returned': 'Liquidation Returned',
        'liquidation returned': 'Liquidation Returned',
        'liquidation_completed': 'Liquidation Completed',
        'liquidation completed': 'Liquidation Completed',
        'completed': 'Completed'
    }
    return known.get(status.strip().lower().replace('-', '_'), status)


def cash_advance_requester_user(header):
    if not header or not clean_int(getattr(header, 'user_id', None)):
        return None
    return db.session.get(User, clean_int(header.user_id))


def cash_advance_requester_profile(header):
    user_obj = cash_advance_requester_user(header)
    if not user_obj:
        return None
    return getattr(user_obj, 'engineer_profile', None)


def cash_advance_requester_name(header):
    user_obj = cash_advance_requester_user(header)
    profile = getattr(user_obj, 'engineer_profile', None) if user_obj else None
    return (
        clean_str(getattr(profile, 'name', None)) or
        approval_user_display_name(user_obj) or
        clean_str(getattr(user_obj, 'username', None)) or
        'Requester'
    )


def cash_advance_notification_url(header, for_approver=False):
    if not header:
        return '/cash_advance'
    if for_approver:
        return f"/approvals?module=cash_advance&id={header.id}"
    return f"/cash_advance?cash_advance_id={header.id}"


def cash_advance_requester_signature_data(header):
    """Return the requester signature snapshot for Cash Advance forms.

    New Cash Advance submissions store a signature snapshot at submit time.
    Older approved records can still fall back to the requester's current saved
    Settings signature so Accounting handoff attachments remain usable.
    """
    if not header:
        return ''

    snapshot = clean_str(getattr(header, 'requester_signature_snapshot', None)) or ''
    if snapshot:
        return snapshot

    requester = cash_advance_requester_user(header)
    return get_user_signature_snapshot(requester) if requester else ''


def build_cash_advance_requester_signature_snapshot(header, user_obj=None, signed_at=None):
    """Capture the requester's saved signature when submitting Cash Advance."""
    user_obj = user_obj or current_user
    signed_at = signed_at or get_manila_time()
    signature_data = get_user_signature_snapshot(user_obj)
    if not signature_data:
        return None

    return {
        'requester_name_snapshot': cash_advance_requester_name(header)[:150],
        'requester_signature_snapshot': signature_data,
        'requester_signature_layout': 'signature_over_printed_name',
        'requester_signed_at': signed_at
    }


def apply_cash_advance_requester_signature_snapshot(header, user_obj=None, signed_at=None):
    """Persist the requester's signature snapshot onto a Cash Advance header."""
    snapshot = build_cash_advance_requester_signature_snapshot(header, user_obj=user_obj, signed_at=signed_at)
    if not snapshot:
        return None
    for field_name, value in snapshot.items():
        if hasattr(header, field_name):
            setattr(header, field_name, value)
    return snapshot


def cash_advance_signature_required_response(user_obj=None):
    """Return JSON if requester has no saved signature before submission."""
    target = user_obj or current_user
    if get_user_signature_snapshot(target):
        return None

    message = (
        'Saved signature is required before submitting Cash Advance. '
        'Go to Settings -> My Signature, save your signature, then submit again.'
    )
    return jsonify({
        'success': False,
        'status': 'error',
        'error': message,
        'message': message,
        'requires_signature': True,
        'signature_required': True,
        'settings_target': 'my_signature'
    }), 400


def cash_advance_email_context(header):
    """Build common readable Cash Advance email fields."""
    requester = cash_advance_requester_user(header)
    requester_name = cash_advance_requester_name(header)
    request_no = clean_str(getattr(header, 'cash_advance_no', None)) or cash_advance_generate_no(getattr(header, 'id', None))
    amount = cash_advance_money(getattr(header, 'amount_requested', 0))
    approved_amount = cash_advance_money(getattr(header, 'approved_amount', 0) or getattr(header, 'amount_requested', 0))
    needed_date = getattr(header, 'needed_date', None)
    request_date = getattr(header, 'request_date', None)

    def date_label(value):
        if not value:
            return 'Not specified'
        try:
            return value.strftime('%B %-d, %Y') if os.name != 'nt' else value.strftime('%B %#d, %Y')
        except Exception:
            return str(value)

    return {
        'request_no': request_no,
        'requester_name': requester_name,
        'requester_username': clean_str(getattr(requester, 'username', None)) or '',
        'amount_label': f"PHP {amount:,.2f}",
        'approved_amount_label': f"PHP {approved_amount:,.2f}",
        'needed_date': date_label(needed_date),
        'request_date': date_label(request_date),
        'liquidation_days': int(getattr(header, 'liquidation_days', None) or 30),
        'purpose': clean_str(getattr(header, 'purpose', None)) or 'No purpose entered.',
        'status': cash_advance_normalize_status(getattr(header, 'status', None)),
        'system_link': globals().get('TRAVEL_REQUEST_SYSTEM_LINK', 'Medical Service SMS')
    }


def format_cash_advance_notification_email(action_label, header, actor_user=None, remarks=''):
    """Return subject/text/html for Cash Advance lifecycle notification email."""
    ctx = cash_advance_email_context(header)
    actor_name = universal_approval_actor_name(actor_user) if actor_user else ctx['requester_name']
    action_key = (clean_str(action_label) or 'updated').strip().lower()
    action_remarks = clean_str(remarks) or clean_str(getattr(header, 'approval_remarks', None)) or ''

    subject_map = {
        'submitted': f"Cash Advance Awaiting Approval - {ctx['request_no']}",
        'approved': f"Cash Advance Approved - {ctx['request_no']}",
        'rejected': f"Cash Advance Rejected - {ctx['request_no']}",
        'returned': f"Cash Advance Returned - {ctx['request_no']}"
    }
    title_map = {
        'submitted': 'Cash Advance Awaiting Approval',
        'approved': 'Cash Advance Approved',
        'rejected': 'Cash Advance Rejected / Returned',
        'returned': 'Cash Advance Returned for Correction'
    }
    actor_label_map = {
        'submitted': 'Submitted By',
        'approved': 'Approved By',
        'rejected': 'Rejected / Returned By',
        'returned': 'Returned By'
    }
    note_map = {
        'submitted': 'A Cash Advance request has been submitted and is awaiting your approval.',
        'approved': 'Your Cash Advance request has been approved by the manager.',
        'rejected': 'Your Cash Advance request was rejected / returned for correction. Please review the remarks and update the request if needed.',
        'returned': 'Your Cash Advance request was returned for correction. Please review the remarks and update the request if needed.'
    }

    subject = subject_map.get(action_key, f"Cash Advance Update - {ctx['request_no']}")
    title = title_map.get(action_key, 'Cash Advance Update')
    actor_label = actor_label_map.get(action_key, 'Updated By')
    action_note = note_map.get(action_key, 'Please open the Medical Service system for full details.')

    amount_label = ctx['approved_amount_label'] if action_key == 'approved' else ctx['amount_label']
    amount_caption = 'Approved Amount' if action_key == 'approved' else 'Requested Amount'

    text_lines = [
        title,
        '',
        action_note,
        '',
        f"Cash Advance No.: {ctx['request_no']}",
        f"Requester: {ctx['requester_name']}",
        f"Request Date: {ctx['request_date']}",
        f"Date Needed: {ctx['needed_date']}",
        f"{amount_caption}: {amount_label}",
        f"Liquidation Days: {ctx['liquidation_days']}",
        f"Purpose: {ctx['purpose']}",
        f"Status: {ctx['status']}",
        f"{actor_label}: {actor_name}",
    ]
    if action_remarks:
        text_lines.append(f"Remarks: {action_remarks}")
    text_lines.extend([
        '',
        'Please open the Medical Service system for full details.',
        '',
        f"System Link: {ctx['system_link']}",
        '',
        'Medical Service SMS',
        'Shimadzu Philippines Corporation'
    ])
    text_body = "\n".join(text_lines)

    rows = [
        ('Cash Advance No.', ctx['request_no']),
        ('Requester', ctx['requester_name']),
        ('Request Date', ctx['request_date']),
        ('Date Needed', ctx['needed_date']),
        (amount_caption, amount_label),
        ('Liquidation Days', ctx['liquidation_days']),
        ('Purpose', ctx['purpose']),
        ('Status', ctx['status']),
        (actor_label, actor_name)
    ]
    if action_remarks:
        rows.append(('Remarks', action_remarks))

    detail_rows = ''.join(
        f"<tr><td style='padding:8px 10px;font-weight:700;border-bottom:1px solid #e5e7eb;color:#334155;vertical-align:top;'>{html.escape(str(label or ''))}</td>"
        f"<td style='padding:8px 10px;border-bottom:1px solid #e5e7eb;color:#0f172a;vertical-align:top;'>{html.escape(str(value or ''))}</td></tr>"
        for label, value in rows
    )

    html_body = f"""
    <div style="font-family:Arial,sans-serif;color:#111827;line-height:1.5;">
        <h2 style="margin:0 0 12px;color:#0f172a;">{html.escape(title)}</h2>
        <p style="margin:0 0 14px;color:#374151;">{html.escape(action_note)}</p>
        <table style="border-collapse:collapse;border:1px solid #e5e7eb;min-width:420px;">
            {detail_rows}
        </table>
        <p style="margin-top:16px;color:#374151;">Please open the Medical Service system for full details.</p>
        <p style="margin-top:8px;color:#374151;">
            <strong>System Link:</strong><br>
            <a href="{html.escape(ctx['system_link'])}" style="color:#0d6efd;text-decoration:none;font-weight:700;">{html.escape(ctx['system_link'])}</a>
        </p>
        <p style="margin-top:16px;color:#374151;">
            Regards,<br>
            Medical Service SMS<br>
            Shimadzu Philippines Corporation
        </p>
    </div>
    """
    return subject, text_body, html_body


def send_cash_advance_notification_email_async(app_obj, recipient_user_ids, cash_advance_id, action_label, actor_user_id=None, remarks=''):
    """Send Cash Advance lifecycle notification email in the background."""
    recipient_ids = [clean_int(item) for item in (recipient_user_ids or []) if clean_int(item)]
    if not recipient_ids:
        return

    def worker():
        with app_obj.app_context():
            try:
                ensure_cash_advance_tables()
                header = db.session.get(CashAdvanceHeader, clean_int(cash_advance_id))
                if not header:
                    print(f"[EMAIL] Cash Advance notification skipped: record #{cash_advance_id} not found.", flush=True)
                    return

                recipients = [db.session.get(User, user_id) for user_id in recipient_ids]
                recipients = [user for user in recipients if user]
                recipient_emails = get_users_email_addresses_for_notifications(recipients)
                if not recipient_emails:
                    print("[EMAIL] Cash Advance notification skipped: no recipient email addresses.", flush=True)
                    return

                actor_user = db.session.get(User, clean_int(actor_user_id)) if actor_user_id else None
                subject, text_body, html_body = format_cash_advance_notification_email(
                    action_label,
                    header,
                    actor_user=actor_user,
                    remarks=remarks
                )
                sent, message = send_email_notification(recipient_emails, subject, text_body, html_body)
                print(f"[EMAIL] Cash Advance notification {action_label}: sent={sent} | {message}", flush=True)
            except Exception as email_error:
                print(f"[EMAIL] Cash Advance notification worker failed: {email_error}", flush=True)

    email_thread = threading.Thread(target=worker, daemon=True)
    email_thread.start()
    print(f"[EMAIL] Cash Advance notification background email queued: {action_label}", flush=True)




def mask_email_for_log(email_addr):
    """Mask an email address for safe console diagnostics."""
    email_addr = clean_str(email_addr)
    if not email_addr or '@' not in email_addr:
        return ''
    name, domain = email_addr.split('@', 1)
    if len(name) <= 2:
        masked_name = name[:1] + '*'
    else:
        masked_name = name[:2] + '*' * max(1, len(name) - 2)
    return f"{masked_name}@{domain}"


def get_active_email_recipients_by_exact_group_key(group_key):
    """Return active emails for a raw group key without requiring it in the catalog."""
    ensure_email_recipient_setting_table()
    group_key = (clean_str(group_key) or '').strip().lower()
    if not group_key:
        return []
    recipients = (
        EmailRecipientSetting.query
        .filter(func.lower(EmailRecipientSetting.group_key) == group_key)
        .filter(EmailRecipientSetting.is_active == True)
        .order_by(EmailRecipientSetting.sort_order.asc(), EmailRecipientSetting.email.asc())
        .all()
    )
    return normalize_email_list([recipient.email for recipient in recipients])


def get_cash_advance_accounting_recipient_emails():
    """Return Settings-managed Accounting recipients for approved standalone Cash Advances.

    Primary source is the dedicated Cash Advance Accounting group. The alias pass
    covers early test data that may have been saved under temporary group keys
    while this module was being introduced. It intentionally does not fall back
    to Travel Request Accounting because standalone Cash Advance now has its own
    accounting recipient route.
    """
    primary = get_active_email_recipients_by_group('cash_advance_accounting')
    if primary:
        return primary

    alias_emails = []
    for alias_key in (
        'cash_advance',
        'cash_advance_email',
        'cash_advance_accounting_email',
        'cash_advance_accounting_recipients',
        'standalone_cash_advance_accounting'
    ):
        alias_emails.extend(get_active_email_recipients_by_exact_group_key(alias_key))

    return normalize_email_list(alias_emails)


def cash_advance_accounting_recipient_debug_counts():
    """Return safe recipient diagnostics for console/API troubleshooting."""
    ensure_email_recipient_setting_table()
    output = {}
    group_keys = [
        'cash_advance_accounting',
        'cash_advance_release',
        'cash_advance',
        'cash_advance_email',
        'cash_advance_accounting_email',
        'cash_advance_accounting_recipients',
        'standalone_cash_advance_accounting',
        'travel_accounting',
        'reimbursement_accounting'
    ]
    for group_key in group_keys:
        emails = get_active_email_recipients_by_exact_group_key(group_key)
        output[group_key] = {
            'active_count': len(emails),
            'masked_emails': [mask_email_for_log(email_addr) for email_addr in emails if mask_email_for_log(email_addr)]
        }
    return output


def cash_advance_email_route_for_header(header):
    """Return the Settings recipient group for approved Cash Advance handoff."""
    amount = cash_advance_money(getattr(header, 'approved_amount', 0) or getattr(header, 'amount_requested', 0))
    if amount > 10000:
        group_key = 'cash_advance_accounting'
    else:
        group_key = 'cash_advance_release'
    group_meta = EMAIL_RECIPIENT_GROUPS.get(group_key, {})
    return {
        'group_key': group_key,
        'group_label': group_meta.get('label', group_key),
        'amount': amount,
        'threshold': 10000,
        'package_label': f"{group_meta.get('label', 'Cash Advance')} form handoff",
        'attachment_label': 'Request for Cash Advance Form PDF'
    }


def get_cash_advance_handoff_recipient_emails(header):
    route = cash_advance_email_route_for_header(header)
    return get_active_email_recipients_by_group(route['group_key']), route


def cash_advance_accounting_settings_warning_payload(route=None):
    """Warning payload used when no Cash Advance handoff recipients are configured."""
    can_manage = bool(is_superadmin_user())
    route = route or cash_advance_email_route_for_header(None)
    group_label = route.get('group_label') or 'Cash Advance recipients'
    message = f'Cash Advance was approved, but no handoff email was sent because Settings -> Email Recipients -> {group_label} has no active email address.'
    return {
        'enabled': True,
        'type': f"missing_{route.get('group_key') or 'cash_advance'}_recipients",
        'title': f'{group_label} Email Recipients Missing',
        'message': message,
        'settings_url': '/settings?section=email-recipients' if can_manage else '',
        'can_open_settings': can_manage
    }


def cash_advance_accounting_subject_context(header, approved_by_user=None):
    """Build placeholder context for the Settings-managed Cash Advance Accounting subject."""
    ctx = cash_advance_email_context(header)
    approved_by = universal_approval_actor_name(approved_by_user) if approved_by_user else clean_str(getattr(header, 'approval_name_snapshot', None)) or ''
    return {
        'cash_advance_no': ctx.get('request_no') or '',
        'requester': ctx.get('requester_name') or 'Requester',
        'request_date': ctx.get('request_date') or '',
        'needed_date': ctx.get('needed_date') or '',
        'requested_amount': f"{cash_advance_money(getattr(header, 'amount_requested', 0)):,.2f}",
        'approved_amount': f"{cash_advance_money(getattr(header, 'approved_amount', 0) or getattr(header, 'amount_requested', 0)):,.2f}",
        'approved_by': approved_by,
        'liquidation_days': int(getattr(header, 'liquidation_days', None) or 30)
    }


