def cash_advance_accounting_pdf_filename(header):
    """Return a safe filename for the official Cash Advance form attachment."""
    ctx = cash_advance_email_context(header)
    request_no = clean_str(ctx.get('request_no')) or f"CA-{getattr(header, 'id', '')}"
    requester = clean_str(ctx.get('requester_name')) or 'Requester'
    safe_name = secure_filename(f"Request_for_Cash_Advance_{request_no}_{requester}.pdf")
    return safe_name or f"Request_for_Cash_Advance_CA-{getattr(header, 'id', '')}.pdf"


def find_cash_advance_form_template_path():
    """Return the official Request for Cash Advance form template path.

    The system expects the official template to be stored in the project forms
    folder. Several fallback locations are checked so local development and
    Railway deployments can use the same backend file.
    """
    template_names = [
        'Request for Cash Advance Form.pdf',
        'REQUEST FOR CASH ADVANCE FORM.pdf',
        'request for cash advance form.pdf',
        'Cash Advance Form.pdf',
        'CASH ADVANCE FORM.pdf'
    ]
    folders = [
        os.path.join(basedir, 'forms'),
        os.path.join(basedir, 'static', 'forms'),
        os.path.join(basedir, 'static', 'templates'),
        basedir,
        os.path.join('/data', 'forms'),
        os.path.join('/data', 'templates'),
        '/data'
    ]

    for folder in folders:
        for template_name in template_names:
            candidate = os.path.join(folder, template_name)
            if os.path.isfile(candidate):
                return candidate

    lowered_names = {name.lower() for name in template_names}
    for folder in folders:
        try:
            for filename in os.listdir(folder):
                if filename.lower() in lowered_names:
                    candidate = os.path.join(folder, filename)
                    if os.path.isfile(candidate):
                        return candidate
        except Exception:
            continue

    return ''


def cash_advance_amount_to_words_php(amount):
    """Convert a Peso amount into a compact official-form amount-in-words label."""
    try:
        value = round(float(amount or 0), 2)
    except Exception:
        value = 0.0

    pesos = int(value)
    centavos = int(round((value - pesos) * 100))
    if centavos == 100:
        pesos += 1
        centavos = 0

    ones = [
        'zero', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight', 'nine',
        'ten', 'eleven', 'twelve', 'thirteen', 'fourteen', 'fifteen', 'sixteen',
        'seventeen', 'eighteen', 'nineteen'
    ]
    tens = ['', '', 'twenty', 'thirty', 'forty', 'fifty', 'sixty', 'seventy', 'eighty', 'ninety']

    def under_thousand(n):
        words = []
        if n >= 100:
            words.append(ones[n // 100])
            words.append('hundred')
            n %= 100
        if n >= 20:
            words.append(tens[n // 10])
            n %= 10
        if 0 < n < 20:
            words.append(ones[n])
        return ' '.join(words)

    def number_words(n):
        if n == 0:
            return 'zero'
        scales = [(1_000_000_000, 'billion'), (1_000_000, 'million'), (1000, 'thousand')]
        words = []
        for scale, label in scales:
            if n >= scale:
                words.append(under_thousand(n // scale))
                words.append(label)
                n %= scale
        if n:
            words.append(under_thousand(n))
        return ' '.join(words)

    phrase = f"{number_words(pesos)} pesos"
    if centavos:
        phrase += f" and {centavos:02d}/100"
    phrase += ' only'
    return phrase.upper()


def build_cash_advance_accounting_pdf_bytes(header, approved_by_user=None, remarks=''):
    """Fill the official Request for Cash Advance PDF template for Accounting.

    F4A3D12 keeps the official PDF template as the visual source, outputs only
    one Cash Advance form copy, and stamps the saved requester and approver
    signature snapshots as images. Requester signature is captured at submit;
    approver signature is captured at approval. The approver signature and
    approver printed name are both centered on the official Approved by line.
    """
    try:
        import fitz  # PyMuPDF is used only to render the official template page.
        from io import BytesIO
        from reportlab.pdfgen import canvas
        from reportlab.pdfbase import pdfmetrics
    except Exception as pdf_import_error:
        raise RuntimeError(
            'Cash Advance official form dependencies are unavailable. Install PyMuPDF and reportlab.'
        ) from pdf_import_error

    template_path = find_cash_advance_form_template_path()
    if not template_path:
        raise FileNotFoundError(
            'Official Cash Advance template not found. Put "Request for Cash Advance Form.pdf" in the project forms folder.'
        )
    print(f"[EMAIL] Cash Advance official form template path: {template_path}", flush=True)
    print("[EMAIL] Cash Advance official form fill mode: F4A3D12 approver signature and printed name centered", flush=True)

    ctx = cash_advance_email_context(header)
    approved_by = universal_approval_actor_name(approved_by_user) if approved_by_user else clean_str(getattr(header, 'approval_name_snapshot', None)) or 'Approver'
    requested_amount = cash_advance_money(getattr(header, 'amount_requested', 0))
    requester_signature_data = cash_advance_requester_signature_data(header)
    approver_signature_data = clean_str(getattr(header, 'approval_signature_snapshot', None)) or ''
    temp_signature_paths = []

    def date_label(value):
        if not value:
            return ''
        try:
            return value.strftime('%B %d, %Y')
        except Exception:
            return str(value)

    def safe_text(value):
        # clean_str() can return None, so always normalize to ''.
        return clean_str(value) or ''

    def safe_pdf_text(value):
        # Built-in PDF fonts are WinAnsi/Latin-1. Strip unsupported glyphs rather
        # than letting the email worker fail while creating the attachment.
        text_value = safe_text(value).replace('\r', ' ').replace('\n', ' ')
        return text_value.encode('latin-1', errors='ignore').decode('latin-1', errors='ignore')

    def short_text(value, max_chars=120):
        raw = safe_pdf_text(value)
        if len(raw) <= max_chars:
            return raw
        return raw[:max_chars - 3].rstrip() + '...'

    def fit_text(value, max_width, font_name='Helvetica', font_size=9, min_size=6):
        text_value = safe_pdf_text(value)
        size = float(font_size)
        while size > min_size and pdfmetrics.stringWidth(text_value, font_name, size) > max_width:
            size -= 0.5
        if pdfmetrics.stringWidth(text_value, font_name, size) <= max_width:
            return text_value, size
        while text_value and pdfmetrics.stringWidth(text_value + '...', font_name, size) > max_width:
            text_value = text_value[:-1]
        return (text_value.rstrip() + '...' if text_value else ''), size

    def split_lines_for_width(value, widths, font_name='Helvetica', font_size=9):
        words = safe_pdf_text(value).replace('\r', ' ').replace('\n', ' ').split()
        lines = []
        for max_width in widths:
            line_words = []
            while words:
                candidate = ' '.join(line_words + [words[0]])
                if not line_words or pdfmetrics.stringWidth(candidate, font_name, font_size) <= max_width:
                    line_words.append(words.pop(0))
                else:
                    break
            lines.append(' '.join(line_words))
        if words and lines:
            remainder = ' '.join(words)
            merged = (lines[-1] + ' ' + remainder).strip()
            lines[-1], _ = fit_text(merged, widths[-1], font_name, font_size, min_size=font_size)
        return lines

    def draw_text_top(pdf_canvas, page_height, x, top, value, max_width=180, font_name='Helvetica', font_size=9):
        value, fitted_size = fit_text(value, max_width, font_name=font_name, font_size=font_size)
        if not value:
            return
        baseline_y = float(page_height) - (float(top) + (float(fitted_size) * 0.88))
        pdf_canvas.setFont(font_name, float(fitted_size))
        pdf_canvas.setFillColorRGB(0, 0, 0)
        pdf_canvas.drawString(float(x), baseline_y, value)

    def draw_centered_text_top(pdf_canvas, page_height, x, top, width, value, font_name='Helvetica', font_size=9, min_size=6):
        value, fitted_size = fit_text(value, width, font_name=font_name, font_size=font_size, min_size=min_size)
        if not value:
            return
        baseline_y = float(page_height) - (float(top) + (float(fitted_size) * 0.88))
        text_width = pdfmetrics.stringWidth(value, font_name, float(fitted_size))
        draw_x = float(x) + ((float(width) - text_width) / 2.0)
        pdf_canvas.setFont(font_name, float(fitted_size))
        pdf_canvas.setFillColorRGB(0, 0, 0)
        pdf_canvas.drawString(draw_x, baseline_y, value)

    def draw_muted_text_top(pdf_canvas, page_height, x, top, value, max_width=180, font_size=7):
        value, fitted_size = fit_text(value, max_width, font_name='Helvetica', font_size=font_size)
        if not value:
            return
        baseline_y = float(page_height) - (float(top) + (float(fitted_size) * 0.88))
        pdf_canvas.setFont('Helvetica', float(fitted_size))
        pdf_canvas.setFillColorRGB(0.25, 0.25, 0.25)
        pdf_canvas.drawString(float(x), baseline_y, value)
        pdf_canvas.setFillColorRGB(0, 0, 0)

    def signature_data_to_temp_png(signature_data, label='signature'):
        if not signature_data:
            return ''
        try:
            png_bytes = reimbursement_signature_data_url_to_png_bytes(signature_data)
            if not png_bytes:
                print(f"[CashAdvance] {label} signature skipped: invalid or empty signature data.", flush=True)
                return ''

            # Trim transparent/white padding so centering is based on the actual
            # signature strokes, not the full canvas/image bounds. This follows
            # the same practical layout intent as the reimbursement stamp: a
            # compact signature centered over the printed-name area.
            try:
                from PIL import Image, ImageChops
                image = Image.open(BytesIO(png_bytes)).convert('RGBA')
                bbox = image.getchannel('A').getbbox()
                if not bbox:
                    # Some uploaded signatures are opaque white backgrounds.
                    # Detect non-white pixels as a fallback.
                    bg = Image.new('RGBA', image.size, (255, 255, 255, 255))
                    diff = ImageChops.difference(image, bg)
                    bbox = diff.getbbox()
                if bbox:
                    pad = 4
                    left = max(bbox[0] - pad, 0)
                    top = max(bbox[1] - pad, 0)
                    right = min(bbox[2] + pad, image.size[0])
                    bottom = min(bbox[3] + pad, image.size[1])
                    image = image.crop((left, top, right, bottom))
                trimmed = BytesIO()
                image.save(trimmed, format='PNG')
                png_bytes = trimmed.getvalue()
            except Exception as trim_error:
                print(f"[CashAdvance] {label} signature trim skipped: {trim_error}", flush=True)

            with tempfile.NamedTemporaryFile(delete=False, suffix='.png') as sig_file:
                sig_file.write(png_bytes)
                sig_path = sig_file.name
            temp_signature_paths.append(sig_path)
            return sig_path
        except Exception as sig_error:
            print(f"[CashAdvance] {label} signature decode skipped: {sig_error}", flush=True)
            return ''

    requester_signature_path = signature_data_to_temp_png(requester_signature_data, 'requester')
    approver_signature_path = signature_data_to_temp_png(approver_signature_data, 'approver')

    def draw_signature_top(pdf_canvas, page_height, x, top, width, height, signature_path, label='signature'):
        if not signature_path:
            return
        try:
            from PIL import Image
            with Image.open(signature_path) as signature_image:
                image_width, image_height = signature_image.size
            if not image_width or not image_height:
                return

            box_width = float(width)
            box_height = float(height)
            fit_scale = min(box_width / float(image_width), box_height / float(image_height))
            draw_width = image_width * fit_scale
            draw_height = image_height * fit_scale
            draw_x = float(x) + ((box_width - draw_width) / 2.0)
            draw_top = float(top) + ((box_height - draw_height) / 2.0)
            draw_y = float(page_height) - draw_top - draw_height

            pdf_canvas.drawImage(
                signature_path,
                draw_x,
                draw_y,
                width=draw_width,
                height=draw_height,
                preserveAspectRatio=True,
                mask='auto'
            )
        except Exception as sig_draw_error:
            print(f"[CashAdvance] {label} signature draw skipped: {sig_draw_error}", flush=True)

    def stamp_one_form(pdf_canvas, page_height):
        request_date = date_label(getattr(header, 'request_date', None)) or ctx.get('request_date') or ''
        amount_number = f"PHP {requested_amount:,.2f}"
        amount_words = cash_advance_amount_to_words_php(requested_amount)
        liquidation_days = f"{int(getattr(header, 'liquidation_days', None) or 30)} days"
        purpose = short_text(ctx.get('purpose') or '', 220)
        purpose_lines = split_lines_for_width(purpose, [382, 388], font_size=8.5)

        # Small system reference added in whitespace so Accounting can match the
        # official printed form to the SMS record. This is not a signature.
        draw_muted_text_top(pdf_canvas, page_height, 90, 98, f"System Ref.: {ctx.get('request_no') or ''}", max_width=220, font_size=7)

        draw_text_top(pdf_canvas, page_height, 421, 115.3, request_date, max_width=96, font_size=9)
        draw_text_top(pdf_canvas, page_height, 236, 134.3, ctx.get('requester_name') or '', max_width=150, font_size=9)
        # Stamp requester signature image captured when the Cash Advance was submitted.
        draw_signature_top(pdf_canvas, page_height, 451, 124.5, 72, 22, requester_signature_path, 'requester')

        draw_text_top(pdf_canvas, page_height, 190, 153.2, amount_words, max_width=329, font_size=8.5)
        draw_text_top(pdf_canvas, page_height, 104, 172.2, amount_number, max_width=148, font_size=9)

        draw_text_top(pdf_canvas, page_height, 137, 191.2, purpose_lines[0] if len(purpose_lines) > 0 else '', max_width=383, font_size=8.5)
        draw_text_top(pdf_canvas, page_height, 132, 210.2, purpose_lines[1] if len(purpose_lines) > 1 else '', max_width=390, font_size=8.5)
        draw_text_top(pdf_canvas, page_height, 229, 229.2, liquidation_days, max_width=292, font_size=9)

        # Voucher/check/petty cash release fields remain blank for Accounting.
        # Stamp approver signature image captured when the manager approved.
        # D12: center BOTH the signature and the approver printed name on the
        # official Approved by underline. The name stays on the line; the
        # signature sits close above it, using the same center point.
        approved_line_x = 157
        approved_line_width = 150
        draw_signature_top(pdf_canvas, page_height, approved_line_x, 388.5, approved_line_width, 13, approver_signature_path, 'approver')
        draw_centered_text_top(pdf_canvas, page_height, approved_line_x, 400.0, approved_line_width, approved_by, font_size=8.5)
        # Approval remarks stay in the email/audit trail, not on this official form.

    src_doc = None
    bg_png_path = ''
    try:
        src_doc = fitz.open(template_path)
        if src_doc.page_count < 1:
            raise ValueError('Official Cash Advance template has no pages.')
        src_page = src_doc[0]
        try:
            if src_page.mediabox and (abs(src_page.rect.height - src_page.mediabox.height) > 1 or abs(src_page.rect.width - src_page.mediabox.width) > 1):
                src_page.set_cropbox(src_page.mediabox)
        except Exception as crop_error:
            print(f"[CashAdvance] Official template cropbox normalize skipped: {crop_error}", flush=True)

        page_width = float(src_page.rect.width)
        full_page_height = float(src_page.rect.height)
        if full_page_height >= 900:
            # The official SPC template is about 1008pt tall and contains two
            # copies. The first usable copy ends before the dashed separator and
            # before the second header starts, around 470pt from the top.
            single_form_height = min(full_page_height, 470.0)
        else:
            # Defensive fallback for unusual/cropped versions of the same form.
            single_form_height = min(full_page_height, max(full_page_height / 2.0, 420.0))

        # Render only the upper official form copy. The original PDF template has
        # a duplicate copy below it; that lower copy must not appear in the email
        # attachment.
        clip_rect = fitz.Rect(0, 0, page_width, single_form_height)
        pix = src_page.get_pixmap(matrix=fitz.Matrix(2, 2), clip=clip_rect, alpha=False)
        with tempfile.NamedTemporaryFile(delete=False, suffix='.png') as bg_png_file:
            bg_png_path = bg_png_file.name
        pix.save(bg_png_path)
    except Exception as render_error:
        print(f"[CashAdvance] Official template render failed before stamping: {render_error}", flush=True)
        raise
    finally:
        try:
            if src_doc is not None:
                src_doc.close()
        except Exception:
            pass

    try:
        packet = BytesIO()
        pdf_canvas = canvas.Canvas(packet, pagesize=(page_width, single_form_height), pageCompression=1)
        pdf_canvas.drawImage(bg_png_path, 0, 0, width=page_width, height=single_form_height, preserveAspectRatio=False, mask=None)
        stamp_one_form(pdf_canvas, single_form_height)
        pdf_canvas.showPage()
        pdf_canvas.save()
        pdf_bytes = packet.getvalue()
        if not pdf_bytes:
            raise RuntimeError('Official Cash Advance form attachment generated empty PDF bytes.')
        print(f"[EMAIL] Cash Advance official signed single-form attachment generated: {len(pdf_bytes)} bytes", flush=True)
        return pdf_bytes
    except Exception as official_form_error:
        print(f"[CashAdvance] Official Request for Cash Advance template fill failed: {official_form_error}", flush=True)
        raise
    finally:
        try:
            if bg_png_path and os.path.exists(bg_png_path):
                os.unlink(bg_png_path)
        except Exception:
            pass
        for sig_path in temp_signature_paths:
            try:
                if sig_path and os.path.exists(sig_path):
                    os.unlink(sig_path)
            except Exception:
                pass

def send_cash_advance_accounting_email_async(app_obj, cash_advance_id, accounting_emails, approved_by_user_id=None, remarks=''):
    """Send approved standalone Cash Advance handoff email to Settings-managed Accounting recipients with official form attachment."""
    recipient_emails = normalize_email_list(accounting_emails)
    if not recipient_emails:
        print("[EMAIL] Cash Advance accounting handoff not queued: no active Cash Advance Accounting recipients.", flush=True)
        return False

    print(
        f"[EMAIL] Cash Advance accounting handoff queue requested: record={cash_advance_id} recipients={len(recipient_emails)} "
        f"masked={', '.join([mask_email_for_log(email_addr) for email_addr in recipient_emails if mask_email_for_log(email_addr)])}",
        flush=True
    )

    def worker():
        temp_pdf_path = ''
        header = None
        with app_obj.app_context():
            try:
                ensure_cash_advance_tables()
                header = db.session.get(CashAdvanceHeader, clean_int(cash_advance_id))
                if not header:
                    print(f"[EMAIL] Cash Advance accounting handoff skipped: record #{cash_advance_id} not found.", flush=True)
                    return

                approver = db.session.get(User, clean_int(approved_by_user_id)) if approved_by_user_id else None
                subject, text_body, html_body = format_cash_advance_accounting_email(
                    header,
                    approved_by_user=approver,
                    remarks=remarks
                )

                pdf_filename = cash_advance_accounting_pdf_filename(header)
                pdf_bytes = build_cash_advance_accounting_pdf_bytes(
                    header,
                    approved_by_user=approver,
                    remarks=remarks
                )
                with tempfile.NamedTemporaryFile(delete=False, suffix='.pdf') as temp_pdf:
                    temp_pdf.write(pdf_bytes)
                    temp_pdf_path = temp_pdf.name

                requester_copy_emails = get_requester_accounting_copy_emails(header, recipient_emails)
                sent, message = send_email_with_attachments(
                    recipient_emails,
                    subject,
                    text_body,
                    html_body,
                    attachments=[{
                        'display_name': pdf_filename,
                        'filename': pdf_filename,
                        'path': temp_pdf_path
                    }],
                    cc_emails=requester_copy_emails
                )
                print(f"[EMAIL] Cash Advance accounting handoff with official form attachment: sent={sent} | {message}", flush=True)

                if sent:
                    header.sent_to_accounting_at = get_manila_time()
                    header.accounting_status = 'Sent to Accounting'
                    header.accounting_remarks = None
                    header.updated_at = get_manila_time()
                    db.session.add(ActivityLog(
                        user=universal_approval_actor_name(approver) if approver else 'System',
                        action=f"Sent completed Request for Cash Advance form to Accounting: {header.cash_advance_no or f'CA-{header.id}'}"
                    ))
                    db.session.commit()
                else:
                    header.accounting_status = 'Accounting Email Failed'
                    header.accounting_remarks = message or 'Unable to send Cash Advance accounting email with official form attachment.'
                    header.updated_at = get_manila_time()
                    db.session.add(ActivityLog(
                        user=universal_approval_actor_name(approver) if approver else 'System',
                        action=f"Failed to send Request for Cash Advance form to Accounting: {header.cash_advance_no or f'CA-{header.id}'}"
                    ))
                    db.session.commit()
            except Exception as email_error:
                db.session.rollback()
                print(f"[EMAIL] Cash Advance accounting handoff worker failed: {email_error}", flush=True)
                try:
                    if header:
                        header.accounting_status = 'Accounting Email Failed'
                        header.accounting_remarks = f"Cash Advance accounting form email failed: {email_error}"[:500]
                        header.updated_at = get_manila_time()
                        db.session.add(header)
                        db.session.commit()
                except Exception:
                    db.session.rollback()
            finally:
                if temp_pdf_path:
                    try:
                        os.unlink(temp_pdf_path)
                    except Exception:
                        pass

    email_thread = threading.Thread(target=worker, daemon=True)
    email_thread.start()
    print("[EMAIL] Cash Advance accounting handoff background email queued.", flush=True)
    return True


def cash_advance_to_dict(header, include_audit=False):
    if not header:
        return {}

    requester = cash_advance_requester_user(header)
    requester_profile = getattr(requester, 'engineer_profile', None) if requester else None
    approver = db.session.get(User, clean_int(getattr(header, 'approved_by_id', None))) if clean_int(getattr(header, 'approved_by_id', None)) else None
    rejector = db.session.get(User, clean_int(getattr(header, 'rejected_by_id', None))) if clean_int(getattr(header, 'rejected_by_id', None)) else None
    status = cash_advance_normalize_status(getattr(header, 'status', None))
    assigned_approvers = get_assigned_approvers_for_requester(getattr(header, 'user_id', None), 'cash_advance')

    payload = {
        'id': header.id,
        'cash_advance_id': header.id,
        'cash_advance_no': header.cash_advance_no or cash_advance_generate_no(header.id),
        'request_no': header.cash_advance_no or cash_advance_generate_no(header.id),
        'user_id': header.user_id,
        'requester_user_id': header.user_id,
        'requester_name': cash_advance_requester_name(header),
        'requested_by': cash_advance_requester_name(header),
        'requester_name_snapshot': getattr(header, 'requester_name_snapshot', '') or '',
        'requester_signature_snapshot': getattr(header, 'requester_signature_snapshot', '') or '',
        'requester_signature_layout': getattr(header, 'requester_signature_layout', '') or '',
        'requester_signed_at': header.requester_signed_at.isoformat() if getattr(header, 'requester_signed_at', None) else '',
        'username': clean_str(getattr(requester, 'username', None)) or '',
        'engineer_id': clean_int(getattr(requester_profile, 'id', None)),
        'engineer_name': clean_str(getattr(requester_profile, 'name', None)) or '',
        'assigned_approver_user_id': getattr(get_assigned_approver_for_requester(getattr(header, 'user_id', None), 'cash_advance'), 'id', None),
        'assigned_approver_name': approval_user_display_name(get_assigned_approver_for_requester(getattr(header, 'user_id', None), 'cash_advance')),
        'assigned_approvers': [approval_user_to_dict(user) for user in assigned_approvers],
        'assigned_approver_names': [approval_user_display_name(user) for user in assigned_approvers],
        'request_date': cash_advance_format_date(header.request_date),
        'needed_date': cash_advance_format_date(header.needed_date),
        'purpose': header.purpose or '',
        'amount_requested': cash_advance_money(header.amount_requested),
        'amount': cash_advance_money(header.amount_requested),
        'approved_amount': cash_advance_money(getattr(header, 'approved_amount', 0) or header.amount_requested),
        'grand_total': cash_advance_money(header.amount_requested),
        'liquidation_days': int(header.liquidation_days or 30),
        'status': status,
        'submitted_at': header.submitted_at.isoformat() if getattr(header, 'submitted_at', None) else '',
        'approved_at': header.approved_at.isoformat() if getattr(header, 'approved_at', None) else '',
        'approved_by_id': clean_int(getattr(header, 'approved_by_id', None)),
        'approved_by': approval_user_display_name(approver) if approver else '',
        'rejected_at': header.rejected_at.isoformat() if getattr(header, 'rejected_at', None) else '',
        'rejected_by_id': clean_int(getattr(header, 'rejected_by_id', None)),
        'rejected_by': approval_user_display_name(rejector) if rejector else '',
        'approval_remarks': clean_str(getattr(header, 'approval_remarks', None)) or '',
        'approval_action': getattr(header, 'approval_action', '') or '',
        'approval_name_snapshot': getattr(header, 'approval_name_snapshot', '') or '',
        'approval_title_snapshot': getattr(header, 'approval_title_snapshot', '') or '',
        'approval_signature_snapshot': getattr(header, 'approval_signature_snapshot', '') or '',
        'approval_signature_layout': getattr(header, 'approval_signature_layout', '') or '',
        'approval_signed_at': header.approval_signed_at.isoformat() if getattr(header, 'approval_signed_at', None) else '',
        'accounting_status': clean_str(getattr(header, 'accounting_status', None)) or '',
        'sent_to_accounting_at': header.sent_to_accounting_at.isoformat() if getattr(header, 'sent_to_accounting_at', None) else '',
        'accounting_remarks': clean_str(getattr(header, 'accounting_remarks', None)) or '',
        'released_at': header.released_at.isoformat() if getattr(header, 'released_at', None) else '',
        'released_by_id': clean_int(getattr(header, 'released_by_id', None)),
        'received_at': header.received_at.isoformat() if getattr(header, 'received_at', None) else '',
        'received_by_id': clean_int(getattr(header, 'received_by_id', None)),
        'ready_for_liquidation_at': header.ready_for_liquidation_at.isoformat() if getattr(header, 'ready_for_liquidation_at', None) else '',
        'payment_method': clean_str(getattr(header, 'payment_method', None)) or '',
        'payment_reference': clean_str(getattr(header, 'payment_reference', None)) or '',
        'payment_remarks': clean_str(getattr(header, 'payment_remarks', None)) or '',
        'paid_at': header.received_at.isoformat() if getattr(header, 'received_at', None) else '',
        'paid_at_label': header.received_at.strftime('%m/%d/%Y %I:%M %p') if getattr(header, 'received_at', None) else '',
        'created_at': header.created_at.isoformat() if getattr(header, 'created_at', None) else '',
        'updated_at': header.updated_at.isoformat() if getattr(header, 'updated_at', None) else '',
        'editable': status in ['Draft', 'Rejected'],
        'locked': status not in ['Draft', 'Rejected'],
        'detail_url': f'/cash_advance?cash_advance_id={header.id}',
        'approval_url': f'/approvals?module=cash_advance&id={header.id}'
    }

    try:
        ensure_cash_advance_liquidation_tables()
        liquidation = CashAdvanceLiquidationHeader.query.filter_by(cash_advance_id=header.id).first()
    except Exception:
        liquidation = None
    ready_for_liquidation = bool(
        getattr(header, 'received_at', None) or
        status in {
            'Ready for Liquidation',
            'Liquidation Draft',
            'Liquidation Submitted',
            'Liquidation Approved',
            'Liquidation Returned',
            'Liquidation Completed'
        }
    )
    payload.update({
        'liquidation_id': clean_int(getattr(liquidation, 'id', None)) if liquidation else None,
        'liquidation_no': clean_str(getattr(liquidation, 'liquidation_no', None)) if liquidation else '',
        'liquidation_status': cash_advance_liquidation_normalize_status(getattr(liquidation, 'status', None)) if liquidation else '',
        'liquidation_url': f'/cash_advance_liquidation?liquidation_id={liquidation.id}' if liquidation else '',
        'can_create_liquidation': bool(ready_for_liquidation and not liquidation),
        'can_open_liquidation': bool(liquidation),
        'create_liquidation_url': f'/create_cash_advance_liquidation_draft/{header.id}' if ready_for_liquidation and not liquidation else '',
        'open_liquidation_url': f'/cash_advance_liquidation?liquidation_id={liquidation.id}' if liquidation else ''
    })

    if include_audit:
        payload['audit_trail'] = [
            universal_approval_audit_to_dict(entry)
            for entry in get_universal_approval_audit_entries('cash_advance', header.id)
        ]

    return payload

def can_user_access_cash_advance(header, user_obj=None):
    user_obj = user_obj or current_user
    if not header or not user_obj or not getattr(user_obj, 'is_authenticated', False):
        return False
    if getattr(user_obj, 'role', '') in ['superadmin', 'regional_admin']:
        return True
    return int(getattr(header, 'user_id', 0) or 0) == int(getattr(user_obj, 'id', 0) or 0)


def can_user_manage_own_cash_advance(header, user_obj=None):
    """Return True only for the requester-owned Cash Advance page workflow."""
    user_obj = user_obj or current_user
    if not header or not user_obj or not getattr(user_obj, 'is_authenticated', False):
        return False
    return int(getattr(header, 'user_id', 0) or 0) == int(getattr(user_obj, 'id', 0) or 0)


def cash_advance_add_audit(header, action, remarks=''):
    try:
        db.session.add(CashAdvanceAudit(
            cash_advance_id=header.id,
            action=action,
            remarks=remarks or '',
            created_at=get_manila_time()
        ))
    except Exception as audit_error:
        print(f"[CashAdvance] Audit skipped: {audit_error}", flush=True)


