@app.route('/add_cash_advance_liquidation_row/<int:liquidation_id>', methods=['POST'])
@app.route('/create_cash_advance_liquidation_row/<int:liquidation_id>', methods=['POST'])
@csrf.exempt
@login_required
def add_cash_advance_liquidation_row(liquidation_id):
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_cash_advance_liquidation_tables()
    liquidation = cash_advance_liquidation_get_for_requester_page(liquidation_id=liquidation_id)
    if not liquidation:
        return jsonify({'success': False, 'error': 'Cash Advance Liquidation draft not found or not accessible.'}), 404

    allowed, message = can_edit_cash_advance_liquidation(liquidation)
    if not allowed:
        return jsonify({'success': False, 'error': message}), 403

    try:
        payload = request.get_json(silent=True) or {}
        data = cash_advance_liquidation_parse_row_payload(payload)
        existing_max_sort = (
            db.session.query(func.max(CashAdvanceLiquidationRow.sort_order))
            .filter(CashAdvanceLiquidationRow.liquidation_id == liquidation.id)
            .scalar()
        ) or 0
        header = getattr(liquidation, 'cash_advance', None)
        row = CashAdvanceLiquidationRow(
            liquidation_id=liquidation.id,
            expense_date=data['expense_date'] or getattr(header, 'needed_date', None) or getattr(header, 'request_date', None) or get_manila_today(),
            expense_type=data['expense_type'],
            particulars=data['particulars'],
            branch_code=data['branch_code'],
            class_code=data['class_code'],
            dept_code=data['dept_code'],
            product_code=data['product_code'],
            planned_amount=data['planned_amount'],
            actual_amount=data['actual_amount'],
            remarks=data['remarks'],
            sort_order=data['sort_order'] if data['sort_order'] is not None else (existing_max_sort + 1),
            created_at=get_manila_time(),
            updated_at=get_manila_time()
        )
        db.session.add(row)
        db.session.flush()
        cash_advance_liquidation_recalculate_totals(liquidation)
        record_universal_approval_audit(
            'cash_advance_liquidation',
            liquidation.id,
            'row_added',
            actor_user=current_user,
            status_from=liquidation.status,
            status_to=liquidation.status,
            remarks=f"Added liquidation row: {row.particulars}",
            metadata={'cash_advance_id': liquidation.cash_advance_id, 'liquidation_no': liquidation.liquidation_no, 'row_id': row.id, 'actual_amount': row.actual_amount}
        )
        db.session.commit()
        return jsonify({
            'success': True,
            'message': 'Cash Advance Liquidation row added.',
            'row': cash_advance_liquidation_row_to_dict(row),
            'liquidation': cash_advance_liquidation_to_dict(liquidation, include_rows=True)
        })
    except Exception as exc:
        db.session.rollback()
        print(f"[CashAdvanceLiquidation] Add row failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to add Cash Advance Liquidation row.'}), 500


