@app.route('/remove_cash_advance_liquidation_row/<int:row_id>', methods=['POST', 'DELETE'])
@csrf.exempt
@login_required
def delete_cash_advance_liquidation_row(row_id):
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_cash_advance_liquidation_tables()
    row = db.session.get(CashAdvanceLiquidationRow, clean_int(row_id))
    if not row:
        return jsonify({'success': False, 'error': 'Cash Advance Liquidation row not found.'}), 404
    liquidation = getattr(row, 'liquidation', None)
    allowed, message = can_edit_cash_advance_liquidation(liquidation)
    if not allowed:
        return jsonify({'success': False, 'error': message}), 403

    try:
        row_label = clean_str(getattr(row, 'particulars', None)) or f'Row #{row.id}'
        receipts = CashAdvanceLiquidationReceipt.query.filter_by(row_id=row.id).all()
        for receipt in receipts:
            stored_filename = os.path.basename(clean_str(getattr(receipt, 'stored_filename', None)) or '')
            if stored_filename:
                file_path = os.path.join(cash_advance_liquidation_receipt_folder(), stored_filename)
                try:
                    if os.path.exists(file_path) and os.path.isfile(file_path):
                        os.remove(file_path)
                except Exception as delete_error:
                    print(f"[CashAdvanceLiquidation] Receipt file delete skipped: {delete_error}", flush=True)
            db.session.delete(receipt)
        db.session.delete(row)
        db.session.flush()
        cash_advance_liquidation_recalculate_totals(liquidation)
        record_universal_approval_audit(
            'cash_advance_liquidation',
            liquidation.id,
            'row_deleted',
            actor_user=current_user,
            status_from=liquidation.status,
            status_to=liquidation.status,
            remarks=f"Deleted liquidation row: {row_label}",
            metadata={'cash_advance_id': liquidation.cash_advance_id, 'liquidation_no': liquidation.liquidation_no, 'deleted_row_id': clean_int(row_id)}
        )
        db.session.commit()
        return jsonify({'success': True, 'message': 'Cash Advance Liquidation row deleted.', 'liquidation': cash_advance_liquidation_to_dict(liquidation, include_rows=True)})
    except Exception as exc:
        db.session.rollback()
        print(f"[CashAdvanceLiquidation] Delete row failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to delete Cash Advance Liquidation row.'}), 500


@app.route('/upload_cash_advance_liquidation_receipt/<int:row_id>', methods=['POST'])
@app.route('/attach_cash_advance_liquidation_receipt/<int:row_id>', methods=['POST'])
@csrf.exempt
@login_required
def upload_cash_advance_liquidation_receipt(row_id):
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_cash_advance_liquidation_tables()
    row = db.session.get(CashAdvanceLiquidationRow, clean_int(row_id))
    if not row:
        return jsonify({'success': False, 'error': 'Cash Advance Liquidation row not found.'}), 404
    liquidation = getattr(row, 'liquidation', None)
    allowed, message = can_edit_cash_advance_liquidation(liquidation)
    if not allowed:
        return jsonify({'success': False, 'error': message}), 403

    file_obj = request.files.get('receipt') or request.files.get('file') or request.files.get('attachment')
    valid_receipt, receipt_error = validate_travel_liquidation_receipt_upload(file_obj)
    if not valid_receipt:
        return jsonify({'success': False, 'error': receipt_error or 'Unsupported receipt file type.'}), 400

    try:
        stored_filename, original_filename = cash_advance_liquidation_secure_receipt_filename(file_obj, row.id)
        prepared_bytes, stored_ext, content_type = reimbursement_prepare_receipt_upload_bytes(file_obj, original_filename)
        stored_filename = os.path.splitext(stored_filename)[0] + f'.{stored_ext}'
        folder = cash_advance_liquidation_receipt_folder()
        file_path = os.path.join(folder, stored_filename)
        with open(file_path, 'wb') as target_file:
            target_file.write(prepared_bytes)
        receipt = CashAdvanceLiquidationReceipt(
            liquidation_id=liquidation.id,
            row_id=row.id,
            uploaded_by_id=current_user.id,
            stored_filename=stored_filename,
            original_filename=original_filename,
            content_type=content_type or clean_str(getattr(file_obj, 'mimetype', None)) or '',
            file_size=os.path.getsize(file_path) if os.path.exists(file_path) else 0,
            created_at=get_manila_time()
        )
        db.session.add(receipt)
        liquidation.updated_at = get_manila_time()
        record_universal_approval_audit(
            'cash_advance_liquidation',
            liquidation.id,
            'receipt_uploaded',
            actor_user=current_user,
            status_from=liquidation.status,
            status_to=liquidation.status,
            remarks=f"Uploaded liquidation receipt: {original_filename}",
            metadata={'cash_advance_id': liquidation.cash_advance_id, 'liquidation_no': liquidation.liquidation_no, 'row_id': row.id, 'receipt_filename': original_filename}
        )
        db.session.commit()
        return jsonify({
            'success': True,
            'message': 'Receipt uploaded.',
            'receipt': cash_advance_liquidation_receipt_to_dict(receipt),
            'row': cash_advance_liquidation_row_to_dict(row),
            'liquidation': cash_advance_liquidation_to_dict(liquidation, include_rows=True)
        })
    except Exception as exc:
        db.session.rollback()
        print(f"[CashAdvanceLiquidation] Receipt upload failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to upload receipt.'}), 500


@app.route('/delete_cash_advance_liquidation_receipt/<int:receipt_id>', methods=['POST', 'DELETE'])
@app.route('/remove_cash_advance_liquidation_receipt/<int:receipt_id>', methods=['POST', 'DELETE'])
@csrf.exempt
@login_required
def delete_cash_advance_liquidation_receipt(receipt_id):
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_cash_advance_liquidation_tables()
    receipt = db.session.get(CashAdvanceLiquidationReceipt, clean_int(receipt_id))
    if not receipt:
        return jsonify({'success': False, 'error': 'Receipt not found.'}), 404
    row = db.session.get(CashAdvanceLiquidationRow, clean_int(getattr(receipt, 'row_id', None)))
    liquidation = getattr(row, 'liquidation', None) if row else cash_advance_liquidation_get_for_current_user(liquidation_id=getattr(receipt, 'liquidation_id', None))
    if not liquidation:
        return jsonify({'success': False, 'error': 'Liquidation draft not found or not accessible.'}), 404
    allowed, message = can_edit_cash_advance_liquidation(liquidation)
    if not allowed:
        return jsonify({'success': False, 'error': message}), 403

    original_filename = clean_str(getattr(receipt, 'original_filename', None)) or clean_str(getattr(receipt, 'stored_filename', None)) or 'receipt'
    stored_filename = os.path.basename(clean_str(getattr(receipt, 'stored_filename', None)) or '')
    file_deleted = False
    try:
        if stored_filename:
            file_path = os.path.join(cash_advance_liquidation_receipt_folder(), stored_filename)
            if os.path.exists(file_path) and os.path.isfile(file_path):
                os.remove(file_path)
                file_deleted = True
        db.session.delete(receipt)
        cash_advance_liquidation_recalculate_totals(liquidation)
        record_universal_approval_audit(
            'cash_advance_liquidation',
            liquidation.id,
            'receipt_deleted',
            actor_user=current_user,
            status_from=liquidation.status,
            status_to=liquidation.status,
            remarks=f"Deleted liquidation receipt: {original_filename}",
            metadata={'cash_advance_id': liquidation.cash_advance_id, 'liquidation_no': liquidation.liquidation_no, 'receipt_id': clean_int(receipt_id), 'file_deleted': file_deleted}
        )
        db.session.commit()
        return jsonify({'success': True, 'message': 'Receipt deleted.', 'deleted_receipt_id': clean_int(receipt_id), 'file_deleted': file_deleted, 'liquidation': cash_advance_liquidation_to_dict(liquidation, include_rows=True)})
    except Exception as exc:
        db.session.rollback()
        print(f"[CashAdvanceLiquidation] Receipt delete failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to delete receipt.'}), 500


