@app.route('/download_cash_advance_liquidation_receipt/<int:receipt_id>')
@login_required
def download_cash_advance_liquidation_receipt(receipt_id):
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_cash_advance_liquidation_tables()
    receipt = db.session.get(CashAdvanceLiquidationReceipt, clean_int(receipt_id))
    if not receipt:
        return redirect(url_for('accounting_center_page'))
    liquidation = cash_advance_liquidation_get_for_current_user(liquidation_id=getattr(receipt, 'liquidation_id', None))
    if not liquidation:
        return redirect(url_for('accounting_center_page'))
    file_path = os.path.join(cash_advance_liquidation_receipt_folder(), os.path.basename(clean_str(getattr(receipt, 'stored_filename', None)) or ''))
    if not os.path.exists(file_path):
        return redirect(url_for('accounting_center_page'))
    filename = clean_str(getattr(receipt, 'original_filename', None)) or os.path.basename(file_path)
    force_download = (request.args.get('force_download') or request.args.get('download') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
    response = send_file(file_path, as_attachment=bool(force_download), download_name=filename, mimetype=cash_advance_liquidation_receipt_mimetype(receipt, file_path), max_age=0)
    if not force_download:
        return force_inline_file_response(response, filename)
    return response


@app.route('/submit_cash_advance_liquidation/<int:liquidation_id>', methods=['POST'])
@app.route('/submit_cash_advance_liquidation_for_approval/<int:liquidation_id>', methods=['POST'])
@csrf.exempt
@login_required
def submit_cash_advance_liquidation(liquidation_id):
    denial = require_accounting_center_access()
    if denial:
        return denial

    ensure_cash_advance_tables()
    ensure_cash_advance_liquidation_tables()
    ensure_system_notification_table()

    liquidation = cash_advance_liquidation_get_for_requester_page(liquidation_id=liquidation_id)
    if not liquidation:
        return jsonify({'success': False, 'error': 'Cash Advance Liquidation draft not found or not accessible.'}), 404
    allowed, message = can_edit_cash_advance_liquidation(liquidation)
    if not allowed:
        return jsonify({'success': False, 'error': message}), 403

    header = getattr(liquidation, 'cash_advance', None)
    if not header:
        return jsonify({'success': False, 'error': 'Linked Cash Advance request was not found.'}), 404
    if not can_current_user_manage_my_accounting_record(header):
        return jsonify({'success': False, 'error': 'You can only submit liquidation for your own Cash Advance request.'}), 403

    rows = CashAdvanceLiquidationRow.query.filter_by(liquidation_id=liquidation.id).all()
    if not rows:
        return jsonify({'success': False, 'error': 'Please add at least one actual expense row before submitting liquidation.'}), 400

    try:
        now = get_manila_time()
        previous_liquidation_status = cash_advance_liquidation_normalize_status(getattr(liquidation, 'status', None))
        previous_cash_status = cash_advance_normalize_status(getattr(header, 'status', None))
        request_label = cash_advance_liquidation_request_label(header)
        liquidation_label = clean_str(getattr(liquidation, 'liquidation_no', None)) or f'CAL-{liquidation.id}'

        cash_advance_liquidation_recalculate_totals(liquidation)
        row_count = CashAdvanceLiquidationRow.query.filter_by(liquidation_id=liquidation.id).count()
        receipt_count = CashAdvanceLiquidationReceipt.query.filter_by(liquidation_id=liquidation.id).count()

        liquidation.status = 'Submitted'
        liquidation.accounting_status = 'Submitted for Approval'
        liquidation.submitted_at = now
        liquidation.approved_at = None
        liquidation.approved_by_id = None
        liquidation.rejected_at = None
        liquidation.rejected_by_id = None
        liquidation.approval_remarks = None
        clear_approval_signature_snapshot(liquidation)
        liquidation.updated_at = now

        header.status = 'Liquidation Submitted'
        header.accounting_status = 'Liquidation Submitted'
        header.updated_at = now

        record_universal_approval_audit(
            'cash_advance',
            header.id,
            'liquidation_submitted',
            actor_user=current_user,
            status_from=previous_cash_status,
            status_to='Liquidation Submitted',
            remarks='Submitted standalone Cash Advance liquidation for manager review.',
            metadata={
                'cash_advance_id': header.id,
                'cash_advance_no': request_label,
                'liquidation_id': liquidation.id,
                'liquidation_no': liquidation_label,
                'liquidation_status_from': previous_liquidation_status,
                'liquidation_status_to': 'Submitted',
                'cash_advance_amount': cash_advance_liquidation_money(getattr(liquidation, 'cash_advance_amount', 0)),
                'total_actual_expenses': cash_advance_liquidation_money(getattr(liquidation, 'total_actual_expenses', 0)),
                'due_to_shimadzu': cash_advance_liquidation_money(getattr(liquidation, 'due_to_shimadzu', 0)),
                'due_to_employee': cash_advance_liquidation_money(getattr(liquidation, 'due_to_employee', 0)),
                'row_count': row_count,
                'receipt_count': receipt_count
            }
        )
        record_universal_approval_audit(
            'cash_advance_liquidation',
            liquidation.id,
            'submitted',
            actor_user=current_user,
            status_from=previous_liquidation_status,
            status_to='Submitted',
            remarks='Submitted standalone Cash Advance liquidation for manager review.',
            metadata={
                'cash_advance_id': header.id,
                'cash_advance_no': request_label,
                'liquidation_id': liquidation.id,
                'liquidation_no': liquidation_label,
                'cash_advance_amount': cash_advance_liquidation_money(getattr(liquidation, 'cash_advance_amount', 0)),
                'total_actual_expenses': cash_advance_liquidation_money(getattr(liquidation, 'total_actual_expenses', 0)),
                'due_to_shimadzu': cash_advance_liquidation_money(getattr(liquidation, 'due_to_shimadzu', 0)),
                'due_to_employee': cash_advance_liquidation_money(getattr(liquidation, 'due_to_employee', 0)),
                'row_count': row_count,
                'receipt_count': receipt_count
            }
        )

        approvers = cash_advance_liquidation_submit_notification_approvers(liquidation)
        approver_email_addresses = get_users_email_addresses_for_notifications(approvers)
        clear_existing_pending_approval_notifications('cash_advance_liquidation', liquidation.id)
        create_system_notifications_for_users(
            approvers,
            title='Cash Advance Liquidation Awaiting Approval',
            message=f"{liquidation_label} for {request_label} is awaiting your approval.",
            module='cash_advance_liquidation',
            record_id=liquidation.id,
            target_url=f'/approvals?module=cash_advance_liquidation&id={liquidation.id}',
            metadata={
                'event': 'submitted',
                'cash_advance_id': header.id,
                'cash_advance_no': request_label,
                'liquidation_id': liquidation.id,
                'liquidation_no': liquidation_label,
                'requester_user_id': header.user_id,
                'requester_name': cash_advance_requester_name(header),
                'total_actual_expenses': cash_advance_liquidation_money(getattr(liquidation, 'total_actual_expenses', 0))
            },
            exclude_user_ids=[header.user_id]
        )
        create_system_notification(
            header.user_id,
            title='Cash Advance Liquidation Submitted',
            message=f'{liquidation_label} was submitted for manager review.',
            module='cash_advance_liquidation',
            record_id=liquidation.id,
            target_url=f'/cash_advance_liquidation?liquidation_id={liquidation.id}',
            metadata={'event': 'submitted_by_requester', 'cash_advance_id': header.id, 'cash_advance_no': request_label, 'liquidation_id': liquidation.id, 'liquidation_no': liquidation_label}
        )
        db.session.add(ActivityLog(user=current_user.username.capitalize(), action=f"Submitted Cash Advance Liquidation: {liquidation_label} for {request_label}"))
        db.session.commit()

        # F4A5G1: Send the manager/approver email immediately so submit does not
        # silently depend on a background worker. This also returns diagnostic
        # details to the frontend/API response for easier live testing.
        approval_email_result = send_cash_advance_liquidation_notification_email_now(
            [getattr(item, 'id', None) for item in approvers],
            liquidation.id,
            'submitted',
            actor_user_id=current_user.id
        )

        return jsonify({
            'success': True,
            'message': 'Cash Advance Liquidation submitted for manager approval.',
            'status': 'Submitted',
            'liquidation': cash_advance_liquidation_to_dict(liquidation, include_rows=True),
            'cash_advance': cash_advance_to_dict(header, include_audit=False),
            'approval_notification': {
                'queued': bool(approvers),
                'recipient_count': len(approvers),
                'email_recipient_count': len(approver_email_addresses),
                'email_recipients': approver_email_addresses,
                'email': approval_email_result
            }
        })
    except Exception as exc:
        db.session.rollback()
        print(f"[CashAdvanceLiquidation] Submit failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to submit Cash Advance Liquidation.'}), 500



# ============================================================
# F4A5C STANDALONE CASH ADVANCE LIQUIDATION MANAGER APPROVAL
# ============================================================

def cash_advance_liquidation_email_context(liquidation):
    """Build common readable standalone Cash Advance Liquidation email fields."""
    header = getattr(liquidation, 'cash_advance', None)
    requester = getattr(liquidation, 'requester', None)
    engineer = getattr(liquidation, 'engineer', None)

    requester_name = (
        clean_str(getattr(engineer, 'name', None)) or
        approval_user_display_name(requester) or
        clean_str(getattr(requester, 'username', None)) or
        cash_advance_requester_name(header) or
        'Employee'
    )
    liquidation_no = clean_str(getattr(liquidation, 'liquidation_no', None)) or f"CAL-{getattr(liquidation, 'id', '')}"
    cash_advance_no = cash_advance_liquidation_request_label(header)
    cash_advance_amount = cash_advance_liquidation_money(getattr(liquidation, 'cash_advance_amount', 0))
    actual_expenses = cash_advance_liquidation_money(getattr(liquidation, 'total_actual_expenses', 0))
    due_to_shimadzu = cash_advance_liquidation_money(getattr(liquidation, 'due_to_shimadzu', 0))
    due_to_employee = cash_advance_liquidation_money(getattr(liquidation, 'due_to_employee', 0))

    return {
        'liquidation_no': liquidation_no,
        'cash_advance_no': cash_advance_no,
        'requester_name': requester_name,
        'status': cash_advance_liquidation_normalize_status(getattr(liquidation, 'status', None)),
        'cash_advance_label': f"PHP {cash_advance_amount:,.2f}",
        'actual_expenses_label': f"PHP {actual_expenses:,.2f}",
        'due_to_shimadzu_label': f"PHP {due_to_shimadzu:,.2f}",
        'due_to_employee_label': f"PHP {due_to_employee:,.2f}",
        'purpose': clean_str(getattr(header, 'purpose', None)) or 'No purpose entered.',
        'system_link': globals().get('TRAVEL_REQUEST_SYSTEM_LINK', 'Medical Service SMS')
    }


def format_cash_advance_liquidation_notification_email(action_label, liquidation, actor_user=None, remarks=''):
    """Return subject/text/html for standalone Cash Advance Liquidation workflow email."""
    ctx = cash_advance_liquidation_email_context(liquidation)
    actor_name = universal_approval_actor_name(actor_user) if actor_user else ctx['requester_name']
    action_key = (clean_str(action_label) or 'updated').strip().lower()
    action_remarks = clean_str(remarks) or clean_str(getattr(liquidation, 'approval_remarks', None)) or ''

    subject_map = {
        'submitted': f"Cash Advance Liquidation Awaiting Approval - {ctx['liquidation_no']}",
        'approved': f"Cash Advance Liquidation Approved - {ctx['liquidation_no']}",
        'returned': f"Cash Advance Liquidation Returned - {ctx['liquidation_no']}",
        'rejected': f"Cash Advance Liquidation Returned - {ctx['liquidation_no']}"
    }
    title_map = {
        'submitted': 'Cash Advance Liquidation Awaiting Approval',
        'approved': 'Cash Advance Liquidation Approved',
        'returned': 'Cash Advance Liquidation Returned for Correction',
        'rejected': 'Cash Advance Liquidation Returned for Correction'
    }
    actor_label_map = {
        'submitted': 'Submitted By',
        'approved': 'Approved By',
        'returned': 'Returned By',
        'rejected': 'Returned By'
    }
    note_map = {
        'submitted': 'A standalone Cash Advance Liquidation has been submitted and is awaiting your review inside Approval Center. No attachments are included in this notification email.',
        'approved': 'Your standalone Cash Advance Liquidation has been approved by the manager.',
        'returned': 'Your standalone Cash Advance Liquidation was returned for correction. Please review the remarks, revise the liquidation, and submit again.',
        'rejected': 'Your standalone Cash Advance Liquidation was returned for correction. Please review the remarks, revise the liquidation, and submit again.'
    }

    subject = subject_map.get(action_key, f"Cash Advance Liquidation Update - {ctx['liquidation_no']}")
    title = title_map.get(action_key, 'Cash Advance Liquidation Update')
    actor_label = actor_label_map.get(action_key, 'Updated By')
    action_note = note_map.get(action_key, 'Please open the Medical Service system for full details.')

    text_lines = [
        title,
        '',
        action_note,
        '',
        f"Liquidation No.: {ctx['liquidation_no']}",
        f"Cash Advance No.: {ctx['cash_advance_no']}",
        f"Requester: {ctx['requester_name']}",
        f"Cash Advance Amount: {ctx['cash_advance_label']}",
        f"Actual Expenses: {ctx['actual_expenses_label']}",
        f"Due to Shimadzu: {ctx['due_to_shimadzu_label']}",
        f"Due to Employee: {ctx['due_to_employee_label']}",
        f"Purpose: {ctx['purpose']}",
        f"Status: {ctx['status']}",
        f"{actor_label}: {actor_name}",
    ]
    if action_remarks:
        text_lines.append(f"Remarks: {action_remarks}")
    text_lines.extend([
        '',
        'Please open the Medical Service system for full details.',
        '',
        f"System Link: {ctx['system_link']}",
        '',
        'Medical Service SMS',
        'Shimadzu Philippines Corporation'
    ])
    text_body = "\n".join(text_lines)

    rows = [
        ('Liquidation No.', ctx['liquidation_no']),
        ('Cash Advance No.', ctx['cash_advance_no']),
        ('Requester', ctx['requester_name']),
        ('Cash Advance Amount', ctx['cash_advance_label']),
        ('Actual Expenses', ctx['actual_expenses_label']),
        ('Due to Shimadzu', ctx['due_to_shimadzu_label']),
        ('Due to Employee', ctx['due_to_employee_label']),
        ('Purpose', ctx['purpose']),
        ('Status', ctx['status']),
        (actor_label, actor_name)
    ]
    if action_remarks:
        rows.append(('Remarks', action_remarks))

    detail_rows = ''.join(
        f"<tr><td style='padding:8px 10px;font-weight:700;border-bottom:1px solid #e5e7eb;color:#334155;vertical-align:top;'>{html.escape(str(label or ''))}</td>"
        f"<td style='padding:8px 10px;border-bottom:1px solid #e5e7eb;color:#0f172a;vertical-align:top;'>{html.escape(str(value or ''))}</td></tr>"
        for label, value in rows
    )

    html_body = f"""
    <div style="font-family:Arial,sans-serif;color:#111827;line-height:1.5;">
        <h2 style="margin:0 0 12px;color:#0f172a;">{html.escape(title)}</h2>
        <p style="margin:0 0 14px;color:#374151;">{html.escape(action_note)}</p>
        <table style="border-collapse:collapse;border:1px solid #e5e7eb;min-width:420px;">
            {detail_rows}
        </table>
        <p style="margin-top:16px;color:#374151;">Please open the Medical Service system for full details.</p>
        <p style="margin-top:8px;color:#374151;">
            <strong>System Link:</strong><br>
            <a href="{html.escape(ctx['system_link'])}" style="color:#0d6efd;text-decoration:none;font-weight:700;">{html.escape(ctx['system_link'])}</a>
        </p>
        <p style="margin-top:16px;color:#374151;">
            Regards,<br>
            Medical Service SMS<br>
            Shimadzu Philippines Corporation
        </p>
    </div>
    """
    return subject, text_body, html_body



def cash_advance_liquidation_rfp_filename(liquidation):
    """Safe filename for generated standalone Cash Advance Liquidation RFP PDF."""
    requester_name = (
        clean_str(getattr(getattr(liquidation, 'engineer', None), 'name', None)) or
        approval_user_display_name(getattr(liquidation, 'requester', None)) or
        clean_str(getattr(getattr(liquidation, 'requester', None), 'username', None)) or
        'Employee'
    )
    safe_name = secure_filename(requester_name) or 'Employee'
    liquidation_no = clean_str(getattr(liquidation, 'liquidation_no', None)) or f"CAL-{clean_int(getattr(liquidation, 'id', None)) or 0}"
    safe_liquidation_no = secure_filename(liquidation_no) or 'Cash_Advance_Liquidation'
    return f"RFP_{safe_name}_{safe_liquidation_no}.pdf"


def cash_advance_liquidation_rfp_covering_text(liquidation):
    """Return compact RFP covering text for standalone CA Liquidation.

    F4A5E:
    The official RFP COVERING field is narrow. Do not include liquidation number,
    cash advance number, date range, or long system labels here. Use only the real
    request description/purpose, then fall back to the actual expense particulars.
    """
    header = getattr(liquidation, 'cash_advance', None)

    candidates = [
        clean_str(getattr(header, 'purpose', None)) if header else '',
        clean_str(getattr(header, 'description', None)) if header else '',
        clean_str(getattr(header, 'remarks', None)) if header else ''
    ]

    rows = sorted(
        list(getattr(liquidation, 'rows', None) or []),
        key=lambda row: (
            getattr(row, 'expense_date', None) or datetime.min.date(),
            clean_int(getattr(row, 'sort_order', None)) or 100,
            clean_int(getattr(row, 'id', None)) or 0
        )
    )

    row_particulars = []
    for row in rows:
        if cash_advance_liquidation_money(getattr(row, 'actual_amount', 0)) <= 0:
            continue
        value = clean_str(getattr(row, 'particulars', None)) or clean_str(getattr(row, 'expense_type', None)) or ''
        if value and value.lower() not in {item.lower() for item in row_particulars}:
            row_particulars.append(value)
        if len(row_particulars) >= 2:
            break

    if row_particulars:
        candidates.append(' / '.join(row_particulars))

    covering = next((item for item in candidates if clean_str(item)), '') or 'Cash advance liquidation reimbursement'
    covering = re.sub(r'\s+', ' ', str(covering)).strip()

    # Remove system-style prefixes if a user pasted a structured note into the purpose.
    covering = re.sub(r'^(Purpose|Description|Request|Covering)\s*:\s*', '', covering, flags=re.I).strip()

    # The field gets visually crowded. Keep the text concise and descriptive.
    max_covering_len = 115
    if len(covering) > max_covering_len:
        covering = covering[:max_covering_len - 1].rstrip(' ,;:/-') + '…'

    return covering


def cash_advance_liquidation_rfp_approval_signature_overlay_pdf(header, page_width, page_height):
    """Create a CA Liquidation RFP approver stamp aligned to the official underline.

    F4A5G3:
    The generated RFP uses the old Shimadzu Request for Payment template. The
    APPROVED BY underline on that template is on the lower-left block, roughly
    x=44.66 to x=258.33 and y=519.25 in bottom-origin PDF coordinates on the
    612 x 936 page. The generic reimbursement approval stamper placed the
    signature block too high and let the text crowd the underline. This
    purpose-built overlay centers the signature/name on that official underline
    only for Cash Advance Liquidation RFPs, leaving Travel Liquidation and
    Reimbursement RFP layouts untouched.
    """
    from PIL import Image
    from reportlab.lib.utils import ImageReader
    from reportlab.pdfgen import canvas

    if not reimbursement_is_approved_for_stamp(header):
        return None

    approver_name = reimbursement_approval_printed_name(header)
    if not approver_name:
        return None

    signature_data = reimbursement_approval_signature_data(header)
    approver_title = reimbursement_approval_title(header)
    signed_at = reimbursement_approval_signed_at_label(header)

    # Official RFP APPROVED BY underline coordinates, derived from rendered
    # template review. Keep the block inside this line width and below NOTED BY.
    page_width = float(page_width or 612.0)
    page_height = float(page_height or 936.0)
    line_x1 = 44.66
    line_x2 = 258.33
    line_y = 519.25

    # Defensive scaling for non-standard template sizes.
    if page_width and abs(page_width - 612.0) > 1.5:
        scale_x = page_width / 612.0
        line_x1 *= scale_x
        line_x2 *= scale_x
    if page_height and abs(page_height - 936.0) > 1.5:
        scale_y = page_height / 936.0
        line_y *= scale_y

    line_width = max(line_x2 - line_x1, 120.0)
    center_x = line_x1 + (line_width / 2.0)

    buffer = io.BytesIO()
    c = canvas.Canvas(buffer, pagesize=(page_width, page_height))

    # F4A5G4: Trim signature canvas first, then center the visible strokes
    # inside the official APPROVED BY underline. Move the block downward so the
    # signature no longer floats into the NOTED BY area or crowds the label.
    signature_area_width = min(line_width * 0.58, 124.0)
    signature_area_height = 18.0
    signature_bottom = line_y + 5.2

    png_bytes = reimbursement_signature_data_url_to_png_bytes(signature_data) if signature_data else None
    png_bytes = trim_cash_advance_liquidation_signature_png_bytes(png_bytes) if png_bytes else None
    if png_bytes:
        try:
            with Image.open(io.BytesIO(png_bytes)) as signature_image:
                image_width, image_height = signature_image.size

            if image_width and image_height:
                fit_scale = min(
                    signature_area_width / float(image_width),
                    signature_area_height / float(image_height),
                    1.0
                )
                draw_width = image_width * fit_scale
                draw_height = image_height * fit_scale
                draw_x = center_x - (draw_width / 2.0)
                draw_y = signature_bottom + ((signature_area_height - draw_height) / 2.0)
                c.drawImage(
                    ImageReader(io.BytesIO(png_bytes)),
                    draw_x,
                    draw_y,
                    width=draw_width,
                    height=draw_height,
                    preserveAspectRatio=True,
                    mask='auto'
                )
        except Exception as image_error:
            print(f"[CashAdvanceLiquidationRFP] Approval signature image skipped: {image_error}", flush=True)

    c.setFillColorRGB(0, 0, 0)
    c.setFont('Helvetica-Bold', 6.4)
    c.drawCentredString(center_x, line_y + 1.9, str(approver_name)[:36])

    if approver_title:
        c.setFont('Helvetica', 4.9)
        c.drawCentredString(center_x, line_y - 5.2, str(approver_title)[:42])

    if signed_at:
        c.setFont('Helvetica', 4.5)
        c.drawCentredString(center_x, line_y - 11.2, f"Approved: {signed_at}")

    c.showPage()
    c.save()
    buffer.seek(0)
    return buffer.getvalue()


def cash_advance_liquidation_stamp_rfp_approval_signature(writer, liquidation):
    """Stamp CA Liquidation RFP approver signature/name using fixed RFP layout."""
    if not reimbursement_is_approved_for_stamp(liquidation):
        return False
    try:
        from pypdf import PdfReader

        first_page = writer.pages[0]
        media_box = first_page.mediabox
        page_width = float(media_box.width)
        page_height = float(media_box.height)
        overlay_bytes = cash_advance_liquidation_rfp_approval_signature_overlay_pdf(
            liquidation,
            page_width,
            page_height
        )
        if not overlay_bytes:
            return False
        overlay_reader = PdfReader(io.BytesIO(overlay_bytes))
        first_page.merge_page(overlay_reader.pages[0])
        return True
    except Exception as approval_stamp_error:
        print(f"[CashAdvanceLiquidationRFP] Approval signature stamp skipped: {approval_stamp_error}", flush=True)
        return False


def cash_advance_liquidation_prepare_rfp_field_values(liquidation):
    """Prepare official Request for Payment PDF values from a standalone CA Liquidation."""
    header = getattr(liquidation, 'cash_advance', None)
    engineer = getattr(liquidation, 'engineer', None)
    requester = getattr(liquidation, 'requester', None)

    employee_name = (
        clean_str(getattr(engineer, 'name', None)) or
        approval_user_display_name(requester) or
        clean_str(getattr(requester, 'username', None)) or
        cash_advance_requester_name(header) or
        'Employee'
    ).upper()

    cash_advance_liquidation_recalculate_totals(liquidation)
    amount = cash_advance_liquidation_money(getattr(liquidation, 'due_to_employee', 0))
    covering = cash_advance_liquidation_rfp_covering_text(liquidation)

    rows = sorted(
        list(getattr(liquidation, 'rows', None) or []),
        key=lambda row: (getattr(row, 'expense_date', None) or datetime.min.date(), clean_int(getattr(row, 'sort_order', None)) or 100, clean_int(getattr(row, 'id', None)) or 0)
    )
    first_row = next((row for row in rows if cash_advance_liquidation_money(getattr(row, 'actual_amount', 0)) > 0), None)

    field_values = {
        'CHECK PAYABLE TO': employee_name,
        'DATE': get_manila_time().strftime('%m-%d-%Y'),
        'SUBMITTED BY': employee_name,
        'COVERING': covering,
        'Textfield': f"{amount:,.2f}",
    }

    code_aliases = {
        clean_str(getattr(first_row, 'branch_code', None)) or 'BC01': ['BRANCH', 'Branch', 'branch', 'Branch Code', 'BRANCH CODE'],
        clean_str(getattr(first_row, 'class_code', None)) or 'CC04': ['CLASS', 'Class', 'class', 'Class Code', 'CLASS CODE'],
        clean_str(getattr(first_row, 'dept_code', None)) or 'DC03': ['DEPT', 'Dept', 'DEPARTMENT', 'Department', 'dept', 'Dept Code', 'DEPT CODE'],
        clean_str(getattr(first_row, 'product_code', None)) or 'PC18/PC22': ['PRODUCT', 'Product', 'product', 'Product Code', 'PRODUCT CODE'],
    }
    for value, aliases in code_aliases.items():
        for alias in aliases:
            field_values[alias] = value

    return field_values


def build_cash_advance_liquidation_rfp_template_pdf(liquidation):
    """Fill the official Request for Payment PDF template for standalone CA Liquidation."""
    try:
        from pypdf import PdfReader, PdfWriter
        from pypdf.generic import BooleanObject, NameObject
    except Exception as exc:
        raise ImportError('pypdf is required to fill the RFP PDF template.') from exc

    template_path = reimbursement_find_rfp_template_path()
    field_values = cash_advance_liquidation_prepare_rfp_field_values(liquidation)

    reader = PdfReader(template_path)
    writer = PdfWriter()
    writer.clone_document_from_reader(reader)

    reimbursement_apply_rfp_field_formatting(writer)

    try:
        writer.set_need_appearances_writer(True)
    except Exception:
        try:
            if '/AcroForm' in writer._root_object:
                writer._root_object['/AcroForm'].update({NameObject('/NeedAppearances'): BooleanObject(True)})
        except Exception:
            pass

    for page in writer.pages:
        writer.update_page_form_field_values(page, field_values)

    # Reuse the requester RFP signature stamper. CashAdvanceLiquidationHeader has engineer_id.
    reimbursement_stamp_rfp_signature(writer, liquidation)
    # F4A5G3: Use a purpose-built CA Liquidation RFP approver stamper.
    # It centers the signature/name on the official APPROVED BY underline and
    # keeps it below the NOTED BY area. Other RFP workflows are untouched.
    cash_advance_liquidation_stamp_rfp_approval_signature(writer, liquidation)

    output = io.BytesIO()
    writer.write(output)
    pdf_bytes = output.getvalue()
    compressed_pdf_bytes = reimbursement_compress_pdf_bytes_best_effort(pdf_bytes)
    final_output = io.BytesIO(compressed_pdf_bytes)
    final_output.seek(0)
    return final_output


def build_cash_advance_liquidation_approval_package_manifest(liquidation):
    """Build Approval Center document manifest for standalone Cash Advance Liquidation."""
    if not liquidation:
        return {}

    header = getattr(liquidation, 'cash_advance', None)
    cash_advance_liquidation_recalculate_totals(liquidation)

    liquidation_id = clean_int(getattr(liquidation, 'id', None)) or 0
    cash_advance_id = clean_int(getattr(liquidation, 'cash_advance_id', None)) or 0
    cash_advance_amount = cash_advance_liquidation_money(getattr(liquidation, 'cash_advance_amount', 0))
    total_expenses = cash_advance_liquidation_money(getattr(liquidation, 'total_actual_expenses', 0))
    due_to_shimadzu = cash_advance_liquidation_money(getattr(liquidation, 'due_to_shimadzu', 0))
    due_to_employee = cash_advance_liquidation_money(getattr(liquidation, 'due_to_employee', 0))
    rfp_required = due_to_employee > 0

    receipts = (
        CashAdvanceLiquidationReceipt.query
        .filter_by(liquidation_id=liquidation_id)
        .order_by(CashAdvanceLiquidationReceipt.created_at.asc(), CashAdvanceLiquidationReceipt.id.asc())
        .all()
    )

    receipt_items = [cash_advance_liquidation_receipt_to_dict(receipt) for receipt in receipts]
    cash_advance_no = cash_advance_liquidation_request_label(header)
    liquidation_no = clean_str(getattr(liquidation, 'liquidation_no', None)) or f"CAL-{liquidation_id}"

    documents = [
        {
            'key': 'receipts',
            'label': 'Individual Receipts',
            'description': 'Uploaded receipt files attached to liquidation expense rows.',
            'required': False,
            'available': len(receipt_items) > 0,
            'open_url': '',
            'file_type': 'attachments',
            'open_mode': 'in_review_modal',
            'status': f"{len(receipt_items)} receipt(s)" if receipt_items else 'No receipts uploaded',
            'count': len(receipt_items),
            'items': receipt_items
        },
        {
            'key': 'rfp',
            'label': 'Request for Payment (RFP)',
            'description': 'Required only when Due to Employee is greater than zero.',
            'required': bool(rfp_required),
            'available': bool(rfp_required and liquidation_id),
            'open_url': f"/preview_cash_advance_liquidation_rfp/{liquidation_id}" if rfp_required and liquidation_id else '',
            'download_url': f"/download_cash_advance_liquidation_rfp/{liquidation_id}" if rfp_required and liquidation_id else '',
            'file_type': 'pdf',
            'open_mode': 'new_tab',
            'status': 'Ready' if rfp_required else 'Not required',
            'amount': due_to_employee,
            'amount_label': f"PHP {due_to_employee:,.2f}"
        }
    ]

    required_documents = [doc for doc in documents if doc.get('required')]
    ready_required_documents = [doc for doc in required_documents if doc.get('available')]
    missing_required_documents = [doc for doc in required_documents if not doc.get('available')]

    return {
        'success': True,
        'module': 'cash_advance_liquidation',
        'phase': 'F4A5D',
        'liquidation_id': liquidation_id,
        'liquidation_no': liquidation_no,
        'cash_advance_id': cash_advance_id,
        'request_no': cash_advance_no,
        'source_label': 'Cash Advance',
        'status': clean_str(getattr(liquidation, 'status', None)) or '',
        'summary': {
            'cash_advance_amount': cash_advance_amount,
            'total_actual_expenses': total_expenses,
            'due_to_shimadzu': due_to_shimadzu,
            'due_to_employee': due_to_employee,
            'cash_advance_label': f"PHP {cash_advance_amount:,.2f}",
            'total_expenses_label': f"PHP {total_expenses:,.2f}",
            'due_to_shimadzu_label': f"PHP {due_to_shimadzu:,.2f}",
            'due_to_employee_label': f"PHP {due_to_employee:,.2f}",
            'rfp_required': bool(rfp_required)
        },
        'documents': documents,
        'receipt_count': len(receipt_items),
        'required_count': len(required_documents),
        'ready_required_count': len(ready_required_documents),
        'missing_required_count': len(missing_required_documents),
        'is_ready_for_manager_review': len(missing_required_documents) == 0,
        'notes': [
            'RFP is generated only when Due to Employee is greater than zero.',
            'Manager notification email has no attachments.',
            'Accounting handoff package will be assembled after manager approval.'
        ]
    }


@app.route('/get_cash_advance_liquidation_approval_package/<int:liquidation_id>')
@app.route('/get_cash_advance_liquidation_package_manifest/<int:liquidation_id>')
@login_required
def get_cash_advance_liquidation_approval_package(liquidation_id):
    """Return Approval Center document package manifest for standalone CA Liquidation."""
    ensure_cash_advance_tables()
    ensure_cash_advance_liquidation_tables()

    liquidation = db.session.get(CashAdvanceLiquidationHeader, clean_int(liquidation_id))
    if not liquidation:
        return jsonify({'success': False, 'error': 'Cash Advance Liquidation record not found.'}), 404

    if not can_current_user_view_cash_advance_liquidation(liquidation):
        return jsonify({'success': False, 'error': 'You are not allowed to view this Cash Advance Liquidation package.'}), 403

    try:
        manifest = build_cash_advance_liquidation_approval_package_manifest(liquidation)
        db.session.commit()
        response = jsonify(manifest)
        response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
        response.headers['Pragma'] = 'no-cache'
        response.headers['Expires'] = '0'
        return response
    except Exception as exc:
        db.session.rollback()
        print(f"[CashAdvanceLiquidationPackage] Manifest failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to build Cash Advance Liquidation approval package.'}), 500


@app.route('/preview_cash_advance_liquidation_rfp/<int:liquidation_id>')
@app.route('/open_cash_advance_liquidation_rfp/<int:liquidation_id>')
@app.route('/inline_cash_advance_liquidation_rfp/<int:liquidation_id>')
@app.route('/download_cash_advance_liquidation_rfp/<int:liquidation_id>')
@login_required
def preview_cash_advance_liquidation_rfp(liquidation_id):
    """Preview the official RFP PDF when standalone CA Liquidation Due to Employee > 0."""
    ensure_cash_advance_tables()
    ensure_cash_advance_liquidation_tables()

    liquidation = db.session.get(CashAdvanceLiquidationHeader, clean_int(liquidation_id))
    if not liquidation:
        return jsonify({'success': False, 'error': 'Cash Advance Liquidation record not found.'}), 404

    if not can_current_user_view_cash_advance_liquidation(liquidation):
        return jsonify({'success': False, 'error': 'You are not allowed to view this RFP.'}), 403

    try:
        cash_advance_liquidation_recalculate_totals(liquidation)
        due_to_employee = cash_advance_liquidation_money(getattr(liquidation, 'due_to_employee', 0))
        if due_to_employee <= 0:
            return jsonify({'success': False, 'error': 'RFP is not required because Due to Employee is zero.'}), 400

        db.session.commit()
        pdf_buffer = build_cash_advance_liquidation_rfp_template_pdf(liquidation)
        filename = cash_advance_liquidation_rfp_filename(liquidation)

        if request.path.startswith('/inline_'):
            response = send_file(
                pdf_buffer,
                mimetype='application/pdf',
                as_attachment=False,
                download_name=filename,
                max_age=0
            )
            return force_inline_file_response(response, filename)

        if request.args.get('force_download') == '1':
            return send_file(
                pdf_buffer,
                mimetype='application/pdf',
                as_attachment=True,
                download_name=filename,
                max_age=0
            )

        return render_embedded_pdf_preview_shell(
            title=f"Request for Payment - {clean_str(getattr(liquidation, 'liquidation_no', None)) or f'CAL-{liquidation_id}'}",
            pdf_bytes=pdf_buffer,
            filename=filename
        )

    except Exception as exc:
        db.session.rollback()
        print(f"[CashAdvanceLiquidationRFP] Preview failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to preview Cash Advance Liquidation RFP.'}), 500


