@app.route('/approve_cash_advance_liquidation/<int:liquidation_id>', methods=['POST'])
@csrf.exempt
@login_required
def approve_cash_advance_liquidation(liquidation_id):
    """Approve submitted standalone Cash Advance Liquidation."""
    denied_response = require_approval_center_user()
    if denied_response:
        return denied_response

    signature_denial = approval_signature_required_response(current_user, module_label='cash advance liquidation')
    if signature_denial:
        return signature_denial

    payload = request.get_json(silent=True) or {}
    remarks = clean_str(payload.get('remarks') or payload.get('approval_remarks') or '') or ''

    ensure_cash_advance_tables()
    ensure_cash_advance_liquidation_tables()
    liquidation = db.session.get(CashAdvanceLiquidationHeader, clean_int(liquidation_id))
    if not liquidation:
        return jsonify({'success': False, 'error': 'Cash Advance Liquidation not found.'}), 404
    if not can_user_approve_cash_advance_liquidation(current_user, liquidation):
        return jsonify({'success': False, 'error': 'This Cash Advance Liquidation is not assigned to you for approval.'}), 403
    if cash_advance_liquidation_normalize_status(getattr(liquidation, 'status', None)) != 'Submitted':
        return jsonify({'success': False, 'error': f'Cash Advance Liquidation is already {cash_advance_liquidation_normalize_status(getattr(liquidation, "status", None))}.'}), 409

    try:
        now = get_manila_time()
        header = getattr(liquidation, 'cash_advance', None)
        previous_liquidation_status = cash_advance_liquidation_normalize_status(getattr(liquidation, 'status', None))
        previous_cash_status = cash_advance_normalize_status(getattr(header, 'status', None)) if header else ''
        liquidation_label = clean_str(getattr(liquidation, 'liquidation_no', None)) or f'CAL-{liquidation.id}'
        request_label = cash_advance_liquidation_request_label(header)

        cash_advance_liquidation_recalculate_totals(liquidation)
        accounting_emails = get_cash_advance_liquidation_accounting_recipient_emails()
        accounting_warning = None
        accounting_email_queued = False

        liquidation.status = 'Approved'
        liquidation.accounting_status = 'Accounting Email Queued' if accounting_emails else 'Accounting Email Not Configured'
        liquidation.accounting_remarks = None if accounting_emails else 'No active Cash Advance Accounting email recipient is configured.'
        liquidation.approved_at = now
        liquidation.approved_by_id = current_user.id
        liquidation.rejected_at = None
        liquidation.rejected_by_id = None
        liquidation.approval_remarks = remarks
        apply_approval_signature_snapshot(liquidation, current_user, action_label='Approved', signed_at=now)
        liquidation.updated_at = now

        if header:
            header.status = 'Liquidation Approved'
            header.accounting_status = 'Liquidation Accounting Email Queued' if accounting_emails else 'Liquidation Accounting Email Not Configured'
            header.updated_at = now

        if not accounting_emails:
            accounting_warning = cash_advance_liquidation_accounting_settings_warning_payload()
            add_activity_log_entry(
                f"Cash Advance Liquidation Accounting email not sent: no Accounting recipients configured for {liquidation_label}"
            )

        record_universal_approval_audit(
            'cash_advance_liquidation',
            liquidation.id,
            'approved',
            actor_user=current_user,
            status_from=previous_liquidation_status,
            status_to='Approved',
            remarks=remarks or 'Approved standalone Cash Advance Liquidation.',
            metadata={
                'cash_advance_id': getattr(header, 'id', None),
                'cash_advance_no': request_label,
                'liquidation_id': liquidation.id,
                'liquidation_no': liquidation_label,
                'approved_by_id': current_user.id,
                'approved_by': universal_approval_actor_name(current_user),
                'signature_snapshot_saved': bool(clean_str(getattr(liquidation, 'approval_signature_snapshot', None))),
                'due_to_employee': cash_advance_liquidation_money(getattr(liquidation, 'due_to_employee', 0)),
                'due_to_shimadzu': cash_advance_liquidation_money(getattr(liquidation, 'due_to_shimadzu', 0))
            }
        )
        if header:
            record_universal_approval_audit(
                'cash_advance',
                header.id,
                'liquidation_approved',
                actor_user=current_user,
                status_from=previous_cash_status,
                status_to='Liquidation Approved',
                remarks=remarks or 'Standalone Cash Advance Liquidation approved.',
                metadata={'cash_advance_id': header.id, 'cash_advance_no': request_label, 'liquidation_id': liquidation.id, 'liquidation_no': liquidation_label}
            )

        resolve_pending_approval_notifications('cash_advance_liquidation', liquidation.id, event='submitted')
        if header:
            resolve_pending_approval_notifications('cash_advance', header.id, event='liquidation_submitted')
        requester_message = (
            f"{liquidation_label} was approved by {universal_approval_actor_name(current_user)} and queued for Accounting handoff."
            if accounting_emails else
            f"{liquidation_label} was approved by {universal_approval_actor_name(current_user)}, but Accounting email recipients are not configured."
        )
        create_system_notification(
            user_id=liquidation.user_id,
            title='Cash Advance Liquidation Approved',
            message=requester_message,
            module='cash_advance_liquidation',
            record_id=liquidation.id,
            target_url=f'/cash_advance_liquidation?liquidation_id={liquidation.id}',
            metadata={
                'event': 'approved',
                'cash_advance_id': getattr(header, 'id', None),
                'liquidation_id': liquidation.id,
                'approved_by_user_id': current_user.id,
                'accounting_email_queued': bool(accounting_emails),
                'accounting_recipient_count': len(accounting_emails)
            }
        )
        db.session.add(ActivityLog(
            user=current_user.username.capitalize(),
            action=f"Approved Cash Advance Liquidation: {liquidation_label}"
        ))
        db.session.commit()

        send_cash_advance_liquidation_notification_email_async(
            app,
            [liquidation.user_id],
            liquidation.id,
            'approved',
            actor_user_id=current_user.id,
            remarks=remarks
        )

        if accounting_emails:
            accounting_email_queued = send_cash_advance_liquidation_accounting_email_async(
                app,
                liquidation.id,
                accounting_emails,
                approved_by_user_id=current_user.id,
                remarks=remarks
            )

        response_payload = {
            'success': True,
            'status': liquidation.status,
            'message': 'Cash Advance Liquidation approved and Accounting handoff queued.' if accounting_emails else 'Cash Advance Liquidation approved. Accounting email was not sent because no Accounting recipients are configured.',
            'liquidation': cash_advance_liquidation_to_dict(liquidation, include_rows=True),
            'cash_advance_liquidation': cash_advance_liquidation_to_dict(liquidation, include_rows=True),
            'accounting_email': {
                'queued': bool(accounting_email_queued),
                'recipient_count': len(accounting_emails),
                'recipients': accounting_emails if is_superadmin_user() else [],
                'status': liquidation.accounting_status or '',
                'package_label': 'Cash Advance Liquidation Accounting package ZIP',
                'attachment_label': 'Complete Cash Advance Liquidation Accounting package ZIP'
            }
        }

        if accounting_warning:
            response_payload['warning'] = accounting_warning
            response_payload['accounting_warning'] = accounting_warning

        return jsonify(response_payload)
    except Exception as exc:
        db.session.rollback()
        print(f"[CashAdvanceLiquidation] Approve failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to approve Cash Advance Liquidation.'}), 500




@app.route('/complete_travel_liquidation/<int:liquidation_id>', methods=['POST'])
@app.route('/mark_travel_liquidation_completed/<int:liquidation_id>', methods=['POST'])
@app.route('/accounting_mark_travel_liquidation_paid/<int:liquidation_id>', methods=['POST'])
@csrf.exempt
@login_required
def complete_travel_liquidation(liquidation_id):
    """F4A5I: Engineer/requester marks approved Travel Liquidation as completed.

    The current workflow has no Accounting acknowledgement screen, so the requester
    closes the Travel Liquidation after manager approval/accounting handoff.
    The legacy /accounting_mark_travel_liquidation_paid route is kept as a safe
    compatibility alias so older My Requests buttons cannot fail silently.
    """
    payload = request.get_json(silent=True) or {}
    remarks = clean_str(payload.get('remarks') or payload.get('completion_remarks') or payload.get('payment_remarks') or '')
    payment_method = clean_str(payload.get('payment_method') or '')
    payment_reference = clean_str(payload.get('payment_reference') or '')
    if payment_method or payment_reference:
        payment_bits = []
        if payment_method:
            payment_bits.append(f"Method: {payment_method}")
        if payment_reference:
            payment_bits.append(f"Reference: {payment_reference}")
        payment_note = '; '.join(payment_bits)
        remarks = f"{remarks} | {payment_note}".strip(' |') if remarks else payment_note

    ensure_travel_request_tables()
    ensure_travel_liquidation_tables()
    ensure_system_notification_table()
    ensure_universal_approval_audit_table()

    liquidation = db.session.get(TravelLiquidationHeader, clean_int(liquidation_id))
    if not liquidation:
        return jsonify({'success': False, 'error': 'Travel Liquidation not found.'}), 404

    request_rec = getattr(liquidation, 'travel_request', None)
    user_id = clean_int(getattr(current_user, 'id', None))
    owner_id = clean_int(getattr(liquidation, 'user_id', None))
    request_manage_allowed = can_current_user_manage_my_accounting_record(request_rec) if request_rec else False
    if owner_id != user_id and not request_manage_allowed and not is_superadmin_user() and getattr(current_user, 'role', '') != 'regional_admin':
        return jsonify({'success': False, 'error': 'Only the requester/participant can mark this Travel Liquidation as completed.'}), 403

    current_status = normalize_travel_liquidation_status(getattr(liquidation, 'status', None))
    if current_status == 'Completed':
        return jsonify({
            'success': True,
            'status': 'Completed',
            'message': 'Travel Liquidation is already completed.',
            'liquidation': travel_liquidation_to_dict(liquidation, include_rows=True),
            'travel_liquidation': travel_liquidation_to_dict(liquidation, include_rows=True)
        })

    if current_status != 'Approved':
        return jsonify({'success': False, 'error': f'Only Approved Travel Liquidations can be marked completed. Current status: {current_status}.'}), 409

    try:
        now = get_manila_time()
        previous_liquidation_status = current_status
        previous_travel_status = travel_request_normalize_status(getattr(request_rec, 'status', None)) if request_rec else ''
        previous_accounting_status = clean_str(getattr(liquidation, 'accounting_status', None)) or ''
        liquidation_label = clean_str(getattr(liquidation, 'liquidation_no', None)) or f'TL-{liquidation.id}'
        request_label = clean_str(getattr(request_rec, 'request_no', None)) or f'TR-{getattr(request_rec, "id", liquidation.travel_request_id)}'

        liquidation.status = 'Completed'
        liquidation.accounting_status = 'Completed'
        liquidation.completed_at = now
        if hasattr(liquidation, 'completed_by_id'):
            liquidation.completed_by_id = current_user.id
        if hasattr(liquidation, 'completion_remarks'):
            liquidation.completion_remarks = remarks
        liquidation.updated_at = now

        if request_rec:
            request_rec.status = 'Liquidation Completed'
            request_rec.accounting_status = 'Liquidation Completed'
            request_rec.liquidation_completed_at = now
            request_rec.updated_at = now

        record_universal_approval_audit(
            'travel_liquidation',
            liquidation.id,
            'engineer_completed',
            actor_user=current_user,
            status_from=previous_liquidation_status,
            status_to='Completed',
            remarks=remarks or 'Requester marked Travel Liquidation as completed.',
            metadata={
                'travel_request_id': getattr(request_rec, 'id', None),
                'request_no': request_label,
                'liquidation_id': liquidation.id,
                'liquidation_no': liquidation_label,
                'previous_accounting_status': previous_accounting_status,
                'completed_by_id': current_user.id,
                'completed_by': universal_approval_actor_name(current_user),
                'completed_at': now.isoformat()
            }
        )

        if request_rec:
            record_universal_approval_audit(
                'travel_request',
                request_rec.id,
                'liquidation_completed',
                actor_user=current_user,
                status_from=previous_travel_status,
                status_to='Liquidation Completed',
                remarks=remarks or 'Requester marked Travel Liquidation as completed.',
                metadata={
                    'travel_request_id': request_rec.id,
                    'request_no': request_label,
                    'liquidation_id': liquidation.id,
                    'liquidation_no': liquidation_label
                }
            )

        create_system_notification(
            user_id=liquidation.user_id,
            title='Travel Liquidation Completed',
            message=f'{liquidation_label} was marked completed.',
            module='travel_liquidation',
            record_id=liquidation.id,
            target_url=f'/travel_liquidation?liquidation_id={liquidation.id}',
            metadata={
                'event': 'engineer_completed',
                'travel_request_id': getattr(request_rec, 'id', None),
                'request_no': request_label,
                'liquidation_id': liquidation.id,
                'liquidation_no': liquidation_label,
                'completed_at': now.isoformat()
            }
        )

        db.session.add(ActivityLog(
            user=current_user.username.capitalize(),
            action=f'Completed Travel Liquidation: {liquidation_label}'
        ))
        db.session.commit()

        return jsonify({
            'success': True,
            'status': 'Completed',
            'message': 'Travel Liquidation marked completed.',
            'liquidation': travel_liquidation_to_dict(liquidation, include_rows=True),
            'travel_liquidation': travel_liquidation_to_dict(liquidation, include_rows=True),
            'travel_request_id': getattr(request_rec, 'id', None),
            'travel_request_status': travel_request_normalize_status(getattr(request_rec, 'status', None)) if request_rec else ''
        })
    except Exception as exc:
        db.session.rollback()
        print(f"[TravelLiquidation] Completion failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to mark Travel Liquidation as completed.'}), 500


