@app.route('/reject_cash_advance_liquidation/<int:liquidation_id>', methods=['POST'])
@app.route('/return_cash_advance_liquidation/<int:liquidation_id>', methods=['POST'])
@csrf.exempt
@login_required
def reject_cash_advance_liquidation(liquidation_id):
    """Return submitted standalone Cash Advance Liquidation for correction."""
    denied_response = require_approval_center_user()
    if denied_response:
        return denied_response

    payload = request.get_json(silent=True) or {}
    remarks = clean_str(payload.get('remarks') or payload.get('approval_remarks') or payload.get('reason') or '')
    if not remarks:
        return jsonify({'success': False, 'error': 'Return remarks are required.'}), 400

    ensure_cash_advance_tables()
    ensure_cash_advance_liquidation_tables()
    liquidation = db.session.get(CashAdvanceLiquidationHeader, clean_int(liquidation_id))
    if not liquidation:
        return jsonify({'success': False, 'error': 'Cash Advance Liquidation not found.'}), 404
    if not can_user_approve_cash_advance_liquidation(current_user, liquidation):
        return jsonify({'success': False, 'error': 'This Cash Advance Liquidation is not assigned to you for approval.'}), 403
    if cash_advance_liquidation_normalize_status(getattr(liquidation, 'status', None)) != 'Submitted':
        return jsonify({'success': False, 'error': f'Cash Advance Liquidation is already {cash_advance_liquidation_normalize_status(getattr(liquidation, "status", None))}.'}), 409

    try:
        now = get_manila_time()
        header = getattr(liquidation, 'cash_advance', None)
        previous_liquidation_status = cash_advance_liquidation_normalize_status(getattr(liquidation, 'status', None))
        previous_cash_status = cash_advance_normalize_status(getattr(header, 'status', None)) if header else ''
        liquidation_label = clean_str(getattr(liquidation, 'liquidation_no', None)) or f'CAL-{liquidation.id}'
        request_label = cash_advance_liquidation_request_label(header)

        liquidation.status = 'Returned'
        liquidation.accounting_status = 'Returned for Correction'
        liquidation.rejected_at = now
        liquidation.rejected_by_id = current_user.id
        liquidation.approved_at = None
        liquidation.approved_by_id = None
        liquidation.approval_remarks = remarks
        clear_approval_signature_snapshot(liquidation)
        liquidation.updated_at = now

        if header:
            header.status = 'Liquidation Returned'
            header.accounting_status = 'Liquidation Returned for Correction'
            header.updated_at = now

        record_universal_approval_audit(
            'cash_advance_liquidation',
            liquidation.id,
            'returned',
            actor_user=current_user,
            status_from=previous_liquidation_status,
            status_to='Returned',
            remarks=remarks,
            metadata={
                'cash_advance_id': getattr(header, 'id', None),
                'cash_advance_no': request_label,
                'liquidation_id': liquidation.id,
                'liquidation_no': liquidation_label,
                'returned_by_id': current_user.id,
                'returned_by': universal_approval_actor_name(current_user),
                'approval_signature_cleared': True
            }
        )
        if header:
            record_universal_approval_audit(
                'cash_advance',
                header.id,
                'liquidation_returned',
                actor_user=current_user,
                status_from=previous_cash_status,
                status_to='Liquidation Returned',
                remarks=remarks,
                metadata={'cash_advance_id': header.id, 'cash_advance_no': request_label, 'liquidation_id': liquidation.id, 'liquidation_no': liquidation_label}
            )

        resolve_pending_approval_notifications('cash_advance_liquidation', liquidation.id, event='submitted')
        if header:
            resolve_pending_approval_notifications('cash_advance', header.id, event='liquidation_submitted')
        create_system_notification(
            user_id=liquidation.user_id,
            title='Cash Advance Liquidation Returned',
            message=f"{liquidation_label} was returned by {universal_approval_actor_name(current_user)}. Remarks: {remarks}",
            module='cash_advance_liquidation',
            record_id=liquidation.id,
            target_url=f'/cash_advance_liquidation?liquidation_id={liquidation.id}',
            metadata={'event': 'returned', 'cash_advance_id': getattr(header, 'id', None), 'liquidation_id': liquidation.id, 'returned_by_user_id': current_user.id, 'remarks': remarks}
        )
        db.session.add(ActivityLog(
            user=current_user.username.capitalize(),
            action=f"Returned Cash Advance Liquidation: {liquidation_label}"
        ))
        db.session.commit()

        send_cash_advance_liquidation_notification_email_async(
            app,
            [liquidation.user_id],
            liquidation.id,
            'returned',
            actor_user_id=current_user.id,
            remarks=remarks
        )

        return jsonify({
            'success': True,
            'status': liquidation.status,
            'message': 'Cash Advance Liquidation returned for correction.',
            'liquidation': cash_advance_liquidation_to_dict(liquidation, include_rows=True),
            'cash_advance_liquidation': cash_advance_liquidation_to_dict(liquidation, include_rows=True)
        })
    except Exception as exc:
        db.session.rollback()
        print(f"[CashAdvanceLiquidation] Return failed: {exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to return Cash Advance Liquidation.'}), 500

