# F4A5G12: Approval Center Global Resend Email Controls
@app.route('/resend_approved_request_email', methods=['POST'])
@csrf.exempt
@login_required
def resend_approved_request_email():
    """Unified Approval Center resend endpoint for approved request handoff emails.

    This does not create or duplicate requests. It simply re-queues the same
    accounting/approved-request email package for a record that has already
    completed manager approval.
    """
    denied_response = require_approval_center_user()
    if denied_response:
        return denied_response

    payload = request.get_json(silent=True) or {}
    module = clean_str(payload.get('module') or payload.get('module_key') or payload.get('type') or '').lower().replace('-', '_')
    record_id = clean_int(payload.get('record_id') or payload.get('id') or payload.get('liquidation_id') or payload.get('request_id'))
    remarks = clean_str(payload.get('remarks') or payload.get('email_remarks') or 'Resent from Approval Center.')

    module_aliases = {
        'travel': 'travel_request',
        'travel_requests': 'travel_request',
        'travelrequest': 'travel_request',
        'reimbursements': 'reimbursement',
        'reimbursement_header': 'reimbursement',
        'cash_advances': 'cash_advance',
        'cashadvance': 'cash_advance',
        'travel_liquidations': 'travel_liquidation',
        'liquidation': 'travel_liquidation',
        'liquidations': 'travel_liquidation',
        'cash_advance_liquidations': 'cash_advance_liquidation',
        'ca_liquidation': 'cash_advance_liquidation',
        'cal': 'cash_advance_liquidation'
    }
    module = module_aliases.get(module, module)

    if not module or not record_id:
        return jsonify({'success': False, 'error': 'Module and record_id are required.'}), 400

    supported_modules = {
        'travel_request',
        'reimbursement',
        'cash_advance',
        'travel_liquidation',
        'cash_advance_liquidation'
    }
    if module not in supported_modules:
        return jsonify({'success': False, 'error': f'Resend email is not supported for module: {module}.'}), 400

    now = get_manila_time()

    def _fail_missing_recipients(record, warning_payload, accounting_label):
        try:
            if hasattr(record, 'accounting_status'):
                record.accounting_status = 'Accounting Email Not Configured'
            if hasattr(record, 'accounting_remarks'):
                record.accounting_remarks = warning_payload.get('message') if isinstance(warning_payload, dict) else 'No accounting recipients configured.'
            if hasattr(record, 'updated_at'):
                record.updated_at = get_manila_time()
            db.session.add(record)
            db.session.commit()
        except Exception as missing_error:
            db.session.rollback()
            print(f"[EMAIL] Global resend missing-recipient state update skipped: {missing_error}", flush=True)
        return jsonify({
            'success': False,
            'error': f'No active {accounting_label} recipient is configured.',
            'accounting_warning': warning_payload,
            'module': module,
            'record_id': record_id
        }), 400

    def _queue_result(record, recipient_emails, queued, package_label, attachment_label='', item_payload=None):
        return jsonify({
            'success': True,
            'message': f'{package_label} email queued.',
            'module': module,
            'record_id': record_id,
            'accounting_email': {
                'queued': bool(queued),
                'recipient_count': len(recipient_emails or []),
                'recipients': recipient_emails if is_superadmin_user() else [],
                'status': getattr(record, 'accounting_status', '') or '',
                'package_label': package_label,
                'attachment_label': attachment_label
            },
            'item': item_payload or {}
        })

    try:
        if module == 'reimbursement':
            ensure_reimbursement_accounting_columns()
            header = db.session.get(ReimbursementHeader, record_id)
            if not header:
                return jsonify({'success': False, 'error': 'Reimbursement not found.'}), 404
            if not is_superadmin_user() and not can_user_approve_reimbursement_header(current_user, header):
                return jsonify({'success': False, 'error': 'This reimbursement is not assigned to you.'}), 403
            if str(getattr(header, 'status', '') or '').strip().lower() != 'approved':
                return jsonify({'success': False, 'error': 'Only approved reimbursements can be resent.'}), 409

            recipient_emails = get_reimbursement_accounting_recipient_emails()
            if not recipient_emails:
                return _fail_missing_recipients(header, reimbursement_accounting_settings_warning_payload(), 'Reimbursement Accounting')

            previous_accounting_status = getattr(header, 'accounting_status', None) or ''
            header.accounting_status = 'Accounting Email Queued'
            header.accounting_remarks = remarks
            header.updated_at = now
            record_universal_approval_audit(
                'reimbursement', header.id, 'accounting_email_resent',
                actor_user=current_user,
                status_from=previous_accounting_status,
                status_to='Accounting Email Queued',
                remarks=remarks,
                metadata={'resend': True, 'recipient_count': len(recipient_emails)}
            )
            db.session.add(header)
            db.session.commit()
            queued = send_reimbursement_accounting_email_async(
                app, header.id, recipient_emails,
                approved_by_user_id=clean_int(getattr(header, 'approved_by_id', None)) or current_user.id,
                remarks=clean_str(getattr(header, 'approval_remarks', None)) or remarks
            )
            return _queue_result(header, recipient_emails, queued, 'Reimbursement Accounting handoff', 'Reimbursement accounting package', reimbursement_header_to_manager_dict(header, include_rows=False))

        if module == 'travel_request':
            request_rec = db.session.get(TravelRequest, record_id)
            if not request_rec:
                return jsonify({'success': False, 'error': 'Travel Request not found.'}), 404
            if not is_superadmin_user() and not can_user_approve_travel_request(current_user, request_rec):
                return jsonify({'success': False, 'error': 'This travel request is not assigned to you.'}), 403
            if not clean_int(getattr(request_rec, 'approved_by_id', None)) and travel_request_normalize_status(getattr(request_rec, 'status', None)) != 'Approved':
                return jsonify({'success': False, 'error': 'Only approved Travel Requests can be resent.'}), 409

            recipient_emails = get_travel_accounting_recipient_emails()
            if not recipient_emails:
                return _fail_missing_recipients(request_rec, travel_request_accounting_settings_warning_payload(), 'Travel Request Accounting')

            previous_accounting_status = getattr(request_rec, 'accounting_status', None) or ''
            request_rec.accounting_status = 'Accounting Email Queued'
            request_rec.accounting_remarks = remarks
            request_rec.updated_at = now
            record_universal_approval_audit(
                'travel_request', request_rec.id, 'accounting_email_resent',
                actor_user=current_user,
                status_from=previous_accounting_status,
                status_to='Accounting Email Queued',
                remarks=remarks,
                metadata={'resend': True, 'recipient_count': len(recipient_emails), 'travel_request_id': request_rec.id}
            )
            db.session.add(request_rec)
            db.session.commit()
            queued = send_travel_request_accounting_email_async(
                app, request_rec.id, recipient_emails,
                approved_by_user_id=clean_int(getattr(request_rec, 'approved_by_id', None)) or current_user.id,
                remarks=clean_str(getattr(request_rec, 'approval_remarks', None)) or remarks
            )
            return _queue_result(request_rec, recipient_emails, queued, 'Travel Request Accounting handoff', 'Approved Travel Request PDF', travel_request_to_dict(request_rec, include_lines=False, include_audit=False))

        if module == 'cash_advance':
            ensure_cash_advance_tables()
            header = db.session.get(CashAdvanceHeader, record_id)
            if not header:
                return jsonify({'success': False, 'error': 'Cash Advance request not found.'}), 404
            if not is_superadmin_user() and not can_user_approve_cash_advance(current_user, header):
                return jsonify({'success': False, 'error': 'This cash advance is not assigned to you.'}), 403
            if str(getattr(header, 'status', '') or '').strip().lower() != 'approved':
                return jsonify({'success': False, 'error': 'Only approved Cash Advance requests can be resent.'}), 409

            recipient_emails, cash_advance_email_route = get_cash_advance_handoff_recipient_emails(header)
            if not recipient_emails:
                return _fail_missing_recipients(
                    header,
                    cash_advance_accounting_settings_warning_payload(cash_advance_email_route),
                    cash_advance_email_route.get('group_label') or 'Cash Advance'
                )

            previous_accounting_status = getattr(header, 'accounting_status', None) or ''
            header.accounting_status = 'Accounting Email Queued'
            header.accounting_remarks = None
            header.updated_at = now
            record_universal_approval_audit(
                'cash_advance', header.id, 'accounting_email_resent',
                actor_user=current_user,
                status_from=previous_accounting_status,
                status_to='Accounting Email Queued',
                remarks=remarks,
                metadata={
                    'resend': True,
                    'recipient_count': len(recipient_emails),
                    'cash_advance_id': header.id,
                    'recipient_group': cash_advance_email_route.get('group_key'),
                    'recipient_group_label': cash_advance_email_route.get('group_label')
                }
            )
            db.session.add(header)
            db.session.commit()
            queued = send_cash_advance_accounting_email_async(
                app, header.id, recipient_emails,
                approved_by_user_id=clean_int(getattr(header, 'approved_by_id', None)) or current_user.id,
                remarks=clean_str(getattr(header, 'approval_remarks', None)) or remarks
            )
            return _queue_result(
                header,
                recipient_emails,
                queued,
                cash_advance_email_route.get('package_label') or 'Cash Advance form handoff',
                cash_advance_email_route.get('attachment_label') or 'Request for Cash Advance Form PDF',
                cash_advance_to_dict(header, include_audit=True)
            )

        if module == 'travel_liquidation':
            liquidation = db.session.get(TravelLiquidationHeader, record_id)
            if not liquidation:
                return jsonify({'success': False, 'error': 'Travel Liquidation not found.'}), 404
            if not is_superadmin_user() and not can_user_approve_travel_liquidation(current_user, liquidation):
                return jsonify({'success': False, 'error': 'This travel liquidation is not assigned to you.'}), 403
            if normalize_travel_liquidation_status(getattr(liquidation, 'status', None)) != 'Approved':
                return jsonify({'success': False, 'error': 'Only approved Travel Liquidations can be resent.'}), 409

            recipient_emails = get_travel_liquidation_accounting_recipient_emails()
            if not recipient_emails:
                return _fail_missing_recipients(liquidation, travel_liquidation_accounting_settings_warning_payload(), 'Travel Liquidation Accounting')

            previous_accounting_status = getattr(liquidation, 'accounting_status', None) or ''
            liquidation.accounting_status = 'Accounting Email Queued'
            liquidation.accounting_remarks = None
            liquidation.updated_at = now
            request_rec = getattr(liquidation, 'travel_request', None)
            if request_rec:
                request_rec.accounting_status = 'Liquidation Accounting Email Queued'
                request_rec.updated_at = now
            record_universal_approval_audit(
                'travel_liquidation', liquidation.id, 'accounting_email_resent',
                actor_user=current_user,
                status_from=previous_accounting_status,
                status_to='Accounting Email Queued',
                remarks=remarks,
                metadata={'resend': True, 'recipient_count': len(recipient_emails), 'liquidation_id': liquidation.id, 'travel_request_id': getattr(liquidation, 'travel_request_id', None)}
            )
            db.session.add(liquidation)
            db.session.commit()
            queued = send_travel_liquidation_accounting_email_async(
                app, liquidation.id, recipient_emails,
                approved_by_user_id=clean_int(getattr(liquidation, 'approved_by_id', None)) or current_user.id,
                remarks=clean_str(getattr(liquidation, 'approval_remarks', None)) or remarks
            )
            return _queue_result(liquidation, recipient_emails, queued, 'Travel Liquidation Accounting handoff', 'Travel Liquidation Accounting package ZIP', travel_liquidation_to_dict(liquidation, include_rows=True))

        if module == 'cash_advance_liquidation':
            ensure_cash_advance_tables()
            ensure_cash_advance_liquidation_tables()
            liquidation = db.session.get(CashAdvanceLiquidationHeader, record_id)
            if not liquidation:
                return jsonify({'success': False, 'error': 'Cash Advance Liquidation not found.'}), 404
            if not is_superadmin_user() and not can_user_approve_cash_advance_liquidation(current_user, liquidation):
                return jsonify({'success': False, 'error': 'This cash advance liquidation is not assigned to you.'}), 403
            if cash_advance_liquidation_normalize_status(getattr(liquidation, 'status', None)) != 'Approved':
                return jsonify({'success': False, 'error': 'Only approved Cash Advance Liquidations can be resent.'}), 409

            recipient_emails = get_cash_advance_liquidation_accounting_recipient_emails()
            if not recipient_emails:
                return _fail_missing_recipients(liquidation, cash_advance_liquidation_accounting_settings_warning_payload(), 'Cash Advance Liquidation Accounting')

            previous_accounting_status = getattr(liquidation, 'accounting_status', None) or ''
            liquidation.accounting_status = 'Accounting Email Queued'
            liquidation.accounting_remarks = None
            liquidation.updated_at = now
            header = getattr(liquidation, 'cash_advance', None)
            if header:
                header.accounting_status = 'Liquidation Accounting Email Queued'
                header.updated_at = now
            record_universal_approval_audit(
                'cash_advance_liquidation', liquidation.id, 'accounting_email_resent',
                actor_user=current_user,
                status_from=previous_accounting_status,
                status_to='Accounting Email Queued',
                remarks=remarks,
                metadata={'resend': True, 'recipient_count': len(recipient_emails), 'liquidation_id': liquidation.id, 'cash_advance_id': clean_int(getattr(liquidation, 'cash_advance_id', None))}
            )
            db.session.add(liquidation)
            db.session.commit()
            queued = send_cash_advance_liquidation_accounting_email_async(
                app, liquidation.id, recipient_emails,
                approved_by_user_id=clean_int(getattr(liquidation, 'approved_by_id', None)) or current_user.id,
                remarks=clean_str(getattr(liquidation, 'approval_remarks', None)) or remarks
            )
            return _queue_result(liquidation, recipient_emails, queued, 'Cash Advance Liquidation Accounting handoff', 'Cash Advance Liquidation Accounting package ZIP', cash_advance_liquidation_to_dict(liquidation, include_rows=True))

    except Exception as exc:
        db.session.rollback()
        print(f"[EMAIL] Global approved-request resend failed: module={module} record_id={record_id} error={exc}", flush=True)
        return jsonify({'success': False, 'error': 'Unable to queue resend email.'}), 500

    return jsonify({'success': False, 'error': 'Unsupported resend module.'}), 400

if __name__ == '__main__':
    initialize_database()
    run_development_server()
